{
  "name": "ManualMaster AI",
  "description": "A professional tool to create visual user manuals and instruction guides. Upload images, write steps, enhance text with AI, and export to PDF."
}

export interface ManualStep {
  id: string;
  title: string;
  description: string;
  imageUrl: string | null;
  imageFile: File | null;
}

export interface ManualMetadata {
  title: string;
  subtitle: string;
  author: string;
  version: string;
}

export interface AIResponse {
  refinedTitle: string;
  refinedDescription: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIResponse } from "../types";

const createClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }
  return new GoogleGenAI({ apiKey });
};

export const refineStepText = async (
  currentTitle: string,
  currentDescription: string
): Promise<AIResponse> => {
  const ai = createClient();

  const prompt = `
    You are an expert technical writer and editor. 
    Your task is to refine the following user manual step to be clear, concise, professional, and easy to understand.

    Current Title: "${currentTitle}"
    Current Description: "${currentDescription}"

    Return the refined title and description in valid JSON format.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            refinedTitle: { type: Type.STRING },
            refinedDescription: { type: Type.STRING },
          },
          required: ["refinedTitle", "refinedDescription"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text) as AIResponse;
    return data;
  } catch (error) {
    console.error("Error calling Gemini API:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { ManualStep } from '../types';
import { refineStepText } from '../services/geminiService';

interface StepEditorProps {
  step: ManualStep;
  index: number;
  onUpdate: (id: string, updates: Partial<ManualStep>) => void;
  onDelete: (id: string) => void;
  onMoveUp: (index: number) => void;
  onMoveDown: (index: number) => void;
  totalSteps: number;
}

const StepEditor: React.FC<StepEditorProps> = ({ 
  step, 
  index, 
  onUpdate, 
  onDelete,
  onMoveUp,
  onMoveDown,
  totalSteps
}) => {
  const [isEnhancing, setIsEnhancing] = useState(false);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const imageUrl = URL.createObjectURL(file);
      onUpdate(step.id, { imageFile: file, imageUrl });
    }
  };

  const handleAIEnhance = async () => {
    if (!step.title && !step.description) return;

    setIsEnhancing(true);
    try {
      const result = await refineStepText(step.title, step.description);
      onUpdate(step.id, {
        title: result.refinedTitle,
        description: result.refinedDescription
      });
    } catch (error) {
      alert("Failed to enhance text. Please check your API configuration.");
    } finally {
      setIsEnhancing(false);
    }
  };

  return (
    <div className="bg-white p-4 rounded-lg shadow-sm border border-slate-200 mb-4 transition-all hover:shadow-md">
      <div className="flex justify-between items-center mb-4">
        <h3 className="font-semibold text-slate-700">Step {index + 1}</h3>
        <div className="flex gap-2">
           <button 
            onClick={() => onMoveUp(index)} 
            disabled={index === 0}
            className="p-1 text-slate-400 hover:text-primary disabled:opacity-30"
            title="Move Up"
          >
            <i className="fas fa-chevron-up"></i>
          </button>
          <button 
            onClick={() => onMoveDown(index)} 
            disabled={index === totalSteps - 1}
            className="p-1 text-slate-400 hover:text-primary disabled:opacity-30"
            title="Move Down"
          >
            <i className="fas fa-chevron-down"></i>
          </button>
          <button 
            onClick={() => onDelete(step.id)} 
            className="p-1 text-red-400 hover:text-red-600 ml-2"
            title="Delete Step"
          >
            <i className="fas fa-trash"></i>
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {/* Image Upload Area */}
        <div className="w-full">
          <label className="block text-sm font-medium text-slate-600 mb-1">Image</label>
          <div className="flex items-start gap-4">
            <div className={`
              w-24 h-24 border-2 border-dashed rounded-lg flex items-center justify-center bg-slate-50 overflow-hidden relative
              ${!step.imageUrl ? 'border-slate-300' : 'border-primary'}
            `}>
              {step.imageUrl ? (
                <img src={step.imageUrl} alt="Preview" className="w-full h-full object-cover" />
              ) : (
                <i className="fas fa-image text-slate-300 text-2xl"></i>
              )}
            </div>
            <div className="flex-1">
              <input 
                type="file" 
                accept="image/*"
                onChange={handleImageChange}
                className="block w-full text-sm text-slate-500
                  file:mr-4 file:py-2 file:px-4
                  file:rounded-full file:border-0
                  file:text-sm file:font-semibold
                  file:bg-blue-50 file:text-primary
                  hover:file:bg-blue-100 cursor-pointer
                "
              />
              <p className="text-xs text-slate-400 mt-1">Recommended: Landscape orientation</p>
            </div>
          </div>
        </div>

        {/* Text Inputs */}
        <div className="grid grid-cols-1 gap-3">
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Title</label>
            <input
              type="text"
              value={step.title}
              onChange={(e) => onUpdate(step.id, { title: e.target.value })}
              placeholder="e.g., Unbox the device"
              className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary/50 text-sm"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1 flex justify-between">
              Description
              <button 
                onClick={handleAIEnhance}
                disabled={isEnhancing || (!step.title && !step.description)}
                className="text-xs flex items-center gap-1 text-purple-600 hover:text-purple-800 disabled:opacity-50 disabled:cursor-not-allowed font-semibold"
              >
                {isEnhancing ? (
                  <><i className="fas fa-spinner fa-spin"></i> Enhancing...</>
                ) : (
                  <><i className="fas fa-magic"></i> AI Polish</>
                )}
              </button>
            </label>
            <textarea
              rows={3}
              value={step.description}
              onChange={(e) => onUpdate(step.id, { description: e.target.value })}
              placeholder="Describe the action in detail..."
              className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary/50 text-sm"
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default StepEditor;

