import React, { useState, useRef, useCallback } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import { ManualStep, ManualMetadata } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const previewRef = useRef<HTMLDivElement>(null);

  const [metadata, setMetadata] = useState<ManualMetadata>({
    title: 'Product Manual',
    subtitle: 'Setup & Configuration Guide',
    author: 'My Company Inc.',
    version: '1.0'
  });

  const [steps, setSteps] = useState<ManualStep[]>([
    {
      id: uuidv4(),
      title: 'Unboxing',
      description: 'Carefully remove the device from the packaging. Ensure all accessories are present.',
      imageUrl: 'https://picsum.photos/400/300',
      imageFile: null
    }
  ]);

  // --- Handlers ---

  const addStep = () => {
    setSteps([
      ...steps,
      {
        id: uuidv4(),
        title: '',
        description: '',
        imageUrl: null,
        imageFile: null
      }
    ]);
  };

  const updateStep = (id: string, updates: Partial<ManualStep>) => {
    setSteps(steps.map(step => step.id === id ? { ...step, ...updates } : step));
  };

  const deleteStep = (id: string) => {
    if (steps.length > 1) {
      setSteps(steps.filter(step => step.id !== id));
    } else {
      // If deleting last step, just clear it
      updateStep(id, { title: '', description: '', imageUrl: null, imageFile: null });
    }
  };

  const moveStep = (index: number, direction: 'up' | 'down') => {
    if (direction === 'up' && index === 0) return;
    if (direction === 'down' && index === steps.length - 1) return;

    const newSteps = [...steps];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    [newSteps[index], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[index]];
    setSteps(newSteps);
  };

  const generatePDF = useCallback(async () => {
    if (!previewRef.current) {
        // If in editor mode on mobile, preview might not be mounted visible, switch tab logic handles layout
        // But for PDF generation, we need the element. 
        // In desktop split view it's always there.
        // In mobile tab view, we force show it momentarily or rely on user being on preview tab.
        // For better UX, let's alert if not visible.
        if (window.innerWidth < 768 && activeTab !== 'preview') {
            alert("Please switch to Preview tab to generate PDF.");
            return;
        }
    }

    setIsGenerating(true);
    try {
      const element = previewRef.current;
      if (!element) return;

      const canvas = await html2canvas(element, {
        scale: 2, // Higher quality
        useCORS: true, // For external images
        logging: false,
        backgroundColor: '#ffffff'
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
      });

      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();
      const imgWidth = canvas.width;
      const imgHeight = canvas.height;
      const ratio = Math.min(pdfWidth / imgWidth, pdfHeight / imgHeight);

      // Calculate height to fit A4 width
      const imgProps = pdf.getImageProperties(imgData);
      const finalHeight = (imgProps.height * pdfWidth) / imgProps.width;

      // Handle multi-page content if needed (simple version here assumes single long page scales or cuts)
      // For a proper manual, html2canvas creates one big image. 
      // We will fit it to one page or split it. 
      // For this MVP, we will fit to width and allow height to expand if user prints, 
      // or simply add pages if the content is too long.

      // Simpler approach for MVP: One long continuous PDF page or multiple A4s.
      // Let's stick to standard A4 single page scaling for now, assuming content fits.
      // If content is very long, a more complex splitting logic is needed.

      let heightLeft = finalHeight;
      let position = 0;
      let pageHeight = 297;

      pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, finalHeight);
      heightLeft -= pageHeight;

      while (heightLeft >= 0) {
        position = heightLeft - finalHeight; // top padding for next page
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, finalHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`${metadata.title.replace(/\s+/g, '_')}_Manual.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, activeTab]);

  return (
    <div className="flex flex-col h-screen bg-slate-50">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 py-3 flex items-center justify-between shadow-sm sticky top-0 z-50">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center text-white">
            <i className="fas fa-book-open"></i>
          </div>
          <span className="font-bold text-xl text-slate-800">ManualMaster AI</span>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className="bg-slate-900 hover:bg-slate-700 text-white px-4 py-2 rounded-lg text-sm font-semibold flex items-center gap-2 transition-colors disabled:opacity-70"
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-file-pdf"></i>}
            Export PDF
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-5/12 border-r border-slate-200 bg-white overflow-y-auto
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>
          <div className="p-6 space-y-8">
            {/* Metadata Section */}
            <section className="bg-slate-50 p-4 rounded-xl border border-slate-100">
              <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4">Metadata</h2>
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="text-xs font-bold text-slate-500">Manual Title</label>
                  <input 
                    type="text" 
                    value={metadata.title}
                    onChange={(e) => setMetadata({...metadata, title: e.target.value})}
                    className="w-full mt-1 p-2 border border-slate-300 rounded text-sm focus:border-primary focus:outline-none"
                  />
                </div>
                <div className="col-span-2">
                  <label className="text-xs font-bold text-slate-500">Subtitle</label>
                  <input 
                    type="text" 
                    value={metadata.subtitle}
                    onChange={(e) => setMetadata({...metadata, subtitle: e.target.value})}
                    className="w-full mt-1 p-2 border border-slate-300 rounded text-sm focus:border-primary focus:outline-none"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-slate-500">Author/Company</label>
                  <input 
                    type="text" 
                    value={metadata.author}
                    onChange={(e) => setMetadata({...metadata, author: e.target.value})}
                    className="w-full mt-1 p-2 border border-slate-300 rounded text-sm focus:border-primary focus:outline-none"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-slate-500">Version</label>
                  <input 
                    type="text" 
                    value={metadata.version}
                    onChange={(e) => setMetadata({...metadata, version: e.target.value})}
                    className="w-full mt-1 p-2 border border-slate-300 rounded text-sm focus:border-primary focus:outline-none"
                  />
                </div>
              </div>
            </section>

            {/* Steps Section */}
            <section>
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Instructions Steps</h2>
                <span className="text-xs bg-slate-100 px-2 py-1 rounded text-slate-500">{steps.length} Steps</span>
              </div>

              <div className="space-y-4">
                {steps.map((step, idx) => (
                  <StepEditor
                    key={step.id}
                    index={idx}
                    step={step}
                    totalSteps={steps.length}
                    onUpdate={updateStep}
                    onDelete={deleteStep}
                    onMoveUp={() => moveStep(idx, 'up')}
                    onMoveDown={() => moveStep(idx, 'down')}
                  />
                ))}
              </div>

              <button 
                onClick={addStep}
                className="w-full mt-6 py-3 border-2 border-dashed border-primary/30 text-primary font-semibold rounded-lg hover:bg-blue-50 transition-colors flex items-center justify-center gap-2"
              >
                <i className="fas fa-plus"></i> Add New Step
              </button>
            </section>
          </div>
        </div>

        {/* Preview Side (Right) */}
        <div className={`
          flex-col w-full md:w-7/12 bg-slate-100 relative
          ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Mobile Tab Switcher */}
          <div className="md:hidden flex border-b border-slate-200 bg-white">
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-primary border-b-2 border-primary' : 'text-slate-500'}`}
              onClick={() => setActiveTab('editor')}
            >
              Edit
            </button>
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-primary border-b-2 border-primary' : 'text-slate-500'}`}
              onClick={() => setActiveTab('preview')}
            >
              Preview
            </button>
          </div>

          <Preview 
            steps={steps} 
            metadata={metadata} 
            previewRef={previewRef}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

