                ${isCustom ? 'border-primary-600 bg-primary-50/30' : 'border-slate-100 bg-slate-50/50'}
              `}
              onClick={handleCustomFocus}
            >
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Width (mm)</label>
                <input
                  type="number"
                  value={customWidth}
                  onChange={(e) => setCustomWidth(e.target.value)}
                  onFocus={handleCustomFocus}
                  className="w-full p-2 rounded-lg border border-slate-200 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 outline-none"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Height (mm)</label>
                <input
                  type="number"
                  value={customHeight}
                  onChange={(e) => setCustomHeight(e.target.value)}
                  onFocus={handleCustomFocus}
                  className="w-full p-2 rounded-lg border border-slate-200 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 outline-none"
                />
              </div>
            </div>

            <button
              onClick={handleSubmit}
              className="w-full py-4 bg-slate-900 text-white font-bold rounded-xl shadow-lg hover:bg-slate-800 hover:shadow-xl hover:-translate-y-0.5 transition-all flex items-center justify-center gap-2 group"
            >
