import React, { useState, useRef, useCallback } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import { ManualStep, ManualMetadata, PageDimensions } from './types';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(true);
  const previewRef = useRef<HTMLDivElement>(null);

  const [metadata, setMetadata] = useState<ManualMetadata>({
    title: 'Product Manual',
    subtitle: 'Setup & Configuration Guide',
    author: 'My Company Inc.',
    version: '1.0'
  });

  const [steps, setSteps] = useState<ManualStep[]>([
    {
      id: uuidv4(),
      title: 'Unboxing',
      description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.',
      imageUrl: null,
      imageFile: null
    }
  ]);

  // --- Handlers ---

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setHasStarted(true);
  };

  const addStep = () => {
    setTimeout(() => {
      const el = document.getElementById('steps-container');
      if (el) el.scrollTop = el.scrollHeight;
    }, 100);

    setSteps([
      ...steps,
      {
        id: uuidv4(),
        title: '',
        description: '',
        imageUrl: null,
        imageFile: null
      }
    ]);
  };

  const updateStep = (id: string, updates: Partial<ManualStep>) => {
    setSteps(steps.map(step => step.id === id ? { ...step, ...updates } : step));
  };

  const deleteStep = (id: string) => {
    if (steps.length > 1) {
      if(window.confirm("Are you sure you want to delete this step?")) {
        setSteps(steps.filter(step => step.id !== id));
      }
    } else {
      updateStep(id, { title: '', description: '', imageUrl: null, imageFile: null });
    }
  };

  const moveStep = (index: number, direction: 'up' | 'down') => {
    if (direction === 'up' && index === 0) return;
    if (direction === 'down' && index === steps.length - 1) return;

    const newSteps = [...steps];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    [newSteps[index], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[index]];
    setSteps(newSteps);
  };

  const generatePDF = useCallback(async () => {
    if (!previewRef.current) {
        if (window.innerWidth < 768 && activeTab !== 'preview') {
            alert("Please switch to Preview tab to generate PDF.");
            return;
        }
    }

    setIsGenerating(true);
    try {
      const element = previewRef.current;
      if (!element) return;

      const originalShadow = element.style.boxShadow;
      element.style.boxShadow = 'none';

      const canvas = await html2canvas(element, {
        scale: 2, 
        useCORS: true, 
        logging: false,
        backgroundColor: '#ffffff',
        windowWidth: 1200 
      });

      element.style.boxShadow = originalShadow;

      const imgData = canvas.toDataURL('image/png');

      // Initialize jsPDF with the selected dimensions
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });

      const pdfWidth = pdf.internal.pageSize.getWidth();
      // const pdfHeight = pdf.internal.pageSize.getHeight(); 
      // Not strictly needed for loop if we trust the format config, but good for calc

      const imgProps = pdf.getImageProperties(imgData);
      const finalHeight = (imgProps.height * pdfWidth) / imgProps.width;

      let heightLeft = finalHeight;
      let position = 0;
      let pageHeight = pageDimensions.height; // Use the selected height

      pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, finalHeight);
      heightLeft -= pageHeight;

      while (heightLeft >= 0) {
        position = heightLeft - finalHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, finalHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_manual.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF. If using remote images, ensure CORS is enabled.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, activeTab, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} />;
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 h-16 flex items-center justify-between shadow-sm shrink-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-primary-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary-500/30">
            <i className="fas fa-book-open text-lg"></i>
          </div>
          <div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight leading-none">ManualMaster</h1>
            <p className="text-xs text-slate-500 font-medium">AI-Powered Documentation</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
           {/* Change Size Button (Optional for future, but good to have a way back) */}
           <button 
             onClick={() => { if(window.confirm('Go back to start? Unsaved changes will be lost.')) window.location.reload(); }}
             className="text-slate-400 hover:text-slate-600 text-xs font-semibold uppercase tracking-wider hidden md:block"
           >
             {pageDimensions.name} ({pageDimensions.width}x{pageDimensions.height}mm)
           </button>

          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-full text-sm font-semibold flex items-center gap-2 transition-all
              ${isGenerating 
                ? 'bg-slate-100 text-slate-400 cursor-wait' 
                : 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-lg active:transform active:scale-95'
              }
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span>{isGenerating ? 'Exporting...' : 'Download PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[480px] lg:w-[560px] border-r border-slate-200 bg-white shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Editor Header / Tabs */}
          <div className="px-6 py-4 border-b border-slate-100 bg-white">
             <div className="flex items-center justify-between">
                <h2 className="text-lg font-bold text-slate-800">Editor</h2>
                <div className="text-xs text-slate-400 font-medium">{steps.length} Steps</div>
             </div>
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto p-6 scroll-smooth">

            {/* Metadata Accordion */}
            <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden mb-8 transition-all">
              <button 
                onClick={() => setIsMetadataExpanded(!isMetadataExpanded)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
              >
                <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                  <i className="fas fa-cog text-slate-400"></i>
                  Document Settings
                </div>
                <i className={`fas fa-chevron-down text-slate-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>

              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                   <div className="col-span-2 h-px bg-slate-200 mb-2"></div>
                   <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Title</label>
                    <input 
                      type="text" 
                      value={metadata.title}
                      onChange={(e) => setMetadata({...metadata, title: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. User Manual"
                    />
                  </div>
                  <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Subtitle</label>
                    <input 
                      type="text" 
                      value={metadata.subtitle}
                      onChange={(e) => setMetadata({...metadata, subtitle: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. Quick Start Guide"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Author</label>
                    <input 
                      type="text" 
                      value={metadata.author}
                      onChange={(e) => setMetadata({...metadata, author: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Version</label>
                    <input 
                      type="text" 
                      value={metadata.version}
                      onChange={(e) => setMetadata({...metadata, version: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                </div>
              )}
            </div>

            {/* Steps List */}
            <div className="space-y-6">
              {steps.map((step, idx) => (
                <StepEditor
                  key={step.id}
                  index={idx}
                  step={step}
                  totalSteps={steps.length}
                  onUpdate={updateStep}
                  onDelete={deleteStep}
                  onMoveUp={() => moveStep(idx, 'up')}
                  onMoveDown={() => moveStep(idx, 'down')}
                />
              ))}
            </div>

            {/* Bottom Spacer for Floating Button */}
            <div className="h-24"></div>
          </div>

          {/* Floating Action Button for Adding Steps */}
          <div className="absolute bottom-6 left-0 w-full md:w-[480px] lg:w-[560px] px-6 pointer-events-none">
            <button 
              onClick={addStep}
              className="pointer-events-auto w-full py-4 bg-white/90 backdrop-blur border-2 border-dashed border-primary-500/30 text-primary-600 font-bold rounded-xl hover:bg-primary-50 hover:border-primary-500 transition-all shadow-lg flex items-center justify-center gap-2 group"
            >
              <div className="w-6 h-6 rounded-full bg-primary-100 flex items-center justify-center group-hover:bg-primary-600 group-hover:text-white transition-colors">
                <i className="fas fa-plus text-xs"></i>
              </div>
              Add New Instruction Step
            </button>
          </div>
        </div>

        {/* Preview Side (Right) */}
        <div className={`
          flex-col flex-grow bg-slate-100 relative
          ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Mobile Tab Switcher */}
          <div className="md:hidden flex border-b border-slate-200 bg-white shrink-0">
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('editor')}
            >
              <i className="fas fa-edit mr-2"></i> Editor
            </button>
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('preview')}
            >
              <i className="fas fa-eye mr-2"></i> Preview
            </button>
          </div>

          <Preview 
            steps={steps} 
            metadata={metadata} 
            dimensions={pageDimensions}
            previewRef={previewRef}
          />
        </div>
      </div>
    </div>
  );
};

