  width: number;
  height: number;
  name: string;
}

import React, { useState, useRef, useCallback } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage } from './types';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(true);

  const previewRef = useRef<HTMLDivElement>(null);

  // --- State: Pages & Content ---
  const [metadata, setMetadata] = useState<ManualMetadata>({
    title: 'Product Manual',
    subtitle: 'Setup & Configuration Guide',
    author: 'My Company Inc.',
    version: '1.0'
  });

  const [pages, setPages] = useState<ManualPage[]>([
    {
      id: uuidv4(),
      type: 'toc',
      title: 'Table of Contents',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'content',
      title: 'Getting Started',
      steps: [
        {
          id: uuidv4(),
          title: 'Unboxing',
          description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.',
          imageUrl: null,
          imageFile: null
        }
      ]
    }
  ]);

  const [activePageIndex, setActivePageIndex] = useState(1); // Start on first content page

  // --- Handlers ---

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setHasStarted(true);
  };

  const activePage = pages[activePageIndex];

  // Add a new empty content page
  const addNewPage = () => {
    setPages([...pages, { id: uuidv4(), type: 'content', title: '', steps: [] }]);
    setActivePageIndex(pages.length); // Switch to new page
  };

  const addTocPage = () => {
     // Check if TOC already exists
     if (pages.some(p => p.type === 'toc')) {
       alert("A Table of Contents page already exists.");
       return;
     }
     // Insert at beginning
     setPages([{ id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] }, ...pages]);
     setActivePageIndex(0);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) {
      setActivePageIndex(index);
    }
  };

  const deletePage = (index: number) => {
    if (pages.length <= 1) {
      alert("You must have at least one page.");
      return;
    }
    const pageToDelete = pages[index];
    const message = pageToDelete.type === 'toc' 
      ? "Delete the Table of Contents?" 
      : "Are you sure you want to delete this page and all its steps?";

    if (window.confirm(message)) {
      const newPages = pages.filter((_, i) => i !== index);
      setPages(newPages);
      setActivePageIndex(Math.max(0, index - 1));
    }
  };

  // Update Page Title (used for TOC)
  const updatePageTitle = (title: string) => {
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  // Step Management (Scoped to Active Page)
  const addStepToActivePage = () => {
    if (activePage.type === 'toc') return;

    const newStep: ManualStep = {
      id: uuidv4(),
      title: '',
      description: '',
      imageUrl: null,
      imageFile: null
    };

    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);

    setTimeout(() => {
      const el = document.getElementById('steps-container');
      if (el) el.scrollTop = el.scrollHeight;
    }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step)
    }));
    setPages(newPages);
  };

  const deleteStep = (stepId: string) => {
    if (window.confirm("Delete this step?")) {
      const newPages = pages.map(page => ({
        ...page,
        steps: page.steps.filter(step => step.id !== stepId)
      }));
      setPages(newPages);
    }
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type === 'toc') return;

    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;

    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];

    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  // --- Automatic Overflow Handling ---
  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      const currentPage = prevPages[pageIndex];
      // Do not handle overflow for TOC pages
      if (currentPage.type === 'toc') return prevPages;

      // Safety check: Don't move if there's only 1 step
      if (currentPage.steps.length <= 1) return prevPages;

      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);

      // Check if next page exists, if not create it
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];

      // Update current page
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };

      if (nextPage && nextPage.type === 'content') {
        // Add to beginning of next page if it is a content page
        newPages[nextPageIndex] = {
          ...nextPage,
          steps: [lastStep, ...nextPage.steps]
        };
      } else {
        // Create new content page (insert it if next page is not content, though normally TOC is first)
        // If next page exists but is TOC (unlikely if TOC is first), insert before? No, standard flow append.
        const newPage: ManualPage = {
            id: uuidv4(),
            type: 'content',
            title: 'Continued...',
            steps: [lastStep]
        };

        // Insert at nextPageIndex
        newPages.splice(nextPageIndex, 0, newPage);
      }

      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });

      // Iterate through all rendered pages in the Preview
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;

        if (i > 0) pdf.addPage();

        // Temporarily remove shadow for clean capture
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';

        const canvas = await html2canvas(pageElement, {
          scale: 2, 
          useCORS: true, 
          logging: false,
          backgroundColor: '#ffffff',
          windowWidth: 1200 
        });

        // Restore styles
        pageElement.style.boxShadow = originalShadow;

        const imgData = canvas.toDataURL('image/png');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} />;
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 h-16 flex items-center justify-between shadow-sm shrink-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-primary-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary-500/30">
            <i className="fas fa-book-open text-lg"></i>
          </div>
          <div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight leading-none">ManualMaster</h1>
            <p className="text-xs text-slate-500 font-medium">AI-Powered Documentation</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
           <button 
             onClick={() => { if(window.confirm('Go back to start? Unsaved changes will be lost.')) window.location.reload(); }}
             className="text-slate-400 hover:text-slate-600 text-xs font-semibold uppercase tracking-wider hidden md:block"
           >
             {pageDimensions.name} ({pageDimensions.width}x{pageDimensions.height}mm)
           </button>

          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-full text-sm font-semibold flex items-center gap-2 transition-all
              ${isGenerating 
                ? 'bg-slate-100 text-slate-400 cursor-wait' 
                : 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-lg active:transform active:scale-95'
              }
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span>{isGenerating ? 'Exporting...' : 'Download PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[480px] lg:w-[560px] border-r border-slate-200 bg-white shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Page Navigator */}
          <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center">
            {/* Add TOC Button if not present */}
            {!pages.some(p => p.type === 'toc') && (
               <button 
                onClick={addTocPage}
                className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-600 border border-slate-200 hover:bg-slate-200 transition-colors mr-2"
                title="Insert Table of Contents"
              >
                <i className="fas fa-list-ol mr-1"></i> TOC
              </button>
            )}

            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all border flex items-center gap-2
                  ${activePageIndex === idx 
                    ? 'bg-slate-800 text-white border-slate-800 shadow-md' 
                    : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
                  }
                `}
              >
                {page.type === 'toc' ? <i className="fas fa-list text-[10px]"></i> : `Page ${idx + 1}`}
              </button>
            ))}
            <button 
              onClick={addNewPage}
              className="px-3 py-1.5 rounded-lg text-xs font-bold bg-primary-50 text-primary-600 border border-primary-200 hover:bg-primary-100 transition-colors"
              title="Add New Page"
            >
              <i className="fas fa-plus"></i>
            </button>
          </div>

          {/* Editor Header */}
          <div className="px-6 py-4 border-b border-slate-100 bg-white flex justify-between items-center">
             <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-lg font-bold text-slate-800">
                        {activePage.type === 'toc' ? 'Directory' : `Page ${activePageIndex + 1}`}
                    </h2>
                    {activePage.type === 'toc' && <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded">Auto-generated</span>}
                </div>
                {activePage.type === 'content' && (
                    <span className="text-xs text-slate-400 font-medium">{activePage.steps.length} Steps</span>
                )}
             </div>
             {pages.length > 1 && (
                <button 
                  onClick={() => deletePage(activePageIndex)}
                  className="text-red-400 hover:text-red-600 text-xs px-2 py-1 rounded hover:bg-red-50 transition-colors"
                >
                  <i className="fas fa-trash-alt mr-1"></i> Delete
                </button>
             )}
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto p-6 scroll-smooth">

            {/* Metadata Accordion */}
            <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden mb-8 transition-all">
              <button 
                onClick={() => setIsMetadataExpanded(!isMetadataExpanded)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
              >
                <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                  <i className="fas fa-cog text-slate-400"></i>
                  Global Document Settings
                </div>
                <i className={`fas fa-chevron-down text-slate-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>

              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                   <div className="col-span-2 h-px bg-slate-200 mb-2"></div>
                   <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Title</label>
                    <input 
                      type="text" 
                      value={metadata.title}
                      onChange={(e) => setMetadata({...metadata, title: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. User Manual"
                    />
                  </div>
                  <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Subtitle</label>
                    <input 
                      type="text" 
                      value={metadata.subtitle}
                      onChange={(e) => setMetadata({...metadata, subtitle: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. Quick Start Guide"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Author</label>
                    <input 
                      type="text" 
                      value={metadata.author}
                      onChange={(e) => setMetadata({...metadata, author: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Version</label>
                    <input 
                      type="text" 
                      value={metadata.version}
                      onChange={(e) => setMetadata({...metadata, version: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                </div>
              )}
            </div>

            {/* Page Title Editor (Specifically for TOC mapping) */}
            <div className="mb-6">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">
                    {activePage.type === 'toc' ? 'Directory Header' : 'Page Title (For Directory)'}
                </label>
                <div className="relative">
                    <input 
                        type="text" 
                        value={activePage.title || ''}
                        onChange={(e) => updatePageTitle(e.target.value)}
                        className="w-full p-3 bg-white border border-slate-300 rounded-lg text-base font-semibold text-slate-800 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                        placeholder={activePage.type === 'toc' ? "Table of Contents" : "e.g. Safety Instructions"}
                    />
                    <i className="fas fa-heading absolute right-3 top-3.5 text-slate-300"></i>
                </div>
                {activePage.type === 'content' && !activePage.title && activePage.steps.length > 0 && activePage.steps[0].title && (
                    <p className="text-[10px] text-slate-400 mt-1 ml-1">
                        <i className="fas fa-info-circle mr-1"></i>
                        Will default to first step title: "{activePage.steps[0].title}"
                    </p>
                )}
            </div>

            {/* Steps List for Active Page */}
            {activePage.type === 'toc' ? (
                <div className="bg-white border border-slate-200 rounded-xl p-8 text-center">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <i className="fas fa-list-ol text-2xl text-slate-300"></i>
                    </div>
                    <h3 className="font-bold text-slate-700 mb-2">Automatic Directory</h3>
                    <p className="text-sm text-slate-500 max-w-xs mx-auto">
                        This page automatically lists all subsequent pages and their titles. You can rename this page above.
                    </p>
                    <div className="mt-6 border-t border-slate-100 pt-4 text-xs text-slate-400">
                        Content is visible in Preview mode.
                    </div>
                </div>
            ) : (
                <div className="space-y-6">
                {activePage.steps.length === 0 && (
                    <div className="text-center py-10 text-slate-400">
                    <i className="fas fa-layer-group text-4xl mb-3 opacity-20"></i>
                    <p className="text-sm">This page is empty.</p>
                    <p className="text-xs">Add a step below to get started.</p>
                    </div>
                )}
                {activePage.steps.map((step, idx) => (
                    <StepEditor
                    key={step.id}
                    index={idx}
                    step={step}
                    totalSteps={activePage.steps.length}
                    onUpdate={updateStep}
                    onDelete={deleteStep}
                    onMoveUp={() => moveStep(idx, 'up')}
                    onMoveDown={() => moveStep(idx, 'down')}
                    />
                ))}
                </div>
            )}

            {/* Bottom Spacer for Floating Button */}
            <div className="h-24"></div>
          </div>

          {/* Floating Action Button for Adding Steps */}
          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[480px] lg:w-[560px] px-6 pointer-events-none">
                <button 
                onClick={addStepToActivePage}
                className="pointer-events-auto w-full py-4 bg-white/90 backdrop-blur border-2 border-dashed border-primary-500/30 text-primary-600 font-bold rounded-xl hover:bg-primary-50 hover:border-primary-500 transition-all shadow-lg flex items-center justify-center gap-2 group"
                >
                <div className="w-6 h-6 rounded-full bg-primary-100 flex items-center justify-center group-hover:bg-primary-600 group-hover:text-white transition-colors">
                    <i className="fas fa-plus text-xs"></i>
                </div>
                Add Step to Page {activePageIndex + 1}
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`
          flex-col flex-grow bg-slate-100 relative
          ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Mobile Tab Switcher */}
          <div className="md:hidden flex border-b border-slate-200 bg-white shrink-0">
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('editor')}
            >
              <i className="fas fa-edit mr-2"></i> Editor
            </button>
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('preview')}
            >
              <i className="fas fa-eye mr-2"></i> Preview
            </button>
          </div>

          <Preview 
            pages={pages} 
            metadata={metadata} 
            dimensions={pageDimensions}
            previewRef={previewRef}
            onPageOverflow={handlePageOverflow}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useLayoutEffect, useRef } from 'react';
import { ManualPage, ManualMetadata, PageDimensions } from '../types';

interface PreviewProps {
  pages: ManualPage[];
  metadata: ManualMetadata;
  dimensions: PageDimensions;
  previewRef: React.RefObject<HTMLDivElement>;
  onPageOverflow: (pageIndex: number) => void;
}

const PageContainer: React.FC<{
  page: ManualPage;
  pageIndex: number;
  allPages: ManualPage[];
  totalPages: number;
  metadata: ManualMetadata;
  dimensions: PageDimensions;
  onOverflow: (index: number) => void;
}> = ({ page, pageIndex, allPages, totalPages, metadata, dimensions, onOverflow }) => {
  const pageRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  useLayoutEffect(() => {
    // Only check overflow for content pages
    if (page.type === 'content' && pageRef.current && contentRef.current) {
      const pageHeightPx = pageRef.current.offsetHeight;
      const contentHeightPx = contentRef.current.scrollHeight;

      if (contentHeightPx > pageHeightPx && page.steps.length > 1) {
        const timer = setTimeout(() => {
          onOverflow(pageIndex);
        }, 500);
        return () => clearTimeout(timer);
      }
    }
  }, [page.steps, pageIndex, onOverflow, page.type]);

  const currentDate = new Date().toLocaleDateString();
  const isFirstPage = pageIndex === 0;

  // Render Table of Contents
  const renderTOC = () => {
    // Filter pages that are content and have something to show
    const contentPages = allPages.map((p, idx) => ({ ...p, originalIndex: idx })).filter(p => p.type === 'content');

    return (
      <div className="flex flex-col h-full">
         <h1 className="text-3xl font-bold text-slate-900 mb-12 uppercase tracking-wider text-center border-b-2 border-slate-900 pb-4">
             {page.title || "Table of Contents"}
         </h1>

         <div className="flex-grow space-y-4 px-4">
             {contentPages.map((contentPage) => {
                 // Determine label: explicit title > first step title > "Page X"
                 let label = contentPage.title;
                 if (!label && contentPage.steps.length > 0) {
                     label = contentPage.steps[0].title;
                 }
                 if (!label) {
                     label = `Page ${contentPage.originalIndex + 1}`;
                 }

                 return (
                    <div key={contentPage.id} className="flex items-end mb-4">
                        <div className="font-bold text-slate-700 text-lg">{label}</div>
                        <div className="flex-grow border-b-2 border-dotted border-slate-300 mx-2 relative top-[-6px]"></div>
                        <div className="font-bold text-slate-900 text-lg w-8 text-right">
                            {contentPage.originalIndex + 1}
                        </div>
                    </div>
                 );
             })}
         </div>
      </div>
    );
  };

  return (
    <div 
      id={`preview-page-${pageIndex}`}
      ref={pageRef}
      className="bg-white relative flex flex-col shrink-0 mb-8 shadow-md transition-transform"
      style={{ 
        width: `${dimensions.width}mm`, 
        height: `${dimensions.height}mm`, // Fixed height to enforce paging
        overflow: 'hidden' 
      }}
    >
      <div ref={contentRef} className="p-12 h-full flex flex-col relative">
        {page.type === 'toc' ? (
             renderTOC()
        ) : (
          <>
            {/* Header */}
            <header className={`${isFirstPage ? 'border-b-2 border-slate-900 pb-6 mb-10' : 'border-b border-slate-200 pb-4 mb-6'}`}>
              <div className="flex justify-between items-end">
                <div className="max-w-[70%]">
                  {isFirstPage ? (
                    <>
                      <h1 className="text-4xl font-extrabold text-slate-900 tracking-tight leading-tight">
                        {metadata.title || "User Manual"}
                      </h1>
                      <p className="text-xl text-slate-500 mt-2 font-light">
                        {metadata.subtitle || "Instruction Guide"}
                      </p>
                    </>
                  ) : (
                    <h2 className="text-lg font-bold text-slate-400 uppercase tracking-wide">
                      {metadata.title || "User Manual"} <span className="text-slate-300">/ Continued</span>
                    </h2>
                  )}
                </div>
                <div className="text-right">
                  {isFirstPage && (
                    <div className="inline-block px-3 py-1 bg-slate-100 rounded text-xs font-bold text-slate-900 mb-1">
                      v{metadata.version}
                    </div>
                  )}
                  <div className="text-xs text-slate-400">{currentDate}</div>
                </div>
              </div>
            </header>

            {/* Content */}
            <main className="flex-grow space-y-8">
              {page.steps.length === 0 && (
                <div className="flex flex-col items-center justify-center h-48 text-slate-300 border-2 border-dashed border-slate-100 rounded-xl m-8">
                  <p className="font-medium text-sm">Empty Page</p>
                </div>
              )}

              {page.steps.map((step, idx) => (
                <div key={step.id} className="flex gap-6 items-start break-inside-avoid step-item">
                  <div className="flex-shrink-0 pt-1">
                    <div className="w-8 h-8 rounded-lg bg-slate-900 text-white flex items-center justify-center font-bold text-sm shadow-md">
                       <i className="fas fa-check text-xs"></i>
                    </div>
                  </div>

                  <div className="flex-grow grid grid-cols-12 gap-6">
                     <div className={`${step.imageUrl ? 'col-span-7' : 'col-span-12'}`}>
                        <h3 className="text-lg font-bold text-slate-800 mb-2 uppercase tracking-wide">
                          {step.title || "Untitled Step"}
                        </h3>
                        <p className="text-slate-600 text-sm leading-relaxed whitespace-pre-wrap">
                          {step.description || "No description provided."}
                        </p>
                     </div>

                     {step.imageUrl && (
                       <div className="col-span-5">
                          <div className="rounded-lg border border-slate-200 overflow-hidden bg-slate-50 shadow-sm">
                            <img 
                              src={step.imageUrl} 
                              alt={step.title} 
                              className="w-full h-auto object-cover"
                            />
                          </div>
                       </div>
                     )}
                  </div>
                </div>
              ))}
            </main>
          </>
        )}

        {/* Footer with Page Number */}
        <footer className="border-t border-slate-200 pt-6 mt-auto flex justify-between items-center text-xs text-slate-400">
          <p>© {new Date().getFullYear()} {metadata.author || "Your Company"}.</p>
          <div className="font-bold text-slate-500">
            Page {pageIndex + 1} of {totalPages}
          </div>
        </footer>
      </div>
    </div>
  );
};

const Preview: React.FC<PreviewProps> = ({ pages, metadata, dimensions, previewRef, onPageOverflow }) => {
  return (
    <div className="w-full h-full bg-slate-100 p-4 md:p-8 overflow-y-auto flex justify-center">
      {/* Container for all pages */}
      <div ref={previewRef} className="flex flex-col items-center pb-20">
        {pages.map((page, index) => (
          <PageContainer
            key={page.id}
            page={page}
            pageIndex={index}
            allPages={pages}
            totalPages={pages.length}
            metadata={metadata}
            dimensions={dimensions}
            onOverflow={onPageOverflow}
          />
        ))}
      </div>
    </div>
  );
};

export default Preview;

import { GoogleGenAI, Type } from "@google/genai";
import { AIResponse, ManualStep } from "../types";

const createClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }
  return new GoogleGenAI({ apiKey });
};

export const refineStepText = async (
  currentTitle: string,
  currentDescription: string
): Promise<AIResponse> => {
  const ai = createClient();

  const prompt = `
    You are an expert technical writer and editor. 
    Your task is to refine the following user manual step to be clear, concise, professional, and easy to understand.

    Current Title: "${currentTitle}"
    Current Description: "${currentDescription}"

    Return the refined title and description in valid JSON format.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            refinedTitle: { type: Type.STRING },
            refinedDescription: { type: Type.STRING },
          },
          required: ["refinedTitle", "refinedDescription"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text) as AIResponse;
    return data;
  } catch (error) {
    console.error("Error calling Gemini API:", error);
    throw error;
  }
};

export const generatePageTitle = async (steps: ManualStep[]): Promise<string> => {
  const ai = createClient();

  const stepsContent = steps.map((s, i) => `Step ${i+1}: ${s.title} - ${s.description}`).join('\n');

  const prompt = `
    You are organizing a user manual. Based on the following list of steps found on a single page, generate a short, professional Section Title for this page (e.g., "Installation", "Safety Warnings", "Troubleshooting", "Unboxing").

    Keep it under 5 words. Do not use quotation marks.

    Steps content:
    ${stepsContent}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            pageTitle: { type: Type.STRING },
          },
          required: ["pageTitle"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text) as { pageTitle: string };
    return data.pageTitle;
  } catch (error) {
    console.error("Error generating page title:", error);
    return "New Section"; // Fallback
  }
};

import React, { useState, useRef, useCallback } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage } from './types';
import { generatePageTitle } from './services/geminiService';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(true);

  const previewRef = useRef<HTMLDivElement>(null);

  // --- State: Pages & Content ---
  const [metadata, setMetadata] = useState<ManualMetadata>({
    title: 'Product Manual',
    subtitle: 'Setup & Configuration Guide',
    author: 'My Company Inc.',
    version: '1.0'
  });

  const [pages, setPages] = useState<ManualPage[]>([
    {
      id: uuidv4(),
      type: 'toc',
      title: 'Table of Contents',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'content',
      title: 'Getting Started',
      steps: [
        {
          id: uuidv4(),
          title: 'Unboxing',
          description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.',
          imageUrl: null,
          imageFile: null
        }
      ]
    }
  ]);

  const [activePageIndex, setActivePageIndex] = useState(1); // Start on first content page

  // --- Handlers ---

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setHasStarted(true);
  };

  const activePage = pages[activePageIndex];

  // Add a new empty content page
  const addNewPage = () => {
    setPages([...pages, { id: uuidv4(), type: 'content', title: '', steps: [] }]);
    setActivePageIndex(pages.length); // Switch to new page
  };

  const addTocPage = () => {
     // Check if TOC already exists
     if (pages.some(p => p.type === 'toc')) {
       alert("A Table of Contents page already exists.");
       return;
     }
     // Insert at beginning
     setPages([{ id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] }, ...pages]);
     setActivePageIndex(0);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) {
      setActivePageIndex(index);
    }
  };

  const deletePage = (index: number) => {
    if (pages.length <= 1) {
      alert("You must have at least one page.");
      return;
    }
    const pageToDelete = pages[index];
    const message = pageToDelete.type === 'toc' 
      ? "Delete the Table of Contents?" 
      : "Are you sure you want to delete this page and all its steps?";

    if (window.confirm(message)) {
      const newPages = pages.filter((_, i) => i !== index);
      setPages(newPages);
      setActivePageIndex(Math.max(0, index - 1));
    }
  };

  // Update Page Title (used for TOC)
  const updatePageTitle = (title: string) => {
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) {
      alert("Add some steps to the page first so AI can generate a title.");
      return;
    }

    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      updatePageTitle(suggestedTitle);
    } catch (error) {
      alert("Failed to generate title. Check API key or connection.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  // Step Management (Scoped to Active Page)
  const addStepToActivePage = () => {
    if (activePage.type === 'toc') return;

    const newStep: ManualStep = {
      id: uuidv4(),
      title: '',
      description: '',
      imageUrl: null,
      imageFile: null
    };

    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);

    setTimeout(() => {
      const el = document.getElementById('steps-container');
      if (el) el.scrollTop = el.scrollHeight;
    }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step)
    }));
    setPages(newPages);
  };

  const deleteStep = (stepId: string) => {
    if (window.confirm("Delete this step?")) {
      const newPages = pages.map(page => ({
        ...page,
        steps: page.steps.filter(step => step.id !== stepId)
      }));
      setPages(newPages);
    }
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type === 'toc') return;

    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;

    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];

    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  // --- Automatic Overflow Handling ---
  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      const currentPage = prevPages[pageIndex];
      // Do not handle overflow for TOC pages
      if (currentPage.type === 'toc') return prevPages;

      // Safety check: Don't move if there's only 1 step
      if (currentPage.steps.length <= 1) return prevPages;

      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);

      // Check if next page exists, if not create it
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];

      // Update current page
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };

      if (nextPage && nextPage.type === 'content') {
        // Add to beginning of next page if it is a content page
        newPages[nextPageIndex] = {
          ...nextPage,
          steps: [lastStep, ...nextPage.steps]
        };
      } else {
        // Create new content page (insert it if next page is not content, though normally TOC is first)
        // If next page exists but is TOC (unlikely if TOC is first), insert before? No, standard flow append.
        const newPage: ManualPage = {
            id: uuidv4(),
            type: 'content',
            title: 'Continued...',
            steps: [lastStep]
        };

        // Insert at nextPageIndex
        newPages.splice(nextPageIndex, 0, newPage);
      }

      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });

      // Iterate through all rendered pages in the Preview
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;

        if (i > 0) pdf.addPage();

        // Temporarily remove shadow for clean capture
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';

        const canvas = await html2canvas(pageElement, {
          scale: 2, 
          useCORS: true, 
          logging: false,
          backgroundColor: '#ffffff',
          windowWidth: 1200 
        });

        // Restore styles
        pageElement.style.boxShadow = originalShadow;

        const imgData = canvas.toDataURL('image/png');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} />;
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 h-16 flex items-center justify-between shadow-sm shrink-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-primary-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary-500/30">
            <i className="fas fa-book-open text-lg"></i>
          </div>
          <div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight leading-none">ManualMaster</h1>
            <p className="text-xs text-slate-500 font-medium">AI-Powered Documentation</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
           <button 
             onClick={() => { if(window.confirm('Go back to start? Unsaved changes will be lost.')) window.location.reload(); }}
             className="text-slate-400 hover:text-slate-600 text-xs font-semibold uppercase tracking-wider hidden md:block"
           >
             {pageDimensions.name} ({pageDimensions.width}x{pageDimensions.height}mm)
           </button>

          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-full text-sm font-semibold flex items-center gap-2 transition-all
              ${isGenerating 
                ? 'bg-slate-100 text-slate-400 cursor-wait' 
                : 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-lg active:transform active:scale-95'
              }
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span>{isGenerating ? 'Exporting...' : 'Download PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[480px] lg:w-[560px] border-r border-slate-200 bg-white shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Page Navigator */}
          <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center">
            {/* Add TOC Button if not present */}
            {!pages.some(p => p.type === 'toc') && (
               <button 
                onClick={addTocPage}
                className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-600 border border-slate-200 hover:bg-slate-200 transition-colors mr-2"
                title="Insert Table of Contents"
              >
                <i className="fas fa-list-ol mr-1"></i> TOC
              </button>
            )}

            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all border flex items-center gap-2
                  ${activePageIndex === idx 
                    ? 'bg-slate-800 text-white border-slate-800 shadow-md' 
                    : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
                  }
                `}
              >
                {page.type === 'toc' ? <i className="fas fa-list text-[10px]"></i> : `Page ${idx + 1}`}
              </button>
            ))}
            <button 
              onClick={addNewPage}
              className="px-3 py-1.5 rounded-lg text-xs font-bold bg-primary-50 text-primary-600 border border-primary-200 hover:bg-primary-100 transition-colors"
              title="Add New Page"
            >
              <i className="fas fa-plus"></i>
            </button>
          </div>

          {/* Editor Header */}
          <div className="px-6 py-4 border-b border-slate-100 bg-white flex justify-between items-center">
             <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-lg font-bold text-slate-800">
                        {activePage.type === 'toc' ? 'Directory' : `Page ${activePageIndex + 1}`}
                    </h2>
                    {activePage.type === 'toc' && <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded">Auto-generated</span>}
                </div>
                {activePage.type === 'content' && (
                    <span className="text-xs text-slate-400 font-medium">{activePage.steps.length} Steps</span>
                )}
             </div>
             {pages.length > 1 && (
                <button 
                  onClick={() => deletePage(activePageIndex)}
                  className="text-red-400 hover:text-red-600 text-xs px-2 py-1 rounded hover:bg-red-50 transition-colors"
                >
                  <i className="fas fa-trash-alt mr-1"></i> Delete
                </button>
             )}
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto p-6 scroll-smooth">

            {/* Metadata Accordion */}
            <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden mb-8 transition-all">
              <button 
                onClick={() => setIsMetadataExpanded(!isMetadataExpanded)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
              >
                <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                  <i className="fas fa-cog text-slate-400"></i>
                  Global Document Settings
                </div>
                <i className={`fas fa-chevron-down text-slate-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>

              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                   <div className="col-span-2 h-px bg-slate-200 mb-2"></div>
                   <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Title</label>
                    <input 
                      type="text" 
                      value={metadata.title}
                      onChange={(e) => setMetadata({...metadata, title: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. User Manual"
                    />
                  </div>
                  <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Subtitle</label>
                    <input 
                      type="text" 
                      value={metadata.subtitle}
                      onChange={(e) => setMetadata({...metadata, subtitle: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. Quick Start Guide"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Author</label>
                    <input 
                      type="text" 
                      value={metadata.author}
                      onChange={(e) => setMetadata({...metadata, author: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Version</label>
                    <input 
                      type="text" 
                      value={metadata.version}
                      onChange={(e) => setMetadata({...metadata, version: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                </div>
              )}
            </div>

            {/* Page Title Editor (Specifically for TOC mapping) */}
            <div className="mb-6">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 flex justify-between items-end">
                    <span>{activePage.type === 'toc' ? 'Directory Header' : 'Page Title (For Directory & Header)'}</span>
                    {activePage.type === 'content' && (
                      <button 
                        onClick={handleAutoGeneratePageTitle}
                        disabled={isGeneratingTitle || activePage.steps.length === 0}
                        className="text-[10px] text-primary-600 hover:text-primary-700 bg-primary-50 hover:bg-primary-100 px-2 py-1 rounded transition-colors disabled:opacity-50"
                      >
                         {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Generate
                      </button>
                    )}
                </label>
                <div className="relative">
                    <input 
                        type="text" 
                        value={activePage.title || ''}
                        onChange={(e) => updatePageTitle(e.target.value)}
                        className="w-full p-3 bg-white border border-slate-300 rounded-lg text-base font-semibold text-slate-800 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                        placeholder={activePage.type === 'toc' ? "Table of Contents" : "e.g. Safety Instructions"}
                    />
                    <i className="fas fa-heading absolute right-3 top-3.5 text-slate-300"></i>
                </div>
                {activePage.type === 'content' && !activePage.title && activePage.steps.length > 0 && activePage.steps[0].title && (
                    <p className="text-[10px] text-slate-400 mt-1 ml-1">
                        <i className="fas fa-info-circle mr-1"></i>
                        Will default to first step title: "{activePage.steps[0].title}"
                    </p>
                )}
            </div>

            {/* Steps List for Active Page */}
            {activePage.type === 'toc' ? (
                <div className="bg-white border border-slate-200 rounded-xl p-8 text-center">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <i className="fas fa-list-ol text-2xl text-slate-300"></i>
                    </div>
                    <h3 className="font-bold text-slate-700 mb-2">Automatic Directory</h3>
                    <p className="text-sm text-slate-500 max-w-xs mx-auto">
                        This page automatically lists all subsequent pages and their titles. You can rename this page above.
                    </p>
                    <div className="mt-6 border-t border-slate-100 pt-4 text-xs text-slate-400">
                        Content is visible in Preview mode.
                    </div>
                </div>
            ) : (
                <div className="space-y-6">
                {activePage.steps.length === 0 && (
                    <div className="text-center py-10 text-slate-400">
                    <i className="fas fa-layer-group text-4xl mb-3 opacity-20"></i>
                    <p className="text-sm">This page is empty.</p>
                    <p className="text-xs">Add a step below to get started.</p>
                    </div>
                )}
                {activePage.steps.map((step, idx) => (
                    <StepEditor
                    key={step.id}
                    index={idx}
                    step={step}
                    totalSteps={activePage.steps.length}
                    onUpdate={updateStep}
                    onDelete={deleteStep}
                    onMoveUp={() => moveStep(idx, 'up')}
                    onMoveDown={() => moveStep(idx, 'down')}
                    />
                ))}
                </div>
            )}

            {/* Bottom Spacer for Floating Button */}
            <div className="h-24"></div>
          </div>

          {/* Floating Action Button for Adding Steps */}
          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[480px] lg:w-[560px] px-6 pointer-events-none">
                <button 
                onClick={addStepToActivePage}
                className="pointer-events-auto w-full py-4 bg-white/90 backdrop-blur border-2 border-dashed border-primary-500/30 text-primary-600 font-bold rounded-xl hover:bg-primary-50 hover:border-primary-500 transition-all shadow-lg flex items-center justify-center gap-2 group"
                >
                <div className="w-6 h-6 rounded-full bg-primary-100 flex items-center justify-center group-hover:bg-primary-600 group-hover:text-white transition-colors">
                    <i className="fas fa-plus text-xs"></i>
                </div>
                Add Step to Page {activePageIndex + 1}
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`
          flex-col flex-grow bg-slate-100 relative
          ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Mobile Tab Switcher */}
          <div className="md:hidden flex border-b border-slate-200 bg-white shrink-0">
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('editor')}
            >
              <i className="fas fa-edit mr-2"></i> Editor
            </button>
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('preview')}
            >
              <i className="fas fa-eye mr-2"></i> Preview
            </button>
          </div>

          <Preview 
            pages={pages} 
            metadata={metadata} 
            dimensions={pageDimensions}
            previewRef={previewRef}
            onPageOverflow={handlePageOverflow}
          />
        </div>
      </div>
    </div>
  );
};

