import { GoogleGenAI, Type } from "@google/genai";
import { AIResponse, ManualStep } from "../types";

const createClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }
  return new GoogleGenAI({ apiKey });
};

export const refineStepText = async (
  currentTitle: string,
  currentDescription: string
): Promise<AIResponse> => {
  const ai = createClient();

  const prompt = `
    You are an expert technical writer and editor. 
    Your task is to refine the following user manual step to be clear, concise, professional, and easy to understand.

    Current Title: "${currentTitle}"
    Current Description: "${currentDescription}"

    Return the refined title and description in valid JSON format.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            refinedTitle: { type: Type.STRING },
            refinedDescription: { type: Type.STRING },
          },
          required: ["refinedTitle", "refinedDescription"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text) as AIResponse;
    return data;
  } catch (error) {
    console.error("Error calling Gemini API:", error);
    throw error;
  }
};

export const generateStepTitle = async (description: string): Promise<string> => {
  const ai = createClient();

  const prompt = `
    Based on the following step description, generate a short, action-oriented title (max 5 words).

    Description: "${description}"

    Return just the title string in JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
          },
          required: ["title"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text) as { title: string };
    return data.title;
  } catch (error) {
    console.error("Error generating title:", error);
    throw error;
  }
};

export const generatePageTitle = async (steps: ManualStep[]): Promise<string> => {
  const ai = createClient();

  const stepsContent = steps.map((s, i) => `Step ${i+1}: ${s.title} - ${s.description}`).join('\n');

  const prompt = `
    You are organizing a user manual. Based on the following list of steps found on a single page, generate a short, professional Section Title for this page (e.g., "Installation", "Safety Warnings", "Troubleshooting", "Unboxing").

    Keep it under 5 words. Do not use quotation marks.

    Steps content:
    ${stepsContent}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            pageTitle: { type: Type.STRING },
          },
          required: ["pageTitle"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text) as { pageTitle: string };
    return data.pageTitle;
  } catch (error) {
    console.error("Error generating page title:", error);
    return "New Section"; // Fallback
  }
};

import React, { useState } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { ManualStep } from '../types';
import { refineStepText, generateStepTitle } from '../services/geminiService';

interface StepEditorProps {
  step: ManualStep;
  index: number;
  onUpdate: (id: string, updates: Partial<ManualStep>) => void;
  onDelete: (id: string) => void;
  onMoveUp: (index: number) => void;
  onMoveDown: (index: number) => void;
  totalSteps: number;
}

const StepEditor: React.FC<StepEditorProps> = ({ 
  step, 
  index, 
  onUpdate, 
  onDelete,
  onMoveUp,
  onMoveDown,
  totalSteps
}) => {
  const [isEnhancing, setIsEnhancing] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isHovered, setIsHovered] = useState(false);

  const handleImagesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newImages = Array.from(e.target.files).filter(file => {
        if (file.size > 3 * 1024 * 1024) {
          alert(`File ${file.name} is too large (max 3MB).`);
          return false;
        }
        return true;
      }).map(file => ({
        id: uuidv4(),
        url: URL.createObjectURL(file),
        file
      }));

      onUpdate(step.id, { images: [...step.images, ...newImages] });
    }
  };

  const handleRemoveImage = (imageId: string) => {
    onUpdate(step.id, { images: step.images.filter(img => img.id !== imageId) });
  };

  const handleAIEnhance = async () => {
    if (!step.title && !step.description) return;

    setIsEnhancing(true);
    try {
      const result = await refineStepText(step.title, step.description);
      onUpdate(step.id, {
        title: result.refinedTitle,
        description: result.refinedDescription
      });
    } catch (error) {
      alert("Failed to enhance text. Please check your API configuration.");
    } finally {
      setIsEnhancing(false);
    }
  };

  const handleAutoTitle = async () => {
    if (!step.description) {
      alert("Please enter a description first.");
      return;
    }
    setIsGeneratingTitle(true);
    try {
      const title = await generateStepTitle(step.description);
      onUpdate(step.id, { title });
    } catch (error) {
      alert("Failed to generate title.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  return (
    <div 
      className="bg-white rounded-xl shadow-sm border border-slate-200 mb-6 overflow-hidden transition-all duration-200 hover:shadow-md group"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {/* Header / Toolbar */}
      <div className="bg-slate-50 px-4 py-3 border-b border-slate-100 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <span className="flex items-center justify-center w-6 h-6 rounded-full bg-slate-200 text-slate-600 text-xs font-bold">
            {index + 1}
          </span>
          <span className="text-xs font-medium text-slate-400 uppercase tracking-wide">Step</span>
        </div>

        <div className={`flex gap-1 transition-opacity duration-200 ${isHovered ? 'opacity-100' : 'opacity-100 md:opacity-0'}`}>
           <button 
            onClick={() => onMoveUp(index)} 
            disabled={index === 0}
            className="w-8 h-8 flex items-center justify-center rounded-lg text-slate-400 hover:text-slate-700 hover:bg-slate-200 disabled:opacity-30 transition-colors"
            title="Move Up"
          >
            <i className="fas fa-arrow-up text-sm"></i>
          </button>
          <button 
            onClick={() => onMoveDown(index)} 
            disabled={index === totalSteps - 1}
            className="w-8 h-8 flex items-center justify-center rounded-lg text-slate-400 hover:text-slate-700 hover:bg-slate-200 disabled:opacity-30 transition-colors"
            title="Move Down"
          >
            <i className="fas fa-arrow-down text-sm"></i>
          </button>
          <div className="w-px h-6 bg-slate-200 mx-1 self-center"></div>
          <button 
            onClick={() => onDelete(step.id)} 
            className="w-8 h-8 flex items-center justify-center rounded-lg text-red-400 hover:text-red-600 hover:bg-red-50 transition-colors"
            title="Delete Step"
          >
            <i className="fas fa-trash-alt text-sm"></i>
          </button>
        </div>
      </div>

      <div className="p-5 flex flex-col gap-6">

        {/* Main Content Grid: Image | Text */}
        <div className="flex flex-col md:flex-row gap-6">
            {/* Image Upload Area */}
            <div className="w-full md:w-1/3 flex-shrink-0 flex flex-col gap-2">

            {/* If images exist, show grid */}
            {step.images.length > 0 && (
                <div className="grid grid-cols-2 gap-2 mb-2">
                {step.images.map((img) => (
                    <div key={img.id} className="relative aspect-square group/thumb rounded-lg overflow-hidden border border-slate-200">
                    <img src={img.url} alt="Thumbnail" className="w-full h-full object-cover" />
                    <button 
                        onClick={() => handleRemoveImage(img.id)}
                        className="absolute top-1 right-1 w-6 h-6 bg-red-500 text-white rounded-full text-xs flex items-center justify-center opacity-0 group-hover/thumb:opacity-100 transition-opacity shadow-sm"
                    >
                        <i className="fas fa-times"></i>
                    </button>
                    </div>
                ))}
                </div>
            )}

            {/* Upload Button (Large if empty, Small bar if has images) */}
            <label className={`
                flex flex-col items-center justify-center border-2 border-dashed border-slate-300 rounded-lg hover:border-primary hover:bg-slate-50 transition-all cursor-pointer
                ${step.images.length > 0 ? 'h-16 flex-row gap-2' : 'aspect-[4/3]'}
            `}>
                <div className={`
                rounded-full bg-slate-100 flex items-center justify-center text-slate-400 group-hover:text-primary transition-colors
                ${step.images.length > 0 ? 'w-8 h-8' : 'w-10 h-10 mb-2'}
                `}>
                <i className="fas fa-cloud-upload-alt text-lg"></i>
                </div>
                <span className="text-xs font-medium text-slate-500">
                {step.images.length > 0 ? 'Add More' : 'Upload Images (Max 3MB)'}
                </span>
                <input 
                    type="file" 
                    accept="image/*" 
                    multiple 
                    onChange={handleImagesChange} 
                    className="hidden" 
                />
            </label>
            </div>

            {/* Text Inputs */}
            <div className="flex-1 flex flex-col gap-4">
                <div className="relative flex items-center gap-2">
                    <input
                        type="text"
                        value={step.title}
                        onChange={(e) => onUpdate(step.id, { title: e.target.value })}
                        placeholder="Step Title (e.g., 'Connect Power')"
                        className="flex-grow text-lg font-semibold text-slate-800 placeholder:text-slate-300 border-none p-0 focus:ring-0 bg-transparent"
                    />
                    <button 
                        onClick={handleAutoTitle}
                        disabled={isGeneratingTitle || !step.description}
                        className="text-xs bg-slate-100 hover:bg-primary-50 text-slate-500 hover:text-primary-600 px-2 py-1 rounded transition-colors whitespace-nowrap disabled:opacity-50"
                        title="Auto-generate title from description"
                    >
                        {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Title
                    </button>
                </div>

                <div className="relative flex-1">
                    <textarea
                    rows={6}
                    value={step.description}
                    onChange={(e) => onUpdate(step.id, { description: e.target.value })}
                    placeholder="Describe what the user needs to do in this step..."
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-600 focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary/20 resize-none h-full"
                    />

                    {/* AI Action Bar */}
                    <div className="absolute bottom-2 right-2">
                    <button 
                        onClick={handleAIEnhance}
                        disabled={isEnhancing || (!step.title && !step.description)}
                        className={`
                        flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-all shadow-sm
                        ${isEnhancing 
                            ? 'bg-purple-100 text-purple-700 cursor-wait' 
                            : 'bg-white text-slate-600 hover:text-purple-600 hover:bg-purple-50 border border-slate-200'
                        }
                        disabled:opacity-50 disabled:cursor-not-allowed
                        `}
                        title="Use AI to improve clarity and tone"
                    >
                        {isEnhancing ? (
                        <><i className="fas fa-circle-notch fa-spin"></i> Refining...</>
                        ) : (
                        <><i className="fas fa-wand-magic-sparkles text-purple-500"></i> AI Polish</>
                        )}
                    </button>
                    </div>
                </div>
            </div>
        </div>

      </div>
    </div>
  );
};

export default StepEditor;

