                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 flex justify-between items-end">
                    <span>{activePage.type === 'toc' ? 'Directory Header' : 'Page Title (For Directory & Header)'}</span>
                    {activePage.type === 'content' && (
                      <button 
                        onClick={handleAutoGeneratePageTitle}
                        disabled={isGeneratingTitle || activePage.steps.length === 0}
                        className="text-[10px] text-primary-600 hover:text-primary-700 bg-primary-50 hover:bg-primary-100 px-2 py-1 rounded transition-colors disabled:opacity-50"
                      >
                         {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Generate
                      </button>
                    )}
