import React, { useState, useRef, useCallback, useEffect } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage } from './types';
import { generatePageTitle } from './services/geminiService';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(true);

  const previewRef = useRef<HTMLDivElement>(null);

  // --- State: Pages & Content ---
  const [metadata, setMetadata] = useState<ManualMetadata>({
    title: 'Product Manual',
    subtitle: 'Setup & Configuration Guide',
    author: 'My Company Inc.',
    version: '1.0',
    showStepMarkers: true
  });

  const [pages, setPages] = useState<ManualPage[]>([
    {
      id: uuidv4(),
      type: 'toc',
      title: 'Table of Contents',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'content',
      title: 'Getting Started',
      steps: [
        {
          id: uuidv4(),
          title: 'Unboxing',
          description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.',
          images: [],
          layout: 'image_left_text_right'
        }
      ]
    }
  ]);

  const [activePageIndex, setActivePageIndex] = useState(1); // Start on first content page

  // --- Effects ---

  // Auto-scroll to active page in preview when it changes
  useEffect(() => {
    if (hasStarted) {
      // Use a small timeout to allow render to complete (especially for new pages)
      const timer = setTimeout(() => {
        const pageElement = document.getElementById(`preview-page-${activePageIndex}`);
        if (pageElement) {
          pageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activePageIndex, hasStarted]);

  // --- Handlers ---

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setHasStarted(true);
  };

  const activePage = pages[activePageIndex];

  // Add a new empty content page
  const addNewPage = () => {
    setPages([...pages, { id: uuidv4(), type: 'content', title: '', steps: [] }]);
    setActivePageIndex(pages.length); // Switch to new page
  };

  const addTocPage = () => {
     // Check if TOC already exists
     if (pages.some(p => p.type === 'toc')) {
       alert("A Table of Contents page already exists.");
       return;
     }
     // Insert at beginning
     setPages([{ id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] }, ...pages]);
     setActivePageIndex(0);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) {
      setActivePageIndex(index);
    }
  };

  const deletePage = (index: number) => {
    if (pages.length <= 1) {
      alert("You must have at least one page.");
      return;
    }
    const pageToDelete = pages[index];
    const message = pageToDelete.type === 'toc' 
      ? "Delete the Table of Contents?" 
      : "Are you sure you want to delete this page and all its steps?";

    if (window.confirm(message)) {
      const newPages = pages.filter((_, i) => i !== index);
      setPages(newPages);
      setActivePageIndex(Math.max(0, index - 1));
    }
  };

  // Update Page Title (used for TOC)
  const updatePageTitle = (title: string) => {
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) {
      alert("Add some steps to the page first so AI can generate a title.");
      return;
    }

    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      updatePageTitle(suggestedTitle);
    } catch (error) {
      alert("Failed to generate title. Check API key or connection.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  // Step Management (Scoped to Active Page)
  const addStepToActivePage = () => {
    if (activePage.type === 'toc') return;

    const newStep: ManualStep = {
      id: uuidv4(),
      title: '',
      description: '',
      images: [],
      layout: 'image_left_text_right'
    };

    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);

    setTimeout(() => {
      const el = document.getElementById('steps-container');
      if (el) el.scrollTop = el.scrollHeight;
    }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step)
    }));
    setPages(newPages);
  };

  const deleteStep = (stepId: string) => {
    // Confirmation handled in StepEditor for better UX
    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.filter(step => step.id !== stepId)
    }));
    setPages(newPages);
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type === 'toc') return;

    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;

    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];

    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  // --- Automatic Overflow Handling ---
  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      const currentPage = prevPages[pageIndex];
      // Do not handle overflow for TOC pages
      if (currentPage.type === 'toc') return prevPages;

      // Safety check: Don't move if there's only 1 step
      if (currentPage.steps.length <= 1) return prevPages;

      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);

      // Check if next page exists, if not create it
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];

      // Update current page
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };

      if (nextPage && nextPage.type === 'content') {
        // Add to beginning of next page if it is a content page
        newPages[nextPageIndex] = {
          ...nextPage,
          steps: [lastStep, ...nextPage.steps]
        };
      } else {
        // Create new content page (insert it if next page is not content, though normally TOC is first)
        // If next page exists but is TOC (unlikely if TOC is first), insert before? No, standard flow append.
        const newPage: ManualPage = {
            id: uuidv4(),
            type: 'content',
            title: 'Continued...',
            steps: [lastStep]
        };

        // Insert at nextPageIndex
        newPages.splice(nextPageIndex, 0, newPage);
      }

      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });

      // Iterate through all rendered pages in the Preview
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;

        if (i > 0) pdf.addPage();

        // Temporarily remove shadow for clean capture
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';

        const canvas = await html2canvas(pageElement, {
          scale: 2, 
          useCORS: true, 
          logging: false,
          backgroundColor: '#ffffff',
          windowWidth: 1200 
        });

        // Restore styles
        pageElement.style.boxShadow = originalShadow;

        const imgData = canvas.toDataURL('image/png');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} />;
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 h-16 flex items-center justify-between shadow-sm shrink-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-primary-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary-500/30">
            <i className="fas fa-book-open text-lg"></i>
          </div>
          <div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight leading-none">ManualMaster</h1>
            <p className="text-xs text-slate-500 font-medium">AI-Powered Documentation</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
           <button 
             onClick={() => { if(window.confirm('Go back to start? Unsaved changes will be lost.')) window.location.reload(); }}
             className="text-slate-400 hover:text-slate-600 text-xs font-semibold uppercase tracking-wider hidden md:block"
           >
             {pageDimensions.name} ({pageDimensions.width}x{pageDimensions.height}mm)
           </button>

          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-full text-sm font-semibold flex items-center gap-2 transition-all
              ${isGenerating 
                ? 'bg-slate-100 text-slate-400 cursor-wait' 
                : 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-lg active:transform active:scale-95'
              }
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span>{isGenerating ? 'Exporting...' : 'Download PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[480px] lg:w-[560px] border-r border-slate-200 bg-white shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Page Navigator */}
          <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center">
            {/* Add TOC Button if not present */}
            {!pages.some(p => p.type === 'toc') && (
               <button 
                onClick={addTocPage}
                className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-600 border border-slate-200 hover:bg-slate-200 transition-colors mr-2"
                title="Insert Table of Contents"
              >
                <i className="fas fa-list-ol mr-1"></i> TOC
              </button>
            )}

            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all border flex items-center gap-2
                  ${activePageIndex === idx 
                    ? 'bg-slate-800 text-white border-slate-800 shadow-md' 
                    : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
                  }
                `}
              >
                {page.type === 'toc' ? <i className="fas fa-list text-[10px]"></i> : `Page ${idx + 1}`}
              </button>
            ))}
            <button 
              onClick={addNewPage}
              className="px-3 py-1.5 rounded-lg text-xs font-bold bg-primary-50 text-primary-600 border border-primary-200 hover:bg-primary-100 transition-colors"
              title="Add New Page"
            >
              <i className="fas fa-plus"></i>
            </button>
          </div>

          {/* Editor Header */}
          <div className="px-6 py-4 border-b border-slate-100 bg-white flex justify-between items-center">
             <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-lg font-bold text-slate-800">
                        {activePage.type === 'toc' ? 'Directory' : `Page ${activePageIndex + 1}`}
                    </h2>
                    {activePage.type === 'toc' && <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded">Auto-generated</span>}
                </div>
                {activePage.type === 'content' && (
                    <span className="text-xs text-slate-400 font-medium">{activePage.steps.length} Steps</span>
                )}
             </div>
             {pages.length > 1 && (
                <button 
                  onClick={() => deletePage(activePageIndex)}
                  className="text-red-400 hover:text-red-600 text-xs px-2 py-1 rounded hover:bg-red-50 transition-colors"
                >
                  <i className="fas fa-trash-alt mr-1"></i> Delete
                </button>
             )}
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto p-6 scroll-smooth">

            {/* Metadata Accordion */}
            <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden mb-8 transition-all">
              <button 
                onClick={() => setIsMetadataExpanded(!isMetadataExpanded)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
              >
                <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                  <i className="fas fa-cog text-slate-400"></i>
                  Global Document Settings
                </div>
                <i className={`fas fa-chevron-down text-slate-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>

              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                   <div className="col-span-2 h-px bg-slate-200 mb-2"></div>
                   <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Title</label>
                    <input 
                      type="text" 
                      value={metadata.title}
                      onChange={(e) => setMetadata({...metadata, title: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. User Manual"
                    />
                  </div>
                  <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Subtitle</label>
                    <input 
                      type="text" 
                      value={metadata.subtitle}
                      onChange={(e) => setMetadata({...metadata, subtitle: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. Quick Start Guide"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Author</label>
                    <input 
                      type="text" 
                      value={metadata.author}
                      onChange={(e) => setMetadata({...metadata, author: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Version</label>
                    <input 
                      type="text" 
                      value={metadata.version}
                      onChange={(e) => setMetadata({...metadata, version: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>

                  {/* Step Markers Toggle */}
                  <div className="col-span-2 mt-2 pt-2 border-t border-slate-100 flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Show Step Markers</label>
                    <button 
                        onClick={() => setMetadata({...metadata, showStepMarkers: !metadata.showStepMarkers})}
                        className={`w-12 h-6 rounded-full p-1 transition-colors duration-200 ease-in-out ${metadata.showStepMarkers ? 'bg-primary-600' : 'bg-slate-300'}`}
                        title="Toggle bullet points on steps"
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transform transition-transform duration-200 ease-in-out ${metadata.showStepMarkers ? 'translate-x-6' : 'translate-x-0'}`}></div>
                    </button>
                  </div>
                </div>
              )}
            </div>

            {/* Page Title Editor (Specifically for TOC mapping) */}
            <div className="mb-6">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 flex justify-between items-end">
                    <span>{activePage.type === 'toc' ? 'Directory Header' : 'Page Title (For Directory & Header)'}</span>
                    {activePage.type === 'content' && (
                      <button 
                        onClick={handleAutoGeneratePageTitle}
                        disabled={isGeneratingTitle || activePage.steps.length === 0}
                        className="text-[10px] text-primary-600 hover:text-primary-700 bg-primary-50 hover:bg-primary-100 px-2 py-1 rounded transition-colors disabled:opacity-50"
                      >
                         {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Generate
                      </button>
                    )}
                </label>
                <div className="relative">
                    <input 
                        type="text" 
                        value={activePage.title || ''}
                        onChange={(e) => updatePageTitle(e.target.value)}
                        className="w-full p-3 bg-white border border-slate-300 rounded-lg text-base font-semibold text-slate-800 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                        placeholder={activePage.type === 'toc' ? "Table of Contents" : "e.g. Safety Instructions"}
                    />
                    <i className="fas fa-heading absolute right-3 top-3.5 text-slate-300"></i>
                </div>
                {activePage.type === 'content' && !activePage.title && activePage.steps.length > 0 && activePage.steps[0].title && (
                    <p className="text-[10px] text-slate-400 mt-1 ml-1">
                        <i className="fas fa-info-circle mr-1"></i>
                        Will default to first step title: "{activePage.steps[0].title}"
                    </p>
                )}
            </div>

            {/* Steps List for Active Page */}
            {activePage.type === 'toc' ? (
                <div className="bg-white border border-slate-200 rounded-xl p-8 text-center">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <i className="fas fa-list-ol text-2xl text-slate-300"></i>
                    </div>
                    <h3 className="font-bold text-slate-700 mb-2">Automatic Directory</h3>
                    <p className="text-sm text-slate-500 max-w-xs mx-auto">
                        This page automatically lists all subsequent pages and their titles. You can rename this page above.
                    </p>
                    <div className="mt-6 border-t border-slate-100 pt-4 text-xs text-slate-400">
                        Content is visible in Preview mode.
                    </div>
                </div>
            ) : (
                <div className="space-y-6">
                {activePage.steps.length === 0 && (
                    <div className="text-center py-10 text-slate-400">
                    <i className="fas fa-layer-group text-4xl mb-3 opacity-20"></i>
                    <p className="text-sm">This page is empty.</p>
                    <p className="text-xs">Add a step below to get started.</p>
                    </div>
                )}
                {activePage.steps.map((step, idx) => (
                    <StepEditor
                    key={step.id}
                    index={idx}
                    step={step}
                    totalSteps={activePage.steps.length}
                    onUpdate={updateStep}
                    onDelete={deleteStep}
                    onMoveUp={() => moveStep(idx, 'up')}
                    onMoveDown={() => moveStep(idx, 'down')}
                    />
                ))}
                </div>
            )}

            {/* Bottom Spacer for Floating Button */}
            <div className="h-24"></div>
          </div>

          {/* Floating Action Button for Adding Steps */}
          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[480px] lg:w-[560px] px-6 pointer-events-none">
                <button 
                onClick={addStepToActivePage}
                className="pointer-events-auto w-full py-4 bg-white/90 backdrop-blur border-2 border-dashed border-primary-500/30 text-primary-600 font-bold rounded-xl hover:bg-primary-50 hover:border-primary-500 transition-all shadow-lg flex items-center justify-center gap-2 group"
                >
                <div className="w-6 h-6 rounded-full bg-primary-100 flex items-center justify-center group-hover:bg-primary-600 group-hover:text-white transition-colors">
                    <i className="fas fa-plus text-xs"></i>
                </div>
                Add Step to Page {activePageIndex + 1}
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`
          flex-col flex-grow bg-slate-100 relative
          ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Mobile Tab Switcher */}
          <div className="md:hidden flex border-b border-slate-200 bg-white shrink-0">
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('editor')}
            >
              <i className="fas fa-edit mr-2"></i> Editor
            </button>
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('preview')}
            >
              <i className="fas fa-eye mr-2"></i> Preview
            </button>
          </div>

          <Preview 
            pages={pages} 
            metadata={metadata} 
            dimensions={pageDimensions}
            previewRef={previewRef}
            onPageOverflow={handlePageOverflow}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { ManualStep, StepLayout } from '../types';
import { generateDescriptionFromImages, generateStepTitle } from '../services/geminiService';

interface StepEditorProps {
  step: ManualStep;
  index: number;
  onUpdate: (id: string, updates: Partial<ManualStep>) => void;
  onMoveUp: (index: number) => void;
  onMoveDown: (index: number) => void;
  totalSteps: number;
}

const StepEditor: React.FC<StepEditorProps> = ({ 
  step, 
  index, 
  onUpdate, 
  onMoveUp,
  onMoveDown,
  totalSteps
}) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);

  const handleImagesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newImages = (Array.from(e.target.files) as File[]).filter(file => {
        if (file.size > 3 * 1024 * 1024) {
          alert(`File ${file.name} is too large (max 3MB).`);
          return false;
        }
        return true;
      }).map(file => ({
        id: uuidv4(),
        url: URL.createObjectURL(file),
        file
      }));

      onUpdate(step.id, { images: [...step.images, ...newImages] });
    }
  };

  const handleRemoveImage = (imageId: string) => {
    onUpdate(step.id, { images: step.images.filter(img => img.id !== imageId) });
  };

  const handleAnalyzeImages = async () => {
    if (step.images.length === 0) return;

    setIsAnalyzing(true);
    try {
      const files = step.images.map(img => img.file);
      const description = await generateDescriptionFromImages(files);
      onUpdate(step.id, { description });
    } catch (error) {
      alert("Failed to analyze images.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleGenerateTitle = async () => {
    if (!step.description) return;

    setIsGeneratingTitle(true);
    try {
      const title = await generateStepTitle(step.description);
      onUpdate(step.id, { title });
    } catch (error) {
      alert("Failed to generate title.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  const updateLayout = (layout: StepLayout) => {
    onUpdate(step.id, { layout });
  };

  const getImageGridClass = (count: number) => {
    if (count <= 1) return 'grid-cols-1';
    if (count === 3) return 'grid-cols-2'; // 3 images: 2 + 1 spanning
    if (count === 4) return 'grid-cols-2'; // 2x2
    if (count >= 5) return 'grid-cols-3'; // 3 cols for many
    return 'grid-cols-2'; // Default for 2
  };

  return (
    <div 
      className="bg-white rounded-xl shadow-sm border border-slate-200 mb-6 overflow-hidden transition-all duration-200 hover:shadow-md group"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {/* Header / Toolbar */}
      <div className="bg-slate-50 px-4 py-2 border-b border-slate-100 flex justify-between items-center flex-wrap gap-2">
        <div className="flex items-center gap-2">
          <span className="flex items-center justify-center w-6 h-6 rounded-full bg-slate-200 text-slate-600 text-xs font-bold">
            {index + 1}
          </span>
          <span className="text-xs font-medium text-slate-400 uppercase tracking-wide">Step</span>
        </div>

        {/* Layout Controls */}
        <div className="flex bg-white rounded-lg p-1 border border-slate-200 gap-1">
          <button 
            type="button"
            onClick={() => updateLayout('image_left_text_right')}
            className={`p-1 rounded hover:bg-slate-100 transition-colors ${step.layout === 'image_left_text_right' || !step.layout ? 'bg-primary-50 text-primary-600 ring-1 ring-primary-500/20' : 'text-slate-400'}`}
            title="Image Left, Text Right"
          >
            <div className="flex gap-0.5 w-5 h-4 items-center">
              <div className="w-2 h-3 bg-current rounded-[1px] opacity-80"></div>
              <div className="flex-1 h-3 flex flex-col gap-[2px] justify-center">
                <div className="w-full h-[2px] bg-current rounded-[1px] opacity-40"></div>
                <div className="w-2/3 h-[2px] bg-current rounded-[1px] opacity-40"></div>
              </div>
            </div>
          </button>

          <button 
            type="button"
            onClick={() => updateLayout('text_left_image_right')}
            className={`p-1 rounded hover:bg-slate-100 transition-colors ${step.layout === 'text_left_image_right' ? 'bg-primary-50 text-primary-600 ring-1 ring-primary-500/20' : 'text-slate-400'}`}
            title="Text Left, Image Right"
          >
            <div className="flex gap-0.5 w-5 h-4 items-center flex-row-reverse">
              <div className="w-2 h-3 bg-current rounded-[1px] opacity-80"></div>
              <div className="flex-1 h-3 flex flex-col gap-[2px] justify-center">
                <div className="w-full h-[2px] bg-current rounded-[1px] opacity-40"></div>
                <div className="w-2/3 h-[2px] bg-current rounded-[1px] opacity-40"></div>
              </div>
            </div>
          </button>

          <button 
            type="button"
            onClick={() => updateLayout('image_top_text_bottom')}
            className={`p-1 rounded hover:bg-slate-100 transition-colors ${step.layout === 'image_top_text_bottom' ? 'bg-primary-50 text-primary-600 ring-1 ring-primary-500/20' : 'text-slate-400'}`}
            title="Image Top, Text Bottom"
          >
            <div className="flex flex-col gap-0.5 w-4 h-5 justify-center items-center">
              <div className="w-3 h-2 bg-current rounded-[1px] opacity-80"></div>
              <div className="w-3 flex flex-col gap-[2px]">
                 <div className="w-full h-[2px] bg-current rounded-[1px] opacity-40"></div>
                 <div className="w-2/3 h-[2px] bg-current rounded-[1px] opacity-40"></div>
              </div>
            </div>
          </button>

          <button 
            type="button"
            onClick={() => updateLayout('text_top_image_bottom')}
            className={`p-1 rounded hover:bg-slate-100 transition-colors ${step.layout === 'text_top_image_bottom' ? 'bg-primary-50 text-primary-600 ring-1 ring-primary-500/20' : 'text-slate-400'}`}
            title="Text Top, Image Bottom"
          >
            <div className="flex flex-col-reverse gap-0.5 w-4 h-5 justify-center items-center">
              <div className="w-3 h-2 bg-current rounded-[1px] opacity-80"></div>
              <div className="w-3 flex flex-col gap-[2px]">
                 <div className="w-full h-[2px] bg-current rounded-[1px] opacity-40"></div>
                 <div className="w-2/3 h-[2px] bg-current rounded-[1px] opacity-40"></div>
              </div>
            </div>
          </button>
        </div>

        {/* Controls */}
        <div className="flex gap-1 ml-auto relative z-10">
           <button 
            type="button"
            onClick={() => onMoveUp(index)} 
            disabled={index === 0}
            className="w-8 h-8 flex items-center justify-center rounded-lg text-slate-400 hover:text-slate-700 hover:bg-slate-200 disabled:opacity-30 transition-colors"
            title="Move Up"
          >
            <i className="fas fa-arrow-up text-sm"></i>
          </button>
          <button 
            type="button"
            onClick={() => onMoveDown(index)} 
            disabled={index === totalSteps - 1}
            className="w-8 h-8 flex items-center justify-center rounded-lg text-slate-400 hover:text-slate-700 hover:bg-slate-200 disabled:opacity-30 transition-colors"
            title="Move Down"
          >
            <i className="fas fa-arrow-down text-sm"></i>
          </button>
        </div>
      </div>

      <div className="p-5 flex flex-col gap-6">

        {/* Main Content Grid: Image | Text */}
        <div className="flex flex-col md:flex-row gap-6">
            {/* Image Upload Area */}
            <div className="w-full md:w-1/3 flex-shrink-0 flex flex-col gap-2">

            {/* If images exist, show grid */}
            {step.images.length > 0 && (
                <div className={`grid gap-2 mb-2 ${getImageGridClass(step.images.length)}`}>
                {step.images.map((img, idx) => (
                    <div 
                        key={img.id} 
                        className={`
                            relative aspect-square group/thumb rounded-lg overflow-hidden border border-slate-200
                            ${step.images.length === 3 && idx === 2 ? 'col-span-2 aspect-[2/1]' : ''}
                        `}
                    >
                    <img src={img.url} alt="Thumbnail" className="w-full h-full object-cover" />
                    <button 
                        type="button"
                        onClick={() => handleRemoveImage(img.id)}
                        className="absolute top-1 right-1 w-6 h-6 bg-red-500 text-white rounded-full text-xs flex items-center justify-center opacity-0 group-hover/thumb:opacity-100 transition-opacity shadow-sm"
                    >
                        <i className="fas fa-times"></i>
                    </button>
                    </div>
                ))}
                </div>
            )}

            {/* Upload Button (Large if empty, Small bar if has images) */}
            <label className={`
                flex flex-col items-center justify-center border-2 border-dashed border-slate-300 rounded-lg hover:border-primary hover:bg-slate-50 transition-all cursor-pointer
                ${step.images.length > 0 ? 'h-16 flex-row gap-2' : 'aspect-[4/3]'}
            `}>
                <div className={`
                rounded-full bg-slate-100 flex items-center justify-center text-slate-400 group-hover:text-primary transition-colors
                ${step.images.length > 0 ? 'w-8 h-8' : 'w-10 h-10 mb-2'}
                `}>
                <i className="fas fa-cloud-upload-alt text-lg"></i>
                </div>
                <span className="text-xs font-medium text-slate-500">
                {step.images.length > 0 ? 'Add More' : 'Upload Images (Max 3MB)'}
                </span>
                <input 
                    type="file" 
                    accept="image/*" 
                    multiple 
                    onChange={handleImagesChange} 
                    className="hidden" 
                />
            </label>

            {/* Analyze Image Button */}
            {step.images.length > 0 && (
                <button
                type="button"
                onClick={handleAnalyzeImages}
                disabled={isAnalyzing}
                className="w-full py-2 bg-indigo-50 text-indigo-600 rounded-lg text-xs font-semibold hover:bg-indigo-100 transition-colors flex items-center justify-center gap-2 disabled:opacity-50"
                title="Use AI to describe the uploaded images"
                >
                {isAnalyzing ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-eye"></i>}
                {isAnalyzing ? "Analyzing..." : "Describe Image with AI"}
                </button>
            )}
            </div>

            {/* Text Inputs */}
            <div className="flex-1 flex flex-col gap-4">
                <div className="relative flex items-center gap-2">
                    <input
                        type="text"
                        value={step.title}
                        onChange={(e) => onUpdate(step.id, { title: e.target.value })}
                        placeholder="Step Title (e.g., 'Connect Power')"
                        className="flex-grow text-lg font-semibold text-slate-800 placeholder:text-slate-300 border-none p-0 focus:ring-0 bg-transparent"
                    />
                    {/* Title Generation Button */}
                    <button
                        type="button"
                        onClick={handleGenerateTitle}
                        disabled={isGeneratingTitle || !step.description}
                        className="text-xs font-medium text-slate-400 hover:text-primary-600 px-2 py-1 rounded hover:bg-slate-100 transition-colors flex items-center gap-1 disabled:opacity-30 disabled:cursor-not-allowed"
                        title="Generate title from description"
                    >
                        {isGeneratingTitle ? <i className="fas fa-circle-notch fa-spin text-[10px]"></i> : <i className="fas fa-magic text-[10px]"></i>}
                        Generate Title
                    </button>
                </div>

                <div className="relative flex-1">
                    <textarea
                    rows={6}
                    value={step.description}
                    onChange={(e) => onUpdate(step.id, { description: e.target.value })}
                    placeholder="Describe what the user needs to do in this step..."
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-600 focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary/20 resize-none h-full"
                    />
                </div>
            </div>
        </div>

      </div>
    </div>
  );
};

export default StepEditor;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage } from './types';
import { generatePageTitle } from './services/geminiService';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(true);

  const previewRef = useRef<HTMLDivElement>(null);

  // --- State: Pages & Content ---
  const [metadata, setMetadata] = useState<ManualMetadata>({
    title: 'Product Manual',
    subtitle: 'Setup & Configuration Guide',
    author: 'My Company Inc.',
    version: '1.0',
    showStepMarkers: true
  });

  const [pages, setPages] = useState<ManualPage[]>([
    {
      id: uuidv4(),
      type: 'toc',
      title: 'Table of Contents',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'content',
      title: 'Getting Started',
      steps: [
        {
          id: uuidv4(),
          title: 'Unboxing',
          description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.',
          images: [],
          layout: 'image_left_text_right'
        }
      ]
    }
  ]);

  const [activePageIndex, setActivePageIndex] = useState(1); // Start on first content page

  // --- Effects ---

  // Auto-scroll to active page in preview when it changes
  useEffect(() => {
    if (hasStarted) {
      // Use a small timeout to allow render to complete (especially for new pages)
      const timer = setTimeout(() => {
        const pageElement = document.getElementById(`preview-page-${activePageIndex}`);
        if (pageElement) {
          pageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activePageIndex, hasStarted]);

  // --- Handlers ---

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setHasStarted(true);
  };

  const activePage = pages[activePageIndex];

  // Add a new empty content page
  const addNewPage = () => {
    setPages([...pages, { id: uuidv4(), type: 'content', title: '', steps: [] }]);
    setActivePageIndex(pages.length); // Switch to new page
  };

  const addTocPage = () => {
     // Check if TOC already exists
     if (pages.some(p => p.type === 'toc')) {
       alert("A Table of Contents page already exists.");
       return;
     }
     // Insert at beginning
     setPages([{ id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] }, ...pages]);
     setActivePageIndex(0);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) {
      setActivePageIndex(index);
    }
  };

  // Update Page Title (used for TOC)
  const updatePageTitle = (title: string) => {
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) {
      alert("Add some steps to the page first so AI can generate a title.");
      return;
    }

    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      updatePageTitle(suggestedTitle);
    } catch (error) {
      alert("Failed to generate title. Check API key or connection.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  // Step Management (Scoped to Active Page)
  const addStepToActivePage = () => {
    if (activePage.type === 'toc') return;

    const newStep: ManualStep = {
      id: uuidv4(),
      title: '',
      description: '',
      images: [],
      layout: 'image_left_text_right'
    };

    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);

    setTimeout(() => {
      const el = document.getElementById('steps-container');
      if (el) el.scrollTop = el.scrollHeight;
    }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step)
    }));
    setPages(newPages);
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type === 'toc') return;

    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;

    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];

    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  // --- Automatic Overflow Handling ---
  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      const currentPage = prevPages[pageIndex];
      // Do not handle overflow for TOC pages
      if (currentPage.type === 'toc') return prevPages;

      // Safety check: Don't move if there's only 1 step
      if (currentPage.steps.length <= 1) return prevPages;

      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);

      // Check if next page exists, if not create it
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];

      // Update current page
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };

      if (nextPage && nextPage.type === 'content') {
        // Add to beginning of next page if it is a content page
        newPages[nextPageIndex] = {
          ...nextPage,
          steps: [lastStep, ...nextPage.steps]
        };
      } else {
        // Create new content page (insert it if next page is not content, though normally TOC is first)
        // If next page exists but is TOC (unlikely if TOC is first), insert before? No, standard flow append.
        const newPage: ManualPage = {
            id: uuidv4(),
            type: 'content',
            title: 'Continued...',
            steps: [lastStep]
        };

        // Insert at nextPageIndex
        newPages.splice(nextPageIndex, 0, newPage);
      }

      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });

      // Iterate through all rendered pages in the Preview
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;

        if (i > 0) pdf.addPage();

        // Temporarily remove shadow for clean capture
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';

        const canvas = await html2canvas(pageElement, {
          scale: 2, 
          useCORS: true, 
          logging: false,
          backgroundColor: '#ffffff',
          windowWidth: 1200 
        });

        // Restore styles
        pageElement.style.boxShadow = originalShadow;

        const imgData = canvas.toDataURL('image/png');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} />;
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 h-16 flex items-center justify-between shadow-sm shrink-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-primary-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary-500/30">
            <i className="fas fa-book-open text-lg"></i>
          </div>
          <div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight leading-none">ManualMaster</h1>
            <p className="text-xs text-slate-500 font-medium">AI-Powered Documentation</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
           <button 
             onClick={() => { if(window.confirm('Go back to start? Unsaved changes will be lost.')) window.location.reload(); }}
             className="text-slate-400 hover:text-slate-600 text-xs font-semibold uppercase tracking-wider hidden md:block"
           >
             {pageDimensions.name} ({pageDimensions.width}x{pageDimensions.height}mm)
           </button>

          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-full text-sm font-semibold flex items-center gap-2 transition-all
              ${isGenerating 
                ? 'bg-slate-100 text-slate-400 cursor-wait' 
                : 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-lg active:transform active:scale-95'
              }
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span>{isGenerating ? 'Exporting...' : 'Download PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[480px] lg:w-[560px] border-r border-slate-200 bg-white shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Page Navigator */}
          <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center">
            {/* Add TOC Button if not present */}
            {!pages.some(p => p.type === 'toc') && (
               <button 
                onClick={addTocPage}
                className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-600 border border-slate-200 hover:bg-slate-200 transition-colors mr-2"
                title="Insert Table of Contents"
              >
                <i className="fas fa-list-ol mr-1"></i> TOC
              </button>
            )}

            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all border flex items-center gap-2
                  ${activePageIndex === idx 
                    ? 'bg-slate-800 text-white border-slate-800 shadow-md' 
                    : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
                  }
                `}
              >
                {page.type === 'toc' ? <i className="fas fa-list text-[10px]"></i> : `Page ${idx + 1}`}
              </button>
            ))}
            <button 
              onClick={addNewPage}
              className="px-3 py-1.5 rounded-lg text-xs font-bold bg-primary-50 text-primary-600 border border-primary-200 hover:bg-primary-100 transition-colors"
              title="Add New Page"
            >
              <i className="fas fa-plus"></i>
            </button>
          </div>

          {/* Editor Header */}
          <div className="px-6 py-4 border-b border-slate-100 bg-white flex justify-between items-center">
             <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-lg font-bold text-slate-800">
                        {activePage.type === 'toc' ? 'Directory' : `Page ${activePageIndex + 1}`}
                    </h2>
                    {activePage.type === 'toc' && <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded">Auto-generated</span>}
                </div>
                {activePage.type === 'content' && (
                    <span className="text-xs text-slate-400 font-medium">{activePage.steps.length} Steps</span>
                )}
             </div>
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto p-6 scroll-smooth">

            {/* Metadata Accordion */}
            <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden mb-8 transition-all">
              <button 
                onClick={() => setIsMetadataExpanded(!isMetadataExpanded)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
              >
                <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                  <i className="fas fa-cog text-slate-400"></i>
                  Global Document Settings
                </div>
                <i className={`fas fa-chevron-down text-slate-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>

              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                   <div className="col-span-2 h-px bg-slate-200 mb-2"></div>
                   <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Title</label>
                    <input 
                      type="text" 
                      value={metadata.title}
                      onChange={(e) => setMetadata({...metadata, title: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. User Manual"
                    />
                  </div>
                  <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Subtitle</label>
                    <input 
                      type="text" 
                      value={metadata.subtitle}
                      onChange={(e) => setMetadata({...metadata, subtitle: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. Quick Start Guide"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Author</label>
                    <input 
                      type="text" 
                      value={metadata.author}
                      onChange={(e) => setMetadata({...metadata, author: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Version</label>
                    <input 
                      type="text" 
                      value={metadata.version}
                      onChange={(e) => setMetadata({...metadata, version: e.target.value})}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>

                  {/* Step Markers Toggle */}
                  <div className="col-span-2 mt-2 pt-2 border-t border-slate-100 flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Show Step Markers</label>
                    <button 
                        onClick={() => setMetadata({...metadata, showStepMarkers: !metadata.showStepMarkers})}
                        className={`w-12 h-6 rounded-full p-1 transition-colors duration-200 ease-in-out ${metadata.showStepMarkers ? 'bg-primary-600' : 'bg-slate-300'}`}
                        title="Toggle bullet points on steps"
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transform transition-transform duration-200 ease-in-out ${metadata.showStepMarkers ? 'translate-x-6' : 'translate-x-0'}`}></div>
                    </button>
                  </div>
                </div>
              )}
            </div>

            {/* Page Title Editor (Specifically for TOC mapping) */}
            <div className="mb-6">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 flex justify-between items-end">
                    <span>{activePage.type === 'toc' ? 'Directory Header' : 'Page Title (For Directory & Header)'}</span>
                    {activePage.type === 'content' && (
                      <button 
                        onClick={handleAutoGeneratePageTitle}
                        disabled={isGeneratingTitle || activePage.steps.length === 0}
                        className="text-[10px] text-primary-600 hover:text-primary-700 bg-primary-50 hover:bg-primary-100 px-2 py-1 rounded transition-colors disabled:opacity-50"
                      >
                         {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Generate
                      </button>
                    )}
                </label>
                <div className="relative">
                    <input 
                        type="text" 
                        value={activePage.title || ''}
                        onChange={(e) => updatePageTitle(e.target.value)}
                        className="w-full p-3 bg-white border border-slate-300 rounded-lg text-base font-semibold text-slate-800 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                        placeholder={activePage.type === 'toc' ? "Table of Contents" : "e.g. Safety Instructions"}
                    />
                    <i className="fas fa-heading absolute right-3 top-3.5 text-slate-300"></i>
                </div>
                {activePage.type === 'content' && !activePage.title && activePage.steps.length > 0 && activePage.steps[0].title && (
                    <p className="text-[10px] text-slate-400 mt-1 ml-1">
                        <i className="fas fa-info-circle mr-1"></i>
                        Will default to first step title: "{activePage.steps[0].title}"
                    </p>
                )}
            </div>

            {/* Steps List for Active Page */}
            {activePage.type === 'toc' ? (
                <div className="bg-white border border-slate-200 rounded-xl p-8 text-center">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <i className="fas fa-list-ol text-2xl text-slate-300"></i>
                    </div>
                    <h3 className="font-bold text-slate-700 mb-2">Automatic Directory</h3>
                    <p className="text-sm text-slate-500 max-w-xs mx-auto">
                        This page automatically lists all subsequent pages and their titles. You can rename this page above.
                    </p>
                    <div className="mt-6 border-t border-slate-100 pt-4 text-xs text-slate-400">
                        Content is visible in Preview mode.
                    </div>
                </div>
            ) : (
                <div className="space-y-6">
                {activePage.steps.length === 0 && (
                    <div className="text-center py-10 text-slate-400">
                    <i className="fas fa-layer-group text-4xl mb-3 opacity-20"></i>
                    <p className="text-sm">This page is empty.</p>
                    <p className="text-xs">Add a step below to get started.</p>
                    </div>
                )}
                {activePage.steps.map((step, idx) => (
                    <StepEditor
                    key={step.id}
                    index={idx}
                    step={step}
                    totalSteps={activePage.steps.length}
                    onUpdate={updateStep}
                    onMoveUp={() => moveStep(idx, 'up')}
                    onMoveDown={() => moveStep(idx, 'down')}
                    />
                ))}
                </div>
            )}

            {/* Bottom Spacer for Floating Button */}
            <div className="h-24"></div>
          </div>

          {/* Floating Action Button for Adding Steps */}
          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[480px] lg:w-[560px] px-6 pointer-events-none">
                <button 
                onClick={addStepToActivePage}
                className="pointer-events-auto w-full py-4 bg-white/90 backdrop-blur border-2 border-dashed border-primary-500/30 text-primary-600 font-bold rounded-xl hover:bg-primary-50 hover:border-primary-500 transition-all shadow-lg flex items-center justify-center gap-2 group"
                >
                <div className="w-6 h-6 rounded-full bg-primary-100 flex items-center justify-center group-hover:bg-primary-600 group-hover:text-white transition-colors">
                    <i className="fas fa-plus text-xs"></i>
                </div>
                Add Step to Page {activePageIndex + 1}
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`
          flex-col flex-grow bg-slate-100 relative
          ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Mobile Tab Switcher */}
          <div className="md:hidden flex border-b border-slate-200 bg-white shrink-0">
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('editor')}
            >
              <i className="fas fa-edit mr-2"></i> Editor
            </button>
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('preview')}
            >
              <i className="fas fa-eye mr-2"></i> Preview
            </button>
          </div>

          <Preview 
            pages={pages} 
            metadata={metadata} 
            dimensions={pageDimensions}
            previewRef={previewRef}
            onPageOverflow={handlePageOverflow}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage } from './types';
import { generatePageTitle } from './services/geminiService';

interface HistoryState {
  pages: ManualPage[];
  metadata: ManualMetadata;
}

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(true);

  const previewRef = useRef<HTMLDivElement>(null);

  // --- State: Pages & Content ---
  const [metadata, setMetadata] = useState<ManualMetadata>({
    title: 'Product Manual',
    subtitle: 'Setup & Configuration Guide',
    author: 'My Company Inc.',
    version: '1.0',
    showStepMarkers: true
  });

  const [pages, setPages] = useState<ManualPage[]>([
    {
      id: uuidv4(),
      type: 'toc',
      title: 'Table of Contents',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'content',
      title: 'Getting Started',
      steps: [
        {
          id: uuidv4(),
          title: 'Unboxing',
          description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.',
          images: [],
          layout: 'image_left_text_right'
        }
      ]
    }
  ]);

  // --- Undo/Redo History State ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);
  const typingTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const [activePageIndex, setActivePageIndex] = useState(1); // Start on first content page

  // --- Effects ---

  // Auto-scroll to active page in preview when it changes
  useEffect(() => {
    if (hasStarted) {
      // Use a small timeout to allow render to complete (especially for new pages)
      const timer = setTimeout(() => {
        const pageElement = document.getElementById(`preview-page-${activePageIndex}`);
        if (pageElement) {
          pageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activePageIndex, hasStarted]);

  // --- Undo/Redo Logic ---

  const saveSnapshot = useCallback(() => {
    setPast(prev => {
      const newPast = [...prev, { pages, metadata }];
      if (newPast.length > 20) {
        return newPast.slice(newPast.length - 20);
      }
      return newPast;
    });
    setFuture([]);
  }, [pages, metadata]);

  const undo = () => {
    if (past.length === 0) return;

    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);

    setFuture(prev => [{ pages, metadata }, ...prev]);
    setPages(previous.pages);
    setMetadata(previous.metadata);
    setPast(newPast);
  };

  const redo = () => {
    if (future.length === 0) return;

    const next = future[0];
    const newFuture = future.slice(1);

    setPast(prev => [...prev, { pages, metadata }]);
    setPages(next.pages);
    setMetadata(next.metadata);
    setFuture(newFuture);
  };

  // Helper to handle debounce for text inputs history
  const handleTextTypingHistory = () => {
    if (!typingTimeoutRef.current) {
      saveSnapshot();
    }
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }
    typingTimeoutRef.current = setTimeout(() => {
      typingTimeoutRef.current = null;
    }, 1000);
  };

  const handleStructuralChangeHistory = () => {
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = null;
    }
    saveSnapshot();
  };

  // --- Handlers ---

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setHasStarted(true);
  };

  const activePage = pages[activePageIndex];

  // Add a new empty content page
  const addNewPage = () => {
    handleStructuralChangeHistory();
    setPages([...pages, { id: uuidv4(), type: 'content', title: '', steps: [] }]);
    setActivePageIndex(pages.length); // Switch to new page
  };

  const addTocPage = () => {
     if (pages.some(p => p.type === 'toc')) {
       alert("A Table of Contents page already exists.");
       return;
     }
     handleStructuralChangeHistory();
     setPages([{ id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] }, ...pages]);
     setActivePageIndex(0);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) {
      setActivePageIndex(index);
    }
  };

  // Update Page Title (used for TOC)
  const updatePageTitle = (title: string) => {
    handleTextTypingHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) {
      alert("Add some steps to the page first so AI can generate a title.");
      return;
    }

    // Treat as structural change to ensure snapshot before async update
    handleStructuralChangeHistory();
    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      // We manually update state here, reusing logic but without re-triggering history logic if possible, 
      // but simpler to just call setPages directly.
      setPages(currentPages => {
          const newPages = [...currentPages];
          newPages[activePageIndex] = { ...newPages[activePageIndex], title: suggestedTitle };
          return newPages;
      });
    } catch (error) {
      alert("Failed to generate title. Check API key or connection.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  // Wrapper for metadata updates
  const updateMetadata = (updates: Partial<ManualMetadata>) => {
    const isText = 'title' in updates || 'subtitle' in updates || 'author' in updates || 'version' in updates;
    if (isText) {
      handleTextTypingHistory();
    } else {
      handleStructuralChangeHistory();
    }
    setMetadata(prev => ({ ...prev, ...updates }));
  };

  // Step Management (Scoped to Active Page)
  const addStepToActivePage = () => {
    if (activePage.type === 'toc') return;

    handleStructuralChangeHistory();

    const newStep: ManualStep = {
      id: uuidv4(),
      title: '',
      description: '',
      images: [],
      layout: 'image_left_text_right'
    };

    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);

    setTimeout(() => {
      const el = document.getElementById('steps-container');
      if (el) el.scrollTop = el.scrollHeight;
    }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const isTextUpdate = 'title' in updates || 'description' in updates;

    if (isTextUpdate) {
        handleTextTypingHistory();
    } else {
        handleStructuralChangeHistory();
    }

    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step)
    }));
    setPages(newPages);
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type === 'toc') return;

    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;

    handleStructuralChangeHistory();

    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];

    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  // --- Automatic Overflow Handling ---
  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      const currentPage = prevPages[pageIndex];
      // Do not handle overflow for TOC pages
      if (currentPage.type === 'toc') return prevPages;

      // Safety check: Don't move if there's only 1 step
      if (currentPage.steps.length <= 1) return prevPages;

      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);

      // Check if next page exists, if not create it
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];

      // Update current page
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };

      if (nextPage && nextPage.type === 'content') {
        // Add to beginning of next page if it is a content page
        newPages[nextPageIndex] = {
          ...nextPage,
          steps: [lastStep, ...nextPage.steps]
        };
      } else {
        // Create new content page
        const newPage: ManualPage = {
            id: uuidv4(),
            type: 'content',
            title: 'Continued...',
            steps: [lastStep]
        };

        // Insert at nextPageIndex
        newPages.splice(nextPageIndex, 0, newPage);
      }

      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });

      // Iterate through all rendered pages in the Preview
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;

        if (i > 0) pdf.addPage();

        // Temporarily remove shadow for clean capture
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';

        const canvas = await html2canvas(pageElement, {
          scale: 2, 
          useCORS: true, 
          logging: false,
          backgroundColor: '#ffffff',
          windowWidth: 1200 
        });

        // Restore styles
        pageElement.style.boxShadow = originalShadow;

        const imgData = canvas.toDataURL('image/png');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} />;
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 h-16 flex items-center justify-between shadow-sm shrink-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-primary-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary-500/30">
            <i className="fas fa-book-open text-lg"></i>
          </div>
          <div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight leading-none">ManualMaster</h1>
            <p className="text-xs text-slate-500 font-medium">AI-Powered Documentation</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
           {/* Undo/Redo Controls */}
           <div className="flex items-center gap-1 mr-2 border-r border-slate-200 pr-4">
              <button 
                onClick={undo} 
                disabled={past.length === 0} 
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent text-slate-600 transition-colors" 
                title="Undo (Ctrl+Z)"
              >
                  <i className="fas fa-undo text-sm"></i>
              </button>
              <button 
                onClick={redo} 
                disabled={future.length === 0} 
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent text-slate-600 transition-colors" 
                title="Redo (Ctrl+Y)"
              >
                  <i className="fas fa-redo text-sm"></i>
              </button>
           </div>

           <button 
             onClick={() => { if(window.confirm('Go back to start? Unsaved changes will be lost.')) window.location.reload(); }}
             className="text-slate-400 hover:text-slate-600 text-xs font-semibold uppercase tracking-wider hidden md:block"
           >
             {pageDimensions.name} ({pageDimensions.width}x{pageDimensions.height}mm)
           </button>

          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-full text-sm font-semibold flex items-center gap-2 transition-all
              ${isGenerating 
                ? 'bg-slate-100 text-slate-400 cursor-wait' 
                : 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-lg active:transform active:scale-95'
              }
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span>{isGenerating ? 'Exporting...' : 'Download PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[480px] lg:w-[560px] border-r border-slate-200 bg-white shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Page Navigator */}
          <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center">
            {/* Add TOC Button if not present */}
            {!pages.some(p => p.type === 'toc') && (
               <button 
                onClick={addTocPage}
                className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-600 border border-slate-200 hover:bg-slate-200 transition-colors mr-2"
                title="Insert Table of Contents"
              >
                <i className="fas fa-list-ol mr-1"></i> TOC
              </button>
            )}

            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all border flex items-center gap-2
                  ${activePageIndex === idx 
                    ? 'bg-slate-800 text-white border-slate-800 shadow-md' 
                    : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
                  }
                `}
              >
                {page.type === 'toc' ? <i className="fas fa-list text-[10px]"></i> : `Page ${idx + 1}`}
              </button>
            ))}
            <button 
              onClick={addNewPage}
              className="px-3 py-1.5 rounded-lg text-xs font-bold bg-primary-50 text-primary-600 border border-primary-200 hover:bg-primary-100 transition-colors"
              title="Add New Page"
            >
              <i className="fas fa-plus"></i>
            </button>
          </div>

          {/* Editor Header */}
          <div className="px-6 py-4 border-b border-slate-100 bg-white flex justify-between items-center">
             <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-lg font-bold text-slate-800">
                        {activePage.type === 'toc' ? 'Directory' : `Page ${activePageIndex + 1}`}
                    </h2>
                    {activePage.type === 'toc' && <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded">Auto-generated</span>}
                </div>
                {activePage.type === 'content' && (
                    <span className="text-xs text-slate-400 font-medium">{activePage.steps.length} Steps</span>
                )}
             </div>
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto p-6 scroll-smooth">

            {/* Metadata Accordion */}
            <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden mb-8 transition-all">
              <button 
                onClick={() => setIsMetadataExpanded(!isMetadataExpanded)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
              >
                <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                  <i className="fas fa-cog text-slate-400"></i>
                  Global Document Settings
                </div>
                <i className={`fas fa-chevron-down text-slate-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>

              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                   <div className="col-span-2 h-px bg-slate-200 mb-2"></div>
                   <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Title</label>
                    <input 
                      type="text" 
                      value={metadata.title}
                      onChange={(e) => updateMetadata({ title: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. User Manual"
                    />
                  </div>
                  <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Subtitle</label>
                    <input 
                      type="text" 
                      value={metadata.subtitle}
                      onChange={(e) => updateMetadata({ subtitle: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. Quick Start Guide"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Author</label>
                    <input 
                      type="text" 
                      value={metadata.author}
                      onChange={(e) => updateMetadata({ author: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Version</label>
                    <input 
                      type="text" 
                      value={metadata.version}
                      onChange={(e) => updateMetadata({ version: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>

                  {/* Step Markers Toggle */}
                  <div className="col-span-2 mt-2 pt-2 border-t border-slate-100 flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Show Step Markers</label>
                    <button 
                        onClick={() => updateMetadata({ showStepMarkers: !metadata.showStepMarkers })}
                        className={`w-12 h-6 rounded-full p-1 transition-colors duration-200 ease-in-out ${metadata.showStepMarkers ? 'bg-primary-600' : 'bg-slate-300'}`}
                        title="Toggle bullet points on steps"
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transform transition-transform duration-200 ease-in-out ${metadata.showStepMarkers ? 'translate-x-6' : 'translate-x-0'}`}></div>
                    </button>
                  </div>
                </div>
              )}
            </div>

            {/* Page Title Editor (Specifically for TOC mapping) */}
            <div className="mb-6">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 flex justify-between items-end">
                    <span>{activePage.type === 'toc' ? 'Directory Header' : 'Page Title (For Directory & Header)'}</span>
                    {activePage.type === 'content' && (
                      <button 
                        onClick={handleAutoGeneratePageTitle}
                        disabled={isGeneratingTitle || activePage.steps.length === 0}
                        className="text-[10px] text-primary-600 hover:text-primary-700 bg-primary-50 hover:bg-primary-100 px-2 py-1 rounded transition-colors disabled:opacity-50"
                      >
                         {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Generate
                      </button>
                    )}
                </label>
                <div className="relative">
                    <input 
                        type="text" 
                        value={activePage.title || ''}
                        onChange={(e) => updatePageTitle(e.target.value)}
                        className="w-full p-3 bg-white border border-slate-300 rounded-lg text-base font-semibold text-slate-800 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                        placeholder={activePage.type === 'toc' ? "Table of Contents" : "e.g. Safety Instructions"}
                    />
                    <i className="fas fa-heading absolute right-3 top-3.5 text-slate-300"></i>
                </div>
                {activePage.type === 'content' && !activePage.title && activePage.steps.length > 0 && activePage.steps[0].title && (
                    <p className="text-[10px] text-slate-400 mt-1 ml-1">
                        <i className="fas fa-info-circle mr-1"></i>
                        Will default to first step title: "{activePage.steps[0].title}"
                    </p>
                )}
            </div>

            {/* Steps List for Active Page */}
            {activePage.type === 'toc' ? (
                <div className="bg-white border border-slate-200 rounded-xl p-8 text-center">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <i className="fas fa-list-ol text-2xl text-slate-300"></i>
                    </div>
                    <h3 className="font-bold text-slate-700 mb-2">Automatic Directory</h3>
                    <p className="text-sm text-slate-500 max-w-xs mx-auto">
                        This page automatically lists all subsequent pages and their titles. You can rename this page above.
                    </p>
                    <div className="mt-6 border-t border-slate-100 pt-4 text-xs text-slate-400">
                        Content is visible in Preview mode.
                    </div>
                </div>
            ) : (
                <div className="space-y-6">
                {activePage.steps.length === 0 && (
                    <div className="text-center py-10 text-slate-400">
                    <i className="fas fa-layer-group text-4xl mb-3 opacity-20"></i>
                    <p className="text-sm">This page is empty.</p>
                    <p className="text-xs">Add a step below to get started.</p>
                    </div>
                )}
                {activePage.steps.map((step, idx) => (
                    <StepEditor
                    key={step.id}
                    index={idx}
                    step={step}
                    totalSteps={activePage.steps.length}
                    onUpdate={updateStep}
                    onMoveUp={() => moveStep(idx, 'up')}
                    onMoveDown={() => moveStep(idx, 'down')}
                    />
                ))}
                </div>
            )}

            {/* Bottom Spacer for Floating Button */}
            <div className="h-24"></div>
          </div>

          {/* Floating Action Button for Adding Steps */}
          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[480px] lg:w-[560px] px-6 pointer-events-none">
                <button 
                onClick={addStepToActivePage}
                className="pointer-events-auto w-full py-4 bg-white/90 backdrop-blur border-2 border-dashed border-primary-500/30 text-primary-600 font-bold rounded-xl hover:bg-primary-50 hover:border-primary-500 transition-all shadow-lg flex items-center justify-center gap-2 group"
                >
                <div className="w-6 h-6 rounded-full bg-primary-100 flex items-center justify-center group-hover:bg-primary-600 group-hover:text-white transition-colors">
                    <i className="fas fa-plus text-xs"></i>
                </div>
                Add Step to Page {activePageIndex + 1}
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`
          flex-col flex-grow bg-slate-100 relative
          ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Mobile Tab Switcher */}
          <div className="md:hidden flex border-b border-slate-200 bg-white shrink-0">
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('editor')}
            >
              <i className="fas fa-edit mr-2"></i> Editor
            </button>
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('preview')}
            >
              <i className="fas fa-eye mr-2"></i> Preview
            </button>
          </div>

          <Preview 
            pages={pages} 
            metadata={metadata} 
            dimensions={pageDimensions}
            previewRef={previewRef}
            onPageOverflow={handlePageOverflow}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage } from './types';
import { generatePageTitle } from './services/geminiService';

interface HistoryState {
  pages: ManualPage[];
  metadata: ManualMetadata;
}

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(true);

  const previewRef = useRef<HTMLDivElement>(null);

  // --- State: Pages & Content ---
  const [metadata, setMetadata] = useState<ManualMetadata>({
    title: 'Product Manual',
    subtitle: 'Setup & Configuration Guide',
    author: 'My Company Inc.',
    version: '1.0',
    showStepMarkers: true
  });

  const [pages, setPages] = useState<ManualPage[]>([
    {
      id: uuidv4(),
      type: 'toc',
      title: 'Table of Contents',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'content',
      title: 'Getting Started',
      steps: [
        {
          id: uuidv4(),
          title: 'Unboxing',
          description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.',
          images: [],
          layout: 'image_left_text_right'
        }
      ]
    }
  ]);

  // --- Undo/Redo History State ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [activePageIndex, setActivePageIndex] = useState(1); // Start on first content page

  // --- Effects ---

  // Auto-scroll to active page in preview when it changes
  useEffect(() => {
    if (hasStarted) {
      // Use a small timeout to allow render to complete (especially for new pages)
      const timer = setTimeout(() => {
        const pageElement = document.getElementById(`preview-page-${activePageIndex}`);
        if (pageElement) {
          pageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activePageIndex, hasStarted]);

  // --- Undo/Redo Logic ---

  const saveSnapshot = useCallback(() => {
    setPast(prev => {
      const newPast = [...prev, { pages, metadata }];
      if (newPast.length > 20) {
        return newPast.slice(newPast.length - 20);
      }
      return newPast;
    });
    setFuture([]);
  }, [pages, metadata]);

  const undo = () => {
    if (past.length === 0) return;

    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);

    setFuture(prev => [{ pages, metadata }, ...prev]);
    setPages(previous.pages);
    setMetadata(previous.metadata);
    setPast(newPast);
  };

  const redo = () => {
    if (future.length === 0) return;

    const next = future[0];
    const newFuture = future.slice(1);

    setPast(prev => [...prev, { pages, metadata }]);
    setPages(next.pages);
    setMetadata(next.metadata);
    setFuture(newFuture);
  };

  // Helper to handle debounce for text inputs history
  const handleTextTypingHistory = () => {
    if (!typingTimeoutRef.current) {
      saveSnapshot();
    }
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }
    typingTimeoutRef.current = setTimeout(() => {
      typingTimeoutRef.current = null;
    }, 1000);
  };

  const handleStructuralChangeHistory = () => {
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = null;
    }
    saveSnapshot();
  };

  // --- Handlers ---

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setHasStarted(true);
  };

  const activePage = pages[activePageIndex];

  // Add a new empty content page
  const addNewPage = () => {
    handleStructuralChangeHistory();
    setPages([...pages, { id: uuidv4(), type: 'content', title: '', steps: [] }]);
    setActivePageIndex(pages.length); // Switch to new page
  };

  const addTocPage = () => {
     if (pages.some(p => p.type === 'toc')) {
       alert("A Table of Contents page already exists.");
       return;
     }
     handleStructuralChangeHistory();
     setPages([{ id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] }, ...pages]);
     setActivePageIndex(0);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) {
      setActivePageIndex(index);
    }
  };

  // Update Page Title (used for TOC)
  const updatePageTitle = (title: string) => {
    handleTextTypingHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) {
      alert("Add some steps to the page first so AI can generate a title.");
      return;
    }

    // Treat as structural change to ensure snapshot before async update
    handleStructuralChangeHistory();
    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      // We manually update state here, reusing logic but without re-triggering history logic if possible, 
      // but simpler to just call setPages directly.
      setPages(currentPages => {
          const newPages = [...currentPages];
          newPages[activePageIndex] = { ...newPages[activePageIndex], title: suggestedTitle };
          return newPages;
      });
    } catch (error) {
      alert("Failed to generate title. Check API key or connection.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  // Wrapper for metadata updates
  const updateMetadata = (updates: Partial<ManualMetadata>) => {
    const isText = 'title' in updates || 'subtitle' in updates || 'author' in updates || 'version' in updates;
    if (isText) {
      handleTextTypingHistory();
    } else {
      handleStructuralChangeHistory();
    }
    setMetadata(prev => ({ ...prev, ...updates }));
  };

  // Step Management (Scoped to Active Page)
  const addStepToActivePage = () => {
    if (activePage.type === 'toc') return;

    handleStructuralChangeHistory();

    const newStep: ManualStep = {
      id: uuidv4(),
      title: '',
      description: '',
      images: [],
      layout: 'image_left_text_right'
    };

    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);

    setTimeout(() => {
      const el = document.getElementById('steps-container');
      if (el) el.scrollTop = el.scrollHeight;
    }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const isTextUpdate = 'title' in updates || 'description' in updates;

    if (isTextUpdate) {
        handleTextTypingHistory();
    } else {
        handleStructuralChangeHistory();
    }

    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step)
    }));
    setPages(newPages);
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type === 'toc') return;

    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;

    handleStructuralChangeHistory();

    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];

    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  // --- Automatic Overflow Handling ---
  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      const currentPage = prevPages[pageIndex];
      // Do not handle overflow for TOC pages
      if (currentPage.type === 'toc') return prevPages;

      // Safety check: Don't move if there's only 1 step
      if (currentPage.steps.length <= 1) return prevPages;

      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);

      // Check if next page exists, if not create it
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];

      // Update current page
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };

      if (nextPage && nextPage.type === 'content') {
        // Add to beginning of next page if it is a content page
        newPages[nextPageIndex] = {
          ...nextPage,
          steps: [lastStep, ...nextPage.steps]
        };
      } else {
        // Create new content page
        const newPage: ManualPage = {
            id: uuidv4(),
            type: 'content',
            title: 'Continued...',
            steps: [lastStep]
        };

        // Insert at nextPageIndex
        newPages.splice(nextPageIndex, 0, newPage);
      }

      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });

      // Iterate through all rendered pages in the Preview
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;

        if (i > 0) pdf.addPage();

        // Temporarily remove shadow for clean capture
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';

        const canvas = await html2canvas(pageElement, {
          scale: 2, 
          useCORS: true, 
          logging: false,
          backgroundColor: '#ffffff',
          windowWidth: 1200 
        });

        // Restore styles
        pageElement.style.boxShadow = originalShadow;

        const imgData = canvas.toDataURL('image/png');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} />;
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 h-16 flex items-center justify-between shadow-sm shrink-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-primary-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary-500/30">
            <i className="fas fa-book-open text-lg"></i>
          </div>
          <div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight leading-none">ManualMaster</h1>
            <p className="text-xs text-slate-500 font-medium">AI-Powered Documentation</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
           {/* Undo/Redo Controls */}
           <div className="flex items-center gap-1 mr-2 border-r border-slate-200 pr-4">
              <button 
                onClick={undo} 
                disabled={past.length === 0} 
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent text-slate-600 transition-colors" 
                title="Undo (Ctrl+Z)"
              >
                  <i className="fas fa-undo text-sm"></i>
              </button>
              <button 
                onClick={redo} 
                disabled={future.length === 0} 
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent text-slate-600 transition-colors" 
                title="Redo (Ctrl+Y)"
              >
                  <i className="fas fa-redo text-sm"></i>
              </button>
           </div>

           <button 
             onClick={() => { if(window.confirm('Go back to start? Unsaved changes will be lost.')) window.location.reload(); }}
             className="text-slate-400 hover:text-slate-600 text-xs font-semibold uppercase tracking-wider hidden md:block"
           >
             {pageDimensions.name} ({pageDimensions.width}x{pageDimensions.height}mm)
           </button>

          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-full text-sm font-semibold flex items-center gap-2 transition-all
              ${isGenerating 
                ? 'bg-slate-100 text-slate-400 cursor-wait' 
                : 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-lg active:transform active:scale-95'
              }
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span>{isGenerating ? 'Exporting...' : 'Download PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[480px] lg:w-[560px] border-r border-slate-200 bg-white shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Page Navigator */}
          <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center">
            {/* Add TOC Button if not present */}
            {!pages.some(p => p.type === 'toc') && (
               <button 
                onClick={addTocPage}
                className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-600 border border-slate-200 hover:bg-slate-200 transition-colors mr-2"
                title="Insert Table of Contents"
              >
                <i className="fas fa-list-ol mr-1"></i> TOC
              </button>
            )}

            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all border flex items-center gap-2
                  ${activePageIndex === idx 
                    ? 'bg-slate-800 text-white border-slate-800 shadow-md' 
                    : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
                  }
                `}
              >
                {page.type === 'toc' ? <i className="fas fa-list text-[10px]"></i> : `Page ${idx + 1}`}
              </button>
            ))}
            <button 
              onClick={addNewPage}
              className="px-3 py-1.5 rounded-lg text-xs font-bold bg-primary-50 text-primary-600 border border-primary-200 hover:bg-primary-100 transition-colors"
              title="Add New Page"
            >
              <i className="fas fa-plus"></i>
            </button>
          </div>

          {/* Editor Header */}
          <div className="px-6 py-4 border-b border-slate-100 bg-white flex justify-between items-center">
             <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-lg font-bold text-slate-800">
                        {activePage.type === 'toc' ? 'Directory' : `Page ${activePageIndex + 1}`}
                    </h2>
                    {activePage.type === 'toc' && <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded">Auto-generated</span>}
                </div>
                {activePage.type === 'content' && (
                    <span className="text-xs text-slate-400 font-medium">{activePage.steps.length} Steps</span>
                )}
             </div>
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto p-6 scroll-smooth">

            {/* Metadata Accordion */}
            <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden mb-8 transition-all">
              <button 
                onClick={() => setIsMetadataExpanded(!isMetadataExpanded)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
              >
                <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                  <i className="fas fa-cog text-slate-400"></i>
                  Global Document Settings
                </div>
                <i className={`fas fa-chevron-down text-slate-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>

              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                   <div className="col-span-2 h-px bg-slate-200 mb-2"></div>
                   <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Title</label>
                    <input 
                      type="text" 
                      value={metadata.title}
                      onChange={(e) => updateMetadata({ title: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. User Manual"
                    />
                  </div>
                  <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Subtitle</label>
                    <input 
                      type="text" 
                      value={metadata.subtitle}
                      onChange={(e) => updateMetadata({ subtitle: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. Quick Start Guide"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Author</label>
                    <input 
                      type="text" 
                      value={metadata.author}
                      onChange={(e) => updateMetadata({ author: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Version</label>
                    <input 
                      type="text" 
                      value={metadata.version}
                      onChange={(e) => updateMetadata({ version: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>

                  {/* Step Markers Toggle */}
                  <div className="col-span-2 mt-2 pt-2 border-t border-slate-100 flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Show Step Markers</label>
                    <button 
                        onClick={() => updateMetadata({ showStepMarkers: !metadata.showStepMarkers })}
                        className={`w-12 h-6 rounded-full p-1 transition-colors duration-200 ease-in-out ${metadata.showStepMarkers ? 'bg-primary-600' : 'bg-slate-300'}`}
                        title="Toggle bullet points on steps"
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transform transition-transform duration-200 ease-in-out ${metadata.showStepMarkers ? 'translate-x-6' : 'translate-x-0'}`}></div>
                    </button>
                  </div>
                </div>
              )}
            </div>

            {/* Page Title Editor (Specifically for TOC mapping) */}
            <div className="mb-6">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 flex justify-between items-end">
                    <span>{activePage.type === 'toc' ? 'Directory Header' : 'Page Title (For Directory & Header)'}</span>
                    {activePage.type === 'content' && (
                      <button 
                        onClick={handleAutoGeneratePageTitle}
                        disabled={isGeneratingTitle || activePage.steps.length === 0}
                        className="text-[10px] text-primary-600 hover:text-primary-700 bg-primary-50 hover:bg-primary-100 px-2 py-1 rounded transition-colors disabled:opacity-50"
                      >
                         {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Generate
                      </button>
                    )}
                </label>
                <div className="relative">
                    <input 
                        type="text" 
                        value={activePage.title || ''}
                        onChange={(e) => updatePageTitle(e.target.value)}
                        className="w-full p-3 bg-white border border-slate-300 rounded-lg text-base font-semibold text-slate-800 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                        placeholder={activePage.type === 'toc' ? "Table of Contents" : "e.g. Safety Instructions"}
                    />
                    <i className="fas fa-heading absolute right-3 top-3.5 text-slate-300"></i>
                </div>
                {activePage.type === 'content' && !activePage.title && activePage.steps.length > 0 && activePage.steps[0].title && (
                    <p className="text-[10px] text-slate-400 mt-1 ml-1">
                        <i className="fas fa-info-circle mr-1"></i>
                        Will default to first step title: "{activePage.steps[0].title}"
                    </p>
                )}
            </div>

            {/* Steps List for Active Page */}
            {activePage.type === 'toc' ? (
                <div className="bg-white border border-slate-200 rounded-xl p-8 text-center">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <i className="fas fa-list-ol text-2xl text-slate-300"></i>
                    </div>
                    <h3 className="font-bold text-slate-700 mb-2">Automatic Directory</h3>
                    <p className="text-sm text-slate-500 max-w-xs mx-auto">
                        This page automatically lists all subsequent pages and their titles. You can rename this page above.
                    </p>
                    <div className="mt-6 border-t border-slate-100 pt-4 text-xs text-slate-400">
                        Content is visible in Preview mode.
                    </div>
                </div>
            ) : (
                <div className="space-y-6">
                {activePage.steps.length === 0 && (
                    <div className="text-center py-10 text-slate-400">
                    <i className="fas fa-layer-group text-4xl mb-3 opacity-20"></i>
                    <p className="text-sm">This page is empty.</p>
                    <p className="text-xs">Add a step below to get started.</p>
                    </div>
                )}
                {activePage.steps.map((step, idx) => (
                    <StepEditor
                    key={step.id}
                    index={idx}
                    step={step}
                    totalSteps={activePage.steps.length}
                    onUpdate={updateStep}
                    onMoveUp={() => moveStep(idx, 'up')}
                    onMoveDown={() => moveStep(idx, 'down')}
                    />
                ))}
                </div>
            )}

            {/* Bottom Spacer for Floating Button */}
