import React, { useState } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { ManualStep, StepLayout } from '../types';
import { generateDescriptionFromImages, generateStepTitle } from '../services/geminiService';

interface StepEditorProps {
  step: ManualStep;
  index: number;
  onUpdate: (id: string, updates: Partial<ManualStep>) => void;
  onDelete: (id: string) => void;
  onMoveUp: (index: number) => void;
  onMoveDown: (index: number) => void;
  totalSteps: number;
}

const StepEditor: React.FC<StepEditorProps> = ({ 
  step, 
  index, 
  onUpdate, 
  onDelete,
  onMoveUp,
  onMoveDown,
  totalSteps
}) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);

  const handleImagesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newImages = (Array.from(e.target.files) as File[]).filter(file => {
        if (file.size > 3 * 1024 * 1024) {
          alert(`File ${file.name} is too large (max 3MB).`);
          return false;
        }
        return true;
      }).map(file => ({
        id: uuidv4(),
        url: URL.createObjectURL(file),
        file
      }));

      onUpdate(step.id, { images: [...step.images, ...newImages] });
    }
  };

  const handleRemoveImage = (imageId: string) => {
    onUpdate(step.id, { images: step.images.filter(img => img.id !== imageId) });
  };

  const handleAnalyzeImages = async () => {
    if (step.images.length === 0) return;

    setIsAnalyzing(true);
    try {
      const files = step.images.map(img => img.file);
      const description = await generateDescriptionFromImages(files);
      onUpdate(step.id, { description });
    } catch (error) {
      alert("Failed to analyze images.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleGenerateTitle = async () => {
    if (!step.description) return;

    setIsGeneratingTitle(true);
    try {
      const title = await generateStepTitle(step.description);
      onUpdate(step.id, { title });
    } catch (error) {
      alert("Failed to generate title.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  const updateLayout = (layout: StepLayout) => {
    onUpdate(step.id, { layout });
  };

  const getImageGridClass = (count: number) => {
    if (count <= 1) return 'grid-cols-1';
    if (count === 3) return 'grid-cols-2'; // 3 images: 2 + 1 spanning
    if (count === 4) return 'grid-cols-2'; // 2x2
    if (count >= 5) return 'grid-cols-3'; // 3 cols for many
    return 'grid-cols-2'; // Default for 2
  };

  return (
    <div 
      className="bg-white rounded-xl shadow-sm border border-slate-200 mb-6 overflow-hidden transition-all duration-200 hover:shadow-md group"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {/* Header / Toolbar */}
      <div className="bg-slate-50 px-4 py-2 border-b border-slate-100 flex justify-between items-center flex-wrap gap-2">
        <div className="flex items-center gap-2">
          <span className="flex items-center justify-center w-6 h-6 rounded-full bg-slate-200 text-slate-600 text-xs font-bold">
            {index + 1}
          </span>
          <span className="text-xs font-medium text-slate-400 uppercase tracking-wide">Step</span>
        </div>

        {/* Layout Controls */}
        <div className="flex bg-white rounded-lg p-1 border border-slate-200 gap-1">
          <button 
            type="button"
            onClick={() => updateLayout('image_left_text_right')}
            className={`p-1 rounded hover:bg-slate-100 transition-colors ${step.layout === 'image_left_text_right' || !step.layout ? 'bg-primary-50 text-primary-600 ring-1 ring-primary-500/20' : 'text-slate-400'}`}
            title="Image Left, Text Right"
          >
            <div className="flex gap-0.5 w-5 h-4 items-center">
              <div className="w-2 h-3 bg-current rounded-[1px] opacity-80"></div>
              <div className="flex-1 h-3 flex flex-col gap-[2px] justify-center">
                <div className="w-full h-[2px] bg-current rounded-[1px] opacity-40"></div>
                <div className="w-2/3 h-[2px] bg-current rounded-[1px] opacity-40"></div>
              </div>
            </div>
          </button>

          <button 
            type="button"
            onClick={() => updateLayout('text_left_image_right')}
            className={`p-1 rounded hover:bg-slate-100 transition-colors ${step.layout === 'text_left_image_right' ? 'bg-primary-50 text-primary-600 ring-1 ring-primary-500/20' : 'text-slate-400'}`}
            title="Text Left, Image Right"
          >
            <div className="flex gap-0.5 w-5 h-4 items-center flex-row-reverse">
              <div className="w-2 h-3 bg-current rounded-[1px] opacity-80"></div>
              <div className="flex-1 h-3 flex flex-col gap-[2px] justify-center">
                <div className="w-full h-[2px] bg-current rounded-[1px] opacity-40"></div>
                <div className="w-2/3 h-[2px] bg-current rounded-[1px] opacity-40"></div>
              </div>
            </div>
          </button>

          <button 
            type="button"
            onClick={() => updateLayout('image_top_text_bottom')}
            className={`p-1 rounded hover:bg-slate-100 transition-colors ${step.layout === 'image_top_text_bottom' ? 'bg-primary-50 text-primary-600 ring-1 ring-primary-500/20' : 'text-slate-400'}`}
            title="Image Top, Text Bottom"
          >
            <div className="flex flex-col gap-0.5 w-4 h-5 justify-center items-center">
              <div className="w-3 h-2 bg-current rounded-[1px] opacity-80"></div>
              <div className="w-3 flex flex-col gap-[2px]">
                 <div className="w-full h-[2px] bg-current rounded-[1px] opacity-40"></div>
                 <div className="w-2/3 h-[2px] bg-current rounded-[1px] opacity-40"></div>
              </div>
            </div>
          </button>

          <button 
            type="button"
            onClick={() => updateLayout('text_top_image_bottom')}
            className={`p-1 rounded hover:bg-slate-100 transition-colors ${step.layout === 'text_top_image_bottom' ? 'bg-primary-50 text-primary-600 ring-1 ring-primary-500/20' : 'text-slate-400'}`}
            title="Text Top, Image Bottom"
          >
            <div className="flex flex-col-reverse gap-0.5 w-4 h-5 justify-center items-center">
              <div className="w-3 h-2 bg-current rounded-[1px] opacity-80"></div>
              <div className="w-3 flex flex-col gap-[2px]">
                 <div className="w-full h-[2px] bg-current rounded-[1px] opacity-40"></div>
                 <div className="w-2/3 h-[2px] bg-current rounded-[1px] opacity-40"></div>
              </div>
            </div>
          </button>
        </div>

        {/* Controls */}
        <div className="flex gap-1 ml-auto relative z-10">
           <button 
            type="button"
            onClick={() => onMoveUp(index)} 
            disabled={index === 0}
            className="w-8 h-8 flex items-center justify-center rounded-lg text-slate-400 hover:text-slate-700 hover:bg-slate-200 disabled:opacity-30 transition-colors"
            title="Move Up"
          >
            <i className="fas fa-arrow-up text-sm"></i>
          </button>
          <button 
            type="button"
            onClick={() => onMoveDown(index)} 
            disabled={index === totalSteps - 1}
            className="w-8 h-8 flex items-center justify-center rounded-lg text-slate-400 hover:text-slate-700 hover:bg-slate-200 disabled:opacity-30 transition-colors"
            title="Move Down"
          >
            <i className="fas fa-arrow-down text-sm"></i>
          </button>
          <div className="w-px h-6 bg-slate-200 mx-1 self-center"></div>
          <button 
            type="button"
            onClick={(e) => {
              e.stopPropagation();
              onDelete(step.id);
            }} 
            className="w-8 h-8 flex items-center justify-center rounded-lg text-red-400 hover:text-red-600 hover:bg-red-50 transition-colors"
            title="Delete Step"
          >
            <i className="fas fa-trash-alt text-sm"></i>
          </button>
        </div>
      </div>

      <div className="p-5 flex flex-col gap-6">

        {/* Main Content Grid: Image | Text */}
        <div className="flex flex-col md:flex-row gap-6">
            {/* Image Upload Area */}
            <div className="w-full md:w-1/3 flex-shrink-0 flex flex-col gap-2">

            {/* If images exist, show grid */}
            {step.images.length > 0 && (
                <div className={`grid gap-2 mb-2 ${getImageGridClass(step.images.length)}`}>
                {step.images.map((img, idx) => (
                    <div 
                        key={img.id} 
                        className={`
                            relative aspect-square group/thumb rounded-lg overflow-hidden border border-slate-200
                            ${step.images.length === 3 && idx === 2 ? 'col-span-2 aspect-[2/1]' : ''}
                        `}
                    >
                    <img src={img.url} alt="Thumbnail" className="w-full h-full object-cover" />
                    <button 
                        type="button"
                        onClick={() => handleRemoveImage(img.id)}
                        className="absolute top-1 right-1 w-6 h-6 bg-red-500 text-white rounded-full text-xs flex items-center justify-center opacity-0 group-hover/thumb:opacity-100 transition-opacity shadow-sm"
                    >
                        <i className="fas fa-times"></i>
                    </button>
                    </div>
                ))}
                </div>
            )}

            {/* Upload Button (Large if empty, Small bar if has images) */}
            <label className={`
                flex flex-col items-center justify-center border-2 border-dashed border-slate-300 rounded-lg hover:border-primary hover:bg-slate-50 transition-all cursor-pointer
                ${step.images.length > 0 ? 'h-16 flex-row gap-2' : 'aspect-[4/3]'}
            `}>
                <div className={`
                rounded-full bg-slate-100 flex items-center justify-center text-slate-400 group-hover:text-primary transition-colors
                ${step.images.length > 0 ? 'w-8 h-8' : 'w-10 h-10 mb-2'}
                `}>
                <i className="fas fa-cloud-upload-alt text-lg"></i>
                </div>
                <span className="text-xs font-medium text-slate-500">
                {step.images.length > 0 ? 'Add More' : 'Upload Images (Max 3MB)'}
                </span>
                <input 
                    type="file" 
                    accept="image/*" 
                    multiple 
                    onChange={handleImagesChange} 
                    className="hidden" 
                />
            </label>

            {/* Analyze Image Button */}
            {step.images.length > 0 && (
                <button
                type="button"
                onClick={handleAnalyzeImages}
                disabled={isAnalyzing}
                className="w-full py-2 bg-indigo-50 text-indigo-600 rounded-lg text-xs font-semibold hover:bg-indigo-100 transition-colors flex items-center justify-center gap-2 disabled:opacity-50"
                title="Use AI to describe the uploaded images"
                >
                {isAnalyzing ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-eye"></i>}
                {isAnalyzing ? "Analyzing..." : "Describe Image with AI"}
                </button>
            )}
            </div>

            {/* Text Inputs */}
            <div className="flex-1 flex flex-col gap-4">
                <div className="relative flex items-center gap-2">
                    <input
                        type="text"
                        value={step.title}
                        onChange={(e) => onUpdate(step.id, { title: e.target.value })}
                        placeholder="Step Title (e.g., 'Connect Power')"
                        className="flex-grow text-lg font-semibold text-slate-800 placeholder:text-slate-300 border-none p-0 focus:ring-0 bg-transparent"
                    />
                    {/* Title Generation Button */}
                    <button
                        type="button"
                        onClick={handleGenerateTitle}
                        disabled={isGeneratingTitle || !step.description}
                        className="text-xs font-medium text-slate-400 hover:text-primary-600 px-2 py-1 rounded hover:bg-slate-100 transition-colors flex items-center gap-1 disabled:opacity-30 disabled:cursor-not-allowed"
                        title="Generate title from description"
                    >
                        {isGeneratingTitle ? <i className="fas fa-circle-notch fa-spin text-[10px]"></i> : <i className="fas fa-magic text-[10px]"></i>}
                        Generate Title
                    </button>
                </div>

                <div className="relative flex-1">
                    <textarea
                    rows={6}
                    value={step.description}
                    onChange={(e) => onUpdate(step.id, { description: e.target.value })}
                    placeholder="Describe what the user needs to do in this step..."
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-600 focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary/20 resize-none h-full"
                    />
                </div>
            </div>
        </div>

      </div>
    </div>
  );
};

