import React, { useLayoutEffect, useRef } from 'react';
import { ManualPage, ManualMetadata, PageDimensions, StepLayout } from '../types';

interface PreviewProps {
  pages: ManualPage[];
  metadata: ManualMetadata;
  dimensions: PageDimensions;
  previewRef: React.RefObject<HTMLDivElement>;
  onPageOverflow: (pageIndex: number) => void;
}

const PageContainer: React.FC<{
  page: ManualPage;
  pageIndex: number;
  allPages: ManualPage[];
  totalPages: number;
  metadata: ManualMetadata;
  dimensions: PageDimensions;
  onOverflow: (index: number) => void;
}> = ({ page, pageIndex, allPages, totalPages, metadata, dimensions, onOverflow }) => {
  const pageRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  useLayoutEffect(() => {
    // Only check overflow for content pages
    if (page.type === 'content' && pageRef.current && contentRef.current) {
      const pageHeightPx = pageRef.current.offsetHeight;
      const contentHeightPx = contentRef.current.scrollHeight;

      if (contentHeightPx > pageHeightPx && page.steps.length > 1) {
        const timer = setTimeout(() => {
          onOverflow(pageIndex);
        }, 500);
        return () => clearTimeout(timer);
      }
    }
  }, [page.steps, pageIndex, onOverflow, page.type]);

  const currentDate = new Date().toLocaleDateString();
  const isFirstPage = pageIndex === 0;

  // Render Table of Contents
  const renderTOC = () => {
    // Filter pages that are content and have something to show
    const contentPages = allPages.map((p, idx) => ({ ...p, originalIndex: idx })).filter(p => p.type === 'content');

    return (
      <div className="flex flex-col h-full">
         <h1 className="text-3xl font-bold text-slate-900 mb-12 uppercase tracking-wider text-center border-b-2 border-slate-900 pb-4">
             {page.title || "Table of Contents"}
         </h1>

         <div className="flex-grow space-y-4 px-4">
             {contentPages.map((contentPage) => {
                 // Determine label: explicit title > first step title > "Page X"
                 let label = contentPage.title;
                 if (!label && contentPage.steps.length > 0) {
                     label = contentPage.steps[0].title;
                 }
                 if (!label) {
                     label = `Page ${contentPage.originalIndex + 1}`;
                 }

                 return (
                    <div key={contentPage.id} className="flex items-end mb-4">
                        <div className="font-bold text-slate-700 text-lg">{label}</div>
                        <div className="flex-grow border-b-2 border-dotted border-slate-300 mx-2 relative top-[-6px]"></div>
                        <div className="font-bold text-slate-900 text-lg w-8 text-right">
                            {contentPage.originalIndex + 1}
                        </div>
                    </div>
                 );
             })}
         </div>
      </div>
    );
  };

  const getLayoutClasses = (layout: StepLayout = 'image_left_text_right') => {
    switch (layout) {
      case 'text_left_image_right':
        return { 
            text: 'col-span-7 order-1', 
            image: 'col-span-5 order-2' 
        };
      case 'image_top_text_bottom':
        return { 
            text: 'col-span-12 order-2', 
            image: 'col-span-12 order-1 mb-4' 
        };
      case 'text_top_image_bottom':
        return { 
            text: 'col-span-12 order-1 mb-4', 
            image: 'col-span-12 order-2' 
        };
      case 'image_left_text_right':
      default:
        return { 
            text: 'col-span-7 order-2', 
            image: 'col-span-5 order-1' 
        };
    }
  };

  return (
    <div 
      id={`preview-page-${pageIndex}`}
      ref={pageRef}
      className="bg-white relative flex flex-col shrink-0 mb-8 shadow-md transition-transform mx-auto"
      style={{ 
        width: `${dimensions.width}mm`, 
        height: `${dimensions.height}mm`, // Fixed height to enforce paging
        overflow: 'hidden' 
      }}
    >
      {/* Locked Footer */}
      <footer className="absolute bottom-12 left-12 right-12 border-t border-slate-200 pt-6 flex justify-between items-center text-xs text-slate-400 z-20 bg-white">
          <p>© {new Date().getFullYear()} {metadata.author || "Your Company"}.</p>
          <div className="font-bold text-slate-500">
            Page {pageIndex + 1} of {totalPages}
          </div>
      </footer>

      {/* Main Content Area - Added bottom padding to accommodate locked footer */}
      <div ref={contentRef} className="p-12 pb-28 h-full flex flex-col relative z-10">
        {page.type === 'toc' ? (
             renderTOC()
        ) : (
          <>
            {/* Header */}
            <header className={`${isFirstPage ? 'border-b-2 border-slate-900 pb-6 mb-10' : 'border-b border-slate-200 pb-4 mb-6'}`}>
              <div className="flex justify-between items-end">
                <div className="max-w-[70%]">
                  {isFirstPage ? (
                    <>
                      <h1 className="text-4xl font-extrabold text-slate-900 tracking-tight leading-tight">
                        {metadata.title || "User Manual"}
                      </h1>
                      <p className="text-xl text-slate-500 mt-2 font-light">
                        {metadata.subtitle || "Instruction Guide"}
                      </p>
                    </>
                  ) : (
                    <h2 className="text-lg font-bold text-slate-400 uppercase tracking-wide">
                      {metadata.title || "User Manual"} <span className="text-slate-300">/ {page.title || "Continued"}</span>
                    </h2>
                  )}
                </div>
                <div className="text-right">
                  {isFirstPage && (
                    <div className="inline-block px-3 py-1 bg-slate-100 rounded text-xs font-bold text-slate-900 mb-1">
                      v{metadata.version}
                    </div>
                  )}
                  <div className="text-xs text-slate-400">{currentDate}</div>
                </div>
              </div>
            </header>

            {/* Content */}
            <main className="flex-grow space-y-8">
              {page.steps.length === 0 && (
                <div className="flex flex-col items-center justify-center h-48 text-slate-300 border-2 border-dashed border-slate-100 rounded-xl m-8">
                  <p className="font-medium text-sm">Empty Page</p>
                </div>
              )}

              {page.steps.map((step, idx) => {
                  const layoutClasses = getLayoutClasses(step.layout);

                  return (
                    <div key={step.id} className="break-inside-avoid step-item">
                        <div className="grid grid-cols-12 gap-6">
                            {/* Text Section */}
                            <div className={`${step.images.length > 0 ? layoutClasses.text : 'col-span-12 order-last'}`}>
                                <div className="flex items-start gap-3 mb-2">
                                    {metadata.showStepMarkers && (
                                        <div className="flex-shrink-0 pt-2">
                                            <div className="w-2.5 h-2.5 rounded-full bg-slate-900"></div>
                                        </div>
                                    )}
                                    <h3 className="text-lg font-bold text-slate-800 uppercase tracking-wide leading-tight">
                                        {step.title || "Untitled Step"}
                                    </h3>
                                </div>
                                <div className={metadata.showStepMarkers ? "pl-5" : ""}>
                                  <p className="text-slate-600 text-sm leading-relaxed whitespace-pre-wrap">
                                      {step.description || "No description provided."}
                                  </p>
                                </div>
                            </div>

                            {/* Image Section */}
                            {step.images.length > 0 && (
                            <div className={layoutClasses.image}>
                                <div className={`grid gap-2 ${step.images.length > 1 ? 'grid-cols-2' : 'grid-cols-1'}`}>
                                    {step.images.map((img) => (
                                        <div key={img.id} className="rounded-lg border border-slate-200 overflow-hidden bg-slate-50 shadow-sm">
                                            <img 
                                            src={img.url} 
                                            alt="Step illustration" 
                                            className="w-full h-auto object-cover"
                                            />
                                        </div>
                                    ))}
                                </div>
                            </div>
                            )}
                        </div>
                    </div>
                  );
              })}
            </main>
          </>
        )}
      </div>
    </div>
  );
};

const Preview: React.FC<PreviewProps> = ({ 
  pages, 
  metadata, 
  dimensions, 
  previewRef,
  onPageOverflow 
}) => {
  return (
    <div 
      ref={previewRef} 
      className="flex flex-col items-center py-8 overflow-y-auto h-full w-full bg-slate-100 scroll-smooth"
    >
      {pages.map((page, index) => (
        <PageContainer
          key={page.id}
