interface CoverEditorProps {
  page: ManualPage;
  onUpdate: (updates: Partial<ManualPage>) => void;
  metadata: { title: string; subtitle: string; author: string; version: string };
}

const CoverEditor: React.FC<CoverEditorProps> = ({ page, onUpdate, metadata }) => {
  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > 5 * 1024 * 1024) {
        alert("File is too large (max 5MB)");
        return;
      }
      const newImage = {
        id: uuidv4(),
        url: URL.createObjectURL(file),
        file
      };
      onUpdate({ backgroundImage: newImage });
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
      <div className="flex items-center gap-3 mb-6">
         <div className="w-10 h-10 bg-indigo-50 rounded-lg flex items-center justify-center text-indigo-600">
             <i className="fas fa-book-cover text-lg"></i>
         </div>
         <div>
             <h3 className="text-lg font-bold text-slate-800">Front Cover</h3>
             <p className="text-xs text-slate-500">The first page of your manual</p>
         </div>
      </div>

      <div className="mb-6 p-4 bg-slate-50 rounded-lg text-sm text-slate-500 border border-slate-100">
        <p className="mb-2"><strong className="text-slate-700">Title:</strong> {metadata.title}</p>
        <p className="mb-2"><strong className="text-slate-700">Subtitle:</strong> {metadata.subtitle}</p>
        <p><i className="fas fa-info-circle mr-1"></i> These values are managed in "Global Document Settings".</p>
      </div>

      <div className="mb-4">
        <label className="block text-sm font-bold text-slate-700 mb-2">Cover Background Image</label>

        {page.backgroundImage ? (
          <div className="relative rounded-lg overflow-hidden border border-slate-200 group">
            <img src={page.backgroundImage.url} alt="Cover Background" className="w-full h-48 object-cover" />
            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
               <label className="cursor-pointer px-3 py-1.5 bg-white rounded-md text-slate-800 text-xs font-bold hover:bg-slate-100 shadow-lg">
                  Change
                  <input type="file" accept="image/*" onChange={handleImageChange} className="hidden" />
               </label>
               <button 
                onClick={() => onUpdate({ backgroundImage: undefined })}
                className="px-3 py-1.5 bg-red-500 rounded-md text-white text-xs font-bold hover:bg-red-600 shadow-lg"
               >
                 Remove
               </button>
            </div>
          </div>
        ) : (
          <label className="flex flex-col items-center justify-center w-full h-48 border-2 border-dashed border-slate-300 rounded-lg hover:border-primary-500 hover:bg-primary-50 transition-all cursor-pointer">
            <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center mb-3 text-slate-400">
              <i className="fas fa-image text-xl"></i>
            </div>
            <span className="text-sm font-medium text-slate-600">Upload Cover Image</span>
            <span className="text-xs text-slate-400 mt-1">Full-page background recommended</span>
            <input type="file" accept="image/*" onChange={handleImageChange} className="hidden" />
          </label>
        )}
      </div>
    </div>
  );
};

