import './App.css';
import Page from './components/Page';
import ToolBar from './components/ToolBar';
import TextEditor from './components/TextEditor';
import { handleStructuralChangeHistory, saveSnapshot } from './history';
import { useHotkeys } from 'react-hotkeys-hook';

function App() {
  const [pages, setPages] = useState<string[][]>(() => {
    const savedPages = localStorage.getItem('pages');
    return savedPages ? JSON.parse(savedPages) : [['', '']];
  });
  const [activePageIndex, setActivePageIndex] = useState(0);

  useEffect(() => {
    localStorage.setItem('pages', JSON.stringify(pages));
  }, [pages]);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  const handlePageContentChange = (pageIndex: number, newContent: string[][]) => {
    const newPages = [...pages];
    newPages[pageIndex] = newContent;
    setPages(newPages);
  };

  const addPage = () => {
    handleStructuralChangeHistory();
    setPages([...pages, ['', '']]);
    setActivePageIndex(pages.length);
  };

  const deleteCurrentPage = (e: React.MouseEvent<HTMLButtonElement, MouseEvent>) => {
    e.stopPropagation();

    if (pages.length <= 1) {
        alert("Cannot delete the last page.");
        return;
    }

    if (window.confirm("Are you sure you want to delete this page?")) {
        handleStructuralChangeHistory();

        const newPages = pages.filter((_, index) => index !== activePageIndex);
        setPages(newPages);

        if (activePageIndex >= newPages.length) {
            setActivePageIndex(Math.max(0, newPages.length - 1));
        }
    }
  };

  const handleStructuralChange = () => {
    saveSnapshot(pages, activePageIndex);
  };

  const activePage = pages[activePageIndex];

  return (
    <div className="app">
      <ToolBar
        addPage={addPage}
        deletePage={deleteCurrentPage}
        toggleSidebar={toggleSidebar}
        isSidebarOpen={isSidebarOpen}
        handleStructuralChange={handleStructuralChange}
      />
      <div className="main-content">
        {activePage ? (
          <Page
            page={activePage}
            onPageContentChange={(newContent) =>
              handlePageContentChange(activePageIndex, newContent)
            }
          />
        ) : (
          <div>No Page to display</div>
        )}
      </div>
      <TextEditor
        isSidebarOpen={isSidebarOpen}
        pages={pages}
        setPages={setPages}
        activePageIndex={activePageIndex}
        setActivePageIndex={setActivePageIndex}
      />
    </div>
  );
}

export default App;
]]></content>
