import React, { useState, useEffect } from 'react';
import { PageDimensions, SavedProject } from '../types';

interface StartScreenProps {
  onStart: (dimensions: PageDimensions) => void;
  onLoadProject: (project: SavedProject) => void;
}

const PRESETS: PageDimensions[] = [
  { name: 'A4', width: 210, height: 297 },
  { name: 'A5', width: 148, height: 210 },
  { name: 'Letter', width: 216, height: 279 },
];

const StartScreen: React.FC<StartScreenProps> = ({ onStart, onLoadProject }) => {
  const [selectedPreset, setSelectedPreset] = useState<string>('A4');
  const [customWidth, setCustomWidth] = useState<string>('210');
  const [customHeight, setCustomHeight] = useState<string>('297');
  const [isCustom, setIsCustom] = useState(false);
  const [recentProjects, setRecentProjects] = useState<SavedProject[]>([]);

  useEffect(() => {
    try {
      const saved = localStorage.getItem('manual_master_projects');
      if (saved) {
        const parsed = JSON.parse(saved);
        // Sort by last modified desc
        const sorted = Object.values(parsed).sort((a: any, b: any) => b.lastModified - a.lastModified) as SavedProject[];
        setRecentProjects(sorted);
      }
    } catch (e) {
      console.error("Failed to load history", e);
    }
  }, []);

  const handleDeleteProject = (e: React.MouseEvent, projectId: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this project?")) {
      try {
        const saved = localStorage.getItem('manual_master_projects');
        if (saved) {
          const parsed = JSON.parse(saved);
          delete parsed[projectId];
          localStorage.setItem('manual_master_projects', JSON.stringify(parsed));

          // Update UI
          const sorted = Object.values(parsed).sort((a: any, b: any) => b.lastModified - a.lastModified) as SavedProject[];
          setRecentProjects(sorted);
        }
      } catch (e) {
        console.error("Failed to delete project", e);
      }
    }
  };

  const handlePresetSelect = (preset: PageDimensions) => {
    setSelectedPreset(preset.name);
    setIsCustom(false);
    setCustomWidth(preset.width.toString());
    setCustomHeight(preset.height.toString());
  };

  const handleCustomFocus = () => {
    setSelectedPreset('custom');
    setIsCustom(true);
  };

  const handleSubmit = () => {
    const width = parseFloat(customWidth);
    const height = parseFloat(customHeight);

    if (isNaN(width) || isNaN(height) || width <= 0 || height <= 0) {
      alert("Please enter valid positive dimensions.");
      return;
    }

    onStart({
      name: isCustom ? 'Custom' : selectedPreset,
      width,
      height
    });
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
      <div className="max-w-5xl w-full bg-white rounded-2xl shadow-xl overflow-hidden flex flex-col md:flex-row h-[600px]">

        {/* Left Side: Branding */}
        <div className="bg-primary-600 p-12 text-white md:w-5/12 flex flex-col justify-between relative overflow-hidden shrink-0">
          <div className="relative z-10">
            <div className="w-16 h-16 bg-white/20 backdrop-blur-sm rounded-2xl flex items-center justify-center mb-6">
              <i className="fas fa-book-open text-3xl"></i>
            </div>
            <h1 className="text-4xl font-bold mb-4">ManualMaster AI</h1>
            <p className="text-primary-100 text-lg leading-relaxed">
              Create professional, AI-enhanced user manuals and instruction guides in minutes.
            </p>
          </div>
          <div className="relative z-10 mt-12">
            <div className="flex items-center gap-3 text-sm font-medium text-primary-200">
              <i className="fas fa-check-circle"></i>
              <span>Smart Text Refinement</span>
            </div>
            <div className="flex items-center gap-3 text-sm font-medium text-primary-200 mt-2">
              <i className="fas fa-check-circle"></i>
              <span>Instant PDF Export</span>
            </div>
            <div className="flex items-center gap-3 text-sm font-medium text-primary-200 mt-2">
              <i className="fas fa-check-circle"></i>
              <span>Local Auto-Save</span>
            </div>
          </div>

          {/* Decorative Circles */}
          <div className="absolute -top-12 -right-12 w-64 h-64 bg-primary-500 rounded-full opacity-50 blur-3xl"></div>
          <div className="absolute -bottom-12 -left-12 w-64 h-64 bg-primary-700 rounded-full opacity-50 blur-3xl"></div>
        </div>

        {/* Right Side: Selection */}
        <div className="flex-1 flex flex-col overflow-hidden">
          <div className="p-8 pb-0 shrink-0">
             <h2 className="text-2xl font-bold text-slate-800 mb-2">New Project</h2>
             <p className="text-slate-500 text-sm mb-4">Choose your document page size to begin.</p>

              {/* Presets Grid */}
              <div className="grid grid-cols-4 gap-3 mb-4">
                {PRESETS.map((preset) => (
                  <button
                    key={preset.name}
                    onClick={() => handlePresetSelect(preset)}
                    className={`
                      p-2 rounded-lg border-2 flex flex-col items-center transition-all text-center
