                    <span className="text-[10px] opacity-70 whitespace-nowrap">{preset.width}x{preset.height}</span>
                  </button>
                ))}
                 {/* Custom Input Trigger */}
                 <button 
                  onClick={handleCustomFocus}
                  className={`
                    p-2 rounded-lg border-2 flex flex-col items-center transition-all text-center
                    ${isCustom 
                      ? 'border-primary-600 bg-primary-50 text-primary-700' 
