export default App;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import CoverEditor from './components/CoverEditor';
import BackCoverEditor from './components/BackCoverEditor';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage, SavedProject, StepImage } from './types';
import { generatePageTitle } from './services/geminiService';

interface HistoryState {
  pages: ManualPage[];
  metadata: ManualMetadata;
}

const DEFAULT_METADATA: ManualMetadata = {
  title: 'Product Manual',
  subtitle: 'Setup & Configuration Guide',
  author: 'My Company Inc.',
  version: '1.0',
  showStepMarkers: true
};

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });

  // New: Track Project ID for history
  const [projectId, setProjectId] = useState<string>(uuidv4());

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(true);

  // Saving State
  const [isSaving, setIsSaving] = useState(false);
  const [lastSavedTime, setLastSavedTime] = useState<Date | null>(null);

  const previewRef = useRef<HTMLDivElement>(null);

  // --- State: Pages & Content ---
  const [metadata, setMetadata] = useState<ManualMetadata>(DEFAULT_METADATA);

  const [pages, setPages] = useState<ManualPage[]>([
    {
      id: uuidv4(),
      type: 'cover',
      title: 'Cover Page',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'toc',
      title: 'Table of Contents',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'content',
      title: 'Getting Started',
      steps: [
        {
          id: uuidv4(),
          title: 'Unboxing',
          description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.',
          images: [],
          layout: 'image_left_text_right'
        }
      ]
    }
  ]);

  // --- Undo/Redo History State ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [activePageIndex, setActivePageIndex] = useState(0); 

  // --- Utility: Convert Image to Base64 ---
  const convertUrlToBase64 = async (url: string): Promise<string> => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn("Failed to convert image for saving:", url);
      return url; // Fallback
    }
  };

  // --- Save Logic ---
  const saveProjectToHistory = useCallback(async (isManual: boolean = false) => {
    if (!hasStarted) return;
    setIsSaving(true);

    try {
      // 1. Deep clone pages to modify images for storage
      const pagesToSave = JSON.parse(JSON.stringify(pages)) as ManualPage[];

      // 2. Iterate and convert any Blob URLs to Base64 if possible
      for (const page of pagesToSave) {
         if (page.backgroundImage && page.backgroundImage.url.startsWith('blob:')) {
             page.backgroundImage.url = await convertUrlToBase64(page.backgroundImage.url);
             delete page.backgroundImage.file; 
         }
         for (const step of page.steps) {
             for (const img of step.images) {
                 if (img.url.startsWith('blob:')) {
                     img.url = await convertUrlToBase64(img.url);
                     delete img.file; 
                 }
             }
         }
      }

      const projectData: SavedProject = {
        id: projectId,
        lastModified: Date.now(),
        metadata,
        pages: pagesToSave,
        dimensions: pageDimensions
      };

      const storedProjects = localStorage.getItem('manual_master_projects');
      const projects = storedProjects ? JSON.parse(storedProjects) : {};
      projects[projectId] = projectData;

      localStorage.setItem('manual_master_projects', JSON.stringify(projects));
      setLastSavedTime(new Date());

      if (isManual) {
          console.log("Save successful");
      }
    } catch (error) {
       console.error("Failed to save project:", error);
       // Alert if manual save (or returning home) fails, so user knows data isn't safe
       if (isManual) alert("Warning: Failed to save project. Your local storage might be full.");
    } finally {
        setTimeout(() => setIsSaving(false), 500);
    }
  }, [pages, metadata, pageDimensions, projectId, hasStarted]);

  // --- Auto-Save on Change (Debounced) ---
  useEffect(() => {
    if (!hasStarted) return;

    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);

    // Debounce save (2 seconds) for frequent updates
    saveTimeoutRef.current = setTimeout(() => {
        saveProjectToHistory();
    }, 2000);

    return () => {
        if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    };
  }, [pages, metadata, pageDimensions, hasStarted, saveProjectToHistory]);

  // --- Auto-Save Interval (Every 60 Seconds) ---
  useEffect(() => {
    if (!hasStarted) return;

    const intervalId = setInterval(() => {
        saveProjectToHistory(false);
    }, 60000); // 60000ms = 60s

    return () => clearInterval(intervalId);
  }, [hasStarted, saveProjectToHistory]);

  // --- Keyboard Shortcut (Ctrl+S) ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            saveProjectToHistory(true);
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [saveProjectToHistory]);

  // --- Effects ---

  // Auto-scroll to active page in preview when it changes
  useEffect(() => {
    if (hasStarted) {
      // Use a small timeout to allow render to complete (especially for new pages)
      const timer = setTimeout(() => {
        const pageElement = document.getElementById(`preview-page-${activePageIndex}`);
        if (pageElement) {
          pageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activePageIndex, hasStarted]);

  // --- Undo/Redo Logic ---

  const saveSnapshot = useCallback(() => {
    setPast(prev => {
      const newPast = [...prev, { pages, metadata }];
      if (newPast.length > 20) {
        return newPast.slice(newPast.length - 20);
      }
      return newPast;
    });
    setFuture([]);
  }, [pages, metadata]);

  const undo = () => {
    if (past.length === 0) return;

    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);

    setFuture(prev => [{ pages, metadata }, ...prev]);
    setPages(previous.pages);
    setMetadata(previous.metadata);
    setPast(newPast);
  };

  const redo = () => {
    if (future.length === 0) return;

    const next = future[0];
    const newFuture = future.slice(1);

    setPast(prev => [...prev, { pages, metadata }]);
    setPages(next.pages);
    setMetadata(next.metadata);
    setFuture(newFuture);
  };

  // Helper to handle debounce for text inputs history
  const handleTextTypingHistory = () => {
    if (!typingTimeoutRef.current) {
      saveSnapshot();
    }
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }
    typingTimeoutRef.current = setTimeout(() => {
      typingTimeoutRef.current = null;
    }, 1000);
  };

  const handleStructuralChangeHistory = () => {
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = null;
    }
    saveSnapshot();
  };

  // --- Handlers ---

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setProjectId(uuidv4());

    // Reset state for new project
    setMetadata(DEFAULT_METADATA);
    setPages([
      { id: uuidv4(), type: 'cover', title: 'Cover Page', steps: [] },
      { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] },
      { id: uuidv4(), type: 'content', title: 'Getting Started', steps: [{ id: uuidv4(), title: 'Unboxing', description: 'Carefully remove the device from the packaging.', images: [], layout: 'image_left_text_right' }] }
    ]);
    setPast([]);
    setFuture([]);
    setActivePageIndex(0);

    setHasStarted(true);
  };

  const handleLoadProject = (project: SavedProject) => {
      setProjectId(project.id);
      setMetadata(project.metadata);
      setPages(project.pages);
      setPageDimensions(project.dimensions);
      setPast([]);
      setFuture([]);
      setActivePageIndex(0);
      setHasStarted(true);
  };

  const handleGoHome = async () => {
      // Prompt user, then save project (treating as manual save to warn on error), then exit
      if (window.confirm("Save and return to Home Screen?")) {
          await saveProjectToHistory(true); 
          setHasStarted(false);
      }
  };

  // Safety check: Ensure activePage exists. Fallback to first page or a dummy object if empty (shouldn't happen).
  const activePage = pages[activePageIndex] || pages[0] || { id: 'dummy', type: 'content', steps: [] };

  // Add a new empty content page
  const addNewPage = () => {
    handleStructuralChangeHistory();
    // Insert before back cover if it exists
    const lastPage = pages[pages.length - 1];
    const hasBackCover = lastPage.type === 'back_cover';

    const newPage: ManualPage = { id: uuidv4(), type: 'content', title: '', steps: [] };
    const insertIndex = hasBackCover ? pages.length - 1 : pages.length;

    const newPages = [...pages];
    newPages.splice(insertIndex, 0, newPage);
    setPages(newPages);
    setActivePageIndex(insertIndex); 
  };

  const addTocPage = () => {
     if (pages.some(p => p.type === 'toc')) {
       alert("A Table of Contents page already exists.");
       return;
     }
     handleStructuralChangeHistory();
     // Insert after cover
     const insertIndex = pages[0].type === 'cover' ? 1 : 0;
     const newPages = [...pages];
     newPages.splice(insertIndex, 0, { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] });
     setPages(newPages);
     setActivePageIndex(insertIndex);
  };

  const addBackCover = () => {
    if (pages.some(p => p.type === 'back_cover')) {
      alert("Back Cover already exists.");
      return;
    }
    handleStructuralChangeHistory();
    setPages([...pages, { id: uuidv4(), type: 'back_cover', title: 'Back Cover', steps: [] }]);
    setActivePageIndex(pages.length);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) {
      setActivePageIndex(index);
    }
  };

  // Update Page Title (used for TOC)
  const updatePageTitle = (title: string) => {
    handleTextTypingHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) {
      alert("Add some steps to the page first so AI can generate a title.");
      return;
    }

    // Treat as structural change to ensure snapshot before async update
    handleStructuralChangeHistory();
    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      // We manually update state here, reusing logic but without re-triggering history logic if possible, 
      // but simpler to just call setPages directly.
      setPages(currentPages => {
          const newPages = [...currentPages];
          if (newPages[activePageIndex]) {
            newPages[activePageIndex] = { ...newPages[activePageIndex], title: suggestedTitle };
          }
          return newPages;
      });
    } catch (error) {
      alert("Failed to generate title. Check API key or connection.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  // Wrapper for metadata updates
  const updateMetadata = (updates: Partial<ManualMetadata>) => {
    const isText = 'title' in updates || 'subtitle' in updates || 'author' in updates || 'version' in updates;
    if (isText) {
      handleTextTypingHistory();
    } else {
      handleStructuralChangeHistory();
    }
    setMetadata(prev => ({ ...prev, ...updates }));
  };

  // Generic page update
  const updatePage = (updates: Partial<ManualPage>) => {
    handleStructuralChangeHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], ...updates };
    setPages(newPages);
  };

  // Step Management (Scoped to Active Page)
  const addStepToActivePage = () => {
    if (activePage.type !== 'content') return;

    handleStructuralChangeHistory();

    const newStep: ManualStep = {
      id: uuidv4(),
      title: '',
      description: '',
      images: [],
      layout: 'image_left_text_right'
    };

    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);

    setTimeout(() => {
      const el = document.getElementById('steps-container');
      if (el) el.scrollTop = el.scrollHeight;
    }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const isTextUpdate = 'title' in updates || 'description' in updates;

    if (isTextUpdate) {
        handleTextTypingHistory();
    } else {
        handleStructuralChangeHistory();
    }

    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step)
    }));
    setPages(newPages);
  };

  const deleteStep = (stepId: string) => {
    handleStructuralChangeHistory();
    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.filter(step => step.id !== stepId)
    }));
    setPages(newPages);
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type !== 'content') return;

    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;

    handleStructuralChangeHistory();

    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];

    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  const deleteCurrentPage = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (pages.length <= 1) {
        alert("Cannot delete the last page.");
        return;
    }

    if (window.confirm("Are you sure you want to delete this page?")) {
        handleStructuralChangeHistory();

        // Use filter to create a new array excluding the current page
        // This is more robust than splice with functional updates in this context
        const newPages = pages.filter((_, index) => index !== activePageIndex);
        setPages(newPages);

        // Adjust active index if necessary (e.g., if we deleted the last page)
        if (activePageIndex >= newPages.length) {
            setActivePageIndex(Math.max(0, newPages.length - 1));
        }
    }
  };

  // --- Automatic Overflow Handling ---
  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      // Guard against stale indices (e.g., page was deleted while timer was running)
      if (pageIndex < 0 || pageIndex >= prevPages.length) {
        return prevPages;
      }

      const currentPage = prevPages[pageIndex];
      // Guard against undefined page
      if (!currentPage) return prevPages;

      // Do not handle overflow for TOC, Cover, BackCover
      if (currentPage.type !== 'content') return prevPages;

      // Safety check: Don't move if there's only 1 step
      if (currentPage.steps.length <= 1) return prevPages;

      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);

      // Check if next page exists
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];

      // Update current page
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };

      if (nextPage && nextPage.type === 'content') {
        // Add to beginning of next page if it is a content page
        newPages[nextPageIndex] = {
          ...nextPage,
          steps: [lastStep, ...nextPage.steps]
        };
      } else {
        // Create new content page
        const newPage: ManualPage = {
            id: uuidv4(),
            type: 'content',
            title: 'Continued...',
            steps: [lastStep]
        };

        // Insert at nextPageIndex
        newPages.splice(nextPageIndex, 0, newPage);
      }

      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });

      // Iterate through all rendered pages in the Preview
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;

        if (i > 0) pdf.addPage();

        // Temporarily remove shadow for clean capture
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';

        const canvas = await html2canvas(pageElement, {
          scale: 2, 
          useCORS: true, 
          logging: false,
          backgroundColor: '#ffffff',
          windowWidth: 1200 
        });

        // Restore styles
        pageElement.style.boxShadow = originalShadow;

        const imgData = canvas.toDataURL('image/png');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} onLoadProject={handleLoadProject} />;
  }

  const renderPageIcon = (type: ManualPage['type']) => {
      switch(type) {
          case 'cover': return <i className="fas fa-book-cover text-[10px]"></i>;
          case 'toc': return <i className="fas fa-list-ol text-[10px]"></i>;
          case 'back_cover': return <i className="fas fa-book-open fa-flip-horizontal text-[10px]"></i>;
          default: return null;
      }
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 h-16 flex items-center justify-between shadow-sm shrink-0 z-50">
        <div className="flex items-center gap-3">
            {/* HOME BUTTON */}
            <button 
                onClick={handleGoHome}
                className="w-10 h-10 flex items-center justify-center rounded-xl bg-slate-100 hover:bg-slate-200 text-slate-600 transition-colors"
                title="Back to Home"
            >
                <i className="fas fa-home text-lg"></i>
            </button>

            <div className="hidden md:block w-px h-8 bg-slate-200 mx-1"></div>

          <div className="w-10 h-10 bg-primary-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary-500/30">
            <i className="fas fa-book-open text-lg"></i>
          </div>
          <div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight leading-none">ManualMaster</h1>
            <p className="text-xs text-slate-500 font-medium">AI-Powered Documentation</p>
          </div>
        </div>
        <div className="flex items-center gap-4">

           {/* Save Controls */}
           <div className="flex items-center gap-3 mr-2">
                <div className="text-right hidden lg:block">
                     <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                         {isSaving ? 'Saving...' : 'Auto-Save On'}
                     </div>
                     {lastSavedTime && !isSaving && (
                         <div className="text-[10px] text-slate-300">
                             Saved {lastSavedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                         </div>
                     )}
                </div>
                <button 
                    onClick={() => saveProjectToHistory(true)}
                    className={`
                        w-10 h-10 flex items-center justify-center rounded-xl transition-all
                        ${isSaving 
                            ? 'bg-primary-50 text-primary-600' 
                            : 'bg-white border border-slate-200 text-slate-500 hover:text-primary-600 hover:border-primary-200 hover:shadow-md'
                        }
                    `}
                    title="Manual Save (Ctrl+S)"
                >
                    {isSaving ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-save text-lg"></i>}
                </button>
           </div>

           <div className="w-px h-8 bg-slate-200 mx-2 hidden md:block"></div>

           {/* Undo/Redo Controls */}
           <div className="flex items-center gap-1 border-r border-slate-200 pr-4">
              <button 
                onClick={undo} 
                disabled={past.length === 0} 
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent text-slate-600 transition-colors" 
                title="Undo (Ctrl+Z)"
              >
                  <i className="fas fa-undo text-sm"></i>
              </button>
              <button 
                onClick={redo} 
                disabled={future.length === 0} 
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent text-slate-600 transition-colors" 
                title="Redo (Ctrl+Y)"
              >
                  <i className="fas fa-redo text-sm"></i>
              </button>
           </div>

           <div className="hidden lg:block text-slate-400 text-xs font-semibold uppercase tracking-wider">
             {pageDimensions.name}
           </div>

          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-full text-sm font-semibold flex items-center gap-2 transition-all
              ${isGenerating 
                ? 'bg-slate-100 text-slate-400 cursor-wait' 
                : 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-lg active:transform active:scale-95'
              }
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span>{isGenerating ? 'Exporting...' : 'Download PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[480px] lg:w-[560px] border-r border-slate-200 bg-white shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Page Navigator */}
          <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center">
             {/* Add TOC Button if not present */}
             {!pages.some(p => p.type === 'toc') && (
               <button 
                onClick={addTocPage}
                className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-600 border border-slate-200 hover:bg-slate-200 transition-colors mr-2"
                title="Insert Table of Contents"
              >
                <i className="fas fa-list-ol mr-1"></i> TOC
              </button>
            )}

            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all border flex items-center gap-2
                  ${activePageIndex === idx 
                    ? 'bg-slate-800 text-white border-slate-800 shadow-md' 
                    : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
                  }
                `}
              >
                {renderPageIcon(page.type)}
                {page.type === 'content' ? `Page ${idx + 1}` : (page.type === 'cover' ? 'Front' : (page.type === 'back_cover' ? 'Back' : 'TOC'))}
              </button>
            ))}
            <button 
              onClick={addNewPage}
              className="px-3 py-1.5 rounded-lg text-xs font-bold bg-primary-50 text-primary-600 border border-primary-200 hover:bg-primary-100 transition-colors"
              title="Add New Content Page"
            >
              <i className="fas fa-plus"></i>
            </button>

            {!pages.some(p => p.type === 'back_cover') && (
                <button 
                    onClick={addBackCover}
                    className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-500 border border-slate-200 hover:bg-slate-200 transition-colors"
                    title="Add Back Cover"
                >
                    <i className="fas fa-book-open fa-flip-horizontal"></i>
                </button>
            )}
          </div>

          {/* Editor Header */}
          <div className="px-6 py-4 border-b border-slate-100 bg-white flex justify-between items-center">
             <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-lg font-bold text-slate-800">
                        {activePage.type === 'cover' ? 'Front Cover' : 
                         activePage.type === 'back_cover' ? 'Back Cover' :
                         activePage.type === 'toc' ? 'Directory' : `Page ${activePageIndex + 1}`}
                    </h2>
                    {activePage.type === 'toc' && <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded">Auto-generated</span>}
                </div>
                {activePage.type === 'content' && (
                    <span className="text-xs text-slate-400 font-medium">{activePage.steps.length} Steps</span>
                )}
             </div>

             {/* Delete Page Button REMOVED as requested previously, keeping removal intact */}
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto p-6 scroll-smooth">

            {/* Metadata Accordion - Global Settings */}
            <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden mb-8 transition-all">
              <button 
                onClick={() => setIsMetadataExpanded(!isMetadataExpanded)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
              >
                <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                  <i className="fas fa-cog text-slate-400"></i>
                  Global Document Settings
                </div>
                <i className={`fas fa-chevron-down text-slate-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>

              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                   <div className="col-span-2 h-px bg-slate-200 mb-2"></div>
                   <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Title</label>
                    <input 
                      type="text" 
                      value={metadata.title}
                      onChange={(e) => updateMetadata({ title: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. User Manual"
                    />
                  </div>
                  <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Subtitle</label>
                    <input 
                      type="text" 
                      value={metadata.subtitle}
                      onChange={(e) => updateMetadata({ subtitle: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. Quick Start Guide"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Author</label>
                    <input 
                      type="text" 
                      value={metadata.author}
                      onChange={(e) => updateMetadata({ author: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Version</label>
                    <input 
                      type="text" 
                      value={metadata.version}
                      onChange={(e) => updateMetadata({ version: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>

                  {/* Step Markers Toggle */}
                  <div className="col-span-2 mt-2 pt-2 border-t border-slate-100 flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Show Step Markers</label>
                    <button 
                        onClick={() => updateMetadata({ showStepMarkers: !metadata.showStepMarkers })}
                        className={`w-12 h-6 rounded-full p-1 transition-colors duration-200 ease-in-out ${metadata.showStepMarkers ? 'bg-primary-600' : 'bg-slate-300'}`}
                        title="Toggle bullet points on steps"
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transform transition-transform duration-200 ease-in-out ${metadata.showStepMarkers ? 'translate-x-6' : 'translate-x-0'}`}></div>
                    </button>
                  </div>
                </div>
              )}
            </div>

            {/* Conditional Editors based on Page Type */}
            {activePage.type === 'cover' && (
                <CoverEditor page={activePage} onUpdate={updatePage} metadata={metadata} />
            )}

            {activePage.type === 'back_cover' && (
                <BackCoverEditor page={activePage} onUpdate={updatePage} />
            )}

            {activePage.type === 'toc' && (
                <div className="bg-white border border-slate-200 rounded-xl p-8 text-center">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <i className="fas fa-list-ol text-2xl text-slate-300"></i>
                    </div>
                    <h3 className="font-bold text-slate-700 mb-2">Automatic Directory</h3>
                    <p className="text-sm text-slate-500 max-w-xs mx-auto">
                        This page automatically lists all subsequent pages and their titles.
                    </p>
                    <div className="mt-4">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">TOC Title</label>
                        <input 
                            type="text" 
                            value={activePage.title || ''}
                            onChange={(e) => updatePageTitle(e.target.value)}
                            className="w-full p-2 bg-slate-50 border border-slate-200 rounded text-center text-sm font-semibold"
                        />
                    </div>
                </div>
            )}

            {activePage.type === 'content' && (
                <>
                    {/* Page Title Editor */}
                    <div className="mb-6">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 flex justify-between items-end">
                            <span>Page Title (For Directory & Header)</span>
                            <button 
                                onClick={handleAutoGeneratePageTitle}
                                disabled={isGeneratingTitle || activePage.steps.length === 0}
                                className="text-[10px] text-primary-600 hover:text-primary-700 bg-primary-50 hover:bg-primary-100 px-2 py-1 rounded transition-colors disabled:opacity-50"
                            >
                                {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Generate
                            </button>
                        </label>
                        <div className="relative">
                            <input 
                                type="text" 
                                value={activePage.title || ''}
                                onChange={(e) => updatePageTitle(e.target.value)}
                                className="w-full p-3 bg-white border border-slate-300 rounded-lg text-base font-semibold text-slate-800 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                                placeholder="e.g. Safety Instructions"
                            />
                            <i className="fas fa-heading absolute right-3 top-3.5 text-slate-300"></i>
                        </div>
                        {!activePage.title && activePage.steps.length > 0 && activePage.steps[0].title && (
                            <p className="text-[10px] text-slate-400 mt-1 ml-1">
                                <i className="fas fa-info-circle mr-1"></i>
                                Will default to first step title: "{activePage.steps[0].title}"
                            </p>
                        )}
                    </div>

                    {/* Steps List */}
                    <div className="space-y-6">
                        {activePage.steps.length === 0 && (
                            <div className="text-center py-10 text-slate-400">
                            <i className="fas fa-layer-group text-4xl mb-3 opacity-20"></i>
                            <p className="text-sm">This page is empty.</p>
                            <p className="text-xs">Add a step below to get started.</p>
                            </div>
                        )}
                        {activePage.steps.map((step, idx) => (
                            <StepEditor
                            key={step.id}
                            index={idx}
                            step={step}
                            totalSteps={activePage.steps.length}
                            onUpdate={updateStep}
                            onDelete={deleteStep}
                            onMoveUp={() => moveStep(idx, 'up')}
                            onMoveDown={() => moveStep(idx, 'down')}
                            />
                        ))}
                    </div>
                </>
            )}

            {/* Bottom Spacer for Floating Button */}
            <div className="h-24"></div>
          </div>

          {/* Floating Action Button for Adding Steps */}
          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[480px] lg:w-[560px] px-6 pointer-events-none">
                <button 
                onClick={addStepToActivePage}
                className="pointer-events-auto w-full py-4 bg-white/90 backdrop-blur border-2 border-dashed border-primary-500/30 text-primary-600 font-bold rounded-xl hover:bg-primary-50 hover:border-primary-500 transition-all shadow-lg flex items-center justify-center gap-2 group"
                >
                <div className="w-6 h-6 rounded-full bg-primary-100 flex items-center justify-center group-hover:bg-primary-600 group-hover:text-white transition-colors">
                    <i className="fas fa-plus text-xs"></i>
                </div>
                Add Step to Page {activePageIndex + 1}
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`
          flex-col flex-grow bg-slate-100 relative
          ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Mobile Tab Switcher */}
          <div className="md:hidden flex border-b border-slate-200 bg-white shrink-0">
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('editor')}
            >
              <i className="fas fa-edit mr-2"></i> Editor
            </button>
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('preview')}
            >
              <i className="fas fa-eye mr-2"></i> Preview
            </button>
          </div>

          <Preview 
            pages={pages} 
            metadata={metadata} 
            dimensions={pageDimensions}
            previewRef={previewRef}
            onPageOverflow={handlePageOverflow}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import CoverEditor from './components/CoverEditor';
import BackCoverEditor from './components/BackCoverEditor';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage, SavedProject, StepImage } from './types';
import { generatePageTitle } from './services/geminiService';

interface HistoryState {
  pages: ManualPage[];
  metadata: ManualMetadata;
}

const DEFAULT_METADATA: ManualMetadata = {
  title: 'Product Manual',
  subtitle: 'Setup & Configuration Guide',
  author: 'My Company Inc.',
  version: '1.0',
  showStepMarkers: true
};

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });

  // New: Track Project ID for history
  const [projectId, setProjectId] = useState<string>(uuidv4());

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(true);

  // Saving State
  const [isSaving, setIsSaving] = useState(false);
  const [lastSavedTime, setLastSavedTime] = useState<Date | null>(null);

  const previewRef = useRef<HTMLDivElement>(null);

  // --- State: Pages & Content ---
  const [metadata, setMetadata] = useState<ManualMetadata>(DEFAULT_METADATA);

  const [pages, setPages] = useState<ManualPage[]>([
    {
      id: uuidv4(),
      type: 'cover',
      title: 'Cover Page',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'toc',
      title: 'Table of Contents',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'content',
      title: 'Getting Started',
      steps: [
        {
          id: uuidv4(),
          title: 'Unboxing',
          description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.',
          images: [],
          layout: 'image_left_text_right'
        }
      ]
    }
  ]);

  // --- Undo/Redo History State ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [activePageIndex, setActivePageIndex] = useState(0); 

  // --- Utility: Convert Image to Base64 ---
  const convertUrlToBase64 = async (url: string): Promise<string> => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn("Failed to convert image for saving:", url);
      return url; // Fallback
    }
  };

  // --- Save Logic ---
  const saveProjectToHistory = useCallback(async (isManual: boolean = false) => {
    if (!hasStarted) return;
    setIsSaving(true);

    try {
      // 1. Deep clone pages to modify images for storage
      const pagesToSave = JSON.parse(JSON.stringify(pages)) as ManualPage[];

      // 2. Iterate and convert any Blob URLs to Base64 if possible
      for (const page of pagesToSave) {
         if (page.backgroundImage && page.backgroundImage.url.startsWith('blob:')) {
             page.backgroundImage.url = await convertUrlToBase64(page.backgroundImage.url);
             delete page.backgroundImage.file; 
         }
         for (const step of page.steps) {
             for (const img of step.images) {
                 if (img.url.startsWith('blob:')) {
                     img.url = await convertUrlToBase64(img.url);
                     delete img.file; 
                 }
             }
         }
      }

      const projectData: SavedProject = {
        id: projectId,
        lastModified: Date.now(),
        metadata,
        pages: pagesToSave,
        dimensions: pageDimensions
      };

      const storedProjects = localStorage.getItem('manual_master_projects');
      const projects = storedProjects ? JSON.parse(storedProjects) : {};
      projects[projectId] = projectData;

      localStorage.setItem('manual_master_projects', JSON.stringify(projects));
      setLastSavedTime(new Date());

      if (isManual) {
          console.log("Save successful");
      }
    } catch (error) {
       console.error("Failed to save project:", error);
       // Alert if manual save fails, so user knows data isn't safe
       if (isManual) alert("Warning: Failed to save project. Your local storage might be full.");
    } finally {
        setTimeout(() => setIsSaving(false), 500);
    }
  }, [pages, metadata, pageDimensions, projectId, hasStarted]);

  // --- Auto-Save on Change (Debounced) ---
  useEffect(() => {
    if (!hasStarted) return;

    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);

    // Debounce save (2 seconds) for frequent updates
    saveTimeoutRef.current = setTimeout(() => {
        saveProjectToHistory();
    }, 2000);

    return () => {
        if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    };
  }, [pages, metadata, pageDimensions, hasStarted, saveProjectToHistory]);

  // --- Auto-Save Interval (Every 60 Seconds) ---
  useEffect(() => {
    if (!hasStarted) return;

    const intervalId = setInterval(() => {
        saveProjectToHistory(false);
    }, 60000); // 60000ms = 60s

    return () => clearInterval(intervalId);
  }, [hasStarted, saveProjectToHistory]);

  // --- Keyboard Shortcut (Ctrl+S) ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            saveProjectToHistory(true);
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [saveProjectToHistory]);

  // --- Effects ---

  // Auto-scroll to active page in preview when it changes
  useEffect(() => {
    if (hasStarted) {
      // Use a small timeout to allow render to complete (especially for new pages)
      const timer = setTimeout(() => {
        const pageElement = document.getElementById(`preview-page-${activePageIndex}`);
        if (pageElement) {
          pageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activePageIndex, hasStarted]);

  // --- Undo/Redo Logic ---

  const saveSnapshot = useCallback(() => {
    setPast(prev => {
      const newPast = [...prev, { pages, metadata }];
      if (newPast.length > 20) {
        return newPast.slice(newPast.length - 20);
      }
      return newPast;
    });
    setFuture([]);
  }, [pages, metadata]);

  const undo = () => {
    if (past.length === 0) return;

    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);

    setFuture(prev => [{ pages, metadata }, ...prev]);
    setPages(previous.pages);
    setMetadata(previous.metadata);
    setPast(newPast);
  };

  const redo = () => {
    if (future.length === 0) return;

    const next = future[0];
    const newFuture = future.slice(1);

    setPast(prev => [...prev, { pages, metadata }]);
    setPages(next.pages);
    setMetadata(next.metadata);
    setFuture(newFuture);
  };

  // Helper to handle debounce for text inputs history
  const handleTextTypingHistory = () => {
    if (!typingTimeoutRef.current) {
      saveSnapshot();
    }
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }
    typingTimeoutRef.current = setTimeout(() => {
      typingTimeoutRef.current = null;
    }, 1000);
  };

  const handleStructuralChangeHistory = () => {
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = null;
    }
    saveSnapshot();
  };

  // --- Handlers ---

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setProjectId(uuidv4());

    // Reset state for new project
    setMetadata(DEFAULT_METADATA);
    setPages([
      { id: uuidv4(), type: 'cover', title: 'Cover Page', steps: [] },
      { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] },
      { id: uuidv4(), type: 'content', title: 'Getting Started', steps: [{ id: uuidv4(), title: 'Unboxing', description: 'Carefully remove the device from the packaging.', images: [], layout: 'image_left_text_right' }] }
    ]);
    setPast([]);
    setFuture([]);
    setActivePageIndex(0);

    setHasStarted(true);
  };

  const handleLoadProject = (project: SavedProject) => {
      setProjectId(project.id);
      setMetadata(project.metadata);
      setPages(project.pages);
      setPageDimensions(project.dimensions);
      setPast([]);
      setFuture([]);
      setActivePageIndex(0);
      setHasStarted(true);
  };

  // Safety check: Ensure activePage exists. Fallback to first page or a dummy object if empty (shouldn't happen).
  const activePage = pages[activePageIndex] || pages[0] || { id: 'dummy', type: 'content', steps: [] };

  // Add a new empty content page
  const addNewPage = () => {
    handleStructuralChangeHistory();
    // Insert before back cover if it exists
    const lastPage = pages[pages.length - 1];
    const hasBackCover = lastPage.type === 'back_cover';

    const newPage: ManualPage = { id: uuidv4(), type: 'content', title: '', steps: [] };
    const insertIndex = hasBackCover ? pages.length - 1 : pages.length;

    const newPages = [...pages];
    newPages.splice(insertIndex, 0, newPage);
    setPages(newPages);
    setActivePageIndex(insertIndex); 
  };

  const addTocPage = () => {
     if (pages.some(p => p.type === 'toc')) {
       alert("A Table of Contents page already exists.");
       return;
     }
     handleStructuralChangeHistory();
     // Insert after cover
     const insertIndex = pages[0].type === 'cover' ? 1 : 0;
     const newPages = [...pages];
     newPages.splice(insertIndex, 0, { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] });
     setPages(newPages);
     setActivePageIndex(insertIndex);
  };

  const addBackCover = () => {
    if (pages.some(p => p.type === 'back_cover')) {
      alert("Back Cover already exists.");
      return;
    }
    handleStructuralChangeHistory();
    setPages([...pages, { id: uuidv4(), type: 'back_cover', title: 'Back Cover', steps: [] }]);
    setActivePageIndex(pages.length);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) {
      setActivePageIndex(index);
    }
  };

  // Update Page Title (used for TOC)
  const updatePageTitle = (title: string) => {
    handleTextTypingHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) {
      alert("Add some steps to the page first so AI can generate a title.");
      return;
    }

    // Treat as structural change to ensure snapshot before async update
    handleStructuralChangeHistory();
    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      // We manually update state here, reusing logic but without re-triggering history logic if possible, 
      // but simpler to just call setPages directly.
      setPages(currentPages => {
          const newPages = [...currentPages];
          if (newPages[activePageIndex]) {
            newPages[activePageIndex] = { ...newPages[activePageIndex], title: suggestedTitle };
          }
          return newPages;
      });
    } catch (error) {
      alert("Failed to generate title. Check API key or connection.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  // Wrapper for metadata updates
  const updateMetadata = (updates: Partial<ManualMetadata>) => {
    const isText = 'title' in updates || 'subtitle' in updates || 'author' in updates || 'version' in updates;
    if (isText) {
      handleTextTypingHistory();
    } else {
      handleStructuralChangeHistory();
    }
    setMetadata(prev => ({ ...prev, ...updates }));
  };

  // Generic page update
  const updatePage = (updates: Partial<ManualPage>) => {
    handleStructuralChangeHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], ...updates };
    setPages(newPages);
  };

  // Step Management (Scoped to Active Page)
  const addStepToActivePage = () => {
    if (activePage.type !== 'content') return;

    handleStructuralChangeHistory();

    const newStep: ManualStep = {
      id: uuidv4(),
      title: '',
      description: '',
      images: [],
      layout: 'image_left_text_right'
    };

    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);

    setTimeout(() => {
      const el = document.getElementById('steps-container');
      if (el) el.scrollTop = el.scrollHeight;
    }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const isTextUpdate = 'title' in updates || 'description' in updates;

    if (isTextUpdate) {
        handleTextTypingHistory();
    } else {
        handleStructuralChangeHistory();
    }

    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step)
    }));
    setPages(newPages);
  };

  const deleteStep = (stepId: string) => {
    handleStructuralChangeHistory();
    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.filter(step => step.id !== stepId)
    }));
    setPages(newPages);
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type !== 'content') return;

    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;

    handleStructuralChangeHistory();

    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];

    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  const deleteCurrentPage = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (pages.length <= 1) {
        alert("Cannot delete the last page.");
        return;
    }

    if (window.confirm("Are you sure you want to delete this page?")) {
        handleStructuralChangeHistory();

        // Use filter to create a new array excluding the current page
        // This is more robust than splice with functional updates in this context
        const newPages = pages.filter((_, index) => index !== activePageIndex);
        setPages(newPages);

        // Adjust active index if necessary (e.g., if we deleted the last page)
        if (activePageIndex >= newPages.length) {
            setActivePageIndex(Math.max(0, newPages.length - 1));
        }
    }
  };

  // --- Automatic Overflow Handling ---
  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      // Guard against stale indices (e.g., page was deleted while timer was running)
      if (pageIndex < 0 || pageIndex >= prevPages.length) {
        return prevPages;
      }

      const currentPage = prevPages[pageIndex];
      // Guard against undefined page
      if (!currentPage) return prevPages;

      // Do not handle overflow for TOC, Cover, BackCover
      if (currentPage.type !== 'content') return prevPages;

      // Safety check: Don't move if there's only 1 step
      if (currentPage.steps.length <= 1) return prevPages;

      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);

      // Check if next page exists
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];

      // Update current page
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };

      if (nextPage && nextPage.type === 'content') {
        // Add to beginning of next page if it is a content page
        newPages[nextPageIndex] = {
          ...nextPage,
          steps: [lastStep, ...nextPage.steps]
        };
      } else {
        // Create new content page
        const newPage: ManualPage = {
            id: uuidv4(),
            type: 'content',
            title: 'Continued...',
            steps: [lastStep]
        };

        // Insert at nextPageIndex
        newPages.splice(nextPageIndex, 0, newPage);
      }

      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });

      // Iterate through all rendered pages in the Preview
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;

        if (i > 0) pdf.addPage();

        // Temporarily remove shadow for clean capture
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';

        const canvas = await html2canvas(pageElement, {
          scale: 2, 
          useCORS: true, 
          logging: false,
          backgroundColor: '#ffffff',
          windowWidth: 1200 
        });

        // Restore styles
        pageElement.style.boxShadow = originalShadow;

        const imgData = canvas.toDataURL('image/png');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} onLoadProject={handleLoadProject} />;
  }

  const renderPageIcon = (type: ManualPage['type']) => {
      switch(type) {
          case 'cover': return <i className="fas fa-book-cover text-[10px]"></i>;
          case 'toc': return <i className="fas fa-list-ol text-[10px]"></i>;
          case 'back_cover': return <i className="fas fa-book-open fa-flip-horizontal text-[10px]"></i>;
          default: return null;
      }
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 h-16 flex items-center justify-between shadow-sm shrink-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-primary-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary-500/30">
            <i className="fas fa-book-open text-lg"></i>
          </div>
          <div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight leading-none">ManualMaster</h1>
            <p className="text-xs text-slate-500 font-medium">AI-Powered Documentation</p>
          </div>
        </div>
        <div className="flex items-center gap-4">

           {/* Save Controls */}
           <div className="flex items-center gap-3 mr-2">
                <div className="text-right hidden lg:block">
                     <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                         {isSaving ? 'Saving...' : 'Auto-Save On'}
                     </div>
                     {lastSavedTime && !isSaving && (
                         <div className="text-[10px] text-slate-300">
                             Saved {lastSavedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                         </div>
                     )}
                </div>
                <button 
                    onClick={() => saveProjectToHistory(true)}
                    className={`
                        w-10 h-10 flex items-center justify-center rounded-xl transition-all
                        ${isSaving 
                            ? 'bg-primary-50 text-primary-600' 
                            : 'bg-white border border-slate-200 text-slate-500 hover:text-primary-600 hover:border-primary-200 hover:shadow-md'
                        }
                    `}
                    title="Manual Save (Ctrl+S)"
                >
                    {isSaving ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-save text-lg"></i>}
                </button>
           </div>

           <div className="w-px h-8 bg-slate-200 mx-2 hidden md:block"></div>

           {/* Undo/Redo Controls */}
           <div className="flex items-center gap-1 border-r border-slate-200 pr-4">
              <button 
                onClick={undo} 
                disabled={past.length === 0} 
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent text-slate-600 transition-colors" 
                title="Undo (Ctrl+Z)"
              >
                  <i className="fas fa-undo text-sm"></i>
              </button>
              <button 
                onClick={redo} 
                disabled={future.length === 0} 
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent text-slate-600 transition-colors" 
                title="Redo (Ctrl+Y)"
              >
                  <i className="fas fa-redo text-sm"></i>
              </button>
           </div>

           <div className="hidden lg:block text-slate-400 text-xs font-semibold uppercase tracking-wider">
             {pageDimensions.name}
           </div>

          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-full text-sm font-semibold flex items-center gap-2 transition-all
              ${isGenerating 
                ? 'bg-slate-100 text-slate-400 cursor-wait' 
                : 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-lg active:transform active:scale-95'
              }
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span>{isGenerating ? 'Exporting...' : 'Download PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[480px] lg:w-[560px] border-r border-slate-200 bg-white shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Page Navigator */}
          <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center">
             {/* Add TOC Button if not present */}
             {!pages.some(p => p.type === 'toc') && (
               <button 
                onClick={addTocPage}
                className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-600 border border-slate-200 hover:bg-slate-200 transition-colors mr-2"
                title="Insert Table of Contents"
              >
                <i className="fas fa-list-ol mr-1"></i> TOC
              </button>
            )}

            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all border flex items-center gap-2
                  ${activePageIndex === idx 
                    ? 'bg-slate-800 text-white border-slate-800 shadow-md' 
                    : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
                  }
                `}
              >
                {renderPageIcon(page.type)}
                {page.type === 'content' ? `Page ${idx + 1}` : (page.type === 'cover' ? 'Front' : (page.type === 'back_cover' ? 'Back' : 'TOC'))}
              </button>
            ))}
            <button 
              onClick={addNewPage}
              className="px-3 py-1.5 rounded-lg text-xs font-bold bg-primary-50 text-primary-600 border border-primary-200 hover:bg-primary-100 transition-colors"
              title="Add New Content Page"
            >
              <i className="fas fa-plus"></i>
            </button>

            {!pages.some(p => p.type === 'back_cover') && (
                <button 
                    onClick={addBackCover}
                    className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-500 border border-slate-200 hover:bg-slate-200 transition-colors"
                    title="Add Back Cover"
                >
                    <i className="fas fa-book-open fa-flip-horizontal"></i>
                </button>
            )}
          </div>

          {/* Editor Header */}
          <div className="px-6 py-4 border-b border-slate-100 bg-white flex justify-between items-center">
             <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-lg font-bold text-slate-800">
                        {activePage.type === 'cover' ? 'Front Cover' : 
                         activePage.type === 'back_cover' ? 'Back Cover' :
                         activePage.type === 'toc' ? 'Directory' : `Page ${activePageIndex + 1}`}
                    </h2>
                    {activePage.type === 'toc' && <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded">Auto-generated</span>}
                </div>
                {activePage.type === 'content' && (
                    <span className="text-xs text-slate-400 font-medium">{activePage.steps.length} Steps</span>
                )}
             </div>

             {/* Delete Page Button REMOVED as requested previously, keeping removal intact */}
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto p-6 scroll-smooth">

            {/* Metadata Accordion - Global Settings */}
            <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden mb-8 transition-all">
              <button 
                onClick={() => setIsMetadataExpanded(!isMetadataExpanded)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
              >
                <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                  <i className="fas fa-cog text-slate-400"></i>
                  Global Document Settings
                </div>
                <i className={`fas fa-chevron-down text-slate-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>

              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                   <div className="col-span-2 h-px bg-slate-200 mb-2"></div>
                   <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Title</label>
                    <input 
                      type="text" 
                      value={metadata.title}
                      onChange={(e) => updateMetadata({ title: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. User Manual"
                    />
                  </div>
                  <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Subtitle</label>
                    <input 
                      type="text" 
                      value={metadata.subtitle}
                      onChange={(e) => updateMetadata({ subtitle: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. Quick Start Guide"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Author</label>
                    <input 
                      type="text" 
                      value={metadata.author}
                      onChange={(e) => updateMetadata({ author: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Version</label>
                    <input 
                      type="text" 
                      value={metadata.version}
                      onChange={(e) => updateMetadata({ version: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>

                  {/* Step Markers Toggle */}
                  <div className="col-span-2 mt-2 pt-2 border-t border-slate-100 flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Show Step Markers</label>
                    <button 
                        onClick={() => updateMetadata({ showStepMarkers: !metadata.showStepMarkers })}
                        className={`w-12 h-6 rounded-full p-1 transition-colors duration-200 ease-in-out ${metadata.showStepMarkers ? 'bg-primary-600' : 'bg-slate-300'}`}
                        title="Toggle bullet points on steps"
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transform transition-transform duration-200 ease-in-out ${metadata.showStepMarkers ? 'translate-x-6' : 'translate-x-0'}`}></div>
                    </button>
                  </div>
                </div>
              )}
            </div>

            {/* Conditional Editors based on Page Type */}
            {activePage.type === 'cover' && (
                <CoverEditor page={activePage} onUpdate={updatePage} metadata={metadata} />
            )}

            {activePage.type === 'back_cover' && (
                <BackCoverEditor page={activePage} onUpdate={updatePage} />
            )}

            {activePage.type === 'toc' && (
                <div className="bg-white border border-slate-200 rounded-xl p-8 text-center">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <i className="fas fa-list-ol text-2xl text-slate-300"></i>
                    </div>
                    <h3 className="font-bold text-slate-700 mb-2">Automatic Directory</h3>
                    <p className="text-sm text-slate-500 max-w-xs mx-auto">
                        This page automatically lists all subsequent pages and their titles.
                    </p>
                    <div className="mt-4">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">TOC Title</label>
                        <input 
                            type="text" 
                            value={activePage.title || ''}
                            onChange={(e) => updatePageTitle(e.target.value)}
                            className="w-full p-2 bg-slate-50 border border-slate-200 rounded text-center text-sm font-semibold"
                        />
                    </div>
                </div>
            )}

            {activePage.type === 'content' && (
                <>
                    {/* Page Title Editor */}
                    <div className="mb-6">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 flex justify-between items-end">
                            <span>Page Title (For Directory & Header)</span>
                            <button 
                                onClick={handleAutoGeneratePageTitle}
                                disabled={isGeneratingTitle || activePage.steps.length === 0}
                                className="text-[10px] text-primary-600 hover:text-primary-700 bg-primary-50 hover:bg-primary-100 px-2 py-1 rounded transition-colors disabled:opacity-50"
                            >
                                {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Generate
                            </button>
                        </label>
                        <div className="relative">
                            <input 
                                type="text" 
                                value={activePage.title || ''}
                                onChange={(e) => updatePageTitle(e.target.value)}
                                className="w-full p-3 bg-white border border-slate-300 rounded-lg text-base font-semibold text-slate-800 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                                placeholder="e.g. Safety Instructions"
                            />
                            <i className="fas fa-heading absolute right-3 top-3.5 text-slate-300"></i>
                        </div>
                        {!activePage.title && activePage.steps.length > 0 && activePage.steps[0].title && (
                            <p className="text-[10px] text-slate-400 mt-1 ml-1">
                                <i className="fas fa-info-circle mr-1"></i>
                                Will default to first step title: "{activePage.steps[0].title}"
                            </p>
                        )}
                    </div>

                    {/* Steps List */}
                    <div className="space-y-6">
                        {activePage.steps.length === 0 && (
                            <div className="text-center py-10 text-slate-400">
                            <i className="fas fa-layer-group text-4xl mb-3 opacity-20"></i>
                            <p className="text-sm">This page is empty.</p>
                            <p className="text-xs">Add a step below to get started.</p>
                            </div>
                        )}
                        {activePage.steps.map((step, idx) => (
                            <StepEditor
                            key={step.id}
                            index={idx}
                            step={step}
                            totalSteps={activePage.steps.length}
                            onUpdate={updateStep}
                            onDelete={deleteStep}
                            onMoveUp={() => moveStep(idx, 'up')}
                            onMoveDown={() => moveStep(idx, 'down')}
                            />
                        ))}
                    </div>
                </>
            )}

            {/* Bottom Spacer for Floating Button */}
            <div className="h-24"></div>
          </div>

          {/* Floating Action Button for Adding Steps */}
          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[480px] lg:w-[560px] px-6 pointer-events-none">
                <button 
                onClick={addStepToActivePage}
                className="pointer-events-auto w-full py-4 bg-white/90 backdrop-blur border-2 border-dashed border-primary-500/30 text-primary-600 font-bold rounded-xl hover:bg-primary-50 hover:border-primary-500 transition-all shadow-lg flex items-center justify-center gap-2 group"
                >
                <div className="w-6 h-6 rounded-full bg-primary-100 flex items-center justify-center group-hover:bg-primary-600 group-hover:text-white transition-colors">
                    <i className="fas fa-plus text-xs"></i>
                </div>
                Add Step to Page {activePageIndex + 1}
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`
          flex-col flex-grow bg-slate-100 relative
          ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Mobile Tab Switcher */}
          <div className="md:hidden flex border-b border-slate-200 bg-white shrink-0">
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('editor')}
            >
              <i className="fas fa-edit mr-2"></i> Editor
            </button>
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('preview')}
            >
              <i className="fas fa-eye mr-2"></i> Preview
            </button>
          </div>

          <Preview 
            pages={pages} 
            metadata={metadata} 
            dimensions={pageDimensions}
            previewRef={previewRef}
            onPageOverflow={handlePageOverflow}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import CoverEditor from './components/CoverEditor';
import BackCoverEditor from './components/BackCoverEditor';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage, SavedProject, StepImage } from './types';
import { generatePageTitle } from './services/geminiService';

interface HistoryState {
  pages: ManualPage[];
  metadata: ManualMetadata;
}

const DEFAULT_METADATA: ManualMetadata = {
  title: 'Product Manual',
  subtitle: 'Setup & Configuration Guide',
  author: 'My Company Inc.',
  version: '1.0',
  showStepMarkers: true
};

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });

  // New: Track Project ID for history
  const [projectId, setProjectId] = useState<string>(uuidv4());

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(true);

  // Saving State
  const [isSaving, setIsSaving] = useState(false);
  const [lastSavedTime, setLastSavedTime] = useState<Date | null>(null);

  const previewRef = useRef<HTMLDivElement>(null);

  // --- State: Pages & Content ---
  const [metadata, setMetadata] = useState<ManualMetadata>(DEFAULT_METADATA);

  const [pages, setPages] = useState<ManualPage[]>([
    {
      id: uuidv4(),
      type: 'cover',
      title: 'Cover Page',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'toc',
      title: 'Table of Contents',
      steps: []
    },
    {
      id: uuidv4(),
      type: 'content',
      title: 'Getting Started',
      steps: [
        {
          id: uuidv4(),
          title: 'Unboxing',
          description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.',
          images: [],
          layout: 'image_left_text_right'
        }
      ]
    }
  ]);

  // --- Undo/Redo History State ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [activePageIndex, setActivePageIndex] = useState(0); 

  // --- Utility: Convert Image to Base64 ---
  const convertUrlToBase64 = async (url: string): Promise<string> => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn("Failed to convert image for saving:", url);
      return url; // Fallback
    }
  };

  // --- Save Logic ---
  const saveProjectToHistory = useCallback(async (isManual: boolean = false) => {
    if (!hasStarted) return;
    setIsSaving(true);

    try {
      // 1. Deep clone pages to modify images for storage
      const pagesToSave = JSON.parse(JSON.stringify(pages)) as ManualPage[];

      // 2. Iterate and convert any Blob URLs to Base64 if possible
      for (const page of pagesToSave) {
         if (page.backgroundImage && page.backgroundImage.url.startsWith('blob:')) {
             page.backgroundImage.url = await convertUrlToBase64(page.backgroundImage.url);
             delete page.backgroundImage.file; 
         }
         for (const step of page.steps) {
             for (const img of step.images) {
                 if (img.url.startsWith('blob:')) {
                     img.url = await convertUrlToBase64(img.url);
                     delete img.file; 
                 }
             }
         }
      }

      const projectData: SavedProject = {
        id: projectId,
        lastModified: Date.now(),
        metadata,
        pages: pagesToSave,
        dimensions: pageDimensions
      };

      const storedProjects = localStorage.getItem('manual_master_projects');
      const projects = storedProjects ? JSON.parse(storedProjects) : {};
      projects[projectId] = projectData;

      localStorage.setItem('manual_master_projects', JSON.stringify(projects));
      setLastSavedTime(new Date());

      if (isManual) {
          console.log("Save successful");
      }
    } catch (error) {
       console.error("Failed to save project:", error);
       // Alert if manual save fails, so user knows data isn't safe
       if (isManual) alert("Warning: Failed to save project. Your local storage might be full.");
    } finally {
        setTimeout(() => setIsSaving(false), 500);
    }
  }, [pages, metadata, pageDimensions, projectId, hasStarted]);

  // --- Auto-Save on Change (Debounced) ---
  useEffect(() => {
    if (!hasStarted) return;

    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);

    // Debounce save (2 seconds) for frequent updates
    saveTimeoutRef.current = setTimeout(() => {
        saveProjectToHistory();
    }, 2000);

    return () => {
        if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    };
  }, [pages, metadata, pageDimensions, hasStarted, saveProjectToHistory]);

  // --- Auto-Save Interval (Every 60 Seconds) ---
  useEffect(() => {
    if (!hasStarted) return;

    const intervalId = setInterval(() => {
        saveProjectToHistory(false);
    }, 60000); // 60000ms = 60s

    return () => clearInterval(intervalId);
  }, [hasStarted, saveProjectToHistory]);

  // --- Keyboard Shortcut (Ctrl+S) ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            saveProjectToHistory(true);
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [saveProjectToHistory]);

  // --- Effects ---

  // Auto-scroll to active page in preview when it changes
  useEffect(() => {
    if (hasStarted) {
      // Use a small timeout to allow render to complete (especially for new pages)
      const timer = setTimeout(() => {
        const pageElement = document.getElementById(`preview-page-${activePageIndex}`);
        if (pageElement) {
          pageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activePageIndex, hasStarted]);

  // --- Undo/Redo Logic ---

  const saveSnapshot = useCallback(() => {
    setPast(prev => {
      const newPast = [...prev, { pages, metadata }];
      if (newPast.length > 20) {
        return newPast.slice(newPast.length - 20);
      }
      return newPast;
    });
    setFuture([]);
  }, [pages, metadata]);

  const undo = () => {
    if (past.length === 0) return;

    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);

    setFuture(prev => [{ pages, metadata }, ...prev]);
    setPages(previous.pages);
    setMetadata(previous.metadata);
    setPast(newPast);
  };

  const redo = () => {
    if (future.length === 0) return;

    const next = future[0];
    const newFuture = future.slice(1);

    setPast(prev => [...prev, { pages, metadata }]);
    setPages(next.pages);
    setMetadata(next.metadata);
    setFuture(newFuture);
  };

  // Helper to handle debounce for text inputs history
  const handleTextTypingHistory = () => {
    if (!typingTimeoutRef.current) {
      saveSnapshot();
    }
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }
    typingTimeoutRef.current = setTimeout(() => {
      typingTimeoutRef.current = null;
    }, 1000);
  };

  const handleStructuralChangeHistory = () => {
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = null;
    }
    saveSnapshot();
  };

  // --- Handlers ---

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setProjectId(uuidv4());

    // Reset state for new project
    setMetadata(DEFAULT_METADATA);
    setPages([
      { id: uuidv4(), type: 'cover', title: 'Cover Page', steps: [] },
      { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] },
      { id: uuidv4(), type: 'content', title: 'Getting Started', steps: [{ id: uuidv4(), title: 'Unboxing', description: 'Carefully remove the device from the packaging.', images: [], layout: 'image_left_text_right' }] }
    ]);
    setPast([]);
    setFuture([]);
    setActivePageIndex(0);

    setHasStarted(true);
  };

  const handleLoadProject = (project: SavedProject) => {
      setProjectId(project.id);
      setMetadata(project.metadata);
      setPages(project.pages);
      setPageDimensions(project.dimensions);
      setPast([]);
      setFuture([]);
      setActivePageIndex(0);
      setHasStarted(true);
  };

  const handleGoHome = async () => {
      if (window.confirm("Return to Start Screen? Your work will be saved automatically.")) {
          await saveProjectToHistory(true);
          setHasStarted(false);
      }
  };

  // Safety check: Ensure activePage exists. Fallback to first page or a dummy object if empty (shouldn't happen).
  const activePage = pages[activePageIndex] || pages[0] || { id: 'dummy', type: 'content', steps: [] };

  // Add a new empty content page
  const addNewPage = () => {
    handleStructuralChangeHistory();
    // Insert before back cover if it exists
    const lastPage = pages[pages.length - 1];
    const hasBackCover = lastPage.type === 'back_cover';

    const newPage: ManualPage = { id: uuidv4(), type: 'content', title: '', steps: [] };
    const insertIndex = hasBackCover ? pages.length - 1 : pages.length;

    const newPages = [...pages];
    newPages.splice(insertIndex, 0, newPage);
    setPages(newPages);
    setActivePageIndex(insertIndex); 
  };

  const addTocPage = () => {
     if (pages.some(p => p.type === 'toc')) {
       alert("A Table of Contents page already exists.");
       return;
     }
     handleStructuralChangeHistory();
     // Insert after cover
     const insertIndex = pages[0].type === 'cover' ? 1 : 0;
     const newPages = [...pages];
     newPages.splice(insertIndex, 0, { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] });
     setPages(newPages);
     setActivePageIndex(insertIndex);
  };

  const addBackCover = () => {
    if (pages.some(p => p.type === 'back_cover')) {
      alert("Back Cover already exists.");
      return;
    }
    handleStructuralChangeHistory();
    setPages([...pages, { id: uuidv4(), type: 'back_cover', title: 'Back Cover', steps: [] }]);
    setActivePageIndex(pages.length);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) {
      setActivePageIndex(index);
    }
  };

  // Update Page Title (used for TOC)
  const updatePageTitle = (title: string) => {
    handleTextTypingHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) {
      alert("Add some steps to the page first so AI can generate a title.");
      return;
    }

    // Treat as structural change to ensure snapshot before async update
    handleStructuralChangeHistory();
    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      // We manually update state here, reusing logic but without re-triggering history logic if possible, 
      // but simpler to just call setPages directly.
      setPages(currentPages => {
          const newPages = [...currentPages];
          if (newPages[activePageIndex]) {
            newPages[activePageIndex] = { ...newPages[activePageIndex], title: suggestedTitle };
          }
          return newPages;
      });
    } catch (error) {
      alert("Failed to generate title. Check API key or connection.");
    } finally {
      setIsGeneratingTitle(false);
    }
  };

  // Wrapper for metadata updates
  const updateMetadata = (updates: Partial<ManualMetadata>) => {
    const isText = 'title' in updates || 'subtitle' in updates || 'author' in updates || 'version' in updates;
    if (isText) {
      handleTextTypingHistory();
    } else {
      handleStructuralChangeHistory();
    }
    setMetadata(prev => ({ ...prev, ...updates }));
  };

  // Generic page update
  const updatePage = (updates: Partial<ManualPage>) => {
    handleStructuralChangeHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], ...updates };
    setPages(newPages);
  };

  // Step Management (Scoped to Active Page)
  const addStepToActivePage = () => {
    if (activePage.type !== 'content') return;

    handleStructuralChangeHistory();

    const newStep: ManualStep = {
      id: uuidv4(),
      title: '',
      description: '',
      images: [],
      layout: 'image_left_text_right'
    };

    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);

    setTimeout(() => {
      const el = document.getElementById('steps-container');
      if (el) el.scrollTop = el.scrollHeight;
    }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const isTextUpdate = 'title' in updates || 'description' in updates;

    if (isTextUpdate) {
        handleTextTypingHistory();
    } else {
        handleStructuralChangeHistory();
    }

    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step)
    }));
    setPages(newPages);
  };

  const deleteStep = (stepId: string) => {
    handleStructuralChangeHistory();
    const newPages = pages.map(page => ({
      ...page,
      steps: page.steps.filter(step => step.id !== stepId)
    }));
    setPages(newPages);
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type !== 'content') return;

    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;

    handleStructuralChangeHistory();

    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];

    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  const deleteCurrentPage = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (pages.length <= 1) {
        alert("Cannot delete the last page.");
        return;
    }

    if (window.confirm("Are you sure you want to delete this page?")) {
        handleStructuralChangeHistory();

        // Use filter to create a new array excluding the current page
        // This is more robust than splice with functional updates in this context
        const newPages = pages.filter((_, index) => index !== activePageIndex);
        setPages(newPages);

        // Adjust active index if necessary (e.g., if we deleted the last page)
        if (activePageIndex >= newPages.length) {
            setActivePageIndex(Math.max(0, newPages.length - 1));
        }
    }
  };

  // --- Automatic Overflow Handling ---
  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      // Guard against stale indices (e.g., page was deleted while timer was running)
      if (pageIndex < 0 || pageIndex >= prevPages.length) {
        return prevPages;
      }

      const currentPage = prevPages[pageIndex];
      // Guard against undefined page
      if (!currentPage) return prevPages;

      // Do not handle overflow for TOC, Cover, BackCover
      if (currentPage.type !== 'content') return prevPages;

      // Safety check: Don't move if there's only 1 step
      if (currentPage.steps.length <= 1) return prevPages;

      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);

      // Check if next page exists
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];

      // Update current page
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };

      if (nextPage && nextPage.type === 'content') {
        // Add to beginning of next page if it is a content page
        newPages[nextPageIndex] = {
          ...nextPage,
          steps: [lastStep, ...nextPage.steps]
        };
      } else {
        // Create new content page
        const newPage: ManualPage = {
            id: uuidv4(),
            type: 'content',
            title: 'Continued...',
            steps: [lastStep]
        };

        // Insert at nextPageIndex
        newPages.splice(nextPageIndex, 0, newPage);
      }

      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });

      // Iterate through all rendered pages in the Preview
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;

        if (i > 0) pdf.addPage();

        // Temporarily remove shadow for clean capture
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';

        const canvas = await html2canvas(pageElement, {
          scale: 2, 
          useCORS: true, 
          logging: false,
          backgroundColor: '#ffffff',
          windowWidth: 1200 
        });

        // Restore styles
        pageElement.style.boxShadow = originalShadow;

        const imgData = canvas.toDataURL('image/png');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) {
      console.error("PDF Generation failed", error);
      alert("Failed to generate PDF.");
    } finally {
      setIsGenerating(false);
    }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} onLoadProject={handleLoadProject} />;
  }

  const renderPageIcon = (type: ManualPage['type']) => {
      switch(type) {
          case 'cover': return <i className="fas fa-book-cover text-[10px]"></i>;
          case 'toc': return <i className="fas fa-list-ol text-[10px]"></i>;
          case 'back_cover': return <i className="fas fa-book-open fa-flip-horizontal text-[10px]"></i>;
          default: return null;
      }
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white border-b border-slate-200 px-6 h-16 flex items-center justify-between shadow-sm shrink-0 z-50">
        <div className="flex items-center gap-3">
            {/* HOME BUTTON */}
            <button 
                onClick={handleGoHome}
                className="w-10 h-10 flex items-center justify-center rounded-xl bg-slate-100 hover:bg-slate-200 text-slate-600 transition-colors mr-1"
                title="Back to Home"
            >
                <i className="fas fa-home text-lg"></i>
            </button>
            <div className="hidden md:block w-px h-8 bg-slate-200 mx-1"></div>

          <div className="w-10 h-10 bg-primary-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary-500/30">
            <i className="fas fa-book-open text-lg"></i>
          </div>
          <div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight leading-none">ManualMaster</h1>
            <p className="text-xs text-slate-500 font-medium">AI-Powered Documentation</p>
          </div>
        </div>
        <div className="flex items-center gap-4">

           {/* Save Controls */}
           <div className="flex items-center gap-3 mr-2">
                <div className="text-right hidden lg:block">
                     <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                         {isSaving ? 'Saving...' : 'Auto-Save On'}
                     </div>
                     {lastSavedTime && !isSaving && (
                         <div className="text-[10px] text-slate-300">
                             Saved {lastSavedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                         </div>
                     )}
                </div>
                <button 
                    onClick={() => saveProjectToHistory(true)}
                    className={`
                        w-10 h-10 flex items-center justify-center rounded-xl transition-all
                        ${isSaving 
                            ? 'bg-primary-50 text-primary-600' 
                            : 'bg-white border border-slate-200 text-slate-500 hover:text-primary-600 hover:border-primary-200 hover:shadow-md'
                        }
                    `}
                    title="Manual Save (Ctrl+S)"
                >
                    {isSaving ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-save text-lg"></i>}
                </button>
           </div>

           <div className="w-px h-8 bg-slate-200 mx-2 hidden md:block"></div>

           {/* Undo/Redo Controls */}
           <div className="flex items-center gap-1 border-r border-slate-200 pr-4">
              <button 
                onClick={undo} 
                disabled={past.length === 0} 
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent text-slate-600 transition-colors" 
                title="Undo (Ctrl+Z)"
              >
                  <i className="fas fa-undo text-sm"></i>
              </button>
              <button 
                onClick={redo} 
                disabled={future.length === 0} 
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:hover:bg-transparent text-slate-600 transition-colors" 
                title="Redo (Ctrl+Y)"
              >
                  <i className="fas fa-redo text-sm"></i>
              </button>
           </div>

           <div className="hidden lg:block text-slate-400 text-xs font-semibold uppercase tracking-wider">
             {pageDimensions.name}
           </div>

          <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-full text-sm font-semibold flex items-center gap-2 transition-all
              ${isGenerating 
                ? 'bg-slate-100 text-slate-400 cursor-wait' 
                : 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-lg active:transform active:scale-95'
              }
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span>{isGenerating ? 'Exporting...' : 'Download PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[480px] lg:w-[560px] border-r border-slate-200 bg-white shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Page Navigator */}
          <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center">
             {/* Add TOC Button if not present */}
             {!pages.some(p => p.type === 'toc') && (
               <button 
                onClick={addTocPage}
                className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-600 border border-slate-200 hover:bg-slate-200 transition-colors mr-2"
                title="Insert Table of Contents"
              >
                <i className="fas fa-list-ol mr-1"></i> TOC
              </button>
            )}

            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all border flex items-center gap-2
                  ${activePageIndex === idx 
                    ? 'bg-slate-800 text-white border-slate-800 shadow-md' 
                    : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
                  }
                `}
              >
                {renderPageIcon(page.type)}
                {page.type === 'content' ? `Page ${idx + 1}` : (page.type === 'cover' ? 'Front' : (page.type === 'back_cover' ? 'Back' : 'TOC'))}
              </button>
            ))}
            <button 
              onClick={addNewPage}
              className="px-3 py-1.5 rounded-lg text-xs font-bold bg-primary-50 text-primary-600 border border-primary-200 hover:bg-primary-100 transition-colors"
              title="Add New Content Page"
            >
              <i className="fas fa-plus"></i>
            </button>

            {!pages.some(p => p.type === 'back_cover') && (
                <button 
                    onClick={addBackCover}
                    className="px-3 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-500 border border-slate-200 hover:bg-slate-200 transition-colors"
                    title="Add Back Cover"
                >
                    <i className="fas fa-book-open fa-flip-horizontal"></i>
                </button>
            )}
          </div>

          {/* Editor Header */}
          <div className="px-6 py-4 border-b border-slate-100 bg-white flex justify-between items-center">
             <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-lg font-bold text-slate-800">
                        {activePage.type === 'cover' ? 'Front Cover' : 
                         activePage.type === 'back_cover' ? 'Back Cover' :
                         activePage.type === 'toc' ? 'Directory' : `Page ${activePageIndex + 1}`}
                    </h2>
                    {activePage.type === 'toc' && <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded">Auto-generated</span>}
                </div>
                {activePage.type === 'content' && (
                    <span className="text-xs text-slate-400 font-medium">{activePage.steps.length} Steps</span>
                )}
             </div>

             {/* Delete Page Button REMOVED as requested previously, keeping removal intact */}
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto p-6 scroll-smooth">

            {/* Metadata Accordion - Global Settings */}
            <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden mb-8 transition-all">
              <button 
                onClick={() => setIsMetadataExpanded(!isMetadataExpanded)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
              >
                <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                  <i className="fas fa-cog text-slate-400"></i>
                  Global Document Settings
                </div>
                <i className={`fas fa-chevron-down text-slate-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>

              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                   <div className="col-span-2 h-px bg-slate-200 mb-2"></div>
                   <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Title</label>
                    <input 
                      type="text" 
                      value={metadata.title}
                      onChange={(e) => updateMetadata({ title: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. User Manual"
                    />
                  </div>
                  <div className="col-span-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Subtitle</label>
                    <input 
                      type="text" 
                      value={metadata.subtitle}
                      onChange={(e) => updateMetadata({ subtitle: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                      placeholder="e.g. Quick Start Guide"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Author</label>
                    <input 
                      type="text" 
                      value={metadata.author}
                      onChange={(e) => updateMetadata({ author: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Version</label>
                    <input 
                      type="text" 
                      value={metadata.version}
                      onChange={(e) => updateMetadata({ version: e.target.value })}
                      className="w-full p-2.5 bg-white border border-slate-300 rounded-lg text-sm focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                    />
                  </div>

                  {/* Step Markers Toggle */}
                  <div className="col-span-2 mt-2 pt-2 border-t border-slate-100 flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Show Step Markers</label>
                    <button 
                        onClick={() => updateMetadata({ showStepMarkers: !metadata.showStepMarkers })}
                        className={`w-12 h-6 rounded-full p-1 transition-colors duration-200 ease-in-out ${metadata.showStepMarkers ? 'bg-primary-600' : 'bg-slate-300'}`}
                        title="Toggle bullet points on steps"
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transform transition-transform duration-200 ease-in-out ${metadata.showStepMarkers ? 'translate-x-6' : 'translate-x-0'}`}></div>
                    </button>
                  </div>
                </div>
              )}
            </div>

            {/* Conditional Editors based on Page Type */}
            {activePage.type === 'cover' && (
                <CoverEditor page={activePage} onUpdate={updatePage} metadata={metadata} />
            )}

            {activePage.type === 'back_cover' && (
                <BackCoverEditor page={activePage} onUpdate={updatePage} />
            )}

            {activePage.type === 'toc' && (
                <div className="bg-white border border-slate-200 rounded-xl p-8 text-center">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <i className="fas fa-list-ol text-2xl text-slate-300"></i>
                    </div>
                    <h3 className="font-bold text-slate-700 mb-2">Automatic Directory</h3>
                    <p className="text-sm text-slate-500 max-w-xs mx-auto">
                        This page automatically lists all subsequent pages and their titles.
                    </p>
                    <div className="mt-4">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">TOC Title</label>
                        <input 
                            type="text" 
                            value={activePage.title || ''}
                            onChange={(e) => updatePageTitle(e.target.value)}
                            className="w-full p-2 bg-slate-50 border border-slate-200 rounded text-center text-sm font-semibold"
                        />
                    </div>
                </div>
            )}

            {activePage.type === 'content' && (
                <>
                    {/* Page Title Editor */}
                    <div className="mb-6">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 flex justify-between items-end">
                            <span>Page Title (For Directory & Header)</span>
                            <button 
                                onClick={handleAutoGeneratePageTitle}
                                disabled={isGeneratingTitle || activePage.steps.length === 0}
                                className="text-[10px] text-primary-600 hover:text-primary-700 bg-primary-50 hover:bg-primary-100 px-2 py-1 rounded transition-colors disabled:opacity-50"
                            >
                                {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Generate
                            </button>
                        </label>
                        <div className="relative">
                            <input 
                                type="text" 
                                value={activePage.title || ''}
                                onChange={(e) => updatePageTitle(e.target.value)}
                                className="w-full p-3 bg-white border border-slate-300 rounded-lg text-base font-semibold text-slate-800 focus:border-primary-500 focus:ring-2 focus:ring-primary-100 focus:outline-none transition-all"
                                placeholder="e.g. Safety Instructions"
                            />
                            <i className="fas fa-heading absolute right-3 top-3.5 text-slate-300"></i>
                        </div>
                        {!activePage.title && activePage.steps.length > 0 && activePage.steps[0].title && (
                            <p className="text-[10px] text-slate-400 mt-1 ml-1">
                                <i className="fas fa-info-circle mr-1"></i>
                                Will default to first step title: "{activePage.steps[0].title}"
                            </p>
                        )}
                    </div>

                    {/* Steps List */}
                    <div className="space-y-6">
                        {activePage.steps.length === 0 && (
                            <div className="text-center py-10 text-slate-400">
                            <i className="fas fa-layer-group text-4xl mb-3 opacity-20"></i>
                            <p className="text-sm">This page is empty.</p>
                            <p className="text-xs">Add a step below to get started.</p>
                            </div>
                        )}
                        {activePage.steps.map((step, idx) => (
                            <StepEditor
                            key={step.id}
                            index={idx}
                            step={step}
                            totalSteps={activePage.steps.length}
                            onUpdate={updateStep}
                            onDelete={deleteStep}
                            onMoveUp={() => moveStep(idx, 'up')}
                            onMoveDown={() => moveStep(idx, 'down')}
                            />
                        ))}
                    </div>
                </>
            )}

            {/* Bottom Spacer for Floating Button */}
            <div className="h-24"></div>
          </div>

          {/* Floating Action Button for Adding Steps */}
          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[480px] lg:w-[560px] px-6 pointer-events-none">
                <button 
                onClick={addStepToActivePage}
                className="pointer-events-auto w-full py-4 bg-white/90 backdrop-blur border-2 border-dashed border-primary-500/30 text-primary-600 font-bold rounded-xl hover:bg-primary-50 hover:border-primary-500 transition-all shadow-lg flex items-center justify-center gap-2 group"
                >
                <div className="w-6 h-6 rounded-full bg-primary-100 flex items-center justify-center group-hover:bg-primary-600 group-hover:text-white transition-colors">
                    <i className="fas fa-plus text-xs"></i>
                </div>
                Add Step to Page {activePageIndex + 1}
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`
          flex-col flex-grow bg-slate-100 relative
          ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}
        `}>
          {/* Mobile Tab Switcher */}
          <div className="md:hidden flex border-b border-slate-200 bg-white shrink-0">
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('editor')}
            >
              <i className="fas fa-edit mr-2"></i> Editor
            </button>
            <button 
              className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500'}`}
              onClick={() => setActiveTab('preview')}
            >
              <i className="fas fa-eye mr-2"></i> Preview
            </button>
          </div>

          <Preview 
            pages={pages} 
            metadata={metadata} 
            dimensions={pageDimensions}
            previewRef={previewRef}
            onPageOverflow={handlePageOverflow}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { PageDimensions, SavedProject } from '../types';

interface StartScreenProps {
  onStart: (dimensions: PageDimensions) => void;
  onLoadProject: (project: SavedProject) => void;
}

const PRESETS: PageDimensions[] = [
  { name: 'A4', width: 210, height: 297 },
  { name: 'A5', width: 148, height: 210 },
  { name: 'Letter', width: 216, height: 279 },
];

const StartScreen: React.FC<StartScreenProps> = ({ onStart, onLoadProject }) => {
  const [selectedPreset, setSelectedPreset] = useState<string>('A4');
  const [customWidth, setCustomWidth] = useState<string>('210');
  const [customHeight, setCustomHeight] = useState<string>('297');
  const [isCustom, setIsCustom] = useState(false);
  const [recentProjects, setRecentProjects] = useState<SavedProject[]>([]);

  useEffect(() => {
    try {
      const saved = localStorage.getItem('manual_master_projects');
      if (saved) {
        const parsed = JSON.parse(saved);
        const sorted = Object.values(parsed).sort((a: any, b: any) => b.lastModified - a.lastModified) as SavedProject[];
        setRecentProjects(sorted);
      }
    } catch (e) {
      console.error("Failed to load history", e);
    }
  }, []);

  const handleDeleteProject = (e: React.MouseEvent, projectId: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this project?")) {
      try {
        const saved = localStorage.getItem('manual_master_projects');
        if (saved) {
          const parsed = JSON.parse(saved);
          delete parsed[projectId];
          localStorage.setItem('manual_master_projects', JSON.stringify(parsed));

          const sorted = Object.values(parsed).sort((a: any, b: any) => b.lastModified - a.lastModified) as SavedProject[];
          setRecentProjects(sorted);
        }
      } catch (e) {
        console.error("Failed to delete project", e);
      }
    }
  };

  const handlePresetSelect = (preset: PageDimensions) => {
    setSelectedPreset(preset.name);
    setIsCustom(false);
    setCustomWidth(preset.width.toString());
    setCustomHeight(preset.height.toString());
  };

  const handleCustomFocus = () => {
    setSelectedPreset('custom');
    setIsCustom(true);
  };

  const handleSubmit = () => {
    const width = parseFloat(customWidth);
    const height = parseFloat(customHeight);

    if (isNaN(width) || isNaN(height) || width <= 0 || height <= 0) {
      alert("Please enter valid positive dimensions.");
      return;
    }

    onStart({
      name: isCustom ? 'Custom' : selectedPreset,
      width,
      height
    });
  };

  return (
    <div className="min-h-screen bg-surface-50 flex flex-col items-center justify-center p-6 relative overflow-hidden">
      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-full bg-dot-pattern [background-size:20px_20px] opacity-40 pointer-events-none"></div>
      <div className="absolute top-[-10%] right-[-5%] w-[500px] h-[500px] bg-brand-200/40 rounded-full blur-[100px] pointer-events-none"></div>
      <div className="absolute bottom-[-10%] left-[-5%] w-[400px] h-[400px] bg-blue-200/40 rounded-full blur-[100px] pointer-events-none"></div>

      <div className="max-w-6xl w-full grid grid-cols-1 md:grid-cols-12 gap-8 z-10">

        {/* Left Side: Welcome & New Project */}
        <div className="md:col-span-7 flex flex-col gap-6">
          <div className="glass-panel p-8 rounded-3xl shadow-soft">
            <div className="flex items-center gap-4 mb-6">
                <div className="w-14 h-14 bg-gradient-to-br from-brand-500 to-brand-600 rounded-2xl flex items-center justify-center text-white shadow-glow">
                    <i className="fas fa-book-open text-2xl"></i>
                </div>
                <div>
                    <h1 className="text-3xl font-bold text-zinc-900 tracking-tight">ManualMaster AI</h1>
                    <p className="text-zinc-500 font-medium">Create beautiful documentation in minutes.</p>
                </div>
            </div>

            <div className="space-y-6">
                <div>
                    <h2 className="text-sm font-bold text-zinc-400 uppercase tracking-wider mb-4">Start New Project</h2>
                    <div className="grid grid-cols-4 gap-3">
                        {PRESETS.map((preset) => (
                        <button
                            key={preset.name}
                            onClick={() => handlePresetSelect(preset)}
                            className={`
                            group relative p-4 rounded-xl border transition-all duration-300 flex flex-col items-center gap-2
                            ${selectedPreset === preset.name 
                                ? 'border-brand-500 bg-brand-50/50 text-brand-700 ring-2 ring-brand-500/20 shadow-sm' 
                                : 'border-zinc-200 bg-white hover:border-brand-300 hover:shadow-md text-zinc-600'
                            }
                            `}
                        >
                            <div className={`w-8 h-10 border-2 rounded-sm ${selectedPreset === preset.name ? 'border-brand-400 bg-white' : 'border-zinc-300'} mb-1`}></div>
                            <span className="font-bold text-sm">{preset.name}</span>
                            <span className="text-[10px] opacity-60 font-medium">{preset.width} x {preset.height}</span>
                        </button>
                        ))}
                        <button 
                        onClick={handleCustomFocus}
                        className={`
                            group relative p-4 rounded-xl border transition-all duration-300 flex flex-col items-center gap-2
                            ${isCustom 
                                ? 'border-brand-500 bg-brand-50/50 text-brand-700 ring-2 ring-brand-500/20 shadow-sm' 
                                : 'border-zinc-200 bg-white hover:border-brand-300 hover:shadow-md text-zinc-600'
                            }
                        `}
                        >
                             <div className={`w-8 h-10 border-2 border-dashed rounded-sm ${isCustom ? 'border-brand-400 bg-white' : 'border-zinc-300'} mb-1`}></div>
                            <span className="font-bold text-sm">Custom</span>
                            <span className="text-[10px] opacity-60 font-medium">mm</span>
                        </button>
                    </div>
                </div>

                {isCustom && (
                 <div className="flex gap-4 bg-white p-4 rounded-xl border border-zinc-200 shadow-sm">
                    <div className="flex-1">
                      <label className="block text-xs font-bold text-zinc-500 uppercase mb-1.5">Width (mm)</label>
                      <input type="number" value={customWidth} onChange={(e) => setCustomWidth(e.target.value)} className="w-full p-2.5 bg-surface-50 border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all" />
                    </div>
                    <div className="flex-1">
                      <label className="block text-xs font-bold text-zinc-500 uppercase mb-1.5">Height (mm)</label>
                      <input type="number" value={customHeight} onChange={(e) => setCustomHeight(e.target.value)} className="w-full p-2.5 bg-surface-50 border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all" />
                    </div>
                 </div>
                )}

                <button
                    onClick={handleSubmit}
                    className="w-full py-4 bg-zinc-900 text-white font-bold rounded-xl shadow-lg hover:bg-black hover:shadow-xl hover:-translate-y-0.5 transition-all flex items-center justify-center gap-3 group"
                >
                    <span>Create Project</span>
                    <i className="fas fa-arrow-right group-hover:translate-x-1 transition-transform text-zinc-400 group-hover:text-white"></i>
                </button>
            </div>
          </div>
        </div>

        {/* Right Side: Recent Projects */}
        <div className="md:col-span-5 flex flex-col h-full min-h-[500px]">
           <div className="bg-white/60 backdrop-blur-md border border-white/50 p-6 rounded-3xl h-full flex flex-col shadow-soft">
              <h3 className="text-sm font-bold text-zinc-400 uppercase tracking-wider mb-6 flex items-center gap-2">
                  <i className="far fa-clock"></i> Recent Projects
              </h3>

              <div className="flex-1 overflow-y-auto pr-2 space-y-3 custom-scrollbar">
                {recentProjects.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-zinc-400 opacity-60">
                        <i className="fas fa-layer-group text-4xl mb-3"></i>
                        <p className="text-sm">No recent projects</p>
                    </div>
                ) : (
                    recentProjects.map(project => (
                        <div 
                        key={project.id}
                        onClick={() => onLoadProject(project)}
                        className="group relative bg-white p-4 rounded-xl border border-zinc-100 hover:border-brand-200 hover:shadow-md cursor-pointer transition-all duration-200"
                        >
                            <div className="flex justify-between items-start">
                                <div>
                                    <h4 className="font-bold text-zinc-800 mb-1 group-hover:text-brand-600 transition-colors">{project.metadata.title}</h4>
                                    <p className="text-xs text-zinc-500">
                                        {project.pages.length} Pages • {project.dimensions.name}
                                    </p>
                                </div>
                                <div className="w-8 h-8 rounded-full bg-surface-50 flex items-center justify-center text-zinc-400 group-hover:bg-brand-50 group-hover:text-brand-600 transition-colors">
                                    <i className="fas fa-chevron-right text-xs"></i>
                                </div>
                            </div>
                             <div className="mt-3 pt-3 border-t border-zinc-50 flex justify-between items-center">
                                <span className="text-[10px] text-zinc-400 font-medium">
                                    {new Date(project.lastModified).toLocaleDateString()}
                                </span>
                                <button 
                                    onClick={(e) => handleDeleteProject(e, project.id)}
                                    className="text-zinc-300 hover:text-red-500 transition-colors p-1"
                                    title="Delete"
                                >
                                    <i className="fas fa-trash-alt text-xs"></i>
                                </button>
                             </div>
                        </div>
                    ))
                )}
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

export default StartScreen;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import CoverEditor from './components/CoverEditor';
import BackCoverEditor from './components/BackCoverEditor';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage, SavedProject } from './types';
import { generatePageTitle } from './services/geminiService';

interface HistoryState {
  pages: ManualPage[];
  metadata: ManualMetadata;
}

const DEFAULT_METADATA: ManualMetadata = {
  title: 'Product Manual',
  subtitle: 'Setup & Configuration Guide',
  author: 'My Company Inc.',
  version: '1.0',
  showStepMarkers: true
};

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });
  const [projectId, setProjectId] = useState<string>(uuidv4());

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(false);

  const [isSaving, setIsSaving] = useState(false);
  const [lastSavedTime, setLastSavedTime] = useState<Date | null>(null);

  const previewRef = useRef<HTMLDivElement>(null);

  const [metadata, setMetadata] = useState<ManualMetadata>(DEFAULT_METADATA);
  const [pages, setPages] = useState<ManualPage[]>([
    { id: uuidv4(), type: 'cover', title: 'Cover Page', steps: [] },
    { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] },
    { id: uuidv4(), type: 'content', title: 'Getting Started', steps: [{ id: uuidv4(), title: 'Unboxing', description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.', images: [], layout: 'image_left_text_right' }] }
  ]);

  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [activePageIndex, setActivePageIndex] = useState(0); 

  const convertUrlToBase64 = async (url: string): Promise<string> => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn("Failed to convert image for saving:", url);
      return url; 
    }
  };

  const saveProjectToHistory = useCallback(async (isManual: boolean = false) => {
    if (!hasStarted) return;
    setIsSaving(true);
    try {
      const pagesToSave = JSON.parse(JSON.stringify(pages)) as ManualPage[];
      for (const page of pagesToSave) {
         if (page.backgroundImage && page.backgroundImage.url.startsWith('blob:')) {
             page.backgroundImage.url = await convertUrlToBase64(page.backgroundImage.url);
             delete page.backgroundImage.file; 
         }
         for (const step of page.steps) {
             for (const img of step.images) {
                 if (img.url.startsWith('blob:')) {
                     img.url = await convertUrlToBase64(img.url);
                     delete img.file; 
                 }
             }
         }
      }
      const projectData: SavedProject = {
        id: projectId,
        lastModified: Date.now(),
        metadata,
        pages: pagesToSave,
        dimensions: pageDimensions
      };
      const storedProjects = localStorage.getItem('manual_master_projects');
      const projects = storedProjects ? JSON.parse(storedProjects) : {};
      projects[projectId] = projectData;
      localStorage.setItem('manual_master_projects', JSON.stringify(projects));
      setLastSavedTime(new Date());
    } catch (error) {
       console.error("Failed to save project:", error);
       if (isManual) alert("Warning: Failed to save project. Your local storage might be full.");
    } finally {
        setTimeout(() => setIsSaving(false), 500);
    }
  }, [pages, metadata, pageDimensions, projectId, hasStarted]);

  useEffect(() => {
    if (!hasStarted) return;
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = setTimeout(() => { saveProjectToHistory(); }, 2000);
    return () => { if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current); };
  }, [pages, metadata, pageDimensions, hasStarted, saveProjectToHistory]);

  useEffect(() => {
    if (!hasStarted) return;
    const intervalId = setInterval(() => { saveProjectToHistory(false); }, 60000);
    return () => clearInterval(intervalId);
  }, [hasStarted, saveProjectToHistory]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            saveProjectToHistory(true);
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [saveProjectToHistory]);

  useEffect(() => {
    if (hasStarted) {
      const timer = setTimeout(() => {
        const pageElement = document.getElementById(`preview-page-${activePageIndex}`);
        if (pageElement) {
          pageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activePageIndex, hasStarted]);

  const saveSnapshot = useCallback(() => {
    setPast(prev => {
      const newPast = [...prev, { pages, metadata }];
      if (newPast.length > 20) return newPast.slice(newPast.length - 20);
      return newPast;
    });
    setFuture([]);
  }, [pages, metadata]);

  const undo = () => {
    if (past.length === 0) return;
    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);
    setFuture(prev => [{ pages, metadata }, ...prev]);
    setPages(previous.pages);
    setMetadata(previous.metadata);
    setPast(newPast);
  };

  const redo = () => {
    if (future.length === 0) return;
    const next = future[0];
    const newFuture = future.slice(1);
    setPast(prev => [...prev, { pages, metadata }]);
    setPages(next.pages);
    setMetadata(next.metadata);
    setFuture(newFuture);
  };

  const handleTextTypingHistory = () => {
    if (!typingTimeoutRef.current) saveSnapshot();
    if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    typingTimeoutRef.current = setTimeout(() => { typingTimeoutRef.current = null; }, 1000);
  };

  const handleStructuralChangeHistory = () => {
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = null;
    }
    saveSnapshot();
  };

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setProjectId(uuidv4());
    setMetadata(DEFAULT_METADATA);
    setPages([
      { id: uuidv4(), type: 'cover', title: 'Cover Page', steps: [] },
      { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] },
      { id: uuidv4(), type: 'content', title: 'Getting Started', steps: [{ id: uuidv4(), title: 'Unboxing', description: 'Carefully remove the device from the packaging.', images: [], layout: 'image_left_text_right' }] }
    ]);
    setPast([]);
    setFuture([]);
    setActivePageIndex(0);
    setHasStarted(true);
  };

  const handleLoadProject = (project: SavedProject) => {
      setProjectId(project.id);
      setMetadata(project.metadata);
      setPages(project.pages);
      setPageDimensions(project.dimensions);
      setPast([]);
      setFuture([]);
      setActivePageIndex(0);
      setHasStarted(true);
  };

  const handleGoHome = async () => {
      if (window.confirm("Return to Start Screen? Your work will be saved automatically.")) {
          await saveProjectToHistory(true);
          setHasStarted(false);
      }
  };

  const activePage = pages[activePageIndex] || pages[0] || { id: 'dummy', type: 'content', steps: [] };

  const addNewPage = () => {
    handleStructuralChangeHistory();
    const lastPage = pages[pages.length - 1];
    const hasBackCover = lastPage.type === 'back_cover';
    const newPage: ManualPage = { id: uuidv4(), type: 'content', title: '', steps: [] };
    const insertIndex = hasBackCover ? pages.length - 1 : pages.length;
    const newPages = [...pages];
    newPages.splice(insertIndex, 0, newPage);
    setPages(newPages);
    setActivePageIndex(insertIndex); 
  };

  const addTocPage = () => {
     if (pages.some(p => p.type === 'toc')) { alert("A Table of Contents page already exists."); return; }
     handleStructuralChangeHistory();
     const insertIndex = pages[0].type === 'cover' ? 1 : 0;
     const newPages = [...pages];
     newPages.splice(insertIndex, 0, { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] });
     setPages(newPages);
     setActivePageIndex(insertIndex);
  };

  const addBackCover = () => {
    if (pages.some(p => p.type === 'back_cover')) { alert("Back Cover already exists."); return; }
    handleStructuralChangeHistory();
    setPages([...pages, { id: uuidv4(), type: 'back_cover', title: 'Back Cover', steps: [] }]);
    setActivePageIndex(pages.length);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) setActivePageIndex(index);
  };

  const updatePageTitle = (title: string) => {
    handleTextTypingHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) { alert("Add some steps first."); return; }
    handleStructuralChangeHistory();
    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      setPages(currentPages => {
          const newPages = [...currentPages];
          if (newPages[activePageIndex]) newPages[activePageIndex] = { ...newPages[activePageIndex], title: suggestedTitle };
          return newPages;
      });
    } catch (error) { alert("Failed to generate title."); } finally { setIsGeneratingTitle(false); }
  };

  const updateMetadata = (updates: Partial<ManualMetadata>) => {
    const isText = 'title' in updates || 'subtitle' in updates || 'author' in updates || 'version' in updates;
    if (isText) handleTextTypingHistory(); else handleStructuralChangeHistory();
    setMetadata(prev => ({ ...prev, ...updates }));
  };

  const updatePage = (updates: Partial<ManualPage>) => {
    handleStructuralChangeHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], ...updates };
    setPages(newPages);
  };

  const addStepToActivePage = () => {
    if (activePage.type !== 'content') return;
    handleStructuralChangeHistory();
    const newStep: ManualStep = { id: uuidv4(), title: '', description: '', images: [], layout: 'image_left_text_right' };
    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);
    setTimeout(() => { const el = document.getElementById('steps-container'); if (el) el.scrollTop = el.scrollHeight; }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const isTextUpdate = 'title' in updates || 'description' in updates;
    if (isTextUpdate) handleTextTypingHistory(); else handleStructuralChangeHistory();
    const newPages = pages.map(page => ({ ...page, steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step) }));
    setPages(newPages);
  };

  const deleteStep = (stepId: string) => {
    handleStructuralChangeHistory();
    const newPages = pages.map(page => ({ ...page, steps: page.steps.filter(step => step.id !== stepId) }));
    setPages(newPages);
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type !== 'content') return;
    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;
    handleStructuralChangeHistory();
    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];
    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      if (pageIndex < 0 || pageIndex >= prevPages.length) return prevPages;
      const currentPage = prevPages[pageIndex];
      if (!currentPage || currentPage.type !== 'content' || currentPage.steps.length <= 1) return prevPages;
      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };
      if (nextPage && nextPage.type === 'content') {
        newPages[nextPageIndex] = { ...nextPage, steps: [lastStep, ...nextPage.steps] };
      } else {
        const newPage: ManualPage = { id: uuidv4(), type: 'content', title: 'Continued...', steps: [lastStep] };
        newPages.splice(nextPageIndex, 0, newPage);
      }
      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;
        if (i > 0) pdf.addPage();
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';
        const canvas = await html2canvas(pageElement, { scale: 2, useCORS: true, logging: false, backgroundColor: '#ffffff', windowWidth: 1200 });
        pageElement.style.boxShadow = originalShadow;
        const imgData = canvas.toDataURL('image/png');
        pdf.addImage(imgData, 'PNG', 0, 0, pdf.internal.pageSize.getWidth(), pdf.internal.pageSize.getHeight());
      }
      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) { console.error("PDF Generation failed", error); alert("Failed to generate PDF."); } finally { setIsGenerating(false); }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} onLoadProject={handleLoadProject} />;
  }

  const renderPageIcon = (type: ManualPage['type']) => {
      switch(type) {
          case 'cover': return <i className="fas fa-book-cover text-[10px]"></i>;
          case 'toc': return <i className="fas fa-list-ol text-[10px]"></i>;
          case 'back_cover': return <i className="fas fa-book-open fa-flip-horizontal text-[10px]"></i>;
          default: return null;
      }
  }

  return (
    <div className="flex flex-col h-screen bg-surface-50 text-zinc-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white/80 backdrop-blur-md border-b border-zinc-200/60 px-6 h-16 flex items-center justify-between shadow-sm z-50 fixed w-full top-0 left-0 transition-all">
        <div className="flex items-center gap-4">
            <button 
                onClick={handleGoHome}
                className="w-10 h-10 flex items-center justify-center rounded-xl bg-surface-100 hover:bg-surface-200 text-zinc-600 transition-colors"
                title="Back to Home"
            >
                <i className="fas fa-home text-lg"></i>
            </button>
            <div className="h-6 w-px bg-zinc-200"></div>
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-gradient-to-br from-brand-500 to-brand-600 rounded-xl flex items-center justify-center text-white shadow-glow">
                <i className="fas fa-book-open text-lg"></i>
              </div>
              <div className="hidden sm:block">
                <h1 className="font-bold text-lg text-zinc-900 tracking-tight leading-none">ManualMaster</h1>
                <p className="text-[10px] text-zinc-500 font-medium">AI Documentation Tool</p>
              </div>
            </div>
        </div>

        <div className="flex items-center gap-3">
           {/* Save & History Controls */}
           <div className="flex items-center gap-2 bg-surface-100/50 p-1 rounded-xl border border-zinc-100">
                <button 
                    onClick={() => saveProjectToHistory(true)}
