          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[450px] lg:w-[500px] px-6 pointer-events-none z-30">
                <button onClick={addStepToActivePage} className="pointer-events-auto w-full py-3.5 bg-zinc-900 text-white font-bold rounded-xl shadow-lg hover:bg-black hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-2 group">
                    <i className="fas fa-plus text-xs group-hover:rotate-90 transition-transform"></i>
                    Add Step
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`flex-col flex-grow bg-surface-100 relative ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}`}>
          <div className="absolute inset-0 bg-dot-pattern [background-size:20px_20px] opacity-40 pointer-events-none"></div>

          <div className="md:hidden flex border-b border-zinc-200 bg-white shrink-0 z-20">
            <button className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-brand-600 border-b-2 border-brand-600' : 'text-zinc-500'}`} onClick={() => setActiveTab('editor')}>Editor</button>
            <button className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-brand-600 border-b-2 border-brand-600' : 'text-zinc-500'}`} onClick={() => setActiveTab('preview')}>Preview</button>
          </div>

          <Preview pages={pages} metadata={metadata} dimensions={pageDimensions} previewRef={previewRef} onPageOverflow={handlePageOverflow} />
        </div>
      </div>
    </div>
  );
};

