             <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
               <label className="cursor-pointer px-3 py-1.5 bg-white rounded-lg text-zinc-900 text-xs font-bold hover:bg-zinc-100 shadow-lg">Change<input type="file" accept="image/*" onChange={handleImageChange} className="hidden" /></label>
               <button onClick={() => onUpdate({ backgroundImage: undefined })} className="px-3 py-1.5 bg-red-500 rounded-lg text-white text-xs font-bold hover:bg-red-600 shadow-lg">Remove</button>
            </div>
          </div>
        ) : (
          <label className="flex flex-col items-center justify-center w-full h-40 border-2 border-dashed border-zinc-200 rounded-xl hover:border-brand-400 hover:bg-brand-50/30 transition-all cursor-pointer">
             <i className="fas fa-image text-2xl text-zinc-300 mb-2"></i>
            <span className="text-xs font-bold text-zinc-500">Upload Image</span>
            <input type="file" accept="image/*" onChange={handleImageChange} className="hidden" />
          </label>
        )}
      </div>
    </div>
  );
};

