import React, { useState } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { ManualStep, StepLayout } from '../types';
import { generateDescriptionFromImages, generateStepTitle } from '../services/geminiService';

interface StepEditorProps {
  step: ManualStep;
  index: number;
  onUpdate: (id: string, updates: Partial<ManualStep>) => void;
  onDelete: (id: string) => void;
  onMoveUp: (index: number) => void;
  onMoveDown: (index: number) => void;
  totalSteps: number;
}

const StepEditor: React.FC<StepEditorProps> = ({ 
  step, index, onUpdate, onDelete, onMoveUp, onMoveDown, totalSteps
}) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);

  const handleImagesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newImages = (Array.from(e.target.files) as File[]).filter(file => {
        if (file.size > 3 * 1024 * 1024) {
          alert(`File ${file.name} is too large (max 3MB).`);
          return false;
        }
        return true;
      }).map(file => ({
        id: uuidv4(),
        url: URL.createObjectURL(file),
        file
      }));
      onUpdate(step.id, { images: [...step.images, ...newImages] });
    }
  };

  const handleRemoveImage = (imageId: string) => {
    onUpdate(step.id, { images: step.images.filter(img => img.id !== imageId) });
  };

  const handleAnalyzeImages = async () => {
    if (step.images.length === 0) return;
    setIsAnalyzing(true);
    try {
      const files = step.images.map(img => img.file);
      const description = await generateDescriptionFromImages(files);
      onUpdate(step.id, { description });
    } catch (error) { alert("Failed to analyze images."); } finally { setIsAnalyzing(false); }
  };

  const handleGenerateTitle = async () => {
    if (!step.description) return;
    setIsGeneratingTitle(true);
    try {
      const title = await generateStepTitle(step.description);
      onUpdate(step.id, { title });
    } catch (error) { alert("Failed to generate title."); } finally { setIsGeneratingTitle(false); }
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-zinc-100 p-1 transition-all hover:shadow-md hover:border-zinc-300 group">
      {/* Header */}
      <div className="flex justify-between items-center p-3 bg-surface-50 rounded-xl mb-3">
        <div className="flex items-center gap-2">
            <span className="w-6 h-6 flex items-center justify-center bg-zinc-900 text-white rounded-md text-xs font-bold">{index + 1}</span>
            <div className="h-4 w-px bg-zinc-200 mx-1"></div>
            {/* Compact Layout Controls */}
            <div className="flex bg-white rounded-lg p-0.5 shadow-sm border border-zinc-100">
               {[
                   { id: 'image_left_text_right', icon: 'fas fa-columns' },
                   { id: 'text_left_image_right', icon: 'fas fa-columns fa-flip-horizontal' },
                   { id: 'image_top_text_bottom', icon: 'fas fa-window-maximize' },
                   { id: 'text_top_image_bottom', icon: 'fas fa-window-maximize fa-flip-vertical' }
               ].map((layoutOpt) => (
                   <button
                    key={layoutOpt.id}
                    onClick={() => onUpdate(step.id, { layout: layoutOpt.id as StepLayout })}
                    className={`w-6 h-6 flex items-center justify-center rounded-md text-[10px] transition-colors ${step.layout === layoutOpt.id ? 'bg-zinc-800 text-white' : 'text-zinc-400 hover:bg-surface-100'}`}
                   >
                       <i className={layoutOpt.icon}></i>
                   </button>
               ))}
            </div>
        </div>
        <div className="flex items-center gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
            <button onClick={() => onMoveUp(index)} disabled={index === 0} className="p-1.5 text-zinc-400 hover:text-zinc-800 disabled:opacity-30"><i className="fas fa-chevron-up text-xs"></i></button>
            <button onClick={() => onMoveDown(index)} disabled={index === totalSteps - 1} className="p-1.5 text-zinc-400 hover:text-zinc-800 disabled:opacity-30"><i className="fas fa-chevron-down text-xs"></i></button>
            <button onClick={() => onDelete(step.id)} className="p-1.5 text-zinc-400 hover:text-red-500 ml-1"><i className="fas fa-trash-alt text-xs"></i></button>
        </div>
      </div>

      <div className="px-3 pb-3">
        <div className="flex flex-col gap-4">
            {/* Content Area */}
            <div className="flex flex-col md:flex-row gap-4">
                {/* Image Section */}
                <div className="w-full md:w-1/3 flex-shrink-0">
                    <div className="space-y-2">
                        {step.images.length > 0 && (
                            <div className={`grid gap-2 ${step.images.length > 1 ? 'grid-cols-2' : 'grid-cols-1'}`}>
                                {step.images.map((img) => (
                                    <div key={img.id} className="relative aspect-square rounded-lg overflow-hidden border border-zinc-200 group/img">
                                        <img src={img.url} alt="Step" className="w-full h-full object-cover" />
                                        <button onClick={() => handleRemoveImage(img.id)} className="absolute top-1 right-1 w-5 h-5 bg-black/50 text-white rounded-full flex items-center justify-center text-[10px] opacity-0 group-hover/img:opacity-100 transition-opacity"><i className="fas fa-times"></i></button>
                                    </div>
                                ))}
                            </div>
                        )}
                        <label className={`flex flex-col items-center justify-center border-2 border-dashed border-zinc-200 rounded-lg hover:border-brand-400 hover:bg-brand-50/30 transition-all cursor-pointer ${step.images.length > 0 ? 'h-10 border-solid border-zinc-100 bg-surface-50 text-xs text-zinc-500' : 'aspect-[4/3]'}`}>
                             {step.images.length > 0 ? <span className="font-bold">+ Add Image</span> : (
                                 <div className="text-center">
                                     <i className="fas fa-image text-zinc-300 text-2xl mb-2"></i>
                                     <span className="block text-xs font-bold text-zinc-400">Upload Image</span>
                                 </div>
                             )}
                             <input type="file" accept="image/*" multiple onChange={handleImagesChange} className="hidden" />
                        </label>
                         {step.images.length > 0 && (
                            <button onClick={handleAnalyzeImages} disabled={isAnalyzing} className="w-full py-1.5 bg-brand-50 text-brand-600 rounded-lg text-[10px] font-bold uppercase tracking-wider btn-animated-glow">
                                {isAnalyzing ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-magic mr-1"></i>} AI Describe
                            </button>
                        )}
                    </div>
                </div>

                {/* Text Section */}
                <div className="flex-1 space-y-3">
                    <div className="relative group/title">
                        <input
                            type="text"
                            value={step.title}
                            onChange={(e) => onUpdate(step.id, { title: e.target.value })}
                            placeholder="Step Title"
                            className="w-full text-base font-bold text-zinc-800 placeholder:text-zinc-300 border-none p-0 focus:ring-0 bg-transparent"
                        />
                         <button
                            type="button"
                            onClick={handleGenerateTitle}
                            disabled={isGeneratingTitle || !step.description}
                            className="absolute right-0 top-1/2 -translate-y-1/2 text-[10px] font-bold text-brand-600 bg-brand-50 px-2 py-0.5 rounded opacity-0 group-hover/title:opacity-100 transition-opacity disabled:opacity-0"
                        >
                            Generate
                        </button>
                    </div>
                    <textarea
                        rows={5}
                        value={step.description}
                        onChange={(e) => onUpdate(step.id, { description: e.target.value })}
                        placeholder="Description..."
                        className="w-full p-3 bg-surface-50 border border-zinc-100 rounded-xl text-sm text-zinc-600 focus:bg-white focus:border-brand-500 focus:ring-1 focus:ring-brand-500 outline-none resize-none transition-all"
                    />
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default StepEditor;

import { openDB, DBSchema } from 'idb';
import { SavedProject } from '../types';

interface ManualMasterDB extends DBSchema {
  projects: {
    key: string;
    value: SavedProject;
  };
}

const dbPromise = openDB<ManualMasterDB>('manual-master-db', 1, {
  upgrade(db) {
    db.createObjectStore('projects', { keyPath: 'id' });
  },
});

export const saveProjectToDB = async (project: SavedProject) => {
  try {
    const db = await dbPromise;
    await db.put('projects', project);
  } catch (error) {
    console.error("Failed to save project to IndexedDB", error);
    throw error;
  }
};

export const getProjectsFromDB = async (): Promise<SavedProject[]> => {
  const db = await dbPromise;
  let projects = await db.getAll('projects');

  // Migration logic: if DB is empty, check localStorage for legacy data
  if (projects.length === 0) {
     const local = localStorage.getItem('manual_master_projects');
     if (local) {
         try {
             const parsed = JSON.parse(local);
             const list = Object.values(parsed) as SavedProject[];
             for (const p of list) {
                 await db.put('projects', p);
             }
             // Optional: Clear localStorage after successful migration
             // localStorage.removeItem('manual_master_projects');
             projects = await db.getAll('projects');
         } catch(e) {
             console.error("Migration from localStorage failed", e);
         }
     }
  }
  return projects.sort((a, b) => b.lastModified - a.lastModified);
};

export const deleteProjectFromDB = async (id: string) => {
  const db = await dbPromise;
  await db.delete('projects', id);
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import CoverEditor from './components/CoverEditor';
import BackCoverEditor from './components/BackCoverEditor';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage, SavedProject } from './types';
import { generatePageTitle } from './services/geminiService';
import { saveProjectToDB } from './services/storageService';

interface HistoryState {
  pages: ManualPage[];
  metadata: ManualMetadata;
}

const DEFAULT_METADATA: ManualMetadata = {
  title: 'Product Manual',
  subtitle: 'Setup & Configuration Guide',
  author: 'My Company Inc.',
  version: '1.0',
  showStepMarkers: true
};

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });
  const [projectId, setProjectId] = useState<string>(uuidv4());

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(false);

  const [isSaving, setIsSaving] = useState(false);
  const [lastSavedTime, setLastSavedTime] = useState<Date | null>(null);

  const previewRef = useRef<HTMLDivElement>(null);

  const [metadata, setMetadata] = useState<ManualMetadata>(DEFAULT_METADATA);
  const [pages, setPages] = useState<ManualPage[]>([
    { id: uuidv4(), type: 'cover', title: 'Cover Page', steps: [] },
    { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] },
    { id: uuidv4(), type: 'content', title: 'Getting Started', steps: [{ id: uuidv4(), title: 'Unboxing', description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.', images: [], layout: 'image_left_text_right' }] }
  ]);

  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [activePageIndex, setActivePageIndex] = useState(0); 

  const convertUrlToBase64 = async (url: string): Promise<string> => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn("Failed to convert image for saving:", url);
      return url; 
    }
  };

  const saveProjectToHistory = useCallback(async (isManual: boolean = false) => {
    if (!hasStarted) return;
    setIsSaving(true);
    try {
      const pagesToSave = JSON.parse(JSON.stringify(pages)) as ManualPage[];
      for (const page of pagesToSave) {
         if (page.backgroundImage && page.backgroundImage.url.startsWith('blob:')) {
             page.backgroundImage.url = await convertUrlToBase64(page.backgroundImage.url);
             delete page.backgroundImage.file; 
         }
         for (const step of page.steps) {
             for (const img of step.images) {
                 if (img.url.startsWith('blob:')) {
                     img.url = await convertUrlToBase64(img.url);
                     delete img.file; 
                 }
             }
         }
      }
      const projectData: SavedProject = {
        id: projectId,
        lastModified: Date.now(),
        metadata,
        pages: pagesToSave,
        dimensions: pageDimensions
      };

      await saveProjectToDB(projectData);

      setLastSavedTime(new Date());
    } catch (error) {
       console.error("Failed to save project:", error);
       if (isManual) alert("Warning: Failed to save project. Ensure you have enough disk space.");
    } finally {
        setTimeout(() => setIsSaving(false), 500);
    }
  }, [pages, metadata, pageDimensions, projectId, hasStarted]);

  useEffect(() => {
    if (!hasStarted) return;
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = setTimeout(() => { saveProjectToHistory(); }, 2000);
    return () => { if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current); };
  }, [pages, metadata, pageDimensions, hasStarted, saveProjectToHistory]);

  useEffect(() => {
    if (!hasStarted) return;
    const intervalId = setInterval(() => { saveProjectToHistory(false); }, 60000);
    return () => clearInterval(intervalId);
  }, [hasStarted, saveProjectToHistory]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            saveProjectToHistory(true);
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [saveProjectToHistory]);

  useEffect(() => {
    if (hasStarted) {
      const timer = setTimeout(() => {
        const pageElement = document.getElementById(`preview-page-${activePageIndex}`);
        if (pageElement) {
          pageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activePageIndex, hasStarted]);

  const saveSnapshot = useCallback(() => {
    setPast(prev => {
      const newPast = [...prev, { pages, metadata }];
      if (newPast.length > 20) return newPast.slice(newPast.length - 20);
      return newPast;
    });
    setFuture([]);
  }, [pages, metadata]);

  const undo = () => {
    if (past.length === 0) return;
    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);
    setFuture(prev => [{ pages, metadata }, ...prev]);
    setPages(previous.pages);
    setMetadata(previous.metadata);
    setPast(newPast);
  };

  const redo = () => {
    if (future.length === 0) return;
    const next = future[0];
    const newFuture = future.slice(1);
    setPast(prev => [...prev, { pages, metadata }]);
    setPages(next.pages);
    setMetadata(next.metadata);
    setFuture(newFuture);
  };

  const handleTextTypingHistory = () => {
    if (!typingTimeoutRef.current) saveSnapshot();
    if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    typingTimeoutRef.current = setTimeout(() => { typingTimeoutRef.current = null; }, 1000);
  };

  const handleStructuralChangeHistory = () => {
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = null;
    }
    saveSnapshot();
  };

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setProjectId(uuidv4());
    setMetadata(DEFAULT_METADATA);
    setPages([
      { id: uuidv4(), type: 'cover', title: 'Cover Page', steps: [] },
      { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] },
      { id: uuidv4(), type: 'content', title: 'Getting Started', steps: [{ id: uuidv4(), title: 'Unboxing', description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.', images: [], layout: 'image_left_text_right' }] }
    ]);
    setPast([]);
    setFuture([]);
    setActivePageIndex(0);
    setHasStarted(true);
  };

  const handleLoadProject = (project: SavedProject) => {
      setProjectId(project.id);
      setMetadata(project.metadata);
      setPages(project.pages);
      setPageDimensions(project.dimensions);
      setPast([]);
      setFuture([]);
      setActivePageIndex(0);
      setHasStarted(true);
  };

  const activePage = pages[activePageIndex] || pages[0] || { id: 'dummy', type: 'content', steps: [] };

  const addNewPage = () => {
    handleStructuralChangeHistory();
    const lastPage = pages[pages.length - 1];
    const hasBackCover = lastPage.type === 'back_cover';
    const newPage: ManualPage = { id: uuidv4(), type: 'content', title: '', steps: [] };
    const insertIndex = hasBackCover ? pages.length - 1 : pages.length;
    const newPages = [...pages];
    newPages.splice(insertIndex, 0, newPage);
    setPages(newPages);
    setActivePageIndex(insertIndex); 
  };

  const addTocPage = () => {
     if (pages.some(p => p.type === 'toc')) { alert("A Table of Contents page already exists."); return; }
     handleStructuralChangeHistory();
     const insertIndex = pages[0].type === 'cover' ? 1 : 0;
     const newPages = [...pages];
     newPages.splice(insertIndex, 0, { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] });
     setPages(newPages);
     setActivePageIndex(insertIndex);
  };

  const addBackCover = () => {
    if (pages.some(p => p.type === 'back_cover')) { alert("Back Cover already exists."); return; }
    handleStructuralChangeHistory();
    setPages([...pages, { id: uuidv4(), type: 'back_cover', title: 'Back Cover', steps: [] }]);
    setActivePageIndex(pages.length);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) setActivePageIndex(index);
  };

  const updatePageTitle = (title: string) => {
    handleTextTypingHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) { alert("Add some steps first."); return; }
    handleStructuralChangeHistory();
    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      setPages(currentPages => {
          const newPages = [...currentPages];
          if (newPages[activePageIndex]) newPages[activePageIndex] = { ...newPages[activePageIndex], title: suggestedTitle };
          return newPages;
      });
    } catch (error) { alert("Failed to generate title."); } finally { setIsGeneratingTitle(false); }
  };

  const updateMetadata = (updates: Partial<ManualMetadata>) => {
    const isText = 'title' in updates || 'subtitle' in updates || 'author' in updates || 'version' in updates;
    if (isText) handleTextTypingHistory(); else handleStructuralChangeHistory();
    setMetadata(prev => ({ ...prev, ...updates }));
  };

  const updatePage = (updates: Partial<ManualPage>) => {
    handleStructuralChangeHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], ...updates };
    setPages(newPages);
  };

  const addStepToActivePage = () => {
    if (activePage.type !== 'content') return;
    handleStructuralChangeHistory();
    const newStep: ManualStep = { id: uuidv4(), title: '', description: '', images: [], layout: 'image_left_text_right' };
    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);
    setTimeout(() => { const el = document.getElementById('steps-container'); if (el) el.scrollTop = el.scrollHeight; }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const isTextUpdate = 'title' in updates || 'description' in updates;
    if (isTextUpdate) handleTextTypingHistory(); else handleStructuralChangeHistory();
    const newPages = pages.map(page => ({ ...page, steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step) }));
    setPages(newPages);
  };

  const deleteStep = (stepId: string) => {
    handleStructuralChangeHistory();
    const newPages = pages.map(page => ({ ...page, steps: page.steps.filter(step => step.id !== stepId) }));
    setPages(newPages);
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type !== 'content') return;
    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;
    handleStructuralChangeHistory();
    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];
    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      if (pageIndex < 0 || pageIndex >= prevPages.length) return prevPages;
      const currentPage = prevPages[pageIndex];
      if (!currentPage || currentPage.type !== 'content' || currentPage.steps.length <= 1) return prevPages;
      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };
      if (nextPage && nextPage.type === 'content') {
        newPages[nextPageIndex] = { ...nextPage, steps: [lastStep, ...nextPage.steps] };
      } else {
        const newPage: ManualPage = { id: uuidv4(), type: 'content', title: 'Continued...', steps: [lastStep] };
        newPages.splice(nextPageIndex, 0, newPage);
      }
      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;
        if (i > 0) pdf.addPage();
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';
        const canvas = await html2canvas(pageElement, { scale: 2, useCORS: true, logging: false, backgroundColor: '#ffffff', windowWidth: 1200 });
        pageElement.style.boxShadow = originalShadow;
        const imgData = canvas.toDataURL('image/png');
        pdf.addImage(imgData, 'PNG', 0, 0, pdf.internal.pageSize.getWidth(), pdf.internal.pageSize.getHeight());
      }
      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) { console.error("PDF Generation failed", error); alert("Failed to generate PDF."); } finally { setIsGenerating(false); }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} onLoadProject={handleLoadProject} />;
  }

  const renderPageIcon = (type: ManualPage['type']) => {
      switch(type) {
          case 'cover': return <i className="fas fa-book-cover text-[10px]"></i>;
          case 'toc': return <i className="fas fa-list-ol text-[10px]"></i>;
          case 'back_cover': return <i className="fas fa-book-open fa-flip-horizontal text-[10px]"></i>;
          default: return null;
      }
  }

  return (
    <div className="flex flex-col h-screen bg-surface-50 text-zinc-800 font-sans">
      {/* Top Navbar */}
      <nav className="bg-white/80 backdrop-blur-md border-b border-zinc-200/60 px-6 h-16 flex items-center justify-between shadow-sm z-50 fixed w-full top-0 left-0 transition-all">
        <div className="flex items-center gap-4">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-gradient-to-br from-brand-500 to-brand-600 rounded-xl flex items-center justify-center text-white shadow-glow">
                <i className="fas fa-book-open text-lg"></i>
              </div>
              <div className="hidden sm:block">
                <h1 className="font-bold text-lg text-zinc-900 tracking-tight leading-none">ManualMaster</h1>
                <p className="text-[10px] text-zinc-500 font-medium">AI Documentation Tool</p>
              </div>
            </div>
        </div>

        <div className="flex items-center gap-3">
           {/* Save Status Indicator */}
           <div className="hidden md:flex flex-col items-end mr-2">
              <span className={`text-[10px] font-bold uppercase tracking-wider transition-colors ${isSaving ? 'text-brand-500' : 'text-zinc-400'}`}>
                  {isSaving ? 'Saving...' : 'Saved'}
              </span>
              {lastSavedTime && !isSaving && (
                  <span className="text-[10px] text-zinc-300 font-medium">
                      {lastSavedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
              )}
           </div>

           {/* Save & History Controls */}
           <div className="flex items-center gap-2 bg-surface-100/50 p-1 rounded-xl border border-zinc-100">
                <button 
                    onClick={() => saveProjectToHistory(true)}
                    className={`w-9 h-9 flex items-center justify-center rounded-lg transition-all ${isSaving ? 'text-brand-600 bg-brand-50' : 'text-zinc-500 hover:text-zinc-800 hover:bg-white'}`}
                    title="Manual Save"
                >
                    {isSaving ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-save"></i>}
                </button>
                <div className="w-px h-4 bg-zinc-200"></div>
                <button onClick={undo} disabled={past.length === 0} className="w-9 h-9 flex items-center justify-center rounded-lg text-zinc-500 hover:text-zinc-800 hover:bg-white disabled:opacity-30 disabled:hover:bg-transparent" title="Undo"><i className="fas fa-undo"></i></button>
                <button onClick={redo} disabled={future.length === 0} className="w-9 h-9 flex items-center justify-center rounded-lg text-zinc-500 hover:text-zinc-800 hover:bg-white disabled:opacity-30 disabled:hover:bg-transparent" title="Redo"><i className="fas fa-redo"></i></button>
           </div>

           <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-xl text-sm font-bold flex items-center gap-2 transition-all shadow-md btn-animated-glow
              ${isGenerating ? 'bg-zinc-100 text-zinc-400 cursor-wait' : 'bg-zinc-900 text-white'}
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span className="hidden sm:inline">{isGenerating ? 'Exporting...' : 'Export PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden pt-16">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[450px] lg:w-[500px] border-r border-zinc-200 bg-white z-20 shadow-soft
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>

          {/* Modern Page Navigator */}
          <div className="px-4 py-3 bg-white/80 backdrop-blur-sm border-b border-zinc-100 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center sticky top-0 z-10">
             {!pages.some(p => p.type === 'toc') && (
               <button onClick={addTocPage} className="flex-shrink-0 w-8 h-8 rounded-full bg-surface-100 text-zinc-500 hover:bg-brand-50 hover:text-brand-600 transition-colors flex items-center justify-center" title="Insert TOC">
                 <i className="fas fa-list-ol text-xs"></i>
               </button>
            )}
            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2 border
                  ${activePageIndex === idx 
                    ? 'bg-zinc-900 text-white border-zinc-900 shadow-sm' 
                    : 'bg-white text-zinc-500 border-zinc-200 hover:border-zinc-300 hover:bg-surface-50'
                  }
                `}
              >
                {renderPageIcon(page.type)}
                {page.type === 'content' ? idx + 1 : ''}
              </button>
            ))}
            <button onClick={addNewPage} className="flex-shrink-0 w-8 h-8 rounded-full bg-brand-50 text-brand-600 hover:bg-brand-100 transition-colors flex items-center justify-center ml-1 border border-brand-100">
              <i className="fas fa-plus text-xs"></i>
            </button>
            {!pages.some(p => p.type === 'back_cover') && (
                <button onClick={addBackCover} className="flex-shrink-0 w-8 h-8 rounded-full bg-surface-100 text-zinc-500 hover:bg-surface-200 transition-colors flex items-center justify-center" title="Add Back Cover">
                    <i className="fas fa-book-open fa-flip-horizontal text-xs"></i>
                </button>
            )}
          </div>

          {/* Editor Header */}
          <div className="px-6 py-4 bg-white">
             <div className="flex justify-between items-center mb-1">
                <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">Currently Editing</span>
                {activePage.type === 'content' && <span className="text-[10px] font-medium bg-surface-100 text-zinc-500 px-2 py-0.5 rounded-full">{activePage.steps.length} Steps</span>}
             </div>
             <h2 className="text-xl font-bold text-zinc-900 flex items-center gap-2">
                {activePage.type === 'cover' ? 'Front Cover' : activePage.type === 'back_cover' ? 'Back Cover' : activePage.type === 'toc' ? 'Table of Contents' : `Page ${activePageIndex + 1}`}
             </h2>
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto px-6 pb-24 scroll-smooth">

            {/* Global Settings Accordion */}
            <div className={`mb-8 rounded-2xl border transition-all duration-300 overflow-hidden ${isMetadataExpanded ? 'bg-surface-50 border-zinc-200' : 'bg-white border-zinc-100 hover:border-zinc-300'}`}>
              <button onClick={() => setIsMetadataExpanded(!isMetadataExpanded)} className="w-full flex items-center justify-between p-4 text-left">
                <div className="flex items-center gap-2 text-sm font-bold text-zinc-700">
                  <i className="fas fa-sliders-h text-zinc-400"></i> Document Settings
                </div>
                <i className={`fas fa-chevron-down text-zinc-400 transition-transform ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>
              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid gap-3">
                  <input type="text" value={metadata.title} onChange={(e) => updateMetadata({ title: e.target.value })} className="w-full p-2.5 bg-white border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 outline-none" placeholder="Document Title" />
                  <input type="text" value={metadata.subtitle} onChange={(e) => updateMetadata({ subtitle: e.target.value })} className="w-full p-2.5 bg-white border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 outline-none" placeholder="Subtitle" />
                  <div className="grid grid-cols-2 gap-3">
                    <input type="text" value={metadata.author} onChange={(e) => updateMetadata({ author: e.target.value })} className="w-full p-2.5 bg-white border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 outline-none" placeholder="Author" />
                    <input type="text" value={metadata.version} onChange={(e) => updateMetadata({ version: e.target.value })} className="w-full p-2.5 bg-white border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 outline-none" placeholder="Version" />
                  </div>
                  <div className="flex items-center justify-between pt-2">
                     <span className="text-xs font-bold text-zinc-500">Show Bullet Points</span>
                     <button onClick={() => updateMetadata({ showStepMarkers: !metadata.showStepMarkers })} className={`w-10 h-6 rounded-full p-1 transition-colors ${metadata.showStepMarkers ? 'bg-brand-600' : 'bg-zinc-200'}`}>
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transform transition-transform ${metadata.showStepMarkers ? 'translate-x-4' : 'translate-x-0'}`}></div>
                     </button>
                  </div>
                </div>
              )}
            </div>

            {activePage.type === 'cover' && <CoverEditor page={activePage} onUpdate={updatePage} metadata={metadata} />}
            {activePage.type === 'back_cover' && <BackCoverEditor page={activePage} onUpdate={updatePage} />}

            {activePage.type === 'toc' && (
                <div className="bg-surface-50 border border-zinc-200 rounded-2xl p-8 text-center flex flex-col items-center">
                    <div className="w-12 h-12 bg-white rounded-xl shadow-sm flex items-center justify-center mb-4 text-zinc-400">
                        <i className="fas fa-list-ol text-xl"></i>
                    </div>
                    <h3 className="font-bold text-zinc-800 mb-1">Auto-Generated Directory</h3>
                    <p className="text-xs text-zinc-500 mb-4 max-w-[200px]">This page automatically compiles titles from all subsequent pages.</p>
                    <input type="text" value={activePage.title || ''} onChange={(e) => updatePageTitle(e.target.value)} className="w-full max-w-xs p-2 bg-white border border-zinc-200 rounded-lg text-center text-sm font-semibold focus:ring-2 focus:ring-brand-500/20 outline-none" placeholder="TOC Title" />
                </div>
            )}

            {activePage.type === 'content' && (
                <>
                    <div className="mb-6 relative">
                        <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest mb-2 block flex justify-between">
                            Page Section Title
                            <button onClick={handleAutoGeneratePageTitle} disabled={isGeneratingTitle || activePage.steps.length === 0} className="text-brand-600 hover:text-brand-700 disabled:opacity-50">
                                {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>} Auto-Generate
                            </button>
                        </label>
                        <input type="text" value={activePage.title || ''} onChange={(e) => updatePageTitle(e.target.value)} className="w-full p-4 bg-white border border-zinc-200 rounded-xl text-lg font-bold text-zinc-800 focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all shadow-sm" placeholder="e.g. Safety Instructions" />
                    </div>

                    <div className="space-y-4">
                        {activePage.steps.length === 0 && (
                            <div className="text-center py-12 border-2 border-dashed border-zinc-200 rounded-2xl bg-surface-50">
                                <i className="fas fa-layer-group text-3xl text-zinc-300 mb-3"></i>
                                <p className="text-sm font-medium text-zinc-500">No steps on this page yet.</p>
                            </div>
                        )}
                        {activePage.steps.map((step, idx) => (
                            <StepEditor key={step.id} index={idx} step={step} totalSteps={activePage.steps.length} onUpdate={updateStep} onDelete={deleteStep} onMoveUp={() => moveStep(idx, 'up')} onMoveDown={() => moveStep(idx, 'down')} />
                        ))}
                    </div>
                </>
            )}
          </div>

          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[450px] lg:w-[500px] px-6 pointer-events-none z-30">
                <button onClick={addStepToActivePage} className="pointer-events-auto w-full py-3.5 bg-zinc-900 text-white font-bold rounded-xl shadow-lg btn-animated-glow flex items-center justify-center gap-2 group">
                    <i className="fas fa-plus text-xs group-hover:rotate-90 transition-transform"></i>
                    Add Step
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`flex-col flex-grow bg-surface-100 relative ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'}`}>
          <div className="absolute inset-0 bg-dot-pattern [background-size:20px_20px] opacity-40 pointer-events-none"></div>

          <div className="md:hidden flex border-b border-zinc-200 bg-white shrink-0 z-20">
            <button className={`flex-1 py-3 text-sm font-medium ${activeTab === 'editor' ? 'text-brand-600 border-b-2 border-brand-600' : 'text-zinc-500'}`} onClick={() => setActiveTab('editor')}>Editor</button>
            <button className={`flex-1 py-3 text-sm font-medium ${activeTab === 'preview' ? 'text-brand-600 border-b-2 border-brand-600' : 'text-zinc-500'}`} onClick={() => setActiveTab('preview')}>Preview</button>
          </div>

          <Preview pages={pages} metadata={metadata} dimensions={pageDimensions} previewRef={previewRef} onPageOverflow={handlePageOverflow} />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { PageDimensions, SavedProject } from '../types';
import { getProjectsFromDB, deleteProjectFromDB } from '../services/storageService';

interface StartScreenProps {
  onStart: (dimensions: PageDimensions) => void;
  onLoadProject: (project: SavedProject) => void;
}

const PRESETS: PageDimensions[] = [
  { name: 'A4', width: 210, height: 297 },
  { name: 'A5', width: 148, height: 210 },
  { name: 'Letter', width: 216, height: 279 },
];

const StartScreen: React.FC<StartScreenProps> = ({ onStart, onLoadProject }) => {
  const [selectedPreset, setSelectedPreset] = useState<string>('A4');
  const [customWidth, setCustomWidth] = useState<string>('210');
  const [customHeight, setCustomHeight] = useState<string>('297');
  const [isCustom, setIsCustom] = useState(false);
  const [recentProjects, setRecentProjects] = useState<SavedProject[]>([]);

  useEffect(() => {
    const loadProjects = async () => {
      try {
        const projects = await getProjectsFromDB();
        setRecentProjects(projects);
      } catch (e) {
        console.error("Failed to load history", e);
      }
    };
    loadProjects();
  }, []);

  const handleDeleteProject = async (e: React.MouseEvent, projectId: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this project?")) {
      try {
        await deleteProjectFromDB(projectId);
        const projects = await getProjectsFromDB();
        setRecentProjects(projects);
      } catch (e) {
        console.error("Failed to delete project", e);
      }
    }
  };

  const handlePresetSelect = (preset: PageDimensions) => {
    setSelectedPreset(preset.name);
    setIsCustom(false);
    setCustomWidth(preset.width.toString());
    setCustomHeight(preset.height.toString());
  };

  const handleCustomFocus = () => {
    setSelectedPreset('custom');
    setIsCustom(true);
  };

  const handleSubmit = () => {
    const width = parseFloat(customWidth);
    const height = parseFloat(customHeight);

    if (isNaN(width) || isNaN(height) || width <= 0 || height <= 0) {
      alert("Please enter valid positive dimensions.");
      return;
    }

    onStart({
      name: isCustom ? 'Custom' : selectedPreset,
      width,
      height
    });
  };

  return (
    <div className="min-h-screen bg-surface-50 flex flex-col items-center justify-center p-6 relative overflow-hidden">
      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-full bg-dot-pattern [background-size:20px_20px] opacity-40 pointer-events-none"></div>
      <div className="absolute top-[-10%] right-[-5%] w-[500px] h-[500px] bg-brand-200/40 rounded-full blur-[100px] pointer-events-none"></div>
      <div className="absolute bottom-[-10%] left-[-5%] w-[400px] h-[400px] bg-blue-200/40 rounded-full blur-[100px] pointer-events-none"></div>

      <div className="max-w-6xl w-full grid grid-cols-1 md:grid-cols-12 gap-8 z-10">

        {/* Left Side: Welcome & New Project */}
        <div className="md:col-span-7 flex flex-col gap-6">
          <div className="glass-panel p-8 rounded-3xl shadow-soft">
            <div className="flex items-center gap-4 mb-6">
                <div className="w-14 h-14 bg-gradient-to-br from-brand-500 to-brand-600 rounded-2xl flex items-center justify-center text-white shadow-glow">
                    <i className="fas fa-book-open text-2xl"></i>
                </div>
                <div>
                    <h1 className="text-3xl font-bold text-zinc-900 tracking-tight">ManualMaster AI</h1>
                    <p className="text-zinc-500 font-medium">Create beautiful documentation in minutes.</p>
                </div>
            </div>

            <div className="space-y-6">
                <div>
                    <h2 className="text-sm font-bold text-zinc-400 uppercase tracking-wider mb-4">Start New Project</h2>
                    <div className="grid grid-cols-4 gap-3">
                        {PRESETS.map((preset) => (
                        <button
                            key={preset.name}
                            onClick={() => handlePresetSelect(preset)}
                            className={`
                            group relative p-4 rounded-xl border transition-all duration-300 flex flex-col items-center gap-2
                            ${selectedPreset === preset.name 
                                ? 'border-brand-500 bg-brand-50/50 text-brand-700 ring-2 ring-brand-500/20 shadow-sm' 
                                : 'border-zinc-200 bg-white hover:border-brand-300 hover:shadow-md text-zinc-600'
                            }
                            `}
                        >
                            <div className={`w-8 h-10 border-2 rounded-sm ${selectedPreset === preset.name ? 'border-brand-400 bg-white' : 'border-zinc-300'} mb-1`}></div>
                            <span className="font-bold text-sm">{preset.name}</span>
                            <span className="text-[10px] opacity-60 font-medium">{preset.width} x {preset.height}</span>
                        </button>
                        ))}
                        <button 
                        onClick={handleCustomFocus}
                        className={`
                            group relative p-4 rounded-xl border transition-all duration-300 flex flex-col items-center gap-2
                            ${isCustom 
                                ? 'border-brand-500 bg-brand-50/50 text-brand-700 ring-2 ring-brand-500/20 shadow-sm' 
                                : 'border-zinc-200 bg-white hover:border-brand-300 hover:shadow-md text-zinc-600'
                            }
                        `}
                        >
                             <div className={`w-8 h-10 border-2 border-dashed rounded-sm ${isCustom ? 'border-brand-400 bg-white' : 'border-zinc-300'} mb-1`}></div>
                            <span className="font-bold text-sm">Custom</span>
                            <span className="text-[10px] opacity-60 font-medium">mm</span>
                        </button>
                    </div>
                </div>

                {isCustom && (
                 <div className="flex gap-4 bg-white p-4 rounded-xl border border-zinc-200 shadow-sm">
                    <div className="flex-1">
                      <label className="block text-xs font-bold text-zinc-500 uppercase mb-1.5">Width (mm)</label>
                      <input type="number" value={customWidth} onChange={(e) => setCustomWidth(e.target.value)} className="w-full p-2.5 bg-surface-50 border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all" />
                    </div>
                    <div className="flex-1">
                      <label className="block text-xs font-bold text-zinc-500 uppercase mb-1.5">Height (mm)</label>
                      <input type="number" value={customHeight} onChange={(e) => setCustomHeight(e.target.value)} className="w-full p-2.5 bg-surface-50 border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all" />
                    </div>
                 </div>
                )}

                <button
                    onClick={handleSubmit}
                    className="w-full py-4 bg-zinc-900 text-white font-bold rounded-xl shadow-lg btn-animated-glow flex items-center justify-center gap-3 group"
                >
                    <span>Create Project</span>
                    <i className="fas fa-arrow-right group-hover:translate-x-1 transition-transform"></i>
                </button>
            </div>
          </div>
        </div>

        {/* Right Side: Recent Projects */}
        <div className="md:col-span-5 flex flex-col h-full min-h-[500px]">
           <div className="bg-white/60 backdrop-blur-md border border-white/50 p-6 rounded-3xl h-full flex flex-col shadow-soft">
              <h3 className="text-sm font-bold text-zinc-400 uppercase tracking-wider mb-6 flex items-center gap-2">
                  <i className="far fa-clock"></i> Recent Projects
              </h3>

              <div className="flex-1 overflow-y-auto pr-2 space-y-3 custom-scrollbar">
                {recentProjects.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-zinc-400 opacity-60">
                        <i className="fas fa-layer-group text-4xl mb-3"></i>
                        <p className="text-sm">No recent projects</p>
                    </div>
                ) : (
                    recentProjects.map(project => (
                        <div 
                        key={project.id}
                        onClick={() => onLoadProject(project)}
                        className="group relative bg-white p-4 rounded-xl border border-zinc-100 hover:border-brand-200 hover:shadow-md cursor-pointer transition-all duration-200"
                        >
                            <div className="flex justify-between items-start">
                                <div>
                                    <h4 className="font-bold text-zinc-800 mb-1 group-hover:text-brand-600 transition-colors">{project.metadata.title}</h4>
                                    <p className="text-xs text-zinc-500">
                                        {project.pages.length} Pages • {project.dimensions.name}
                                    </p>
                                </div>
                                <div className="w-8 h-8 rounded-full bg-surface-50 flex items-center justify-center text-zinc-400 group-hover:bg-brand-50 group-hover:text-brand-600 transition-colors">
                                    <i className="fas fa-chevron-right text-xs"></i>
                                </div>
                            </div>
                             <div className="mt-3 pt-3 border-t border-zinc-50 flex justify-between items-center">
                                <span className="text-[10px] text-zinc-400 font-medium">
                                    {new Date(project.lastModified).toLocaleDateString()}
                                </span>
                                <button 
                                    onClick={(e) => handleDeleteProject(e, project.id)}
                                    className="text-zinc-300 hover:text-red-500 transition-colors p-1"
                                    title="Delete"
                                >
                                    <i className="fas fa-trash-alt text-xs"></i>
                                </button>
                             </div>
                        </div>
                    ))
                )}
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

