import React, { useLayoutEffect, useRef } from 'react';
import { ManualPage, ManualMetadata, PageDimensions, StepLayout } from '../types';

interface PreviewProps {
  pages: ManualPage[];
  metadata: ManualMetadata;
  dimensions: PageDimensions;
  previewRef: React.RefObject<HTMLDivElement>;
  onPageOverflow: (pageIndex: number) => void;
}

const PageContainer: React.FC<{
  page: ManualPage;
  pageIndex: number;
  allPages: ManualPage[];
  totalPages: number;
  metadata: ManualMetadata;
  dimensions: PageDimensions;
  onOverflow: (index: number) => void;
}> = ({ page, pageIndex, allPages, totalPages, metadata, dimensions, onOverflow }) => {
  const pageRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  useLayoutEffect(() => {
    if (page.type === 'content' && contentRef.current) {
      const containerHeight = contentRef.current.clientHeight;
      const contentHeight = contentRef.current.scrollHeight;
      if (contentHeight > containerHeight + 1 && page.steps.length > 1) {
        const timer = setTimeout(() => { onOverflow(pageIndex); }, 500);
        return () => clearTimeout(timer);
      }
    }
  }, [page.steps, pageIndex, onOverflow, page.type]);

  const currentDate = new Date().toLocaleDateString();
  const isFirstPage = pageIndex === 0;

  const renderCover = () => {
    return (
        <div className="h-full relative flex flex-col">
            {page.backgroundImage && (
                <div className="absolute inset-0 z-0">
                    <img src={page.backgroundImage.url} alt="Cover" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-b from-white/90 via-white/50 to-transparent h-1/2"></div>
                </div>
            )}
            <div className="relative z-10 p-16 flex flex-col h-full items-center text-center pt-32">
                 <div className="mb-4 inline-block px-4 py-1.5 bg-zinc-900 text-white rounded text-sm font-bold tracking-widest uppercase">{metadata.version ? `Version ${metadata.version}` : 'Manual'}</div>
                 <h1 className="text-6xl font-extrabold text-zinc-900 tracking-tight leading-tight mb-6 drop-shadow-sm">{metadata.title || "User Manual"}</h1>
                 <h2 className="text-2xl text-zinc-600 font-light max-w-lg leading-relaxed">{metadata.subtitle || "Instruction Guide"}</h2>
                 <div className="mt-auto pb-12 w-full border-t border-zinc-900/10 pt-8">
                    <p className="font-bold text-zinc-800">{metadata.author}</p>
                    <p className="text-sm text-zinc-500 mt-1">{currentDate}</p>
                 </div>
            </div>
        </div>
    );
  };

  const renderBackCover = () => {
     return (
        <div className="h-full relative flex flex-col justify-end">
            {page.backgroundImage && (
                <div className="absolute inset-0 z-0"><img src={page.backgroundImage.url} alt="Back Cover" className="w-full h-full object-cover" /></div>
            )}
            <div className="relative z-10 bg-white p-16 pt-12">
                 <div className="w-16 h-2 bg-zinc-900 mb-8"></div>
                 <h3 className="text-2xl font-bold text-zinc-900 mb-4">Contact & Support</h3>
                 <div className="text-zinc-600 whitespace-pre-wrap leading-relaxed">{page.customText || "Thank you for choosing our product.\n\nFor support, please visit our website or contact our customer service team."}</div>
                 <div className="mt-8 pt-8 border-t border-zinc-200 text-xs text-zinc-400">© {new Date().getFullYear()} {metadata.author}. All rights reserved.</div>
            </div>
        </div>
    );
  };

  const renderTOC = () => {
    const contentPages = allPages.map((p, idx) => ({ ...p, originalIndex: idx })).filter(p => p.type === 'content');
    return (
      <div className="flex flex-col h-full">
         <h1 className="text-3xl font-bold text-zinc-900 mb-12 uppercase tracking-wider text-center border-b-2 border-zinc-900 pb-4">{page.title || "Table of Contents"}</h1>
         <div className="flex-grow space-y-4 px-4">
             {contentPages.map((contentPage) => {
                 let label = contentPage.title;
                 if (!label && contentPage.steps.length > 0) label = contentPage.steps[0].title;
                 if (!label) label = `Page ${contentPage.originalIndex + 1}`;
                 return (
                    <div key={contentPage.id} className="flex items-end mb-4">
                        <div className="font-bold text-zinc-700 text-lg">{label}</div>
                        <div className="flex-grow border-b-2 border-dotted border-zinc-300 mx-2 relative top-[-6px]"></div>
                        <div className="font-bold text-zinc-900 text-lg w-8 text-right">{contentPage.originalIndex + 1}</div>
                    </div>
                 );
             })}
         </div>
      </div>
    );
  };

  const getLayoutClasses = (layout: StepLayout = 'image_left_text_right') => {
    switch (layout) {
      case 'text_left_image_right': return { text: 'col-span-7 order-1', image: 'col-span-5 order-2' };
      case 'image_top_text_bottom': return { text: 'col-span-12 order-2', image: 'col-span-12 order-1 mb-4' };
      case 'text_top_image_bottom': return { text: 'col-span-12 order-1 mb-4', image: 'col-span-12 order-2' };
      case 'image_left_text_right': default: return { text: 'col-span-7 order-2', image: 'col-span-5 order-1' };
    }
  };

  if (page.type === 'cover' || page.type === 'back_cover') {
       return (
        <div 
            id={`preview-page-${pageIndex}`}
            ref={pageRef}
            className="bg-white relative shrink-0 mb-12 shadow-paper mx-auto overflow-hidden transition-all duration-300"
            style={{ width: `${dimensions.width}mm`, height: `${dimensions.height}mm` }}
        >
            {page.type === 'cover' ? renderCover() : renderBackCover()}
        </div>
       )
  }

  return (
    <div 
      id={`preview-page-${pageIndex}`}
      ref={pageRef}
      className="bg-white relative shrink-0 mb-12 shadow-paper mx-auto overflow-hidden transition-all duration-300"
      style={{ width: `${dimensions.width}mm`, height: `${dimensions.height}mm` }}
    >
      <div ref={contentRef} className="absolute top-0 left-0 right-0 bottom-32 p-12 flex flex-col">
        {page.type === 'toc' ? renderTOC() : (
          <>
            <header className={`shrink-0 ${isFirstPage ? 'border-b-2 border-zinc-900 pb-6 mb-10' : 'border-b border-zinc-200 pb-4 mb-6'}`}>
              <div className="flex justify-between items-end">
                <div className="max-w-[70%]">
                  <h2 className="text-lg font-bold text-zinc-400 uppercase tracking-wide">
                    {metadata.title || "User Manual"} <span className="text-zinc-300">/ {page.title || "Continued"}</span>
                  </h2>
                </div>
                <div className="text-right"><div className="text-xs text-zinc-400">{currentDate}</div></div>
              </div>
            </header>
            <main className="space-y-8">
              {page.steps.length === 0 && (
                <div className="flex flex-col items-center justify-center h-48 text-zinc-300 border-2 border-dashed border-zinc-100 rounded-xl m-8">
                  <p className="font-medium text-sm">Empty Page</p>
                </div>
              )}
              {page.steps.map((step, idx) => {
                  const layoutClasses = getLayoutClasses(step.layout);
                  return (
                    <div key={step.id} className="break-inside-avoid step-item">
                        <div className="grid grid-cols-12 gap-6">
                            <div className={`${step.images.length > 0 ? layoutClasses.text : 'col-span-12 order-last'}`}>
                                <div className="flex items-start gap-3 mb-2">
                                    {metadata.showStepMarkers && (<div className="flex-shrink-0 pt-2"><div className="w-2.5 h-2.5 rounded-full bg-zinc-900"></div></div>)}
                                    <h3 className="text-lg font-bold text-zinc-800 uppercase tracking-wide leading-tight">{step.title || "Untitled Step"}</h3>
                                </div>
                                <div className={metadata.showStepMarkers ? "pl-5" : ""}>
                                  <p className="text-zinc-600 text-sm leading-relaxed whitespace-pre-wrap">{step.description || "No description provided."}</p>
                                </div>
                            </div>
                            {step.images.length > 0 && (
                            <div className={layoutClasses.image}>
                                <div className="flex flex-wrap gap-2">
                                    {step.images.map((img) => (
                                        <div 
                                          key={img.id} 
                                          className="rounded-lg border border-zinc-200 overflow-hidden bg-surface-50 shadow-sm"
                                          style={{ width: img.width ? `${img.width}%` : (step.images.length > 1 ? '48%' : '100%') }}
                                        >
                                            <img src={img.url} alt="Step" className="w-full h-auto object-cover" />
                                        </div>
                                    ))}
                                </div>
                            </div>
                            )}
                        </div>
                    </div>
                  );
              })}
            </main>
          </>
        )}
      </div>
      <footer className="absolute bottom-0 left-0 right-0 h-32 px-12 pb-12 pt-4 flex justify-between items-end z-20 bg-white">
          <div className="w-full border-t border-zinc-200 pt-6 flex justify-between items-center text-xs text-zinc-400">
            <p>© {new Date().getFullYear()} {metadata.author || "Your Company"}.</p>
            <div className="font-bold text-zinc-500">Page {pageIndex + 1} of {totalPages}</div>
          </div>
      </footer>
    </div>
  );
};

