      const title = await generateStepTitle(step.description);
      onUpdate(step.id, { title });
    } catch (error) { alert("Failed to generate title."); } finally { setIsGeneratingTitle(false); }
  };

  const handleResizeStart = (e: React.MouseEvent, imgId: string) => {
    e.preventDefault();
    e.stopPropagation();
    const handle = e.currentTarget as HTMLElement;
    const container = handle.closest('.image-container') as HTMLElement;
    if (!container || !imagesContainerRef.current) return;

    const startX = e.clientX;
    const startWidth = container.offsetWidth;

    // Logic: If single image side-by-side, we resize relative to the ROW width.
    // Otherwise (vertical or multi-image), we resize relative to the IMAGE CONTAINER width.
    const isSideBySide = step.layout === 'image_left_text_right' || step.layout === 'text_left_image_right';
    const isSingle = step.images.length === 1;

    let parentWidth = imagesContainerRef.current.offsetWidth;
    if (isSideBySide && isSingle && rowContainerRef.current) {
         parentWidth = rowContainerRef.current.offsetWidth;
    }

    setResizingImgId(imgId);

    const handleMouseMove = (moveEvent: MouseEvent) => {
      moveEvent.preventDefault();
      const deltaX = moveEvent.clientX - startX;
      let newWidthPx = startWidth + deltaX;
      let newWidthPercent = (newWidthPx / parentWidth) * 100;

      // Constraints
      newWidthPercent = Math.max(15, Math.min(100, newWidthPercent));

      // Snapping
      const snapPoints = [16.66, 20, 25, 33.33, 40, 45, 50, 60, 66.66, 75, 100];
      for (const snap of snapPoints) {
        if (Math.abs(newWidthPercent - snap) < 2) {
          newWidthPercent = snap;
          break;
        }
      }

      onUpdate(step.id, {
        images: step.images.map(img => 
          img.id === imgId ? { ...img, width: newWidthPercent } : img
        )
      });
    };

    const handleMouseUp = () => {
      setResizingImgId(null);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  // Layout Logic
  const isSideBySide = step.layout === 'image_left_text_right' || step.layout === 'text_left_image_right';
  const isImageFirst = step.layout === 'image_left_text_right' || step.layout === 'image_top_text_bottom';
  const isVertical = step.layout === 'image_top_text_bottom' || step.layout === 'text_top_image_bottom';

  // Determine Image Container Width style
  const getImageContainerStyle = () => {
      if (isVertical) return { width: '100%' };
      // Side by side
      if (step.images.length === 1 && step.images[0].width) {
          return { width: `${step.images[0].width}%` };
      }
      // Default or Multi-image side-by-side
      const defaultWidth = metadata.singleImageSize || 45;
      return { width: `${defaultWidth}%` };
  };

  // Determine individual image width style
  const getIndividualImageStyle = (img: StepImage) => {
      // If single image side-by-side, the container is sized, so image is 100% of container
      if (isSideBySide && step.images.length === 1) return { width: '100%' };

      // Otherwise use stored width or calc for grid
      if (img.width) return { width: `${img.width}%` };

      // Fallback for grid
      if (step.images.length === 1) return { width: `${metadata.singleImageSize || 100}%` };
      const perRow = metadata.imagesPerRow || 2;
      return { width: `calc((100% - ${(perRow - 1) * 8}px) / ${perRow})` };
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-zinc-100 p-1 transition-all hover:shadow-md hover:border-zinc-300 group">
      {/* Header */}
      <div className="flex justify-between items-center p-3 bg-surface-50 rounded-xl mb-3">
        <div className="flex items-center gap-2">
            <span className="w-6 h-6 flex items-center justify-center bg-zinc-900 text-white rounded-md text-xs font-bold">{index + 1}</span>
            <div className="h-4 w-px bg-zinc-200 mx-1"></div>
            {/* Compact Layout Controls */}
            <div className="flex bg-white rounded-lg p-0.5 shadow-sm border border-zinc-100">
               {[
                   { id: 'image_left_text_right', icon: 'fas fa-columns' },
                   { id: 'text_left_image_right', icon: 'fas fa-columns fa-flip-horizontal' },
                   { id: 'image_top_text_bottom', icon: 'fas fa-window-maximize' },
                   { id: 'text_top_image_bottom', icon: 'fas fa-window-maximize fa-flip-vertical' }
               ].map((layoutOpt) => (
                   <button
                    key={layoutOpt.id}
                    onClick={() => onUpdate(step.id, { layout: layoutOpt.id as StepLayout })}
                    className={`w-6 h-6 flex items-center justify-center rounded-md text-[10px] transition-colors ${step.layout === layoutOpt.id ? 'bg-zinc-800 text-white' : 'text-zinc-400 hover:bg-surface-100'}`}
                   >
                       <i className={layoutOpt.icon}></i>
                   </button>
               ))}
            </div>
        </div>
        <div className="flex items-center gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
            <button onClick={() => onMoveUp(index)} disabled={index === 0} className="p-1.5 text-zinc-400 hover:text-zinc-800 disabled:opacity-30"><i className="fas fa-chevron-up text-xs"></i></button>
            <button onClick={() => onMoveDown(index)} disabled={index === totalSteps - 1} className="p-1.5 text-zinc-400 hover:text-zinc-800 disabled:opacity-30"><i className="fas fa-chevron-down text-xs"></i></button>
            <button onClick={() => onDelete(step.id)} className="p-1.5 text-zinc-400 hover:text-red-500 ml-1"><i className="fas fa-trash-alt text-xs"></i></button>
        </div>
      </div>

      <div className="px-3 pb-3">
        <div className="flex flex-col gap-4">
            {/* Content Area */}
            <div 
                ref={rowContainerRef} 
                className={`flex gap-4 step-row-container ${isVertical ? 'flex-col' : 'flex-col md:flex-row'}`}
            >
                {/* Image Section */}
                <div 
                    className={`
                        flex-shrink-0 
                        ${!isImageFirst && !isVertical ? 'order-2 md:order-2' : 'order-1'}
                    `}
                    style={getImageContainerStyle()}
                >
                    <div className="space-y-2">
                        {step.images.length > 0 && (
                            <div ref={imagesContainerRef} className="flex flex-wrap gap-2 w-full">
                                {step.images.map((img) => (
                                    <div 
                                      key={img.id} 
                                      className="relative rounded-lg border border-zinc-200 group/img image-container select-none hover:z-20"
                                      style={getIndividualImageStyle(img)}
                                    >
                                        <div className="aspect-square w-full h-full overflow-hidden rounded-lg bg-surface-50">
                                            <img src={img.url} alt="Step" className="w-full h-full object-cover pointer-events-none" />
                                        </div>
                                        <button 
                                            onClick={() => handleRemoveImage(img.id)} 
                                            className="absolute -top-2 -right-2 w-6 h-6 bg-white text-zinc-400 hover:text-red-500 border border-zinc-200 rounded-full shadow-sm flex items-center justify-center text-xs opacity-0 group-hover/img:opacity-100 transition-all z-30 hover:scale-110 cursor-pointer"
                                            title="Remove Image"
                                        >
                                            <i className="fas fa-times"></i>
                                        </button>

                                        {/* Resize Handle */}
                                        <div 
                                            className="absolute bottom-1 right-1 w-6 h-6 bg-white/80 backdrop-blur-sm rounded-full shadow-sm flex items-center justify-center cursor-nwse-resize opacity-0 group-hover/img:opacity-100 transition-opacity z-10 hover:bg-white text-zinc-600"
                                            onMouseDown={(e) => handleResizeStart(e, img.id)}
                                            title="Drag to resize"
                                        >
                                            <i className="fas fa-expand-alt text-[10px] transform rotate-90"></i>
                                        </div>

                                        {/* Size Label */}
                                        <div className={`absolute bottom-1 left-1 bg-black/60 text-white text-[9px] px-1.5 py-0.5 rounded backdrop-blur-md transition-opacity ${resizingImgId === img.id ? 'opacity-100' : 'opacity-0 group-hover/img:opacity-100'}`}>
                                            {img.width ? Math.round(img.width) : 'Auto'}%
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                        <label className={`flex flex-col items-center justify-center border-2 border-dashed border-zinc-200 rounded-lg hover:border-brand-400 hover:bg-brand-50/30 transition-all cursor-pointer ${step.images.length > 0 ? 'h-10 border-solid border-zinc-100 bg-surface-50 text-xs text-zinc-500' : 'aspect-[4/3]'}`}>
                             {step.images.length > 0 ? <span className="font-bold">+ Add Image</span> : (
                                 <div className="text-center">
                                     <i className="fas fa-image text-zinc-300 text-2xl mb-2"></i>
                                     <span className="block text-xs font-bold text-zinc-400">Upload Image</span>
                                 </div>
                             )}
                             <input type="file" accept="image/*" multiple onChange={handleImagesChange} className="hidden" />
                        </label>
                         {step.images.length > 0 && (
                            <button onClick={handleAnalyzeImages} disabled={isAnalyzing} className="w-full py-1.5 bg-brand-50 text-brand-600 rounded-lg text-[10px] font-bold uppercase tracking-wider btn-animated-glow">
                                {isAnalyzing ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-magic mr-1"></i>} AI Describe
                            </button>
                        )}
                    </div>
                </div>

                {/* Text Section */}
                <div className={`flex-1 space-y-3 ${!isImageFirst && !isVertical ? 'order-1 md:order-1' : 'order-2'}`}>
                    <div className="relative group/title">
                        <input
                            type="text"
                            value={step.title}
                            onChange={(e) => onUpdate(step.id, { title: e.target.value })}
                            placeholder="Step Title"
                            className="w-full text-base font-bold text-zinc-800 placeholder:text-zinc-300 border-none p-0 focus:ring-0 bg-transparent"
                        />
                         <button
                            type="button"
                            onClick={handleGenerateTitle}
                            disabled={isGeneratingTitle || !step.description}
                            className="absolute right-0 top-1/2 -translate-y-1/2 text-[10px] font-bold text-brand-600 bg-brand-50 px-2 py-0.5 rounded opacity-0 group-hover/title:opacity-100 transition-opacity disabled:opacity-0"
                        >
                            Generate
                        </button>
                    </div>
                    <textarea
                        rows={5}
                        value={step.description}
                        onChange={(e) => onUpdate(step.id, { description: e.target.value })}
                        placeholder="Description..."
                        className="w-full p-3 bg-surface-50 border border-zinc-100 rounded-xl text-sm text-zinc-600 focus:bg-white focus:border-brand-500 focus:ring-1 focus:ring-brand-500 outline-none resize-none transition-all"
                    />
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default StepEditor;

import React, { useLayoutEffect, useRef } from 'react';
import { ManualPage, ManualMetadata, PageDimensions, StepLayout } from '../types';

interface PreviewProps {
  pages: ManualPage[];
  metadata: ManualMetadata;
  dimensions: PageDimensions;
  previewRef: React.RefObject<HTMLDivElement>;
  onPageOverflow: (pageIndex: number) => void;
}

const PageContainer: React.FC<{
  page: ManualPage;
  pageIndex: number;
  allPages: ManualPage[];
  totalPages: number;
  metadata: ManualMetadata;
  dimensions: PageDimensions;
  onOverflow: (index: number) => void;
}> = ({ page, pageIndex, allPages, totalPages, metadata, dimensions, onOverflow }) => {
  const pageRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  useLayoutEffect(() => {
    if (page.type === 'content' && contentRef.current) {
      const containerHeight = contentRef.current.clientHeight;
      const contentHeight = contentRef.current.scrollHeight;
      if (contentHeight > containerHeight + 1 && page.steps.length > 1) {
        const timer = setTimeout(() => { onOverflow(pageIndex); }, 500);
        return () => clearTimeout(timer);
      }
    }
  }, [page.steps, pageIndex, onOverflow, page.type]);

  const currentDate = new Date().toLocaleDateString();
  const isFirstPage = pageIndex === 0;

  const renderCover = () => {
    return (
        <div className="h-full relative flex flex-col">
            {page.backgroundImage && (
                <div className="absolute inset-0 z-0">
                    <img src={page.backgroundImage.url} alt="Cover" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-b from-white/90 via-white/50 to-transparent h-1/2"></div>
                </div>
            )}
            <div className="relative z-10 p-16 flex flex-col h-full items-center text-center pt-32">
                 <div className="mb-4 inline-block px-4 py-1.5 bg-zinc-900 text-white rounded text-sm font-bold tracking-widest uppercase">{metadata.version ? `Version ${metadata.version}` : 'Manual'}</div>
                 <h1 className="text-6xl font-extrabold text-zinc-900 tracking-tight leading-tight mb-6 drop-shadow-sm">{metadata.title || "User Manual"}</h1>
                 <h2 className="text-2xl text-zinc-600 font-light max-w-lg leading-relaxed">{metadata.subtitle || "Instruction Guide"}</h2>
                 <div className="mt-auto pb-12 w-full border-t border-zinc-900/10 pt-8">
                    <p className="font-bold text-zinc-800">{metadata.author}</p>
                    <p className="text-sm text-zinc-500 mt-1">{currentDate}</p>
                 </div>
            </div>
        </div>
    );
  };

  const renderBackCover = () => {
     return (
        <div className="h-full relative flex flex-col justify-end">
            {page.backgroundImage && (
                <div className="absolute inset-0 z-0"><img src={page.backgroundImage.url} alt="Back Cover" className="w-full h-full object-cover" /></div>
            )}
            <div className="relative z-10 bg-white p-16 pt-12">
                 <div className="w-16 h-2 bg-zinc-900 mb-8"></div>
                 <h3 className="text-2xl font-bold text-zinc-900 mb-4">Contact & Support</h3>
                 <div className="text-zinc-600 whitespace-pre-wrap leading-relaxed">{page.customText || "Thank you for choosing our product.\n\nFor support, please visit our website or contact our customer service team."}</div>
                 <div className="mt-8 pt-8 border-t border-zinc-200 text-xs text-zinc-400">© {new Date().getFullYear()} {metadata.author}. All rights reserved.</div>
            </div>
        </div>
    );
  };

  const renderTOC = () => {
    const contentPages = allPages.map((p, idx) => ({ ...p, originalIndex: idx })).filter(p => p.type === 'content');
    return (
      <div className="flex flex-col h-full">
         <h1 className="text-3xl font-bold text-zinc-900 mb-12 uppercase tracking-wider text-center border-b-2 border-zinc-900 pb-4">{page.title || "Table of Contents"}</h1>
         <div className="flex-grow space-y-4 px-4">
             {contentPages.map((contentPage) => {
                 let label = contentPage.title;
                 if (!label && contentPage.steps.length > 0) label = contentPage.steps[0].title;
                 if (!label) label = `Page ${contentPage.originalIndex + 1}`;
                 return (
                    <div key={contentPage.id} className="flex items-end mb-4">
                        <div className="font-bold text-zinc-700 text-lg">{label}</div>
                        <div className="flex-grow border-b-2 border-dotted border-zinc-300 mx-2 relative top-[-6px]"></div>
                        <div className="font-bold text-zinc-900 text-lg w-8 text-right">{contentPage.originalIndex + 1}</div>
                    </div>
                 );
             })}
         </div>
      </div>
    );
  };

  if (page.type === 'cover' || page.type === 'back_cover') {
       return (
        <div 
            id={`preview-page-${pageIndex}`}
            ref={pageRef}
            className="bg-white relative shrink-0 mb-12 shadow-paper mx-auto overflow-hidden transition-all duration-300"
            style={{ width: `${dimensions.width}mm`, height: `${dimensions.height}mm` }}
        >
            {page.type === 'cover' ? renderCover() : renderBackCover()}
        </div>
       )
  }

  return (
    <div 
      id={`preview-page-${pageIndex}`}
      ref={pageRef}
      className="bg-white relative shrink-0 mb-12 shadow-paper mx-auto overflow-hidden transition-all duration-300"
      style={{ width: `${dimensions.width}mm`, height: `${dimensions.height}mm` }}
    >
      <div ref={contentRef} className="absolute top-0 left-0 right-0 bottom-32 p-12 flex flex-col">
        {page.type === 'toc' ? renderTOC() : (
          <>
            <header className={`shrink-0 ${isFirstPage ? 'border-b-2 border-zinc-900 pb-6 mb-10' : 'border-b border-zinc-200 pb-4 mb-6'}`}>
              <div className="flex justify-between items-end">
                <div className="max-w-[70%]">
                  <h2 className="text-lg font-bold text-zinc-400 uppercase tracking-wide">
                    {metadata.title || "User Manual"} <span className="text-zinc-300">/ {page.title || "Continued"}</span>
                  </h2>
                </div>
                <div className="text-right"><div className="text-xs text-zinc-400">{currentDate}</div></div>
              </div>
            </header>
            <main className="space-y-8">
              {page.steps.length === 0 && (
                <div className="flex flex-col items-center justify-center h-48 text-zinc-300 border-2 border-dashed border-zinc-100 rounded-xl m-8">
                  <p className="font-medium text-sm">Empty Page</p>
                </div>
              )}
              {page.steps.map((step, idx) => {
                  const isSideBySide = step.layout === 'image_left_text_right' || step.layout === 'text_left_image_right';
                  const isImageFirst = step.layout === 'image_left_text_right' || step.layout === 'image_top_text_bottom';
                  const isVertical = step.layout === 'image_top_text_bottom' || step.layout === 'text_top_image_bottom';

                  // Dynamic Layout Logic
                  let imageColumnWidth = '100%';
                  if (isSideBySide) {
                       if (step.images.length === 1 && step.images[0].width) {
                           imageColumnWidth = `${step.images[0].width}%`;
                       } else {
                           // Default split if not customized or multi-image
                           const defaultWidth = metadata.singleImageSize || 45;
                           imageColumnWidth = `${defaultWidth}%`;
                       }
                  }

                  return (
                    <div key={step.id} className="break-inside-avoid step-item">
                        <div className={`flex gap-6 ${isVertical ? 'flex-col' : 'flex-row'}`}>

                            {/* Text Section */}
                            <div className={`flex-1 ${!isImageFirst ? 'order-1' : 'order-2'}`}>
                                <div className="flex items-start gap-3 mb-2">
                                    {metadata.showStepMarkers && (<div className="flex-shrink-0 pt-2"><div className="w-2.5 h-2.5 rounded-full bg-zinc-900"></div></div>)}
                                    <h3 className="text-lg font-bold text-zinc-800 uppercase tracking-wide leading-tight">{step.title || "Untitled Step"}</h3>
                                </div>
                                <div className={metadata.showStepMarkers ? "pl-5" : ""}>
                                  <p className="text-zinc-600 text-sm leading-relaxed whitespace-pre-wrap">{step.description || "No description provided."}</p>
                                </div>
                            </div>

                            {/* Image Section */}
                            {step.images.length > 0 && (
                            <div 
                                className={`flex-shrink-0 ${!isImageFirst ? 'order-2' : 'order-1'}`}
                                style={{ width: imageColumnWidth }}
                            >
                                <div className="flex flex-wrap gap-2">
                                    {step.images.map((img) => {
                                        // Inner image width logic
                                        let widthStyle = '100%';

                                        // For side-by-side single image, the container is already sized to the image width preference.
                                        // So the image just fills the container.
                                        if (isSideBySide && step.images.length === 1) {
                                            widthStyle = '100%';
                                        } else {
                                            // For vertical or multi-image, respect individual settings or defaults
                                            if (img.width) {
                                                widthStyle = `${img.width}%`;
                                            } else {
                                                 if (step.images.length === 1) {
                                                     widthStyle = `${metadata.singleImageSize || 100}%`;
                                                 } else {
                                                     const perRow = metadata.imagesPerRow || 2;
                                                     widthStyle = `calc((100% - ${(perRow - 1) * 8}px) / ${perRow})`;
                                                 }
                                            }
                                        }

                                        return (
                                        <div 
                                          key={img.id} 
                                          className="rounded-lg border border-zinc-200 overflow-hidden bg-surface-50 shadow-sm"
                                          style={{ width: widthStyle }}
                                        >
                                            <img src={img.url} alt="Step" className="w-full h-auto object-cover" />
                                        </div>
                                    )})}
                                </div>
                            </div>
                            )}
                        </div>
                    </div>
                  );
              })}
            </main>
          </>
        )}
      </div>
      <footer className="absolute bottom-0 left-0 right-0 h-32 px-12 pb-12 pt-4 flex justify-between items-end z-20 bg-white">
          <div className="w-full border-t border-zinc-200 pt-6 flex justify-between items-center text-xs text-zinc-400">
            <p>© {new Date().getFullYear()} {metadata.author || "Your Company"}.</p>
            <div className="font-bold text-zinc-500">Page {pageIndex + 1} of {totalPages}</div>
          </div>
      </footer>
    </div>
  );
};

const Preview: React.FC<PreviewProps> = ({ 
  pages, 
  metadata, 
  dimensions, 
  previewRef, 
  onPageOverflow 
}) => {
  return (
    <div className="flex-1 h-full overflow-y-auto flex justify-center py-10 px-4" ref={previewRef}>
      <div className="flex flex-col items-center gap-8">
        {pages.map((page, index) => (
          <PageContainer
            key={page.id}
            page={page}
            pageIndex={index}
            allPages={pages}
