import React, { useState, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { ManualStep, StepLayout, StepImage, ManualMetadata } from '../types';
import { generateDescriptionFromImages, generateStepTitle } from '../services/geminiService';

interface StepEditorProps {
  step: ManualStep;
  index: number;
  metadata: ManualMetadata;
  onUpdate: (id: string, updates: Partial<ManualStep>) => void;
  onDelete: (id: string) => void;
  onMoveUp: (index: number) => void;
  onMoveDown: (index: number) => void;
  totalSteps: number;
}

const StepEditor: React.FC<StepEditorProps> = ({ 
  step, index, metadata, onUpdate, onDelete, onMoveUp, onMoveDown, totalSteps
}) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [resizingImgId, setResizingImgId] = useState<string | null>(null);

  const imagesContainerRef = useRef<HTMLDivElement>(null);
  const rowContainerRef = useRef<HTMLDivElement>(null);

  const handleImagesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newImages = (Array.from(e.target.files) as File[]).filter(file => {
        if (file.size > 3 * 1024 * 1024) {
          alert(`File ${file.name} is too large (max 3MB).`);
          return false;
        }
        return true;
      }).map(file => ({
        id: uuidv4(),
        url: URL.createObjectURL(file),
        file,
        // No default width set, will fallback to metadata settings
      }));
      onUpdate(step.id, { images: [...step.images, ...newImages] });
    }
  };

  const handleRemoveImage = (imageId: string) => {
    onUpdate(step.id, { images: step.images.filter(img => img.id !== imageId) });
  };

  const handleAnalyzeImages = async () => {
    if (step.images.length === 0) return;
    setIsAnalyzing(true);
    try {
      const files = step.images.map(img => img.file);
      const description = await generateDescriptionFromImages(files);
      onUpdate(step.id, { description });
    } catch (error) { alert("Failed to analyze images."); } finally { setIsAnalyzing(false); }
  };

  const handleGenerateTitle = async () => {
    if (!step.description) return;
    setIsGeneratingTitle(true);
    try {
      const title = await generateStepTitle(step.description);
      onUpdate(step.id, { title });
    } catch (error) { alert("Failed to generate title."); } finally { setIsGeneratingTitle(false); }
  };

  const handleResizeStart = (e: React.MouseEvent, imgId: string) => {
    e.preventDefault();
    e.stopPropagation();
    const handle = e.currentTarget as HTMLElement;
    const container = handle.closest('.image-container') as HTMLElement;
    if (!container || !imagesContainerRef.current) return;

    const startX = e.clientX;
    const startWidth = container.offsetWidth;

    // In the editor, we are always consistent (side-by-side view), so resize logic is consistent
    let parentWidth = imagesContainerRef.current.offsetWidth;
    // If single image, we are resizing the container column relative to the row
    if (step.images.length === 1 && rowContainerRef.current) {
         parentWidth = rowContainerRef.current.offsetWidth;
    }

    setResizingImgId(imgId);

    const handleMouseMove = (moveEvent: MouseEvent) => {
      moveEvent.preventDefault();
      const deltaX = moveEvent.clientX - startX;
      let newWidthPx = startWidth + deltaX;
      let newWidthPercent = (newWidthPx / parentWidth) * 100;

      // Constraints
      newWidthPercent = Math.max(15, Math.min(100, newWidthPercent));

      // Snapping
      const snapPoints = [16.66, 20, 25, 33.33, 40, 45, 50, 60, 66.66, 75, 100];
      for (const snap of snapPoints) {
        if (Math.abs(newWidthPercent - snap) < 2) {
          newWidthPercent = snap;
          break;
        }
      }

      onUpdate(step.id, {
        images: step.images.map(img => 
          img.id === imgId ? { ...img, width: newWidthPercent } : img
        )
      });
    };

    const handleMouseUp = () => {
      setResizingImgId(null);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  // Fixed Editor Layout Logic: Always Side-by-Side (Image Left, Text Right) for stability
  // This decoupling ensures the editor UI doesn't jump around or break when changing PDF layout options.

  // Determine Image Container Width style
  const getImageContainerStyle = () => {
      // If manually sized single image, use that width
      if (step.images.length === 1 && step.images[0].width) {
          return { width: `${step.images[0].width}%` };
      }
      // Default stable width for Editor View
      return { width: '45%' };
  };

  // Determine individual image width style
  const getIndividualImageStyle = (img: StepImage) => {
      // In editor, if single image, it fills the column container
      if (step.images.length === 1) return { width: '100%' };

      // If multi-image grid, respect settings
      if (img.width) return { width: `${img.width}%` };

      const perRow = metadata.imagesPerRow || 2;
      return { width: `calc((100% - ${(perRow - 1) * 8}px) / ${perRow})` };
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-zinc-100 p-1 transition-all hover:shadow-md hover:border-zinc-300 group">
      {/* Header */}
      <div className="flex justify-between items-center p-3 bg-surface-50 rounded-xl mb-3">
        <div className="flex items-center gap-2">
            <span className="w-6 h-6 flex items-center justify-center bg-zinc-900 text-white rounded-md text-xs font-bold">{index + 1}</span>
            <div className="h-4 w-px bg-zinc-200 mx-1"></div>
            {/* Compact Layout Controls - These affect the PREVIEW/PDF, not the Editor UI */}
            <div className="flex bg-white rounded-lg p-0.5 shadow-sm border border-zinc-100">
               {[
                   { id: 'image_left_text_right', icon: 'fas fa-columns' },
                   { id: 'text_left_image_right', icon: 'fas fa-columns fa-flip-horizontal' },
                   { id: 'image_top_text_bottom', icon: 'fas fa-window-maximize' },
                   { id: 'text_top_image_bottom', icon: 'fas fa-window-maximize fa-flip-vertical' }
               ].map((layoutOpt) => (
                   <button
                    key={layoutOpt.id}
                    onClick={() => onUpdate(step.id, { layout: layoutOpt.id as StepLayout })}
                    className={`w-6 h-6 flex items-center justify-center rounded-md text-[10px] transition-colors ${step.layout === layoutOpt.id ? 'bg-zinc-800 text-white' : 'text-zinc-400 hover:bg-surface-100'}`}
                    title="Set PDF Layout"
                   >
                       <i className={layoutOpt.icon}></i>
                   </button>
               ))}
            </div>
        </div>
        <div className="flex items-center gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
            <button onClick={() => onMoveUp(index)} disabled={index === 0} className="p-1.5 text-zinc-400 hover:text-zinc-800 disabled:opacity-30"><i className="fas fa-chevron-up text-xs"></i></button>
            <button onClick={() => onMoveDown(index)} disabled={index === totalSteps - 1} className="p-1.5 text-zinc-400 hover:text-zinc-800 disabled:opacity-30"><i className="fas fa-chevron-down text-xs"></i></button>
            <button onClick={() => onDelete(step.id)} className="p-1.5 text-zinc-400 hover:text-red-500 ml-1"><i className="fas fa-trash-alt text-xs"></i></button>
        </div>
      </div>

      <div className="px-3 pb-3">
        <div className="flex flex-col gap-4">
            {/* Content Area - Fixed Layout for Editing Stability */}
            <div 
                ref={rowContainerRef} 
                className="flex gap-4 step-row-container flex-col md:flex-row"
