import React, { useState, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { ManualStep, StepLayout, StepImage, ManualMetadata } from '../types';
import { generateDescriptionFromImages, generateStepTitle } from '../services/geminiService';

interface StepEditorProps {
  step: ManualStep;
  index: number;
  metadata: ManualMetadata;
  onUpdate: (id: string, updates: Partial<ManualStep>) => void;
  onDelete: (id: string) => void;
  onMoveUp: (index: number) => void;
  onMoveDown: (index: number) => void;
  totalSteps: number;
}

const StepEditor: React.FC<StepEditorProps> = ({ 
  step, index, metadata, onUpdate, onDelete, onMoveUp, onMoveDown, totalSteps
}) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);

  const imagesContainerRef = useRef<HTMLDivElement>(null);

  const handleImagesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newImages = (Array.from(e.target.files) as File[]).filter(file => {
        if (file.size > 3 * 1024 * 1024) {
          alert(`File ${file.name} is too large (max 3MB).`);
          return false;
        }
        return true;
      }).map(file => ({
        id: uuidv4(),
        url: URL.createObjectURL(file),
        file,
        // No default width set, will fallback to metadata settings
      }));
      onUpdate(step.id, { images: [...step.images, ...newImages] });
    }
  };

  const handleRemoveImage = (imageId: string) => {
    onUpdate(step.id, { images: step.images.filter(img => img.id !== imageId) });
  };

  const handleLayoutChange = (newLayout: StepLayout) => {
      const isVertical = newLayout === 'image_top_text_bottom' || newLayout === 'text_top_image_bottom';
      const updates: Partial<ManualStep> = { layout: newLayout };

      // If switching to vertical and imagesPerRow is not set, default to 6 as requested
      if (isVertical && !step.imagesPerRow) {
          updates.imagesPerRow = 6;
      }

      onUpdate(step.id, updates);
  };

  const handleAnalyzeImages = async () => {
    if (step.images.length === 0) return;
    setIsAnalyzing(true);
    try {
      const files = step.images.map(img => img.file);
      const description = await generateDescriptionFromImages(files);
      onUpdate(step.id, { description });
    } catch (error) { alert("Failed to analyze images."); } finally { setIsAnalyzing(false); }
  };

  const handleGenerateTitle = async () => {
    if (!step.description) return;
    setIsGeneratingTitle(true);
    try {
      const title = await generateStepTitle(step.description);
      onUpdate(step.id, { title });
    } catch (error) { alert("Failed to generate title."); } finally { setIsGeneratingTitle(false); }
  };

  // Fixed Editor Layout Logic: Always Side-by-Side (Image Left, Text Right) for stability
  // This decoupling ensures the editor UI doesn't jump around or break when changing PDF layout options.
  const getImageContainerStyle = () => {
      return { width: '45%' }; // Fixed width for editor stability
  };

  // Determine individual image width style for the EDITOR visualization
  const getIndividualImageStyle = (img: StepImage) => {
      // In editor, single image takes full width of the fixed container
      if (step.images.length === 1) return { width: '100%' };

      // Multi-image grid logic for Editor visualization
      const perRow = step.imagesPerRow || (metadata.imagesPerRow || 2);
      return { width: `calc((100% - ${(perRow - 1) * 8}px) / ${perRow})` };
  };

  // Check if current layout is vertical for the slider default value display logic
  const isVerticalPDFLayout = step.layout === 'image_top_text_bottom' || step.layout === 'text_top_image_bottom';

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-zinc-100 p-1 transition-all hover:shadow-md hover:border-zinc-300 group">
      {/* Header */}
      <div className="flex justify-between items-center p-3 bg-surface-50 rounded-xl mb-3">
        <div className="flex items-center gap-2">
            <span className="w-6 h-6 flex items-center justify-center bg-zinc-900 text-white rounded-md text-xs font-bold">{index + 1}</span>
            <div className="h-4 w-px bg-zinc-200 mx-1"></div>
            {/* Compact Layout Controls - These affect the PREVIEW/PDF, not the Editor UI */}
            <div className="flex bg-white rounded-lg p-0.5 shadow-sm border border-zinc-100">
               {[
                   { id: 'image_left_text_right', icon: 'fas fa-columns' },
                   { id: 'text_left_image_right', icon: 'fas fa-columns fa-flip-horizontal' },
                   { id: 'image_top_text_bottom', icon: 'fas fa-window-maximize' },
                   { id: 'text_top_image_bottom', icon: 'fas fa-window-maximize fa-flip-vertical' }
               ].map((layoutOpt) => (
                   <button
                    key={layoutOpt.id}
                    onClick={() => handleLayoutChange(layoutOpt.id as StepLayout)}
                    className={`w-6 h-6 flex items-center justify-center rounded-md text-[10px] transition-colors ${step.layout === layoutOpt.id ? 'bg-zinc-800 text-white' : 'text-zinc-400 hover:bg-surface-100'}`}
                    title="Set PDF Layout"
                   >
                       <i className={layoutOpt.icon}></i>
                   </button>
               ))}
            </div>
        </div>
        <div className="flex items-center gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
            <button onClick={() => onMoveUp(index)} disabled={index === 0} className="p-1.5 text-zinc-400 hover:text-zinc-800 disabled:opacity-30"><i className="fas fa-chevron-up text-xs"></i></button>
            <button onClick={() => onMoveDown(index)} disabled={index === totalSteps - 1} className="p-1.5 text-zinc-400 hover:text-zinc-800 disabled:opacity-30"><i className="fas fa-chevron-down text-xs"></i></button>
            <button onClick={() => onDelete(step.id)} className="p-1.5 text-zinc-400 hover:text-red-500 ml-1"><i className="fas fa-trash-alt text-xs"></i></button>
        </div>
      </div>

      <div className="px-3 pb-3">
        <div className="flex flex-col gap-4">
            {/* Content Area - Fixed Layout for Editing Stability */}
            <div 
                className="flex gap-4 step-row-container flex-col md:flex-row"
            >
                {/* Image Section - Always First in Editor */}
                <div 
                    className="flex-shrink-0 order-1"
                    style={getImageContainerStyle()}
                >
                    <div className="space-y-2">
                         {/* Controls for Single Image: Size Slider */}
                        {step.images.length === 1 && (
                            <div className="flex items-center gap-2 mb-2 p-2 bg-surface-50 rounded-lg border border-zinc-100">
                                <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Size</span>
                                <input 
                                    type="range" 
                                    min="25" max="100" step="5"
                                    value={step.images[0].width || metadata.singleImageSize || 50}
                                    onChange={(e) => {
                                        const val = parseInt(e.target.value);
                                        onUpdate(step.id, {
                                            images: step.images.map((img, i) => i === 0 ? { ...img, width: val } : img)
                                        });
                                    }}
                                    className="flex-1 h-1.5 bg-zinc-200 rounded-lg appearance-none cursor-pointer accent-zinc-800"
                                    title="Adjust image width in PDF"
                                />
                                <span className="font-bold text-xs text-zinc-700 min-w-[3ch] text-right">{step.images[0].width || metadata.singleImageSize || 50}%</span>
                            </div>
                        )}

                         {/* Controls for Multiple Images: Grid Slider */}
                        {step.images.length > 1 && (
                            <div className="flex items-center gap-2 mb-2 p-2 bg-surface-50 rounded-lg border border-zinc-100">
                                <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Grid</span>
                                <input 
                                    type="range" 
                                    min="1" max="6" 
                                    value={step.imagesPerRow || (isVerticalPDFLayout ? 6 : (metadata.imagesPerRow || 2))}
                                    onChange={(e) => onUpdate(step.id, { imagesPerRow: parseInt(e.target.value) })}
                                    className="flex-1 h-1.5 bg-zinc-200 rounded-lg appearance-none cursor-pointer accent-zinc-800"
                                />
                                <span className="font-bold text-xs text-zinc-700 min-w-[1ch]">{step.imagesPerRow || (isVerticalPDFLayout ? 6 : (metadata.imagesPerRow || 2))}</span>
                            </div>
                        )}

                        {step.images.length > 0 && (
                            <div ref={imagesContainerRef} className="flex flex-wrap gap-2 w-full">
                                {step.images.map((img) => (
                                    <div 
                                      key={img.id} 
                                      className="relative rounded-lg border border-zinc-200 group/img image-container select-none hover:z-20"
                                      style={getIndividualImageStyle(img)}
                                    >
                                        <div className="w-full overflow-hidden rounded-lg bg-surface-50">
                                            <img src={img.url} alt="Step" className="w-full h-auto block pointer-events-none" />
                                        </div>
                                        <button 
                                            onClick={() => handleRemoveImage(img.id)} 
                                            className="absolute -top-2 -right-2 w-6 h-6 bg-white text-zinc-400 hover:text-red-500 border border-zinc-200 rounded-full shadow-sm flex items-center justify-center text-xs opacity-0 group-hover/img:opacity-100 transition-all z-30 hover:scale-110 cursor-pointer"
                                            title="Remove Image"
                                        >
                                            <i className="fas fa-times"></i>
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}
                        <label className={`flex flex-col items-center justify-center border-2 border-dashed border-zinc-200 rounded-lg hover:border-brand-400 hover:bg-brand-50/30 transition-all cursor-pointer ${step.images.length > 0 ? 'h-10 border-solid border-zinc-100 bg-surface-50 text-xs text-zinc-500' : 'aspect-[4/3]'}`}>
                             {step.images.length > 0 ? <span className="font-bold">+ Add Image</span> : (
                                 <div className="text-center">
                                     <i className="fas fa-image text-zinc-300 text-2xl mb-2"></i>
                                     <span className="block text-xs font-bold text-zinc-400">Upload Image</span>
                                 </div>
                             )}
                             <input type="file" accept="image/*" multiple onChange={handleImagesChange} className="hidden" />
                        </label>
                         {step.images.length > 0 && (
                            <button onClick={handleAnalyzeImages} disabled={isAnalyzing} className="w-full py-1.5 bg-brand-50 text-brand-600 rounded-lg text-[10px] font-bold uppercase tracking-wider btn-animated-glow">
                                {isAnalyzing ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-magic mr-1"></i>} AI Describe
                            </button>
                        )}
                    </div>
                </div>

                {/* Text Section - Always Second in Editor */}
                <div className="flex-1 space-y-3 order-2">
                    <div className="relative group/title">
                        <input
                            type="text"
                            value={step.title}
                            onChange={(e) => onUpdate(step.id, { title: e.target.value })}
                            placeholder="Step Title"
                            className="w-full text-base font-bold text-zinc-800 placeholder:text-zinc-300 border-none p-0 focus:ring-0 bg-transparent"
                        />
                         <button
                            type="button"
                            onClick={handleGenerateTitle}
                            disabled={isGeneratingTitle || !step.description}
                            className="absolute right-0 top-1/2 -translate-y-1/2 text-[10px] font-bold text-brand-600 bg-brand-50 px-2 py-0.5 rounded opacity-0 group-hover/title:opacity-100 transition-opacity disabled:opacity-0"
                        >
                            Generate
                        </button>
                    </div>
                    <textarea
                        rows={5}
                        value={step.description}
                        onChange={(e) => onUpdate(step.id, { description: e.target.value })}
                        placeholder="Description..."
                        className="w-full p-3 bg-surface-50 border border-zinc-100 rounded-xl text-sm text-zinc-600 focus:bg-white focus:border-brand-500 focus:ring-1 focus:ring-brand-500 outline-none resize-none transition-all"
                    />
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default StepEditor;

