};

export const generateCoverDesign = async (context: string): Promise<{ 
  title: string; 
  subtitle: string;
  design: CoverDesignParams;
}> => {
  const ai = createClient();

  const prompt = `
    You are a professional graphic designer for product manuals. 
    Based on the content of the manual provided below, suggest a catchy, professional Title and Subtitle.

    Additionally, define a UNIQUE visual design style for the cover page.
    - Pick a color palette (Hex codes) that fits the mood (e.g., technical, friendly, eco, luxury).
    - Choose a layout mode: 
      - 'centered': Classic centered text.
      - 'split': Split screen (image/color).
      - 'overlay': Text over full image with contrast.
      - 'minimal': Very clean, lots of whitespace.
      - 'card': Text inside a floating card container.
    - Choose a font style ('sans', 'serif', 'mono').

    Manual Content Summary:
    ${context.slice(0, 2000)}

    Return JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            subtitle: { type: Type.STRING },
            design: {
              type: Type.OBJECT,
              properties: {
                primaryColor: { type: Type.STRING, description: "Main background or accent color (Hex)" },
                secondaryColor: { type: Type.STRING, description: "Secondary background or element color (Hex)" },
                textColor: { type: Type.STRING, description: "Main text color (Hex)" },
                layoutMode: { type: Type.STRING, enum: ['centered', 'split', 'overlay', 'minimal', 'card'] },
                fontStyle: { type: Type.STRING, enum: ['sans', 'serif', 'mono'] },
                overlayOpacity: { type: Type.NUMBER, description: "0.0 to 1.0, opacity of overlay if needed" }
              },
              required: ["primaryColor", "secondaryColor", "textColor", "layoutMode", "fontStyle"]
            }
          },
          required: ["title", "subtitle", "design"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as { title: string; subtitle: string; design: CoverDesignParams };
  } catch (error) {
    console.error("Error generating cover design:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { ManualPage, ManualMetadata } from '../types';
import { generateCoverDesign } from '../services/geminiService';

interface CoverEditorProps {
  page: ManualPage;
  onUpdate: (updates: Partial<ManualPage>) => void;
  metadata: ManualMetadata;
  onUpdateMetadata: (updates: Partial<ManualMetadata>) => void;
  contextSteps: string;
}

const STYLES = [
    { id: 'style-1', name: 'Classic', icon: 'fas fa-image' },
    { id: 'style-2', name: 'Modern Split', icon: 'fas fa-columns' },
    { id: 'style-3', name: 'Bold Left', icon: 'fas fa-align-left' },
    { id: 'style-4', name: 'Tech Frame', icon: 'far fa-square' },
    { id: 'style-5', name: 'Magazine', icon: 'fas fa-newspaper' }
];

const CoverEditor: React.FC<CoverEditorProps> = ({ page, onUpdate, metadata, onUpdateMetadata, contextSteps }) => {
  const [isGenerating, setIsGenerating] = useState(false);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > 5 * 1024 * 1024) { alert("File too large (max 5MB)"); return; }
      const newImage = { id: uuidv4(), url: URL.createObjectURL(file), file };
      onUpdate({ backgroundImage: newImage });
    }
  };

  const handleAIDesign = async () => {
      if (!contextSteps) {
          alert("Please add some content steps first so AI can understand your manual.");
          return;
      }
      setIsGenerating(true);
      try {
          const result = await generateCoverDesign(contextSteps);

          // Update Text
          onUpdateMetadata({
              title: result.title,
              subtitle: result.subtitle
          });

          // Update Design to Dynamic AI Style
          onUpdate({ 
            layoutStyle: 'style-ai-generated',
            coverDesign: result.design 
          });

      } catch (error) {
          console.error(error);
          alert("AI Design failed. Please try again.");
      } finally {
          setIsGenerating(false);
      }
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-zinc-100 p-6 space-y-6">

      {/* Header with AI Button */}
      <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
