             <div>
                 <h3 className="text-base font-bold text-zinc-900">Front Cover</h3>
                 <p className="text-xs text-zinc-500">The first page of your manual</p>
             </div>
          </div>
          <button 
            onClick={handleAIDesign}
            disabled={isGenerating}
            className="flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-violet-500 to-fuchsia-500 text-white rounded-lg text-xs font-bold shadow-md hover:shadow-lg transition-all disabled:opacity-50"
          >
              {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-wand-magic-sparkles"></i>}
              AI Auto-Design
          </button>
      </div>

      {/* Layout Style Selector */}
      <div>
          <label className="block text-xs font-bold text-zinc-500 uppercase tracking-wider mb-2">Layout Style</label>
          <div className="grid grid-cols-6 gap-2">
              {STYLES.map(style => (
                  <button
                    key={style.id}
                    onClick={() => onUpdate({ layoutStyle: style.id })}
                    className={`
                        flex flex-col items-center justify-center p-2 rounded-lg border transition-all
                        ${(page.layoutStyle || 'style-1') === style.id ? 'bg-zinc-900 text-white border-zinc-900 ring-2 ring-zinc-900/20' : 'bg-surface-50 text-zinc-500 border-zinc-200 hover:bg-white hover:border-zinc-300'}
                    `}
                    title={style.name}
                  >
                      <i className={`${style.icon} text-lg mb-1`}></i>
                      <span className="text-[9px] font-bold">{style.name.split(' ')[0]}</span>
                  </button>
              ))}
               {/* AI Generated Indicator Button */}
               {page.layoutStyle === 'style-ai-generated' && (
                  <button
                    className="flex flex-col items-center justify-center p-2 rounded-lg border bg-gradient-to-br from-violet-500 to-fuchsia-600 text-white border-transparent ring-2 ring-fuchsia-500/20 shadow-inner"
                    title="Current AI Generated Design"
                    disabled
                  >
                      <i className="fas fa-magic text-lg mb-1"></i>
                      <span className="text-[9px] font-bold">AI Generated</span>
                  </button>
               )}
          </div>
      </div>

      <div className="p-4 bg-surface-50 rounded-xl border border-zinc-100 text-xs text-zinc-500 space-y-1">
        <p><strong className="text-zinc-700">Title:</strong> {metadata.title}</p>
        <p><strong className="text-zinc-700">Subtitle:</strong> {metadata.subtitle}</p>
        <p className="pt-2 opacity-60 italic">Managed in Document Settings</p>
      </div>

      <div>
        <label className="block text-xs font-bold text-zinc-500 uppercase tracking-wider mb-2">Cover Background</label>
        {page.backgroundImage ? (
          <div className="relative rounded-xl overflow-hidden border border-zinc-200 group h-40">
