                             <div className="text-2xl font-bold uppercase tracking-tighter">MANUAL // <span className="text-zinc-400">{metadata.version}</span></div>
                             <div className="text-right font-mono text-xs">
                                 <p>REF: {new Date().getFullYear()}-DOC</p>
                                 <p>{currentDate}</p>
                             </div>
                         </div>
                         <div className="flex-grow relative bg-zinc-50 mb-8 border border-zinc-200">
                             {bgImage && <div className="absolute inset-0">{bgImage}</div>}
                         </div>
                         <div>
                             <h1 className="text-6xl font-black text-zinc-900 mb-2 uppercase">{metadata.title || "MANUAL"}</h1>
                             <h2 className="text-xl font-mono text-zinc-600 bg-zinc-100 inline-block px-2 py-1">{metadata.subtitle}</h2>
                         </div>
                         <div className="absolute bottom-0 right-0 p-2 bg-zinc-900 text-white font-mono text-xs">{metadata.author}</div>
                     </div>
                 </div>
             );
        case 'style-5': // Magazine Overlay
              return (
                <div className="h-full relative">
                    <div className="absolute inset-0 z-0">
                         {bgImage || <div className="w-full h-full bg-zinc-200"></div>}
                    </div>
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-black/40 z-10"></div>
                    <div className="relative z-20 h-full flex flex-col justify-between p-12">
                        <div className="text-center border-b border-white/30 pb-6">
                            <span className="text-white/80 tracking-[0.5em] text-sm uppercase">{metadata.author} PRESENTS</span>
                        </div>
                        <div className="text-center">
                            <h1 className="text-7xl font-serif italic text-white mb-4 drop-shadow-lg">{metadata.title || "Manual"}</h1>
                            <p className="text-white/90 text-xl font-light tracking-wide">{metadata.subtitle}</p>
                        </div>
                        <div className="flex justify-between items-end text-white/70 text-xs font-bold uppercase tracking-widest border-t border-white/30 pt-6">
                            <span>Version {metadata.version}</span>
                            <span>{new Date().getFullYear()} Edition</span>
                        </div>
                    </div>
                </div>
              );
        case 'style-1': // Classic (Default)
        default:
            return (
                <div className="h-full relative flex flex-col">
                    {page.backgroundImage && (
                        <div className="absolute inset-0 z-0">
                            <img src={page.backgroundImage.url} alt="Cover" className="w-full h-full object-cover" />
                            <div className="absolute inset-0 bg-gradient-to-b from-white/90 via-white/50 to-transparent h-1/2"></div>
                        </div>
                    )}
                    <div className="relative z-10 p-16 flex flex-col h-full items-center text-center pt-32">
                        <div className="mb-4 inline-block px-4 py-1.5 bg-zinc-900 text-white rounded text-sm font-bold tracking-widest uppercase">{metadata.version ? `Version ${metadata.version}` : 'Manual'}</div>
                        <h1 className="text-6xl font-extrabold text-zinc-900 tracking-tight leading-tight mb-6 drop-shadow-sm">{metadata.title || "User Manual"}</h1>
                        <h2 className="text-2xl text-zinc-600 font-light max-w-lg leading-relaxed">{metadata.subtitle || "Instruction Guide"}</h2>
                        <div className="mt-auto pb-12 w-full border-t border-zinc-900/10 pt-8">
                            <p className="font-bold text-zinc-800">{metadata.author}</p>
                            <p className="text-sm text-zinc-500 mt-1">{currentDate}</p>
                        </div>
                    </div>
                </div>
            );
    }
  };

  const renderBackCover = () => {
     const style = page.layoutStyle || 'style-1';
     const bgImage = page.backgroundImage ? <img src={page.backgroundImage.url} alt="Back" className="w-full h-full object-cover" /> : null;
     const customText = page.customText || "Thank you for choosing our product.\n\nFor support, please visit our website or contact our customer service team.";

     switch(style) {
         case 'style-2': // Centered
             return (
                 <div className="h-full relative flex flex-col justify-center items-center text-center p-20">
                     {page.backgroundImage && <div className="absolute inset-0 z-0 opacity-20">{bgImage}</div>}
                     <div className="relative z-10">
                         <div className="w-20 h-20 bg-zinc-900 text-white rounded-full flex items-center justify-center text-3xl mb-8 mx-auto"><i className="fas fa-check"></i></div>
                         <h3 className="text-3xl font-bold text-zinc-900 mb-6">Thank You</h3>
                         <div className="text-zinc-600 whitespace-pre-wrap leading-relaxed max-w-md mx-auto mb-12">{customText}</div>
                         <div className="text-sm font-bold text-brand-600">{metadata.author}</div>
                     </div>
                 </div>
             );
         case 'style-3': // Dark Mode
             return (
                 <div className="h-full bg-zinc-900 text-white p-16 flex flex-col justify-between relative overflow-hidden">
                     {page.backgroundImage && <div className="absolute inset-0 z-0 opacity-30 mix-blend-overlay">{bgImage}</div>}
                     <div className="relative z-10 border-l-4 border-brand-500 pl-6">
                         <h2 className="text-4xl font-bold mb-2">{metadata.title}</h2>
                         <p className="text-zinc-400">User Manual End</p>
                     </div>
                     <div className="relative z-10">
                         <h4 className="text-zinc-500 uppercase tracking-widest text-sm mb-4">Support</h4>
                         <div className="text-zinc-300 whitespace-pre-wrap leading-relaxed">{customText}</div>
                     </div>
                 </div>
             );
         case 'style-4': // Split
              return (
                  <div className="h-full flex">
                      <div className="w-1/2 bg-zinc-100 relative">
                          {bgImage || <div className="w-full h-full flex items-center justify-center text-zinc-300"><i className="fas fa-image text-5xl"></i></div>}
                      </div>
                      <div className="w-1/2 bg-white p-12 flex flex-col justify-center">
                          <h3 className="text-2xl font-bold text-zinc-900 mb-6">Contact Us</h3>
                          <div className="w-12 h-1 bg-brand-500 mb-6"></div>
                          <div className="text-zinc-600 whitespace-pre-wrap leading-relaxed mb-8">{customText}</div>
                          <div className="mt-auto text-xs text-zinc-400">© {new Date().getFullYear()} {metadata.author}</div>
                      </div>
                  </div>
              );
         case 'style-5': // Minimal
              return (
                  <div className="h-full flex flex-col items-center justify-between p-24 bg-surface-50">
                       <div className="text-center pt-20">
                            <div className="text-4xl font-black tracking-tighter text-zinc-200 mb-4 uppercase">FIN</div>
                       </div>
                       <div className="text-center max-w-sm">
                            <div className="text-zinc-500 text-sm whitespace-pre-wrap">{customText}</div>
                       </div>
                       <div className="text-xs font-mono text-zinc-300">{metadata.author} • {new Date().getFullYear()}</div>
                  </div>
              );
         case 'style-1': // Simple (Default)
         default:
            return (
                <div className="h-full relative flex flex-col justify-end">
                    {page.backgroundImage && (
                        <div className="absolute inset-0 z-0"><img src={page.backgroundImage.url} alt="Back Cover" className="w-full h-full object-cover" /></div>
                    )}
                    <div className="relative z-10 bg-white p-16 pt-12">
                        <div className="w-16 h-2 bg-zinc-900 mb-8"></div>
                        <h3 className="text-2xl font-bold text-zinc-900 mb-4">Contact & Support</h3>
                        <div className="text-zinc-600 whitespace-pre-wrap leading-relaxed">{customText}</div>
                        <div className="mt-8 pt-8 border-t border-zinc-200 text-xs text-zinc-400">© {new Date().getFullYear()} {metadata.author}. All rights reserved.</div>
                    </div>
                </div>
            );
     }
  };

  const renderTOC = () => {
    const contentPages = allPages.map((p, idx) => ({ ...p, originalIndex: idx })).filter(p => p.type === 'content');
    return (
      <div className="flex flex-col h-full">
         <h1 className="text-3xl font-bold text-zinc-900 mb-12 uppercase tracking-wider text-center border-b-2 border-zinc-900 pb-4">{page.title || "Table of Contents"}</h1>
         <div className="flex-grow space-y-4 px-4">
             {contentPages.map((contentPage) => {
                 let label = contentPage.title;
                 if (!label && contentPage.steps.length > 0) label = contentPage.steps[0].title;
                 if (!label) label = `Page ${contentPage.originalIndex + 1}`;
                 return (
                    <div key={contentPage.id} className="flex items-end mb-4">
                        <div className="font-bold text-zinc-700 text-lg">{label}</div>
                        <div className="flex-grow border-b-2 border-dotted border-zinc-300 mx-2 relative top-[-6px]"></div>
                        <div className="font-bold text-zinc-900 text-lg w-8 text-right">{contentPage.originalIndex + 1}</div>
                    </div>
                 );
             })}
         </div>
      </div>
    );
  };

  if (page.type === 'cover' || page.type === 'back_cover') {
       return (
        <div 
            id={`preview-page-${pageIndex}`}
            ref={pageRef}
            className="bg-white relative shrink-0 mb-12 shadow-paper mx-auto overflow-hidden transition-all duration-300"
            style={{ width: `${dimensions.width}mm`, height: `${dimensions.height}mm` }}
        >
            {page.type === 'cover' ? renderCover() : renderBackCover()}
        </div>
       )
  }

  return (
    <div 
      id={`preview-page-${pageIndex}`}
      ref={pageRef}
      className="bg-white relative shrink-0 mb-12 shadow-paper mx-auto overflow-hidden transition-all duration-300"
      style={{ width: `${dimensions.width}mm`, height: `${dimensions.height}mm` }}
    >
      <div ref={contentRef} className="absolute top-0 left-0 right-0 bottom-32 p-12 flex flex-col">
        {page.type === 'toc' ? renderTOC() : (
          <>
            <header className={`shrink-0 ${isFirstPage ? 'border-b-2 border-zinc-900 pb-6 mb-10' : 'border-b border-zinc-200 pb-4 mb-6'}`}>
              <div className="flex justify-between items-end">
                <div className="max-w-[70%]">
                  <h2 className="text-lg font-bold text-zinc-400 uppercase tracking-wide">
                    {metadata.title || "User Manual"} <span className="text-zinc-300">/ {page.title || "Continued"}</span>
                  </h2>
                </div>
                <div className="text-right"><div className="text-xs text-zinc-400">{currentDate}</div></div>
              </div>
            </header>
            <main className="space-y-8">
              {page.steps.length === 0 && (
                <div className="flex flex-col items-center justify-center h-48 text-zinc-300 border-2 border-dashed border-zinc-100 rounded-xl m-8">
                  <p className="font-medium text-sm">Empty Page</p>
                </div>
              )}
              {page.steps.map((step, idx) => {
                  const isSideBySide = step.layout === 'image_left_text_right' || step.layout === 'text_left_image_right';
                  const isImageFirst = step.layout === 'image_left_text_right' || step.layout === 'image_top_text_bottom';
                  const isVertical = step.layout === 'image_top_text_bottom' || step.layout === 'text_top_image_bottom';

                  // Dynamic Layout Logic
                  let imageColumnWidth = '100%';
                  if (isSideBySide) {
                       if (step.images.length === 1 && step.images[0].width) {
                           imageColumnWidth = `${step.images[0].width}%`;
                       } else {
                           // Default split if not customized or multi-image
                           const defaultWidth = metadata.singleImageSize || 45;
                           imageColumnWidth = `${defaultWidth}%`;
                       }
                  }

                  return (
                    <div key={step.id} className="break-inside-avoid step-item">
                        <div className={`flex gap-6 ${isVertical ? 'flex-col' : 'flex-row'}`}>

                            {/* Text Section */}
                            <div className={`flex-1 ${!isImageFirst ? 'order-1' : 'order-2'}`}>
                                <div className="flex items-start gap-3 mb-2">
                                    {metadata.showStepMarkers && (<div className="flex-shrink-0 pt-2"><div className="w-2.5 h-2.5 rounded-full bg-zinc-900"></div></div>)}
                                    <h3 className="text-lg font-bold text-zinc-800 uppercase tracking-wide leading-tight">{step.title || "Untitled Step"}</h3>
                                </div>
                                <div className={metadata.showStepMarkers ? "pl-5" : ""}>
                                  <p className="text-zinc-600 text-sm leading-relaxed whitespace-pre-wrap">{step.description || "No description provided."}</p>
                                </div>
                            </div>

                            {/* Image Section */}
                            {step.images.length > 0 && (
                            <div 
                                className={`flex-shrink-0 ${!isImageFirst ? 'order-2' : 'order-1'}`}
                                style={{ width: imageColumnWidth }}
                            >
                                <div className="flex flex-wrap gap-2">
                                    {step.images.map((img) => {
                                        // Inner image width logic
                                        let widthStyle = '100%';

                                        // For side-by-side single image, the container is already sized to the image width preference.
                                        // So the image just fills the container.
                                        if (isSideBySide && step.images.length === 1) {
                                            widthStyle = '100%';
                                        } else {
                                            // For vertical or multi-image, respect individual settings or defaults
                                            if (img.width) {
                                                widthStyle = `${img.width}%`;
                                            } else {
                                                 if (step.images.length === 1) {
                                                     widthStyle = `${metadata.singleImageSize || 100}%`;
                                                 } else {
                                                     const perRow = step.imagesPerRow || (metadata.imagesPerRow || 2);
                                                     widthStyle = `calc((100% - ${(perRow - 1) * 8}px) / ${perRow})`;
                                                 }
                                            }
                                        }

                                        return (
                                        <div 
                                          key={img.id} 
                                          className="rounded-lg border border-zinc-200 overflow-hidden bg-surface-50 shadow-sm"
                                          style={{ width: widthStyle }}
                                        >
                                            <img src={img.url} alt="Step" className="w-full h-auto object-cover" />
                                        </div>
                                    )})}
                                </div>
                            </div>
                            )}
                        </div>
                    </div>
                  );
              })}
            </main>
          </>
        )}
      </div>
      <footer className="absolute bottom-0 left-0 right-0 h-32 px-12 pb-12 pt-4 flex justify-between items-end z-20 bg-white">
          <div className="w-full border-t border-zinc-200 pt-6 flex justify-between items-center text-xs text-zinc-400">
            <p>© {new Date().getFullYear()} {metadata.author || "Your Company"}.</p>
            <div className="font-bold text-zinc-500">Page {pageIndex + 1} of {totalPages}</div>
          </div>
      </footer>
    </div>
  );
};

const Preview: React.FC<PreviewProps> = ({
  pages,
  metadata,
  dimensions,
  previewRef,
  onPageOverflow,
}) => {
  return (
    <div ref={previewRef} className="flex flex-col items-center py-8 w-full">
      {pages.map((page, index) => (
        <PageContainer
          key={page.id}
          page={page}
          pageIndex={index}
          allPages={pages}
          totalPages={pages.length}
          metadata={metadata}
          dimensions={dimensions}
          onOverflow={onPageOverflow}
        />
      ))}
    </div>
  );
};

export default Preview;

import React, { useState, useEffect } from 'react';
import { PageDimensions, SavedProject } from '../types';
import { getProjectsFromDB, deleteProjectFromDB } from '../services/storageService';

interface StartScreenProps {
  onStart: (dimensions: PageDimensions) => void;
  onLoadProject: (project: SavedProject) => void;
}

const PRESETS: PageDimensions[] = [
  { name: 'A4', width: 210, height: 297 },
  { name: 'A5', width: 148, height: 210 },
  { name: 'Letter', width: 216, height: 279 },
];

const StartScreen: React.FC<StartScreenProps> = ({ onStart, onLoadProject }) => {
  const [selectedPreset, setSelectedPreset] = useState<string>('A4');
  const [customWidth, setCustomWidth] = useState<string>('210');
  const [customHeight, setCustomHeight] = useState<string>('297');
  const [isCustom, setIsCustom] = useState(false);
  const [recentProjects, setRecentProjects] = useState<SavedProject[]>([]);

  useEffect(() => {
    const loadProjects = async () => {
      try {
        const projects = await getProjectsFromDB();
        setRecentProjects(projects);
      } catch (e) {
        console.error("Failed to load history", e);
      }
    };
    loadProjects();
  }, []);

  const handleDeleteProject = async (e: React.MouseEvent, projectId: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this project?")) {
      try {
        await deleteProjectFromDB(projectId);
        const projects = await getProjectsFromDB();
        setRecentProjects(projects);
      } catch (e) {
        console.error("Failed to delete project", e);
      }
    }
  };

  const handlePresetSelect = (preset: PageDimensions) => {
    setSelectedPreset(preset.name);
    setIsCustom(false);
    setCustomWidth(preset.width.toString());
    setCustomHeight(preset.height.toString());
  };

  const handleCustomFocus = () => {
    setSelectedPreset('custom');
    setIsCustom(true);
  };

  const handleSubmit = () => {
    const width = parseFloat(customWidth);
    const height = parseFloat(customHeight);

    if (isNaN(width) || isNaN(height) || width <= 0 || height <= 0) {
      alert("Please enter valid positive dimensions.");
      return;
    }

    onStart({
      name: isCustom ? 'Custom' : selectedPreset,
      width,
      height
    });
  };

  return (
    <div className="min-h-screen bg-surface-50 flex flex-col items-center justify-center p-6 relative overflow-hidden">
      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-full bg-dot-pattern [background-size:20px_20px] opacity-40 pointer-events-none"></div>

      {/* Animated Blobs */}
      <div className="absolute top-[-10%] right-[-5%] w-[600px] h-[600px] bg-brand-200/30 rounded-full blur-[120px] pointer-events-none animate-float"></div>
      <div className="absolute bottom-[-10%] left-[-10%] w-[500px] h-[500px] bg-fuchsia-200/30 rounded-full blur-[100px] pointer-events-none animate-float-delayed"></div>
      <div className="absolute top-[20%] left-[20%] w-[300px] h-[300px] bg-blue-100/20 rounded-full blur-[80px] pointer-events-none animate-pulse-slow"></div>

      <div className="max-w-6xl w-full grid grid-cols-1 md:grid-cols-12 gap-8 z-10">

        {/* Left Side: Welcome & New Project */}
        <div className="md:col-span-7 flex flex-col gap-6 animate-slide-up">
          <div className="glass-panel p-8 rounded-[2rem] shadow-soft-lg border border-white/60">
            <div className="flex items-center gap-5 mb-8">
                <div className="w-16 h-16 bg-gradient-to-br from-brand-500 to-brand-600 rounded-2xl flex items-center justify-center text-white shadow-glow transform transition-transform hover:scale-105 duration-300">
                    <i className="fas fa-book-open text-3xl"></i>
                </div>
                <div>
                    <h1 className="text-4xl font-extrabold text-zinc-900 tracking-tight mb-1">ManualMaster AI</h1>
                    <p className="text-zinc-500 font-medium text-lg">Create beautiful documentation in minutes.</p>
                </div>
            </div>

            <div className="space-y-6">
                <div>
                    <h2 className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-4 ml-1">Start New Project</h2>
                    <div className="grid grid-cols-4 gap-4">
                        {PRESETS.map((preset) => (
                        <button
                            key={preset.name}
                            onClick={() => handlePresetSelect(preset)}
                            className={`
                            group relative p-4 rounded-2xl border transition-all duration-300 flex flex-col items-center gap-3
                            ${selectedPreset === preset.name 
                                ? 'border-brand-500 bg-brand-50/60 text-brand-700 ring-2 ring-brand-500/20 shadow-lg transform -translate-y-1' 
                                : 'border-zinc-200/60 bg-white/80 hover:border-brand-300 hover:shadow-md hover:-translate-y-1 text-zinc-600'
                            }
                            `}
                        >
                            <div className={`w-8 h-10 border-2 rounded-sm transition-colors ${selectedPreset === preset.name ? 'border-brand-400 bg-white' : 'border-zinc-300 group-hover:border-zinc-400'} mb-1`}></div>
                            <span className="font-bold text-sm">{preset.name}</span>
                            <span className="text-[10px] opacity-60 font-medium bg-surface-100 px-1.5 py-0.5 rounded-full">{preset.width}x{preset.height}</span>
                        </button>
                        ))}
                        <button 
                        onClick={handleCustomFocus}
                        className={`
                            group relative p-4 rounded-2xl border transition-all duration-300 flex flex-col items-center gap-3
                            ${isCustom 
                                ? 'border-brand-500 bg-brand-50/60 text-brand-700 ring-2 ring-brand-500/20 shadow-lg transform -translate-y-1' 
                                : 'border-zinc-200/60 bg-white/80 hover:border-brand-300 hover:shadow-md hover:-translate-y-1 text-zinc-600'
                            }
                        `}
                        >
                             <div className={`w-8 h-10 border-2 border-dashed rounded-sm transition-colors ${isCustom ? 'border-brand-400 bg-white' : 'border-zinc-300 group-hover:border-zinc-400'} mb-1`}></div>
                            <span className="font-bold text-sm">Custom</span>
                            <span className="text-[10px] opacity-60 font-medium bg-surface-100 px-1.5 py-0.5 rounded-full">mm</span>
                        </button>
                    </div>
                </div>

                {isCustom && (
                 <div className="flex gap-4 bg-white/60 p-4 rounded-2xl border border-brand-200/50 shadow-sm animate-fade-in">
                    <div className="flex-1">
                      <label className="block text-[10px] font-bold text-zinc-500 uppercase mb-1.5 tracking-wider">Width (mm)</label>
                      <input type="number" value={customWidth} onChange={(e) => setCustomWidth(e.target.value)} className="w-full p-3 bg-white border border-zinc-200 rounded-xl text-sm focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all shadow-sm" />
                    </div>
                    <div className="flex-1">
                      <label className="block text-[10px] font-bold text-zinc-500 uppercase mb-1.5 tracking-wider">Height (mm)</label>
                      <input type="number" value={customHeight} onChange={(e) => setCustomHeight(e.target.value)} className="w-full p-3 bg-white border border-zinc-200 rounded-xl text-sm focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all shadow-sm" />
                    </div>
                 </div>
                )}

                <button
                    onClick={handleSubmit}
                    className="w-full py-4 bg-zinc-900 text-white font-bold rounded-2xl shadow-xl shadow-zinc-900/10 btn-animated-glow flex items-center justify-center gap-3 group mt-2"
                >
                    <span className="text-lg">Create Project</span>
                    <i className="fas fa-arrow-right group-hover:translate-x-1 transition-transform"></i>
                </button>
            </div>
          </div>
        </div>

        {/* Right Side: Recent Projects */}
        <div className="md:col-span-5 flex flex-col h-full min-h-[500px] animate-slide-up stagger-1">
           <div className="glass-panel p-6 rounded-[2rem] h-full flex flex-col shadow-soft-lg border border-white/60">
              <h3 className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-6 flex items-center gap-2 ml-1">
                  <i className="far fa-clock"></i> Recent Projects
