              <div className="flex-1 overflow-y-auto pr-2 space-y-3 custom-scrollbar">
                {recentProjects.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-zinc-400 opacity-60">
                        <div className="w-20 h-20 bg-zinc-100 rounded-full flex items-center justify-center mb-4">
                            <i className="fas fa-layer-group text-3xl text-zinc-300"></i>
                        </div>
                        <p className="text-sm font-medium">No recent projects found</p>
                    </div>
                ) : (
                    recentProjects.map((project, index) => (
                        <div 
                        key={project.id}
                        onClick={() => onLoadProject(project)}
                        className={`group relative bg-white/80 p-4 rounded-2xl border border-zinc-100 hover:border-brand-200 hover:bg-white hover:shadow-lg cursor-pointer transition-all duration-300 animate-slide-up`}
                        style={{ animationDelay: `${index * 50}ms`, animationFillMode: 'both' }}
                        >
                            <div className="flex justify-between items-start">
                                <div>
                                    <h4 className="font-bold text-zinc-800 mb-1 group-hover:text-brand-600 transition-colors line-clamp-1 text-base">{project.metadata.title}</h4>
                                    <p className="text-xs text-zinc-500 font-medium">
                                        {project.pages.length} Pages • {project.dimensions.name}
                                    </p>
                                </div>
                                <div className="w-8 h-8 rounded-full bg-surface-100 flex items-center justify-center text-zinc-400 group-hover:bg-brand-50 group-hover:text-brand-600 transition-all group-hover:scale-110">
                                    <i className="fas fa-chevron-right text-xs"></i>
                                </div>
                            </div>
                             <div className="mt-3 pt-3 border-t border-zinc-50 flex justify-between items-center">
                                <span className="text-[10px] text-zinc-400 font-bold bg-surface-50 px-2 py-0.5 rounded-full">
                                    {new Date(project.lastModified).toLocaleDateString()}
                                </span>
                                <button 
                                    onClick={(e) => handleDeleteProject(e, project.id)}
                                    className="text-zinc-300 hover:text-red-500 hover:bg-red-50 transition-all p-1.5 rounded-md"
                                    title="Delete"
                                >
                                    <i className="fas fa-trash-alt text-xs"></i>
                                </button>
                             </div>
                        </div>
                    ))
                )}
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

export default StartScreen;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';
import { v4 as uuidv4 } from 'uuid';
import StepEditor from './components/StepEditor';
import Preview from './components/Preview';
import StartScreen from './components/StartScreen';
import CoverEditor from './components/CoverEditor';
import BackCoverEditor from './components/BackCoverEditor';
import { ManualStep, ManualMetadata, PageDimensions, ManualPage, SavedProject } from './types';
import { generatePageTitle } from './services/geminiService';
import { saveProjectToDB } from './services/storageService';

interface HistoryState {
  pages: ManualPage[];
  metadata: ManualMetadata;
}

const DEFAULT_METADATA: ManualMetadata = {
  title: 'Product Manual',
  subtitle: 'Setup & Configuration Guide',
  author: 'My Company Inc.',
  version: '1.0',
  showStepMarkers: true,
  singleImageSize: 50,
  imagesPerRow: 2
};

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(false);
  const [pageDimensions, setPageDimensions] = useState<PageDimensions>({ width: 210, height: 297, name: 'A4' });
  const [projectId, setProjectId] = useState<string>(uuidv4());

  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
  const [isMetadataExpanded, setIsMetadataExpanded] = useState(false);

  const [isSaving, setIsSaving] = useState(false);
  const [lastSavedTime, setLastSavedTime] = useState<Date | null>(null);

  const previewRef = useRef<HTMLDivElement>(null);

  const [metadata, setMetadata] = useState<ManualMetadata>(DEFAULT_METADATA);
  const [pages, setPages] = useState<ManualPage[]>([
    { id: uuidv4(), type: 'cover', title: 'Cover Page', steps: [], layoutStyle: 'style-1' },
    { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] },
    { id: uuidv4(), type: 'content', title: 'Getting Started', steps: [{ id: uuidv4(), title: 'Unboxing', description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.', images: [], layout: 'image_left_text_right' }] }
  ]);

  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [activePageIndex, setActivePageIndex] = useState(0); 

  const convertUrlToBase64 = async (url: string): Promise<string> => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn("Failed to convert image for saving:", url);
      return url; 
    }
  };

  const saveProjectToHistory = useCallback(async (isManual: boolean = false) => {
    if (!hasStarted) return;
    setIsSaving(true);
    try {
      const pagesToSave = JSON.parse(JSON.stringify(pages)) as ManualPage[];
      for (const page of pagesToSave) {
         if (page.backgroundImage && page.backgroundImage.url.startsWith('blob:')) {
             page.backgroundImage.url = await convertUrlToBase64(page.backgroundImage.url);
             delete page.backgroundImage.file; 
         }
         for (const step of page.steps) {
             for (const img of step.images) {
                 if (img.url.startsWith('blob:')) {
                     img.url = await convertUrlToBase64(img.url);
                     delete img.file; 
                 }
             }
         }
      }
      const projectData: SavedProject = {
        id: projectId,
        lastModified: Date.now(),
        metadata,
        pages: pagesToSave,
        dimensions: pageDimensions
      };

      await saveProjectToDB(projectData);

      setLastSavedTime(new Date());
    } catch (error) {
       console.error("Failed to save project:", error);
       if (isManual) alert("Warning: Failed to save project. Ensure you have enough disk space.");
    } finally {
        setTimeout(() => setIsSaving(false), 500);
    }
  }, [pages, metadata, pageDimensions, projectId, hasStarted]);

  useEffect(() => {
    if (!hasStarted) return;
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = setTimeout(() => { saveProjectToHistory(); }, 2000);
    return () => { if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current); };
  }, [pages, metadata, pageDimensions, hasStarted, saveProjectToHistory]);

  useEffect(() => {
    if (!hasStarted) return;
    const intervalId = setInterval(() => { saveProjectToHistory(false); }, 60000);
    return () => clearInterval(intervalId);
  }, [hasStarted, saveProjectToHistory]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            saveProjectToHistory(true);
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [saveProjectToHistory]);

  useEffect(() => {
    if (hasStarted) {
      const timer = setTimeout(() => {
        const pageElement = document.getElementById(`preview-page-${activePageIndex}`);
        if (pageElement) {
          pageElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activePageIndex, hasStarted]);

  const saveSnapshot = useCallback(() => {
    setPast(prev => {
      const newPast = [...prev, { pages, metadata }];
      if (newPast.length > 20) return newPast.slice(newPast.length - 20);
      return newPast;
    });
    setFuture([]);
  }, [pages, metadata]);

  const undo = () => {
    if (past.length === 0) return;
    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);
    setFuture(prev => [{ pages, metadata }, ...prev]);
    setPages(previous.pages);
    setMetadata(previous.metadata);
    setPast(newPast);
  };

  const redo = () => {
    if (future.length === 0) return;
    const next = future[0];
    const newFuture = future.slice(1);
    setPast(prev => [...prev, { pages, metadata }]);
    setPages(next.pages);
    setMetadata(next.metadata);
    setFuture(newFuture);
  };

  const handleTextTypingHistory = () => {
    if (!typingTimeoutRef.current) saveSnapshot();
    if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    typingTimeoutRef.current = setTimeout(() => { typingTimeoutRef.current = null; }, 1000);
  };

  const handleStructuralChangeHistory = () => {
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = null;
    }
    saveSnapshot();
  };

  const handleStart = (dimensions: PageDimensions) => {
    setPageDimensions(dimensions);
    setProjectId(uuidv4());
    setMetadata(DEFAULT_METADATA);
    setPages([
      { id: uuidv4(), type: 'cover', title: 'Cover Page', steps: [], layoutStyle: 'style-1' },
      { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] },
      { id: uuidv4(), type: 'content', title: 'Getting Started', steps: [{ id: uuidv4(), title: 'Unboxing', description: 'Carefully remove the device from the packaging. Ensure all accessories are present in the box.', images: [], layout: 'image_left_text_right' }] }
    ]);
    setPast([]);
    setFuture([]);
    setActivePageIndex(0);
    setHasStarted(true);
  };

  const handleLoadProject = (project: SavedProject) => {
      setProjectId(project.id);
      // Ensure new metadata fields exist for legacy projects
      setMetadata({ ...DEFAULT_METADATA, ...project.metadata });
      setPages(project.pages);
      setPageDimensions(project.dimensions);
      setPast([]);
      setFuture([]);
      setActivePageIndex(0);
      setHasStarted(true);
  };

  const activePage = pages[activePageIndex] || pages[0] || { id: 'dummy', type: 'content', steps: [] };

  const getContextSteps = useCallback(() => {
    return pages
      .filter(p => p.type === 'content')
      .flatMap(p => p.steps)
      .map(s => `Title: ${s.title}\nDesc: ${s.description}`)
      .join('\n\n');
  }, [pages]);

  const addNewPage = () => {
    handleStructuralChangeHistory();
    const lastPage = pages[pages.length - 1];
    const hasBackCover = lastPage.type === 'back_cover';
    const newPage: ManualPage = { id: uuidv4(), type: 'content', title: '', steps: [] };
    const insertIndex = hasBackCover ? pages.length - 1 : pages.length;
    const newPages = [...pages];
    newPages.splice(insertIndex, 0, newPage);
    setPages(newPages);
    setActivePageIndex(insertIndex); 
  };

  const addTocPage = () => {
     if (pages.some(p => p.type === 'toc')) { alert("A Table of Contents page already exists."); return; }
     handleStructuralChangeHistory();
     const insertIndex = pages[0].type === 'cover' ? 1 : 0;
     const newPages = [...pages];
     newPages.splice(insertIndex, 0, { id: uuidv4(), type: 'toc', title: 'Table of Contents', steps: [] });
     setPages(newPages);
     setActivePageIndex(insertIndex);
  };

  const addBackCover = () => {
    if (pages.some(p => p.type === 'back_cover')) { alert("Back Cover already exists."); return; }
    handleStructuralChangeHistory();
    setPages([...pages, { id: uuidv4(), type: 'back_cover', title: 'Back Cover', steps: [], layoutStyle: 'style-1' }]);
    setActivePageIndex(pages.length);
  };

  const switchPage = (index: number) => {
    if (index >= 0 && index < pages.length) setActivePageIndex(index);
  };

  const updatePageTitle = (title: string) => {
    handleTextTypingHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], title };
    setPages(newPages);
  };

  const handleAutoGeneratePageTitle = async () => {
    if (activePage.steps.length === 0) { alert("Add some steps first."); return; }
    handleStructuralChangeHistory();
    setIsGeneratingTitle(true);
    try {
      const suggestedTitle = await generatePageTitle(activePage.steps);
      setPages(currentPages => {
          const newPages = [...currentPages];
          if (newPages[activePageIndex]) newPages[activePageIndex] = { ...newPages[activePageIndex], title: suggestedTitle };
          return newPages;
      });
    } catch (error) { alert("Failed to generate title."); } finally { setIsGeneratingTitle(false); }
  };

  const updateMetadata = (updates: Partial<ManualMetadata>) => {
    const isText = 'title' in updates || 'subtitle' in updates || 'author' in updates || 'version' in updates;
    if (isText) handleTextTypingHistory(); else handleStructuralChangeHistory();
    setMetadata(prev => ({ ...prev, ...updates }));
  };

  const updatePage = (updates: Partial<ManualPage>) => {
    handleStructuralChangeHistory();
    const newPages = [...pages];
    newPages[activePageIndex] = { ...newPages[activePageIndex], ...updates };
    setPages(newPages);
  };

  const addStepToActivePage = () => {
    if (activePage.type !== 'content') return;
    handleStructuralChangeHistory();
    const newStep: ManualStep = { id: uuidv4(), title: '', description: '', images: [], layout: 'image_left_text_right' };
    const newPages = [...pages];
    newPages[activePageIndex].steps.push(newStep);
    setPages(newPages);
    setTimeout(() => { const el = document.getElementById('steps-container'); if (el) el.scrollTop = el.scrollHeight; }, 100);
  };

  const updateStep = (stepId: string, updates: Partial<ManualStep>) => {
    const isTextUpdate = 'title' in updates || 'description' in updates;
    if (isTextUpdate) handleTextTypingHistory(); else handleStructuralChangeHistory();
    const newPages = pages.map(page => ({ ...page, steps: page.steps.map(step => step.id === stepId ? { ...step, ...updates } : step) }));
    setPages(newPages);
  };

  const deleteStep = (stepId: string) => {
    handleStructuralChangeHistory();
    const newPages = pages.map(page => ({ ...page, steps: page.steps.filter(step => step.id !== stepId) }));
    setPages(newPages);
  };

  const moveStep = (stepIndex: number, direction: 'up' | 'down') => {
    const page = pages[activePageIndex];
    if (page.type !== 'content') return;
    if (direction === 'up' && stepIndex === 0) return;
    if (direction === 'down' && stepIndex === page.steps.length - 1) return;
    handleStructuralChangeHistory();
    const newSteps = [...page.steps];
    const targetIndex = direction === 'up' ? stepIndex - 1 : stepIndex + 1;
    [newSteps[stepIndex], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[stepIndex]];
    const newPages = [...pages];
    newPages[activePageIndex].steps = newSteps;
    setPages(newPages);
  };

  const handlePageOverflow = useCallback((pageIndex: number) => {
    setPages(prevPages => {
      if (pageIndex < 0 || pageIndex >= prevPages.length) return prevPages;
      const currentPage = prevPages[pageIndex];
      if (!currentPage || currentPage.type !== 'content' || currentPage.steps.length <= 1) return prevPages;
      const lastStep = currentPage.steps[currentPage.steps.length - 1];
      const newCurrentPageSteps = currentPage.steps.slice(0, -1);
      const nextPageIndex = pageIndex + 1;
      let nextPage = prevPages[nextPageIndex];
      let newPages = [...prevPages];
      newPages[pageIndex] = { ...currentPage, steps: newCurrentPageSteps };
      if (nextPage && nextPage.type === 'content') {
        newPages[nextPageIndex] = { ...nextPage, steps: [lastStep, ...nextPage.steps] };
      } else {
        const newPage: ManualPage = { id: uuidv4(), type: 'content', title: 'Continued...', steps: [lastStep] };
        newPages.splice(nextPageIndex, 0, newPage);
      }
      return newPages;
    });
  }, []);

  const generatePDF = useCallback(async () => {
    setIsGenerating(true);
    try {
      const pdf = new jsPDF({
        orientation: pageDimensions.width > pageDimensions.height ? 'landscape' : 'portrait',
        unit: 'mm',
        format: [pageDimensions.width, pageDimensions.height]
      });
      for (let i = 0; i < pages.length; i++) {
        const pageElement = document.getElementById(`preview-page-${i}`);
        if (!pageElement) continue;
        if (i > 0) pdf.addPage();
        const originalShadow = pageElement.style.boxShadow;
        pageElement.style.boxShadow = 'none';
        const canvas = await html2canvas(pageElement, { scale: 2, useCORS: true, logging: false, backgroundColor: '#ffffff', windowWidth: 1200 });
        pageElement.style.boxShadow = originalShadow;
        const imgData = canvas.toDataURL('image/png');
        pdf.addImage(imgData, 'PNG', 0, 0, pdf.internal.pageSize.getWidth(), pdf.internal.pageSize.getHeight());
      }
      pdf.save(`${metadata.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (error) { console.error("PDF Generation failed", error); alert("Failed to generate PDF."); } finally { setIsGenerating(false); }
  }, [metadata.title, pages.length, pageDimensions]);

  if (!hasStarted) {
    return <StartScreen onStart={handleStart} onLoadProject={handleLoadProject} />;
  }

  const renderPageIcon = (type: ManualPage['type']) => {
      switch(type) {
          case 'cover': return <i className="fas fa-book-cover text-xs"></i>;
          case 'toc': return <i className="fas fa-list-ol text-xs"></i>;
          case 'back_cover': return <i className="fas fa-book-open fa-flip-horizontal text-xs"></i>;
          default: return null;
      }
  }

  return (
    <div className="flex flex-col h-screen bg-surface-50 text-zinc-800 font-sans animate-fade-in">
      {/* Top Navbar */}
      <nav className="bg-white/70 backdrop-blur-xl border-b border-zinc-200/50 px-6 h-16 flex items-center justify-between shadow-soft z-50 fixed w-full top-0 left-0 transition-all">
        <div className="flex items-center gap-4">
            <div className="flex items-center gap-3 group cursor-default">
              <div className="w-10 h-10 bg-gradient-to-br from-brand-500 to-brand-600 rounded-xl flex items-center justify-center text-white shadow-glow group-hover:scale-110 transition-transform duration-300">
                <i className="fas fa-book-open text-lg"></i>
              </div>
              <div className="hidden sm:block">
                <h1 className="font-extrabold text-lg text-zinc-900 tracking-tight leading-none group-hover:text-brand-600 transition-colors">ManualMaster</h1>
                <p className="text-[10px] text-zinc-500 font-bold tracking-wide uppercase">AI Documentation Tool</p>
              </div>
            </div>
        </div>

        <div className="flex items-center gap-3">
           {/* Save Status Indicator */}
           <div className="hidden md:flex flex-col items-end mr-2">
              <span className={`text-[10px] font-bold uppercase tracking-wider transition-colors duration-300 ${isSaving ? 'text-brand-500 animate-pulse' : 'text-zinc-400'}`}>
                  {isSaving ? 'Saving...' : 'Saved'}
              </span>
              {lastSavedTime && !isSaving && (
                  <span className="text-[10px] text-zinc-300 font-medium">
                      {lastSavedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
              )}
           </div>

           {/* Save & History Controls */}
           <div className="flex items-center gap-2 bg-white/50 backdrop-blur-sm p-1 rounded-xl border border-zinc-200 shadow-sm">
                <button 
                    onClick={() => saveProjectToHistory(true)}
                    className={`w-9 h-9 flex items-center justify-center rounded-lg transition-all active:scale-95 ${isSaving ? 'text-brand-600 bg-brand-50' : 'text-zinc-500 hover:text-zinc-800 hover:bg-white hover:shadow-sm'}`}
                    title="Manual Save"
                >
                    {isSaving ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-save"></i>}
                </button>
                <div className="w-px h-4 bg-zinc-200"></div>
                <button onClick={undo} disabled={past.length === 0} className="w-9 h-9 flex items-center justify-center rounded-lg text-zinc-500 hover:text-zinc-800 hover:bg-white hover:shadow-sm disabled:opacity-30 disabled:hover:bg-transparent active:scale-95 transition-all" title="Undo"><i className="fas fa-undo"></i></button>
                <button onClick={redo} disabled={future.length === 0} className="w-9 h-9 flex items-center justify-center rounded-lg text-zinc-500 hover:text-zinc-800 hover:bg-white hover:shadow-sm disabled:opacity-30 disabled:hover:bg-transparent active:scale-95 transition-all" title="Redo"><i className="fas fa-redo"></i></button>
           </div>

           <button 
            onClick={generatePDF}
            disabled={isGenerating}
            className={`
              h-10 px-6 rounded-xl text-sm font-bold flex items-center gap-2 transition-all shadow-md btn-animated-glow
              ${isGenerating ? 'bg-zinc-100 text-zinc-400 cursor-wait' : 'bg-zinc-900 text-white shadow-zinc-900/20'}
            `}
          >
            {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-download"></i>}
            <span className="hidden sm:inline">{isGenerating ? 'Exporting...' : 'Export PDF'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-grow flex overflow-hidden pt-16">

        {/* Editor Side (Left) */}
        <div className={`
          flex-col w-full md:w-[450px] lg:w-[500px] border-r border-zinc-200 bg-white/90 backdrop-blur-sm z-20 shadow-soft
          ${activeTab === 'preview' ? 'hidden md:flex' : 'flex animate-fade-in'}
        `}>

          {/* Modern Page Navigator */}
          <div className="px-4 py-3 bg-white/80 backdrop-blur-md border-b border-zinc-100 overflow-x-auto whitespace-nowrap scrollbar-hide flex gap-2 items-center sticky top-0 z-10 shadow-sm">
             {!pages.some(p => p.type === 'toc') && (
               <button onClick={addTocPage} className="flex-shrink-0 w-8 h-8 rounded-full bg-surface-100 text-zinc-500 hover:bg-brand-50 hover:text-brand-600 transition-all hover:scale-110 flex items-center justify-center" title="Insert TOC">
                 <i className="fas fa-list-ol text-xs"></i>
               </button>
            )}
            {pages.map((page, idx) => (
              <button
                key={page.id}
                onClick={() => switchPage(idx)}
                className={`
                  px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2 border active:scale-95
                  ${activePageIndex === idx 
                    ? 'bg-zinc-900 text-white border-zinc-900 shadow-md transform scale-105' 
                    : 'bg-white text-zinc-500 border-zinc-200 hover:border-zinc-300 hover:bg-surface-50 hover:text-zinc-700'
                  }
                `}
              >
                {renderPageIcon(page.type)}
                {page.type === 'content' ? idx + 1 : ''}
              </button>
            ))}
            <button onClick={addNewPage} className="flex-shrink-0 w-8 h-8 rounded-full bg-brand-50 text-brand-600 hover:bg-brand-100 transition-all hover:scale-110 flex items-center justify-center ml-1 border border-brand-100 shadow-sm">
              <i className="fas fa-plus text-xs"></i>
            </button>
            {!pages.some(p => p.type === 'back_cover') && (
                <button onClick={addBackCover} className="flex-shrink-0 w-8 h-8 rounded-full bg-surface-100 text-zinc-500 hover:bg-surface-200 transition-all hover:scale-110 flex items-center justify-center" title="Add Back Cover">
                    <i className="fas fa-book-open fa-flip-horizontal text-xs"></i>
                </button>
            )}
          </div>

          {/* Editor Header */}
          <div className="px-6 py-5 bg-white/50">
             <div className="flex justify-between items-center mb-1">
                <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">Currently Editing</span>
                {activePage.type === 'content' && <span className="text-[10px] font-bold bg-zinc-100 text-zinc-500 px-2 py-0.5 rounded-full border border-zinc-200">{activePage.steps.length} Steps</span>}
             </div>
             <h2 className="text-xl font-bold text-zinc-900 flex items-center gap-2 animate-slide-up">
                {activePage.type === 'cover' ? 'Front Cover' : activePage.type === 'back_cover' ? 'Back Cover' : activePage.type === 'toc' ? 'Table of Contents' : `Page ${activePageIndex + 1}`}
             </h2>
          </div>

          <div id="steps-container" className="flex-1 overflow-y-auto px-6 pb-24 scroll-smooth custom-scrollbar">

            {/* Global Settings Accordion */}
            <div className={`mb-8 rounded-2xl border transition-all duration-300 overflow-hidden shadow-sm ${isMetadataExpanded ? 'bg-surface-50 border-zinc-200' : 'bg-white border-zinc-100 hover:border-zinc-200'}`}>
              <button onClick={() => setIsMetadataExpanded(!isMetadataExpanded)} className="w-full flex items-center justify-between p-4 text-left hover:bg-surface-50/50 transition-colors">
                <div className="flex items-center gap-2 text-sm font-bold text-zinc-700">
                  <div className="w-6 h-6 rounded-md bg-zinc-100 flex items-center justify-center text-zinc-500"><i className="fas fa-sliders-h text-xs"></i></div>
                  Document Settings
                </div>
                <i className={`fas fa-chevron-down text-zinc-400 transition-transform duration-300 ${isMetadataExpanded ? 'rotate-180' : ''}`}></i>
              </button>
              {isMetadataExpanded && (
                <div className="p-4 pt-0 grid gap-3 animate-slide-up">
                  <input type="text" value={metadata.title} onChange={(e) => updateMetadata({ title: e.target.value })} className="w-full p-2.5 bg-white border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all shadow-sm" placeholder="Document Title" />
                  <input type="text" value={metadata.subtitle} onChange={(e) => updateMetadata({ subtitle: e.target.value })} className="w-full p-2.5 bg-white border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all shadow-sm" placeholder="Subtitle" />
                  <div className="grid grid-cols-2 gap-3">
                    <input type="text" value={metadata.author} onChange={(e) => updateMetadata({ author: e.target.value })} className="w-full p-2.5 bg-white border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all shadow-sm" placeholder="Author" />
                    <input type="text" value={metadata.version} onChange={(e) => updateMetadata({ version: e.target.value })} className="w-full p-2.5 bg-white border border-zinc-200 rounded-lg text-sm focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all shadow-sm" placeholder="Version" />
                  </div>
                  <div className="flex items-center justify-between pt-2">
                     <span className="text-xs font-bold text-zinc-500 uppercase tracking-wide">Show Step Markers</span>
                     <button onClick={() => updateMetadata({ showStepMarkers: !metadata.showStepMarkers })} className={`w-11 h-6 rounded-full p-1 transition-all duration-300 ${metadata.showStepMarkers ? 'bg-brand-600 shadow-glow-sm' : 'bg-zinc-200'}`}>
                        <div className={`w-4 h-4 bg-white rounded-full shadow-md transform transition-transform duration-300 ${metadata.showStepMarkers ? 'translate-x-5' : 'translate-x-0'}`}></div>
                     </button>
                  </div>

                  {/* Global Image Settings */}
                  <div className="pt-4 border-t border-zinc-100 space-y-4">
                      <h3 className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">Image Layout Defaults</h3>
                      <div>
                          <div className="flex justify-between items-center mb-1">
                              <span className="text-xs font-medium text-zinc-600">Single Image Size</span>
                              <span className="text-xs font-bold text-brand-600 bg-brand-50 px-2 py-0.5 rounded-full">{metadata.singleImageSize || 100}%</span>
                          </div>
                          <input 
                              type="range" 
                              min="25" 
                              max="100" 
                              step="5"
                              value={metadata.singleImageSize || 100} 
                              onChange={(e) => updateMetadata({ singleImageSize: parseInt(e.target.value) })} 
                              className="w-full h-1.5 bg-zinc-200 rounded-lg appearance-none cursor-pointer accent-brand-500"
                          />
                      </div>
                  </div>
                </div>
              )}
            </div>

            {activePage.type === 'cover' && (
                <CoverEditor 
                    page={activePage} 
                    onUpdate={updatePage} 
                    metadata={metadata} 
                    onUpdateMetadata={updateMetadata}
                    contextSteps={getContextSteps()}
                />
            )}
            {activePage.type === 'back_cover' && <BackCoverEditor page={activePage} onUpdate={updatePage} />}

            {activePage.type === 'toc' && (
                <div className="bg-surface-50 border border-zinc-200 rounded-2xl p-8 text-center flex flex-col items-center animate-slide-up shadow-sm">
                    <div className="w-14 h-14 bg-white rounded-2xl shadow-sm flex items-center justify-center mb-4 text-zinc-400 border border-zinc-100">
                        <i className="fas fa-list-ol text-2xl"></i>
                    </div>
                    <h3 className="font-bold text-zinc-800 mb-1">Auto-Generated Directory</h3>
                    <p className="text-xs text-zinc-500 mb-6 max-w-[200px]">This page automatically compiles titles from all subsequent pages.</p>
                    <input type="text" value={activePage.title || ''} onChange={(e) => updatePageTitle(e.target.value)} className="w-full max-w-xs p-3 bg-white border border-zinc-200 rounded-xl text-center text-sm font-semibold focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all shadow-sm" placeholder="TOC Title" />
                </div>
            )}

            {activePage.type === 'content' && (
                <>
                    <div className="mb-6 relative animate-slide-up">
                        <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest mb-2 block flex justify-between items-center">
                            Page Section Title
                            <button onClick={handleAutoGeneratePageTitle} disabled={isGeneratingTitle || activePage.steps.length === 0} className="text-brand-600 hover:text-brand-700 disabled:opacity-50 text-[10px] font-bold bg-brand-50 px-2 py-1 rounded-md transition-all hover:bg-brand-100">
                                {isGeneratingTitle ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic mr-1"></i>} Auto-Generate
                            </button>
                        </label>
                        <input type="text" value={activePage.title || ''} onChange={(e) => updatePageTitle(e.target.value)} className="w-full p-4 bg-white border border-zinc-200 rounded-xl text-lg font-bold text-zinc-800 focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 outline-none transition-all shadow-sm placeholder:text-zinc-300" placeholder="e.g. Safety Instructions" />
                    </div>

                    <div className="space-y-5 pb-6">
                        {activePage.steps.length === 0 && (
                            <div className="text-center py-16 border-2 border-dashed border-zinc-200 rounded-2xl bg-surface-50 animate-fade-in">
                                <div className="w-16 h-16 bg-zinc-100 rounded-full flex items-center justify-center mx-auto mb-4">
                                    <i className="fas fa-layer-group text-2xl text-zinc-300"></i>
                                </div>
                                <p className="text-sm font-medium text-zinc-500">No steps on this page yet.</p>
                                <p className="text-xs text-zinc-400 mt-1">Click "Add Step" to begin</p>
                            </div>
                        )}
                        {activePage.steps.map((step, idx) => (
                            <StepEditor 
                                key={step.id} 
                                index={idx} 
                                step={step} 
                                totalSteps={activePage.steps.length} 
                                metadata={metadata}
                                onUpdate={updateStep} 
                                onDelete={deleteStep} 
                                onMoveUp={() => moveStep(idx, 'up')} 
                                onMoveDown={() => moveStep(idx, 'down')} 
                            />
                        ))}
                    </div>
                </>
            )}
          </div>

          {activePage.type === 'content' && (
              <div className="absolute bottom-6 left-0 w-full md:w-[450px] lg:w-[500px] px-6 pointer-events-none z-30">
                <button onClick={addStepToActivePage} className="pointer-events-auto w-full py-4 bg-zinc-900 text-white font-bold rounded-2xl shadow-xl shadow-zinc-900/20 btn-animated-glow flex items-center justify-center gap-2 group transform transition-all active:scale-95">
                    <i className="fas fa-plus text-xs group-hover:rotate-90 transition-transform duration-300"></i>
                    <span className="tracking-wide">Add New Step</span>
                </button>
            </div>
          )}
        </div>

        {/* Preview Side (Right) */}
        <div className={`flex-col flex-grow bg-surface-100 relative ${activeTab === 'editor' ? 'hidden md:flex' : 'flex'} animate-fade-in`}>
          <div className="absolute inset-0 bg-dot-pattern [background-size:24px_24px] opacity-30 pointer-events-none"></div>

          <div className="md:hidden flex border-b border-zinc-200 bg-white shrink-0 z-20">
            <button className={`flex-1 py-3 text-sm font-medium transition-colors ${activeTab === 'editor' ? 'text-brand-600 border-b-2 border-brand-600 bg-brand-50/50' : 'text-zinc-500 hover:text-zinc-800'}`} onClick={() => setActiveTab('editor')}>Editor</button>
            <button className={`flex-1 py-3 text-sm font-medium transition-colors ${activeTab === 'preview' ? 'text-brand-600 border-b-2 border-brand-600 bg-brand-50/50' : 'text-zinc-500 hover:text-zinc-800'}`} onClick={() => setActiveTab('preview')}>Preview</button>
          </div>

          <Preview pages={pages} metadata={metadata} dimensions={pageDimensions} previewRef={previewRef} onPageOverflow={handlePageOverflow} />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { ManualStep, StepLayout, StepImage, ManualMetadata } from '../types';
import { generateDescriptionFromImages, generateStepTitle } from '../services/geminiService';

interface StepEditorProps {
  step: ManualStep;
  index: number;
  metadata: ManualMetadata;
  onUpdate: (id: string, updates: Partial<ManualStep>) => void;
  onDelete: (id: string) => void;
  onMoveUp: (index: number) => void;
  onMoveDown: (index: number) => void;
  totalSteps: number;
}

const StepEditor: React.FC<StepEditorProps> = ({ 
  step, index, metadata, onUpdate, onDelete, onMoveUp, onMoveDown, totalSteps
}) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);

  const imagesContainerRef = useRef<HTMLDivElement>(null);

  const handleImagesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newImages = (Array.from(e.target.files) as File[]).filter(file => {
        if (file.size > 3 * 1024 * 1024) {
          alert(`File ${file.name} is too large (max 3MB).`);
          return false;
        }
        return true;
      }).map(file => ({
        id: uuidv4(),
        url: URL.createObjectURL(file),
        file,
        // No default width set, will fallback to metadata settings
      }));
      onUpdate(step.id, { images: [...step.images, ...newImages] });
    }
  };

  const handleRemoveImage = (imageId: string) => {
    onUpdate(step.id, { images: step.images.filter(img => img.id !== imageId) });
  };

  const handleLayoutChange = (newLayout: StepLayout) => {
      const isVertical = newLayout === 'image_top_text_bottom' || newLayout === 'text_top_image_bottom';
      const updates: Partial<ManualStep> = { layout: newLayout };

      // If switching to vertical and imagesPerRow is not set, default to 6 as requested
      if (isVertical && !step.imagesPerRow) {
          updates.imagesPerRow = 6;
      }

      onUpdate(step.id, updates);
  };

  const handleAnalyzeImages = async () => {
    if (step.images.length === 0) return;
    setIsAnalyzing(true);
    try {
      const files = step.images.map(img => img.file);
      const description = await generateDescriptionFromImages(files);
      onUpdate(step.id, { description });
    } catch (error) { alert("Failed to analyze images."); } finally { setIsAnalyzing(false); }
  };

  const handleGenerateTitle = async () => {
    if (!step.description) return;
    setIsGeneratingTitle(true);
    try {
      const title = await generateStepTitle(step.description);
      onUpdate(step.id, { title });
    } catch (error) { alert("Failed to generate title."); } finally { setIsGeneratingTitle(false); }
  };

  // Fixed Editor Layout Logic: Always Side-by-Side (Image Left, Text Right) for stability
  // This decoupling ensures the editor UI doesn't jump around or break when changing PDF layout options.
  const getImageContainerStyle = () => {
      return { width: '45%' }; // Fixed width for editor stability
  };

  // Determine individual image width style for the EDITOR visualization
  const getIndividualImageStyle = (img: StepImage) => {
      // In editor, single image takes full width of the fixed container
      if (step.images.length === 1) return { width: '100%' };

      // Multi-image grid logic for Editor visualization
      const perRow = step.imagesPerRow || (metadata.imagesPerRow || 2);
      return { width: `calc((100% - ${(perRow - 1) * 8}px) / ${perRow})` };
  };

  // Check if current layout is vertical for the slider default value display logic
  const isVerticalPDFLayout = step.layout === 'image_top_text_bottom' || step.layout === 'text_top_image_bottom';

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-zinc-100 p-1 transition-all duration-300 hover:shadow-lg hover:border-zinc-300 group animate-slide-up">
      {/* Header */}
      <div className="flex justify-between items-center p-3 bg-surface-50 rounded-xl mb-3 border border-transparent group-hover:border-zinc-100/50 transition-colors">
        <div className="flex items-center gap-3">
            <span className="w-7 h-7 flex items-center justify-center bg-zinc-900 text-white rounded-lg text-xs font-bold shadow-md shadow-zinc-900/10">{index + 1}</span>
            <div className="h-4 w-px bg-zinc-200 mx-1"></div>
            {/* Compact Layout Controls - These affect the PREVIEW/PDF, not the Editor UI */}
            <div className="flex bg-white rounded-lg p-1 shadow-sm border border-zinc-100 gap-1">
               {[
                   { id: 'image_left_text_right', icon: 'fas fa-columns' },
                   { id: 'text_left_image_right', icon: 'fas fa-columns fa-flip-horizontal' },
                   { id: 'image_top_text_bottom', icon: 'fas fa-window-maximize' },
                   { id: 'text_top_image_bottom', icon: 'fas fa-window-maximize fa-flip-vertical' }
               ].map((layoutOpt) => (
                   <button
                    key={layoutOpt.id}
                    onClick={() => handleLayoutChange(layoutOpt.id as StepLayout)}
                    className={`w-6 h-6 flex items-center justify-center rounded-md text-[10px] transition-all duration-200 ${step.layout === layoutOpt.id ? 'bg-zinc-800 text-white shadow-sm' : 'text-zinc-400 hover:bg-surface-100 hover:text-zinc-600'}`}
                    title="Set PDF Layout"
                   >
                       <i className={layoutOpt.icon}></i>
                   </button>
               ))}
            </div>
        </div>
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-200">
            <button onClick={() => onMoveUp(index)} disabled={index === 0} className="w-7 h-7 flex items-center justify-center rounded-lg text-zinc-400 hover:text-zinc-800 hover:bg-white hover:shadow-sm disabled:opacity-30 transition-all"><i className="fas fa-chevron-up text-xs"></i></button>
            <button onClick={() => onMoveDown(index)} disabled={index === totalSteps - 1} className="w-7 h-7 flex items-center justify-center rounded-lg text-zinc-400 hover:text-zinc-800 hover:bg-white hover:shadow-sm disabled:opacity-30 transition-all"><i className="fas fa-chevron-down text-xs"></i></button>
            <button onClick={() => onDelete(step.id)} className="w-7 h-7 flex items-center justify-center rounded-lg text-zinc-400 hover:text-red-500 hover:bg-red-50 hover:shadow-sm ml-1 transition-all"><i className="fas fa-trash-alt text-xs"></i></button>
        </div>
      </div>

      <div className="px-3 pb-3">
        <div className="flex flex-col gap-4">
            {/* Content Area - Fixed Layout for Editing Stability */}
            <div 
                className="flex gap-4 step-row-container flex-col md:flex-row"
            >
                {/* Image Section - Always First in Editor */}
                <div 
                    className="flex-shrink-0 order-1"
                    style={getImageContainerStyle()}
                >
                    <div className="space-y-3">
                         {/* Controls for Single Image: Size Slider */}
                        {step.images.length === 1 && (
                            <div className="flex items-center gap-2 p-2 bg-surface-50 rounded-lg border border-zinc-100 shadow-sm">
                                <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider pl-1">Size</span>
                                <input 
                                    type="range" 
                                    min="25" max="100" step="5"
                                    value={step.images[0].width || metadata.singleImageSize || 50}
                                    onChange={(e) => {
                                        const val = parseInt(e.target.value);
                                        onUpdate(step.id, {
                                            images: step.images.map((img, i) => i === 0 ? { ...img, width: val } : img)
                                        });
                                    }}
                                    className="flex-1 h-1.5 bg-zinc-200 rounded-lg appearance-none cursor-pointer accent-zinc-800"
                                    title="Adjust image width in PDF"
                                />
                                <span className="font-bold text-xs text-zinc-700 min-w-[3ch] text-right">{step.images[0].width || metadata.singleImageSize || 50}%</span>
                            </div>
                        )}

                         {/* Controls for Multiple Images: Grid Slider */}
                        {step.images.length > 1 && (
                            <div className="flex items-center gap-2 p-2 bg-surface-50 rounded-lg border border-zinc-100 shadow-sm">
                                <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider pl-1">Grid</span>
                                <input 
                                    type="range" 
                                    min="1" max="6" 
                                    value={step.imagesPerRow || (isVerticalPDFLayout ? 6 : (metadata.imagesPerRow || 2))}
                                    onChange={(e) => onUpdate(step.id, { imagesPerRow: parseInt(e.target.value) })}
                                    className="flex-1 h-1.5 bg-zinc-200 rounded-lg appearance-none cursor-pointer accent-zinc-800"
                                />
                                <span className="font-bold text-xs text-zinc-700 min-w-[1ch]">{step.imagesPerRow || (isVerticalPDFLayout ? 6 : (metadata.imagesPerRow || 2))}</span>
                            </div>
                        )}

                        {step.images.length > 0 && (
                            <div ref={imagesContainerRef} className="flex flex-wrap gap-2 w-full animate-fade-in">
                                {step.images.map((img) => (
                                    <div 
                                      key={img.id} 
                                      className="relative rounded-lg border border-zinc-200 group/img image-container select-none hover:z-20 hover:shadow-md transition-all duration-300 hover:scale-[1.02]"
                                      style={getIndividualImageStyle(img)}
                                    >
                                        <div className="w-full overflow-hidden rounded-lg bg-surface-50">
                                            <img src={img.url} alt="Step" className="w-full h-auto block pointer-events-none" />
                                        </div>
                                        <button 
                                            onClick={() => handleRemoveImage(img.id)} 
                                            className="absolute -top-2 -right-2 w-6 h-6 bg-white text-zinc-400 hover:text-red-500 border border-zinc-200 rounded-full shadow-sm flex items-center justify-center text-xs opacity-0 group-hover/img:opacity-100 transition-all z-30 hover:scale-110 cursor-pointer"
                                            title="Remove Image"
                                        >
                                            <i className="fas fa-times"></i>
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}
                        <label className={`flex flex-col items-center justify-center border-2 border-dashed border-zinc-200 rounded-xl hover:border-brand-400 hover:bg-brand-50/20 transition-all cursor-pointer group/upload relative overflow-hidden ${step.images.length > 0 ? 'h-12 border-solid border-zinc-100 bg-surface-50 text-xs text-zinc-500' : 'aspect-[4/3] bg-surface-50/50'}`}>
                             {step.images.length > 0 ? (
                                 <span className="font-bold text-zinc-500 group-hover/upload:text-brand-600 transition-colors flex items-center gap-2">
                                     <i className="fas fa-plus-circle"></i> Add Image
                                 </span>
                             ) : (
                                 <div className="text-center transform transition-transform group-hover/upload:scale-105 duration-300">
                                     <div className="w-10 h-10 bg-white rounded-full shadow-sm flex items-center justify-center mx-auto mb-2 text-zinc-400 group-hover/upload:text-brand-500">
                                         <i className="fas fa-image text-lg"></i>
                                     </div>
                                     <span className="block text-xs font-bold text-zinc-400 group-hover/upload:text-brand-600">Upload Image</span>
                                 </div>
                             )}
                             <input type="file" accept="image/*" multiple onChange={handleImagesChange} className="hidden" />
                        </label>
                         {step.images.length > 0 && (
                            <button onClick={handleAnalyzeImages} disabled={isAnalyzing} className="w-full py-2 bg-gradient-to-r from-brand-50 to-indigo-50 text-brand-600 rounded-lg text-[10px] font-bold uppercase tracking-wider btn-animated-glow border border-brand-100/50 hover:shadow-md">
                                {isAnalyzing ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-magic mr-1"></i>} AI Describe
                            </button>
                        )}
                    </div>
                </div>

                {/* Text Section - Always Second in Editor */}
                <div className="flex-1 space-y-3 order-2">
                    <div className="relative group/title">
                        <input
                            type="text"
                            value={step.title}
                            onChange={(e) => onUpdate(step.id, { title: e.target.value })}
                            placeholder="Step Title"
                            className="w-full text-base font-bold text-zinc-800 placeholder:text-zinc-300 border-b border-transparent focus:border-brand-500 p-1 bg-transparent focus:ring-0 transition-colors"
                        />
                         <button
                            type="button"
                            onClick={handleGenerateTitle}
                            disabled={isGeneratingTitle || !step.description}
                            className="absolute right-0 top-1/2 -translate-y-1/2 text-[10px] font-bold text-brand-600 bg-brand-50 px-2 py-0.5 rounded opacity-0 group-hover/title:opacity-100 transition-all hover:bg-brand-100 disabled:opacity-0 translate-x-2 group-hover/title:translate-x-0"
                        >
                            Generate
                        </button>
                    </div>
                    <textarea
                        rows={5}
                        value={step.description}
                        onChange={(e) => onUpdate(step.id, { description: e.target.value })}
                        placeholder="Description..."
                        className="w-full p-3 bg-surface-50 border border-zinc-100 rounded-xl text-sm text-zinc-600 focus:bg-white focus:border-brand-500 focus:ring-4 focus:ring-brand-500/10 outline-none resize-none transition-all duration-200"
                    />
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default StepEditor;

import React, { useState } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { ManualPage, ManualMetadata } from '../types';
import { generateCoverDesign } from '../services/geminiService';

interface CoverEditorProps {
  page: ManualPage;
  onUpdate: (updates: Partial<ManualPage>) => void;
  metadata: ManualMetadata;
  onUpdateMetadata: (updates: Partial<ManualMetadata>) => void;
  contextSteps: string;
}

const STYLES = [
    { id: 'style-1', name: 'Classic', icon: 'fas fa-image' },
    { id: 'style-2', name: 'Modern Split', icon: 'fas fa-columns' },
    { id: 'style-3', name: 'Bold Left', icon: 'fas fa-align-left' },
    { id: 'style-4', name: 'Tech Frame', icon: 'far fa-square' },
    { id: 'style-5', name: 'Magazine', icon: 'fas fa-newspaper' }
];

const CoverEditor: React.FC<CoverEditorProps> = ({ page, onUpdate, metadata, onUpdateMetadata, contextSteps }) => {
  const [isGenerating, setIsGenerating] = useState(false);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > 5 * 1024 * 1024) { alert("File too large (max 5MB)"); return; }
      const newImage = { id: uuidv4(), url: URL.createObjectURL(file), file };
      onUpdate({ backgroundImage: newImage });
    }
  };

  const handleAIDesign = async () => {
      if (!contextSteps) {
          alert("Please add some content steps first so AI can understand your manual.");
          return;
      }
      setIsGenerating(true);
      try {
          const result = await generateCoverDesign(contextSteps);

          // Update Text
          onUpdateMetadata({
              title: result.title,
              subtitle: result.subtitle
          });

          // Update Design to Dynamic AI Style
          onUpdate({ 
            layoutStyle: 'style-ai-generated',
            coverDesign: result.design 
          });

      } catch (error) {
          console.error(error);
          alert("AI Design failed. Please try again.");
      } finally {
          setIsGenerating(false);
      }
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-zinc-100 p-6 space-y-6 animate-slide-up">

      {/* Header with AI Button */}
      <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-brand-50 rounded-xl flex items-center justify-center text-brand-600 border border-brand-100 shadow-sm">
                 <i className="fas fa-book-cover text-lg"></i>
             </div>
             <div>
                 <h3 className="text-base font-bold text-zinc-900">Front Cover</h3>
                 <p className="text-xs text-zinc-500">The first page of your manual</p>
             </div>
          </div>
          <button 
            onClick={handleAIDesign}
            disabled={isGenerating}
            className="flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-violet-500 to-fuchsia-500 text-white rounded-lg text-xs font-bold shadow-md hover:shadow-lg transition-all disabled:opacity-50 btn-animated-glow"
          >
              {isGenerating ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-wand-magic-sparkles"></i>}
              AI Auto-Design
          </button>
      </div>

      {/* Layout Style Selector */}
      <div>
          <label className="block text-xs font-bold text-zinc-500 uppercase tracking-wider mb-3">Layout Style</label>
          <div className="grid grid-cols-6 gap-3">
              {STYLES.map(style => (
                  <button
                    key={style.id}
                    onClick={() => onUpdate({ layoutStyle: style.id })}
